INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Le fait de Lourdes, de l''histoire à la fiction" de Jean François Soulet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Jeudi 24 août à 18H, la Maison de la vallée accueillera Jean-François Soulet pour une conférence:<br> \" Le fait de Lourdes, de l’histoire à la fiction \"<br> Où en est-on plus d’un siècle et demi après l’annonce des visions de Bernadette Soubirous à Lourdes. Que nous disent les centaines d’ouvrages qui ont paru à leur sujet : livres d’histoire mais aussi romans ?\"<br> A l’issue de la conférence, Jean-François Soulet signera son dernier roman, « Mon Dieu ! Si je m’étais trompée », paru aux Editions Cairn.<br> Entrée libre","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c2b950db-2655-402b-a40f-1fed5b7b7801');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Le fait de Lourdes, de l''histoire à la fiction" de Jean François Soulet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Jeudi 24 août à 18H, la Maison de la vallée accueillera Jean-François Soulet pour une conférence:<br> \" Le fait de Lourdes, de l’histoire à la fiction \"<br> Où en est-on plus d’un siècle et demi après l’annonce des visions de Bernadette Soubirous à Lourdes. Que nous disent les centaines d’ouvrages qui ont paru à leur sujet : livres d’histoire mais aussi romans ?\"<br> A l’issue de la conférence, Jean-François Soulet signera son dernier roman, « Mon Dieu ! Si je m’étais trompée », paru aux Editions Cairn.<br> Entrée libre","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'c2b950db-2655-402b-a40f-1fed5b7b7801');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Le fait de Lourdes, de l''histoire à la fiction" de Jean François Soulet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Jeudi 24 août à 18H, la Maison de la vallée accueillera Jean-François Soulet pour une conférence:<br> \" Le fait de Lourdes, de l’histoire à la fiction \"<br> Où en est-on plus d’un siècle et demi après l’annonce des visions de Bernadette Soubirous à Lourdes. Que nous disent les centaines d’ouvrages qui ont paru à leur sujet : livres d’histoire mais aussi romans ?\"<br> A l’issue de la conférence, Jean-François Soulet signera son dernier roman, « Mon Dieu ! Si je m’étais trompée », paru aux Editions Cairn.<br> Entrée libre","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'c2b950db-2655-402b-a40f-1fed5b7b7801');
