INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Spectacle Par Haz''Art', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>PAR HAZ''ART</strong></p>  <p>Spectacle tout public</p>  <p>durée 50min (alléatoire)</p>  <p></p>  <p><strong>Place de l''église - Luz Saint Sauveur</strong></p>  <p></p>  <p>Le spectacle va commencer.</p>  <p>Aldo arrive… tête en l’air, il avait oublié qu’il devait faire son numéro.</p>  <p>Soucieux de satisfaire son public, il s’efforce de présenter des petits numéros de bric et de broc.</p>  <p>Nerveux, sa maladresse l’emporte, il s’emmêle les pinceaux dans ses périlleux tours de jonglage.</p>  <p>Au fur et à mesure, Aldo s’invente un personnage imaginaire et lui donne vie</p>  <p>Il tente alors d’apprivoiser son nouvel ami…</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '62ce8ba0-37ea-41ef-92b8-3ca8a18984c3');
