INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition "Dessins à l''aquarelle"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><b><span style=\"font-size:16pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">« D’ailleurs et de là-bas »</span></span></span></b></p>  <p style=\"text-align:justify\"></p>  <p style=\"text-align:justify\"><b><span style=\"font-size:13pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">Dessins à l’aquarelle par Chantal Allais.</span></span></span></b></p>  <p style=\"text-align:justify\"><b><span style=\"font-size:13pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">Exposition dans la salle des voûtes du 1<sup>er</sup> au 30 septembre.</span></span></span></b></p>  <p style=\"text-align:justify\"><b><span style=\"font-size:13pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">Vernissage le vendredi 8 septembre à 18h.</span></span></span></b></p>  <p style=\"text-align:justify\"></p>  <p style=\"text-align:justify\"></p>  <p style=\"text-align:justify\"></p>  <p style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">L''équipe de la Maison du Parc national et de la vallée a le plaisir de recevoir l’artiste Chantal Allais, personnalité bien connue en Pays Toy où elle a longtemps vécu.</span></span></p>  <p style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">Complétement autodidacte, c’est en découvrant le lavis et la peinture à l’eau que Chantal a été éprise par la passion du dessin. Pour ce faire, elle s’inspire de photos et parfois de modèles… Elle se régale à jouer avec l’eau, les couleurs et le blanc du papier.</span></span></p>  <p style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:black\">Soutenu depuis quelques années par Artizar (association d’arts plastiques au Pays Basque), c’est l’occasion pour Chantal Allais de venir partager son travail dans une vallée qu’elle affectionne particulièrement.</span></span></p>  <p>Renseignements au 05.62.92.38.38</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b4fffc6e-070b-4bf9-bb4f-70a68ed6fb82');
