INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Thé dansant', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:0cm\" align=\"CENTER\"><font face=\"Calibri, serif\"><font style=\"font-size:20pt\"><font size=\"5\"><b>Merveilleux !</b></font></font></font></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><font face=\"Calibri, serif\"><font size=\"4\"><b>Thé dansant dans un endroit magique. </b></font></font></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><font face=\"Calibri, serif\"><font size=\"4\"><b>Avec un excellent accordéoniste, venez danser en gourmandise au cœur de la salle des voûtes.</b></font></font></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><font face=\"Calibri, serif\"><font size=\"4\"><b>Dimanche 17 septembre à partir de 15h jusqu’à 17h.</b></font></font></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'bcd8c039-73ae-47df-8f25-90d84c4743e4');
