INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Madam Créations', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:16pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\"><span>&nbsp;</span>« Madam Créations » par Pierre Angot.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">Exposition de dessins dans la salle des voûtes du 2 au 31 octobre.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">Vernissage lundi 2 octobre à 18h.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">L''équipe de la Maison du Parc national et de la vallée a le plaisir de recevoir l’artiste Pierre Angot.</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Ayant commencé à dessiner à l’âge de 12 ans, essentiellement au crayon à papier, c’est à 17 ans que Pierre est attiré par la peinture acrylique. Son univers c''est alors construit autour de personnages surréalistes. Parallèlement, il vit une seconde passion, la glisse, qui l''inspire comme une évidence. </span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Très proche de la nature, fasciné par les matières brutes&nbsp;: le bois, la pierre, le fer se mêlent à ses créations. </span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Le vernissage de son exposition, lundi 2 octobre à 18h, sera l’occasion d’échanger avec lui sur son travail original et ses futurs projets…</span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f0e7429c-0f3b-41c2-a3cc-7ed05332376c');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Madam Créations', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:16pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\"><span>&nbsp;</span>« Madam Créations » par Pierre Angot.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">Exposition de dessins dans la salle des voûtes du 2 au 31 octobre.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">Vernissage lundi 2 octobre à 18h.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">L''équipe de la Maison du Parc national et de la vallée a le plaisir de recevoir l’artiste Pierre Angot.</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Ayant commencé à dessiner à l’âge de 12 ans, essentiellement au crayon à papier, c’est à 17 ans que Pierre est attiré par la peinture acrylique. Son univers c''est alors construit autour de personnages surréalistes. Parallèlement, il vit une seconde passion, la glisse, qui l''inspire comme une évidence. </span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Très proche de la nature, fasciné par les matières brutes&nbsp;: le bois, la pierre, le fer se mêlent à ses créations. </span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Le vernissage de son exposition, lundi 2 octobre à 18h, sera l’occasion d’échanger avec lui sur son travail original et ses futurs projets…</span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'f0e7429c-0f3b-41c2-a3cc-7ed05332376c');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Madam Créations', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:16pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\"><span>&nbsp;</span>« Madam Créations » par Pierre Angot.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">Exposition de dessins dans la salle des voûtes du 2 au 31 octobre.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">Vernissage lundi 2 octobre à 18h.</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:13pt;font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></b></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">&nbsp;</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif;color:black\">L''équipe de la Maison du Parc national et de la vallée a le plaisir de recevoir l’artiste Pierre Angot.</span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Ayant commencé à dessiner à l’âge de 12 ans, essentiellement au crayon à papier, c’est à 17 ans que Pierre est attiré par la peinture acrylique. Son univers c''est alors construit autour de personnages surréalistes. Parallèlement, il vit une seconde passion, la glisse, qui l''inspire comme une évidence. </span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Très proche de la nature, fasciné par les matières brutes&nbsp;: le bois, la pierre, le fer se mêlent à ses créations. </span></p>  <p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Le vernissage de son exposition, lundi 2 octobre à 18h, sera l’occasion d’échanger avec lui sur son travail original et ses futurs projets…</span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'f0e7429c-0f3b-41c2-a3cc-7ed05332376c');
