INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fête de la science', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:0cm\" align=\"CENTER\"><span style=\"line-height:100%\"><font face=\"Bookman Old Style, serif\"><font style=\"font-size:16pt\"><font size=\"4\"><b>Le Ministère de la recherche et enseignement supérieur organise au niveau national</b></font></font></font></span></p>  <p style=\"margin-bottom:0cm\"></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><span style=\"line-height:100%\"><font color=\"#ff0000\"><font face=\"Bookman Old Style, serif\"><font size=\"5\"><u><b>La fête de la science</b></u></font></font></font></span></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><span style=\"line-height:100%\"><font color=\"#ff0000\"><u><font face=\"Bookman Old Style, serif\"><font size=\"5\"><b>Du 7 au 14 octobre.</b></font></font></u></font></span></p>  <p style=\"margin-bottom:0cm\"></p>  <p style=\"margin-bottom:0cm\"></p>  <p style=\"margin-bottom:0cm\"><span style=\"line-height:100%\"><font face=\"Bookman Old Style, serif\"><font size=\"3\">L''Association GEOPATRIMOINE PYRENEEN dont le siège est au SIVU du Pibeste à Agos-Vidalos a pris l''initiative de réaliser cette fête au :</font></font></span></p>  <p style=\"margin-bottom:0cm\"></p>  <p style=\"margin-bottom:0cm\"></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><span style=\"line-height:100%\"><font face=\"Bookman Old Style, serif\"><font size=\"5\"><i>Cabanon des géologues au hameau de </i></font></font><font face=\"Bookman Old Style, serif\"><font size=\"5\"><i><b>Sia</b></i></font></font><font face=\"Bookman Old Style, serif\"><font size=\"5\"><i> </i></font></font></span></p>  <p style=\"margin-bottom:0cm\" align=\"CENTER\"><span style=\"line-height:100%\"><font face=\"Bookman Old Style, serif\"><font size=\"5\"><i>(lieu aussi du gâteau à la broche de Sia)</i