INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition "Regards insolites"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>« Regards insolites\" est une exposition photographique réalisée par le Parc national des Pyrénées.</p>  <p>Toute l''année, les gardes-moniteurs du parc national des Pyrénées parcourent la montagne, vallons isolés, sentiers oubliés, cheminements discrets, estives, forêts, lacs, .... Leurs pas les ont conduits dans tous les recoins les plus secrets et les plus isolés.</p>  <p>Ces photos sont le fruit de ces rencontres insolites. Regard décalé, intimité de l''animal, instants rares, poésie des paysages, une autre façon d''entrevoir avec un autre œil le patrimoine du Parc national.</p>  <p>Photo: Etienne Farand/ PNP</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a03d91f4-41df-4f03-9d18-9d890b82ddf4');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition "Regards insolites"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>« Regards insolites\" est une exposition photographique réalisée par le Parc national des Pyrénées.</p>  <p>Toute l''année, les gardes-moniteurs du parc national des Pyrénées parcourent la montagne, vallons isolés, sentiers oubliés, cheminements discrets, estives, forêts, lacs, .... Leurs pas les ont conduits dans tous les recoins les plus secrets et les plus isolés.</p>  <p>Ces photos sont le fruit de ces rencontres insolites. Regard décalé, intimité de l''animal, instants rares, poésie des paysages, une autre façon d''entrevoir avec un autre œil le patrimoine du Parc national.</p>  <p>Photo: Etienne Farand/ PNP</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'a03d91f4-41df-4f03-9d18-9d890b82ddf4');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition "Regards insolites"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>« Regards insolites\" est une exposition photographique réalisée par le Parc national des Pyrénées.</p>  <p>Toute l''année, les gardes-moniteurs du parc national des Pyrénées parcourent la montagne, vallons isolés, sentiers oubliés, cheminements discrets, estives, forêts, lacs, .... Leurs pas les ont conduits dans tous les recoins les plus secrets et les plus isolés.</p>  <p>Ces photos sont le fruit de ces rencontres insolites. Regard décalé, intimité de l''animal, instants rares, poésie des paysages, une autre façon d''entrevoir avec un autre œil le patrimoine du Parc national.</p>  <p>Photo: Etienne Farand/ PNP</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'a03d91f4-41df-4f03-9d18-9d890b82ddf4');
