INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Stage clown adultes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p align=\"LEFT\"><span style=\"line-height:0.09cm\"><font color=\"#231f20\"><sup><font face=\"Andalus, serif\"><font size=\"4\"><b>Stage Clown Adultes </b></font></font></sup></font></span></p>  <p align=\"LEFT\"><span style=\"line-height:0.09cm\"><font color=\"#231f20\"><sup><font face=\"Andalus, serif\"><font size=\"3\">2 et 3 décembre 2017 / de 10h à 18h.</font></font></sup></font></span></p>  <p align=\"LEFT\"><span style=\"line-height:0.09cm\"><font color=\"#231f20\"><sup><font face=\"Andalus, serif\"><font size=\"3\">à la Maison de la Vallée de Luz-Saint-Sauveur</font></font></sup></font></span></p>  <p align=\"LEFT\"><span style=\"line-height:0.09cm\"><font color=\"#231f20\"><sup><font face=\"Andalus, serif\"><font size=\"3\">Infos et réservation : 06 77 95 59 80</font></font></sup></font></span></p>  <p><br>  &nbsp;</p>  <p><font face=\"Andalus, serif\"><u><b>Le clown quésaco ?!</b></u></font></p>  <p><font face=\"Andalus, serif\">C’était le circassien en fin de carrière, le valet de ferme reproduisant les numéros des écuyers, ou peut-être le clochard au nez vinassé entré par mégarde dans l’arène du cirque. Échappé des pistes du cirque traditionnel, le clown est devenu une technique d’acteurs partis à la recherche de leur propre sensibilité comme matière de jeu.</font></p>  <p><font face=\"Andalus, serif\"><b>Le clown est une façon d’être au monde</b>, au plus prêt de ses émotions, en prise directe avec l’instant et l’imprévu. Le clown fait d’abord rire mais émeut aussi. Le rire qu’il procure est un véritable acte de libération pour le public et pour le clown lui-même.</font></p>  <p><font face=\"Andalus, serif\"><b>La pratique du clown nous rapproche de ce qui nous rend humain, une sensibilité qui nous fragilise mais qui en l’acceptant donne de la beauté à nos vies.</b></font></p>  <p><br>  &nbsp;</p>  <p><font face=\"Andalus, serif\"><u><b>Comment travailler le clown ?</b></u></font></p>  <p><font face=\"Andalus, serif\">En partant simplement de soi, de nos forces et de nos faiblesses sans autres outils que son corps aux services de ses émotions, son attention au service du ridicule. Nous travaillerons sans nez. Aucun pré-requis particulier n’est demandé si ce n’est une bonne écoute et une grande envie de jouer et de bien se marrer !</font></p>  <p><font face=\"Andalus, serif\"><b>La méthode :</b></font></p>  <p><font face=\"Andalus, serif\"><b>- </b>Travail avec le corps, les énergies, les émotions.</font></p>  <p><font face=\"Andalus, serif\">- Travail sur l’imaginaire, la spontanéité, la fantaisie.</font></p>  <p><font face=\"Andalus, serif\">- Travail sur la respiration, le lâcher prise, la confiance en soi.</font></p>  <p><font face=\"Andalus, serif\">- Travail d’écoute (soi, le partenaire, le public).</font></p>  <p><font face=\"Andalus, serif\">- Les 5 étapes du numéro de clown.</font></p>  <p><br>  &nbsp;</p>  <p><br>  &nbsp;</p>  <p><br>  &nbsp;</p>  <p><font face=\"Andalus, serif\"><u><b>C’est animé par qui ?</b></u></font></p>  <p><span style=\"background:transparent\"><span style=\"page-break-before:auto\"><font face=\"Andalus, serif\">Après une licence de théâtre, <b>Coline Trouvé</b> emprunte le sentier buissonnier qui mène au clown. Elle se forme au Hangar des Mines avec Christophe Thellier, Emmanuel Sembely, Christine Rossignol et Michel Dallaire. Elle suit également quelques stages au Samovar (avec Charlotte Saliou et Laetitia Deckert). </font></span></span></p>  <p style=\"margin-bottom:0cm\"><span style=\"background:transparent\"><font face=\"Andalus, serif\">Elle se met alors à jouer dès que possible et à donner des ateliers jusqu’en Algérie notamment lors du festival itinérant des Racont’arts.</font></span></p>  <p style=\"margin-bottom:0cm\"><span style=\"background:transparent\"><font face=\"Andalus, serif\">Elle se forma aussi à l’art de la cascade burlesque (Elise Ouvrier-Buffet et Stephane Filok).</font></span></p>  <p style=\"margin-bottom:0cm\"><span style=\"background:transparent\"><font face=\"Andalus, serif\">Elle joue actuellement dans <b>Be Fioul</b>, spectacle décalé pour zonards déroutés (Agonie du Palmier) et intervient également comme clown hospitalier en pédiatrie et gériatrie avec l’association Bises de Clown.</font></span></p>  <p style=\"margin-bottom:0cm\"><span style=\"background:transparent\"><font face=\"Andalus, serif\">Elle cherche, grâce à l’outil du clown qui lui permet un rapport juste et direct avec le public, à aborder dans son travail la problématique de « l’être ensemble » notamment dans l’espace public.</font></span></p>  <p><br>  &nbsp;</p>  <p><font face=\"Andalus, serif\"><u><b>A quelle heure et où ?</b></u></font></p>  <p><font face=\"Andalus, serif\">Le week-end du 2 et 3 décembre, de 10h à 18h.</font></p>  <p><font face=\"Andalus, serif\">A la maison de la Vallée, 24 place Saint-Clément, 65120 Luz-Saint-Sauveur.</font></p>  <p></p>  <p><font face=\"Andalus, serif\"><u><b>Combien ça coûte ?</b></u></font></p>  <p><font face=\"Andalus, serif\">60 euros le week-end !</font></p>  <p><font face=\"Andalus, serif\">30 euros d’arrhes sont obligatoires pour valider votre inscription au stage.</font></p>  <p><font face=\"Andalus, serif\"><i>(à envoyer ou à déposer à la maison de la Vallée,1 semaine max avant le stage, à l''ordre du Collectif Agonie du Palmier)</i></font></p>  <p><font face=\"Andalus, serif\">Pour des raisons d’assurance, vous devrez être adhérents de.... ?</font></p>  <p><br>  &nbsp;</p>  <p><font face=\"Andalus, serif\"><u><b>Je questionne, je m’inscris</b></u></font></p>  <p><font face=\"Andalus, serif\">Coline Trouvé </font></p>  <p><font face=\"Andalus, serif\">coline.trouve@gmail.com</font></p>  <p><font face=\"Andalus, serif\">06 77 95 59 80</font></p>  <p style=\"margin-bottom:0cm\" align=\"LEFT\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0decdebe-c8fb-4aae-9570-9f0900946491');
