INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition de sculpture  sur pierre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align:justify\"><span style=\"color:#666666\"><b><span style=\"font-size:16pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">« Sculpture sur pierre »</span></span></b></span></p>  <p style=\"text-align:justify\"><span style=\"color:#666666\"><b><span style=\"font-size:13pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Par Jean-Jacques ABDALLAH</span></span></b></span></p>  <p style=\"text-align:justify\"><span style=\"color:#666666\"><b><span style=\"font-size:13pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Exposition dans la salle des voûtes du 1<sup>er</sup> décembre au 8 janvier.</span></span></b></span></p>  <p style=\"text-align:justify\"><span style=\"color:#666666\"><b>&nbsp;</b></span></p>  <p style=\"text-align:justify\"></p>  <p style=\"text-align:justify\"></p>  <p style=\"text-align:left\"><span style=\"line-height:150%\"><span style=\"color:#666666\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Installé depuis 1995 à Arras-en-Lavedan, Jean Jacques Abdallah est sculpteur professionnel depuis de nombreuses années.</span></span></span></span></span></p>  <p style=\"text-align:left\"><span style=\"line-height:150%\"><span style=\"color:#666666\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Les matériaux qu’il utilise sont la pierre, le marbre, le granit et parfois le bronze.</span></span></span></span></span></p>  <p style=\"text-align:left\"><span style=\"line-height:150%\"><span style=\"color:#666666\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Qu’elles que soient leurs dimensions, moyennes ou monumentales, ses sculptures ont des formes à tendances géométriques, animales, humaines ou non figuratives.&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span></span></span></span></p>  <p style=\"text-align:left\"><span style=\"line-height:150%\"><span style=\"color:#666666\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Son maître mot&nbsp;: aller toujours à l’essentiel, s’occuper de la ligne et non du détail.</span></span></span></span></span></p>  <p style=\"text-align:left\"><span style=\"line-height:150%\"><span style=\"color:#666666\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Après sa venue lors de la foire aux côtelettes à Luz en septembre pour la réalisation d’une tête de mouton, il est de retour pour présenter une belle collection d’œuvres.</span></span></span></span></span></p>  <p style=\"text-align:left\"><span style=\"line-height:150%\"><span style=\"color:#999999\"><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\"><span style=\"color:#666666\">Très engagé dans le milieu artistique, il est Président de&nbsp; l’association l’Abbadiale maison de Arts, de la culture et du patrimoine à Arras en Lavedan depuis plusieurs&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; années.</span>&nbsp;&nbsp;</span></span></span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'aa6dcbdf-384b-4b6e-8dc8-4555adcec6c1');
