INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition : "Plumes de cîmes"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p></p>  <p>Exposition du parc National du 8 au 31 janvier 2018 à la salle des voûtes de la Maison de la vallée</p>  <p>Réalisée par Laurent Nédélec et Gregory Ortet</p>  <p>A travers toutes ces images réalisées dans les Pyrénées Centrales, les réalisateurs souhaitent<br>  témoigner des beautés sauvages et fragiles de l’avifaune qu’abritent encore les espaces<br>  naturels de nos belles montagnes.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '832f0317-2251-45f3-8a8d-3b0f2da75324');
