INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Spectacle  "La pluie jaune"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Résidence «&nbsp;La pluie jaune&nbsp;»</strong></p>  <p><strong>Spectacle de sortie de résidence&nbsp;:<br>  mercredi 17 janvier à 18h30</strong></p>  <p></p>  <p><strong>Tarifs:&nbsp; 3,50€</strong></p>  <p></p>  <p><br>  Équipe Artistique&nbsp;:</p>  <p>Xavier Camarasa : Fender Rhodes, effets, composition<br>  Richard Comte : Guitare, effets<br>  Julien Chamla : Batterie<br>  Melia Bannerman : Voix, récitante, scénographie</p>  <p>Production :<br>  Gigantonium / Delphine Joussein</p>  <p>Au nord de l''Espagne dans l''Alto Aragon, dans les contreforts des Pyrénées, se trouve le village<br>  d''Ainielle.<br>  Ainielle fait partie d''un vaste ensemble montagneux où se trouvent nombre d''autres villages de ce type dans le Sobrepuerto et le Sobrabe. On les nomme en Espagne « los deshabitados » ou<br>  « despoblados ».<br>  Ainielle fut abandonné progressivement de 1950 à 1973 pour des causes multiples : politiques<br>  industrielles et sociales de la dictature franquiste, isolement (accès uniquement pédestre), difficulté de la vie rurale et paysanne.<br>  Ce village est le théâtre de la nouvelle « La Lluvia Amarilla », écrite par Julio Llamazares en 1988,<br>  dont la parution eu un très grand retentissement en Espagne.</p>  <p>La nouvelle&nbsp;:<br>  La Lluvia amarilla, la pluie jaune, de l’auteur espagnol Julio Llamazares, nous parle du dernier<br>  habitant d''Anielle, village « despoblado » des Pyrénées Aragonaises.<br>  Fortement ancré dans un espace et un paysage ce roman touche pourtant à l''universel. Exil,<br>  mémoire, transition entre deux périodes, deux mondes, cet ouvrage fait résonner les tensions propres à notre époque.<br>  Dans un rapport fort à la nature, au passé, au déroulement du temps, la nouvelle de Llamazares est<br>  un monologue puissant qui révèle ce que notre individualité entretient comme rapport avec la<br>  culture, l''environnement et comment l''histoire individuelle se fond avec l''histoire collective.<br>  Enfin la puissance d''évocation de l''écrivain et la richesse de son style construit et déconstruit une<br>  fresque poétique et riche où réel et imaginaire, où passé, présent, futur s''entremêlent.</p>  <p><br>  « Au loin, sur la ligne des montagnes, les toits d''Ainielle flottaient dans la nuit comme les ombres des peupliers<br>  sur l''eau. Mais brusquement, vers les deux ou trois heures du matin, un vent léger se fraya un passage par la<br>  rivière : la fenêtre et le toit du moulin se remplirent tout à coup d''une pluie drue et jaune. C''étaient les feuilles<br>  mortes des peupliers qui tombaient, la pluie lente et paisible de l''automne qui revenait vers les montagnes pour<br>  couvrir les champs de vieil or et les chemins et les villages d''une douce et sauvage mélancolie. Cette pluie dura<br>  quelques minutes à peine, mais suffisamment pour colorer en jaune la nuit entière et pour me faire comprendre,<br>  à l''aube, lorsque la lumière du soleil revint incendier mes yeux et les feuilles mortes que c''était elle qui rouillait<br>  et détruisait lentement, automne après automne, jour après jour, la chaux des murs et les vieux calendriers, le<br>  bord des lettres et des photographies, la machinerie abandonnée du moulin et de mon cœur. »</p>  <p>Ce récit est le point de départ du projet artistique LA PLUIE JAUNE, on y retrouve la richesse des<br>  multiples thèmes abordés dans cette nouvelle&nbsp;:exode, solitude, folie, associés à sa forme (un long<br>  monologue où passé, présent, futur sont confondus), ainsi qu’à la beauté et l''incroyable puissance<br>  émotionnelle que dégagent ces lieux.<br>  La nouvelle présente également des antithèses jamais résolues. Il est ainsi très important, dans le<br>  processus de création et dans le contenu général de la pièce finale, de faire apparaître cette<br>  problématique, notamment entre ce qui constitue dans l''œuvre l''opposition ruralité / urbanité.</p>  <p>La création&nbsp;:<br>  ​Le matériel utilisé pour le socle compositionnel est directement puisé sur place. Un travail de collectage d''informations est réalisé en plusieurs étapes (informations sonores, visuelles, récit original, prolongements poétiques et vécu). Les villages abandonnés des territoires de l''Alto Aragon représentent une source puissante d''inspiration...<br>  La création est initiée en juillet 2017 par une résidence à Germ au Centre de Création «&nbsp;Chez Lily&nbsp;» dans la vallée du Louron (Hautes-Pyrénées) avec un premier collectage dans les villages du Sobrabe (Ainsa).<br>  Cette méthode atypique de création favorise les allers-retours entre texte et musique, texte lu et enregistré, langue espagnole et française, écriture musicale et improvisation, sons concrets et sons musicaux, comme pour mieux cerner toutes les strates du roman, les multiples résonances du texte.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '49fda7cb-470b-432d-84b2-9197a51dad1f');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Spectacle  "La pluie jaune"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Résidence «&nbsp;La pluie jaune&nbsp;»</strong></p>  <p><strong>Spectacle de sortie de résidence&nbsp;:<br>  mercredi 17 janvier à 18h30</strong></p>  <p></p>  <p><strong>Tarifs:&nbsp; 3,50€</strong></p>  <p></p>  <p><br>  Équipe Artistique&nbsp;:</p>  <p>Xavier Camarasa : Fender Rhodes, effets, composition<br>  Richard Comte : Guitare, effets<br>  Julien Chamla : Batterie<br>  Melia Bannerman : Voix, récitante, scénographie</p>  <p>Production :<br>  Gigantonium / Delphine Joussein</p>  <p>Au nord de l''Espagne dans l''Alto Aragon, dans les contreforts des Pyrénées, se trouve le village<br>  d''Ainielle.<br>  Ainielle fait partie d''un vaste ensemble montagneux où se trouvent nombre d''autres villages de ce type dans le Sobrepuerto et le Sobrabe. On les nomme en Espagne « los deshabitados » ou<br>  « despoblados ».<br>  Ainielle fut abandonné progressivement de 1950 à 1973 pour des causes multiples : politiques<br>  industrielles et sociales de la dictature franquiste, isolement (accès uniquement pédestre), difficulté de la vie rurale et paysanne.<br>  Ce village est le théâtre de la nouvelle « La Lluvia Amarilla », écrite par Julio Llamazares en 1988,<br>  dont la parution eu un très grand retentissement en Espagne.</p>  <p>La nouvelle&nbsp;:<br>  La Lluvia amarilla, la pluie jaune, de l’auteur espagnol Julio Llamazares, nous parle du dernier<br>  habitant d''Anielle, village « despoblado » des Pyrénées Aragonaises.<br>  Fortement ancré dans un espace et un paysage ce roman touche pourtant à l''universel. Exil,<br>  mémoire, transition entre deux périodes, deux mondes, cet ouvrage fait résonner les tensions propres à notre époque.<br>  Dans un rapport fort à la nature, au passé, au déroulement du temps, la nouvelle de Llamazares est<br>  un monologue puissant qui révèle ce que notre individualité entretient comme rapport avec la<br>  culture, l''environnement et comment l''histoire individuelle se fond avec l''histoire collective.<br>  Enfin la puissance d''évocation de l''écrivain et la richesse de son style construit et déconstruit une<br>  fresque poétique et riche où réel et imaginaire, où passé, présent, futur s''entremêlent.</p>  <p><br>  « Au loin, sur la ligne des montagnes, les toits d''Ainielle flottaient dans la nuit comme les ombres des peupliers<br>  sur l''eau. Mais brusquement, vers les deux ou trois heures du matin, un vent léger se fraya un passage par la<br>  rivière : la fenêtre et le toit du moulin se remplirent tout à coup d''une pluie drue et jaune. C''étaient les feuilles<br>  mortes des peupliers qui tombaient, la pluie lente et paisible de l''automne qui revenait vers les montagnes pour<br>  couvrir les champs de vieil or et les chemins et les villages d''une douce et sauvage mélancolie. Cette pluie dura<br>  quelques minutes à peine, mais suffisamment pour colorer en jaune la nuit entière et pour me faire comprendre,<br>  à l''aube, lorsque la lumière du soleil revint incendier mes yeux et les feuilles mortes que c''était elle qui rouillait<br>  et détruisait lentement, automne après automne, jour après jour, la chaux des murs et les vieux calendriers, le<br>  bord des lettres et des photographies, la machinerie abandonnée du moulin et de mon cœur. »</p>  <p>Ce récit est le point de départ du projet artistique LA PLUIE JAUNE, on y retrouve la richesse des<br>  multiples thèmes abordés dans cette nouvelle&nbsp;:exode, solitude, folie, associés à sa forme (un long<br>  monologue où passé, présent, futur sont confondus), ainsi qu’à la beauté et l''incroyable puissance<br>  émotionnelle que dégagent ces lieux.<br>  La nouvelle présente également des antithèses jamais résolues. Il est ainsi très important, dans le<br>  processus de création et dans le contenu général de la pièce finale, de faire apparaître cette<br>  problématique, notamment entre ce qui constitue dans l''œuvre l''opposition ruralité / urbanité.</p>  <p>La création&nbsp;:<br>  ​Le matériel utilisé pour le socle compositionnel est directement puisé sur place. Un travail de collectage d''informations est réalisé en plusieurs étapes (informations sonores, visuelles, récit original, prolongements poétiques et vécu). Les villages abandonnés des territoires de l''Alto Aragon représentent une source puissante d''inspiration...<br>  La création est initiée en juillet 2017 par une résidence à Germ au Centre de Création «&nbsp;Chez Lily&nbsp;» dans la vallée du Louron (Hautes-Pyrénées) avec un premier collectage dans les villages du Sobrabe (Ainsa).<br>  Cette méthode atypique de création favorise les allers-retours entre texte et musique, texte lu et enregistré, langue espagnole et française, écriture musicale et improvisation, sons concrets et sons musicaux, comme pour mieux cerner toutes les strates du roman, les multiples résonances du texte.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '49fda7cb-470b-432d-84b2-9197a51dad1f');
