INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Contes " Tristan & Yseult"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>TRISTAN<br>  &amp; YSEULT<br>  <br>  <br>  Récit raconté à deux voix par<br>  Nathalie Lhoste-Clos et Marion Lo Monaco<br>  Conception visuelle : Jean Mosambi</p>  <p>Tarif: 5€</p>  <p><br>  Tout public, dès 10 ans<br>  1h10<br>  <br>  SYNOPSIS<br>  Deux jeunes gens. Des adolescents.<br>  Une mer les sépare.<br>  La fille du roi d’Irlande et le neveu de Marc roi de Cornouailles.<br>  L’une est élevée dans les secrets de la magie, l’autre dans les vertus de la<br>  chevalerie.<br>  Les conflits entre leurs royaumes les séparent.<br>  Mais ils se rencontrent. Et quand il s’agit de trouver une épouse pour son<br>  oncle le roi Marc, Tristan part chercher Yseult, de l’autre côté de la mer.<br>  Pourtant l’amour est là et le désir les enflamment. Ils vont s’aimer,<br>  absolument.<br>  Un oncle, un époux, un roi les sépare.<br>  Pour pouvoir s’aimer, ils vont vivre dans le mensonge, les angoisses, souffrir<br>  les dangers et parfois la misère.<br>  C’est cher payé pour s’aimer. Mais après avoir connu un tel amour, ils ne<br>  peuvent plus vivre sans.<br>  Qui le pourrait ?<br>  LES CONTEUSES<br>  <br>  Nathalie Lhoste-Clos<br>  De nombreuses années dans le spectacle, puis une rencontre déterminante avec le conte et les<br>  conteurs. Alors petit à petit, tranquillement, elle raconte dans les écoles,<br>  les maisons de retraite, les bibliothèques et autres lieux ayant les oreilles grandes ouvertes.<br>  Formation au conte avec René Martinez, Michel Hindenoch, Alberto Garcia Sanchez, Marc Aubaret et<br>  Hassane Kassi Kouyaté.<br>  <br>  Marion Lo Monaco<br>  Marion entre par la porte du théâtre. Elle se forme 4 ans à l''école Claude Mathieu à Paris, puis<br>  devient comédienne de troupes. Mais le conte pointe le bout de son nez depuis longtemps.<br>  C''est en 2012 qu''elle commence véritablement à y prêter les oreilles et la langue. Depuis, elle<br>  n''en démord plus. Ce qu''elle aime : raconter des histoires simplement, avec ou sans musique,<br>  munie de la seule caméra du conte, pour rêver à plusieurs. Depuis, elle se consacre<br>  exclusivement à la littérature orale.<br>  Formation au conte avec Hassane Kassi Kouyaté, Michel Hindenoch, Jihad Darwiche, Didier Kowarsky<br>  et au CMLO avec Marc Aubaret.<br>  Une rencontre...<br>  <br>  Tout ça, finalement, c''est la faute de Hassane Kassi Kouyaté...<br>  Si nous n’avions pas participé à ce stage de trois semaines dans la Drôme avec lui, on ne se<br>  serait pas rencontrées. On aurait pas fait ensemble toutes ces heures de route depuis les Hautes-<br>  Pyrénées à échanger sur le spectacle, sur notre amour naissant et commun pour le conte, sur nos<br>  envies futures; sur la vie en somme. Le stage que proposait Hassane portait très bien son nom :<br>  La liberté dans le conte. Hassane nous a ouvert les portes du conte en mettant un point<br>  d''honneur sur le fait qu''il faut avant tout cultiver sa propre personnalité, intimité, dans l''art de<br>  raconter des histoires. Pas de formatage, mais de l''authenticité et de l''amour. Pas<br>  d''intellectualisme, mais une parole qui passe par le coeur et le corps.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'cb78646c-cadd-40b8-8c9e-aa8a1c73eed3');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Contes " Tristan & Yseult"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>TRISTAN<br>  &amp; YSEULT<br>  <br>  <br>  Récit raconté à deux voix par<br>  Nathalie Lhoste-Clos et Marion Lo Monaco<br>  Conception visuelle : Jean Mosambi</p>  <p>Tarif: 5€</p>  <p><br>  Tout public, dès 10 ans<br>  1h10<br>  <br>  SYNOPSIS<br>  Deux jeunes gens. Des adolescents.<br>  Une mer les sépare.<br>  La fille du roi d’Irlande et le neveu de Marc roi de Cornouailles.<br>  L’une est élevée dans les secrets de la magie, l’autre dans les vertus de la<br>  chevalerie.<br>  Les conflits entre leurs royaumes les séparent.<br>  Mais ils se rencontrent. Et quand il s’agit de trouver une épouse pour son<br>  oncle le roi Marc, Tristan part chercher Yseult, de l’autre côté de la mer.<br>  Pourtant l’amour est là et le désir les enflamment. Ils vont s’aimer,<br>  absolument.<br>  Un oncle, un époux, un roi les sépare.<br>  Pour pouvoir s’aimer, ils vont vivre dans le mensonge, les angoisses, souffrir<br>  les dangers et parfois la misère.<br>  C’est cher payé pour s’aimer. Mais après avoir connu un tel amour, ils ne<br>  peuvent plus vivre sans.<br>  Qui le pourrait ?<br>  LES CONTEUSES<br>  <br>  Nathalie Lhoste-Clos<br>  De nombreuses années dans le spectacle, puis une rencontre déterminante avec le conte et les<br>  conteurs. Alors petit à petit, tranquillement, elle raconte dans les écoles,<br>  les maisons de retraite, les bibliothèques et autres lieux ayant les oreilles grandes ouvertes.<br>  Formation au conte avec René Martinez, Michel Hindenoch, Alberto Garcia Sanchez, Marc Aubaret et<br>  Hassane Kassi Kouyaté.<br>  <br>  Marion Lo Monaco<br>  Marion entre par la porte du théâtre. Elle se forme 4 ans à l''école Claude Mathieu à Paris, puis<br>  devient comédienne de troupes. Mais le conte pointe le bout de son nez depuis longtemps.<br>  C''est en 2012 qu''elle commence véritablement à y prêter les oreilles et la langue. Depuis, elle<br>  n''en démord plus. Ce qu''elle aime : raconter des histoires simplement, avec ou sans musique,<br>  munie de la seule caméra du conte, pour rêver à plusieurs. Depuis, elle se consacre<br>  exclusivement à la littérature orale.<br>  Formation au conte avec Hassane Kassi Kouyaté, Michel Hindenoch, Jihad Darwiche, Didier Kowarsky<br>  et au CMLO avec Marc Aubaret.<br>  Une rencontre...<br>  <br>  Tout ça, finalement, c''est la faute de Hassane Kassi Kouyaté...<br>  Si nous n’avions pas participé à ce stage de trois semaines dans la Drôme avec lui, on ne se<br>  serait pas rencontrées. On aurait pas fait ensemble toutes ces heures de route depuis les Hautes-<br>  Pyrénées à échanger sur le spectacle, sur notre amour naissant et commun pour le conte, sur nos<br>  envies futures; sur la vie en somme. Le stage que proposait Hassane portait très bien son nom :<br>  La liberté dans le conte. Hassane nous a ouvert les portes du conte en mettant un point<br>  d''honneur sur le fait qu''il faut avant tout cultiver sa propre personnalité, intimité, dans l''art de<br>  raconter des histoires. Pas de formatage, mais de l''authenticité et de l''amour. Pas<br>  d''intellectualisme, mais une parole qui passe par le coeur et le corps.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'cb78646c-cadd-40b8-8c9e-aa8a1c73eed3');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Contes " Tristan & Yseult"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>TRISTAN<br>  &amp; YSEULT<br>  <br>  <br>  Récit raconté à deux voix par<br>  Nathalie Lhoste-Clos et Marion Lo Monaco<br>  Conception visuelle : Jean Mosambi</p>  <p>Tarif: 5€</p>  <p><br>  Tout public, dès 10 ans<br>  1h10<br>  <br>  SYNOPSIS<br>  Deux jeunes gens. Des adolescents.<br>  Une mer les sépare.<br>  La fille du roi d’Irlande et le neveu de Marc roi de Cornouailles.<br>  L’une est élevée dans les secrets de la magie, l’autre dans les vertus de la<br>  chevalerie.<br>  Les conflits entre leurs royaumes les séparent.<br>  Mais ils se rencontrent. Et quand il s’agit de trouver une épouse pour son<br>  oncle le roi Marc, Tristan part chercher Yseult, de l’autre côté de la mer.<br>  Pourtant l’amour est là et le désir les enflamment. Ils vont s’aimer,<br>  absolument.<br>  Un oncle, un époux, un roi les sépare.<br>  Pour pouvoir s’aimer, ils vont vivre dans le mensonge, les angoisses, souffrir<br>  les dangers et parfois la misère.<br>  C’est cher payé pour s’aimer. Mais après avoir connu un tel amour, ils ne<br>  peuvent plus vivre sans.<br>  Qui le pourrait ?<br>  LES CONTEUSES<br>  <br>  Nathalie Lhoste-Clos<br>  De nombreuses années dans le spectacle, puis une rencontre déterminante avec le conte et les<br>  conteurs. Alors petit à petit, tranquillement, elle raconte dans les écoles,<br>  les maisons de retraite, les bibliothèques et autres lieux ayant les oreilles grandes ouvertes.<br>  Formation au conte avec René Martinez, Michel Hindenoch, Alberto Garcia Sanchez, Marc Aubaret et<br>  Hassane Kassi Kouyaté.<br>  <br>  Marion Lo Monaco<br>  Marion entre par la porte du théâtre. Elle se forme 4 ans à l''école Claude Mathieu à Paris, puis<br>  devient comédienne de troupes. Mais le conte pointe le bout de son nez depuis longtemps.<b