INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Clown''destins"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Dans le cadre des mercredis artistiques, toute l’équipe de la Maison de la vallée vous propose le spectacle « Clown’destins » par la Compagnie « Les doigts dans le nez ».</span></span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Grouchka et Pietra, deux sans papiers, rêvent de voyages, de passeurs généreux, de terres d’accueil. </span></span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Petits personnages apparemment impuissants d’un destin qui les dépasse, elles mettent le doigt là où ça fait mal. Le burlesque des situations met au grand jour les heurs et malheurs de notre société mais l’optimisme des clowns nous offre une belle leçon d’humanité.</span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '35b193ca-e940-4a99-b545-d432a4a65606');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Clown''destins"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Dans le cadre des mercredis artistiques, toute l’équipe de la Maison de la vallée vous propose le spectacle « Clown’destins » par la Compagnie « Les doigts dans le nez ».</span></span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Grouchka et Pietra, deux sans papiers, rêvent de voyages, de passeurs généreux, de terres d’accueil. </span></span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Petits personnages apparemment impuissants d’un destin qui les dépasse, elles mettent le doigt là où ça fait mal. Le burlesque des situations met au grand jour les heurs et malheurs de notre société mais l’optimisme des clowns nous offre une belle leçon d’humanité.</span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '35b193ca-e940-4a99-b545-d432a4a65606');
