('f9fe506b-1462-488b-b34d-540ca6537fc3', 'exposition', true, false, NULL, '2018-07-15T22:00:00.000Z', '2018-08-30T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2018-07-15T22:00:00.000Z', '2018-07-15T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Le temps d''une traversée" par Jean Lavigne', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p class=\"Corps\">Paysages d’une marche en montagne sur une haute route de l’Orhy au Canigou</p>  <p class=\"Corps\"></p>  <p class=\"Corps\">Les photos présentées ont été réalisées du 23 août au 28 septembre 2015, soit en 36 jours et sont intimement liées à une marche, une itinérance montagnarde.</p>  <p class=\"Corps\">Elles s’inscrivent dans une unité géographique (les Pyrénées) et un temps déterminé (celui des étapes) ponctuant le « fil » de ce qui devient une traversée.</p>  <p class=\"Corps\">Lumières rasantes des petits matins, plissements fuyants des mouvements de la terre, nuages boursoufflant sous les vents, chaos savamment ordonnés, courbes enlacées des pins à crochet, pierres-sculptures solitaires,&nbsp; tout participe&nbsp; dans cette marche à travers d’authentiques et sauvages espaces à l’insatiable quête d’une poésie naturelle et primitive.</p>  <p class=\"Corps\">Partir, vagabonder, aller d’une vallée à une autre, d’un col à un autre, d’un pic à un autre…</p>  <p class=\"Corps\">A l’arrivée un cheminement, un itinéraire qui s’est construit, fruit d’envies et d’expériences, confrontées à la réalité du terrain,&nbsp; au plaisir et à la liberté d’aller et venir au gré du temps, des brumes, du vent, de la pluie, du soleil, des paysages rencontrés, mélange improvisé et magique. Il n’existe pas « une » traversée mais « des » traversées, aucune ne peut se ressembler.&nbsp;</p>  <p class=\"Corps\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;</p>  <p class=\"Corps\"></p>  <p class=\"Corps\">TRAVERSER LES PYRENEES : « Un regard photographique »</p>  <p class=\"Corps\">Marcher, vagabonder pour le plaisir du corps, de l’œil et du cœur !</p>  <p class=\"Corps\">Le temps de la marche est le temps dominant, celui de la mobilité qui donne le rythme. Rythme des pas, rythme du corps…</p>  <p class=\"Corps\">Le temps de l’œil est celui des perceptions, du regard, c’est le temps de l’arrêt, de l’instant qui tente l’immobilité. Il se superpose à celui de la marche, il l’accompagne. Il est pensif, curieux, songeur, alerte. Ces photographies naissent de ce va-et-vient permanent, entre ce « pas » conquérant en mouvement et cet « œil » pensif qui fixe. Ces temps-là sont ici limités.</p>  <p class=\"Corps\">Le temps du cœur est celui qui traverse les autres, celui des images qu’on crée, des mots qu’on cherche. C’est un temps qui accompagne, qui dure, sans fin, et se partage…</p>  <p class=\"Corps\">Partager ces moments là avec compagnes et compagnons, frangines et frangins, amis et public, montagnards ou pas. Un temps collectif, social, indispensable.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f9fe506b-1462-488b-b34d-540ca6537fc3');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Le temps d''une traversée" par Jean Lavigne', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p class=\"Corps\">Paysages d’une marche en montagne sur une haute route de l’Orhy au Canigou</p>  <p class=\"Corps\"></p>  <p class=\"Corps\">Les photos présentées ont été réalisées du 23 août au 28 septembre 2015, soit en 36 jours et sont intimement liées à une marche, une itinérance montagnarde.</p>  <p class=\"Corps\">Elles s’inscrivent dans une unité géographique (les Pyrénées) et un temps déterminé (celui des étapes) ponctuant le « fil » de ce qui devient une traversée.</p>  <p class=\"Corps\">Lumières rasantes des petits matins, plissements fuyants des mouvements de la terre, nuages boursoufflant sous les vents, chaos savamment ordonnés, courbes enlacées des pins à crochet, pierres-sculptures solitaires,&nbsp; tout participe&nbsp; dans cette marche à travers d’authentiques et sauvages espaces à l’insatiable quête d’une poésie naturelle et primitive.</p>  <p class=\"Corps\">Partir, vagabonder, aller d’une vallée à une autre, d’un col à un autre, d’un pic à un autre…</p>  <p class=\"Corps\">A l’arrivée un cheminement, un itinéraire qui s’est construit, fruit d’envies et d’expériences, confrontées à la réalité du terrain,&nbsp; au plaisir et à la liberté d’aller et venir au gré du temps, des brumes, du vent, de la pluie, du soleil, des paysages rencontrés, mélange improvisé et magique. Il n’existe pas « une » traversée mais « des » traversées, aucune ne peut se ressembler.&nbsp;</p>  <p class=\"Corps\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;</p>  <p class=\"Corps\"></p>  <p class=\"Corps\">TRAVERSER LES PYRENEES : « Un regard photographique »</p>  <p class=\"Corps\">Marcher, vagabonder pour le plaisir du corps, de l’œil et du cœur !</p>  <p class=\"Corps\">Le temps de la marche est le temps dominant, celui de la mobilité qui donne le rythme. Rythme des pas, rythme du corps…</p>  <p class=\"Corps\">Le temps de l’œil est celui des perceptions, du regard, c’est le temps de l’arrêt, de l’instant qui tente l’immobilité. Il se superpose à celui de la marche, il l’accompagne. Il est pensif, curieux, songeur, alerte. Ces photographies naissent de ce va-et-vient permanent, entre ce « pas » conquérant en mouvement et cet « œil » pensif qui fixe. Ces temps-là sont ici limités.</p>  <p class=\"Corps\">Le temps du cœur est celui qui traverse les autres, celui des images qu’on crée, des mots qu’on cherche. C’est un temps qui accompagne, qui dure, sans fin, et se partage…</p>  <p class=\"Corps\">Partager ces moments là avec compagnes et compagnons, frangines et frangins, amis et public, montagnards ou pas. Un temps collectif, social, indispensable.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'f9fe506b-1462-488b-b34d-540ca6537fc3');
