INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Vernissage-Concert "Le temps d''une traversée"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Comme un pont entre photographie et musique, Jean Lavigne et Raymond Boni associeront leurs arts lors du vernissage de l''exposition \"Le temps d''une traversée\".</p>  <p>Guitariste, harmoniciste, improvisateur, compositeur mais surtout ami de longues dates de Jean lavigne, Raymond Boni a tenu à l''accompagner en musique lors de la présenatation de ses oeuvres.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '57433f5e-ebc0-445d-9fa8-df890f9d0526');
