INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fête de Saint Sauveur', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\"><span style=\"font-family:LiberationSerif\">La fête de de St Sauveur se déroule cette année sur le pont Napoléon.</span></span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\"><span style=\"font-family:LiberationSerif\">Pour la première fois de son histoire, le pont sera le théâtre de la manifestation. Il sera largement mis à l''honneur avec un feu d''artifice qui clôturera la soirée.&nbsp; </span></span></span></span>Traditionnellement cette fête est celle des fleurs et du végétal, telle<br>  une ode à la nature, c''est pourquoi la fleur sera au centre de cette belle soirée :</p>  <p></p>  <p><br>  <strong>Installation végétale participative : </strong>la Maison de la vallée a conçu ce projet avec Nelly Ducamp, fleuriste et plasticienne Land art originaire de la vallée du Pays Toy. Cet atelier, doit permettre à chacun de s''essayer au land art et à l''installation végétale. Il est ouvert à tous, entre amis ou en famille et associe matériaux naturels et fleurs cultivées pour un résultat digne de la grandeur de ce pont magnifique qu''est le pont Napoléon. La participation est libre et gratuite. Cependant chacun peut<br>  participer à la beauté de cette installation en amenant avec lui des hortensias bleu et vert.<br>  <br>  <strong>Bourse aux fleurs :</strong> chacun peut amener des plantes en pot et les échanger avec les différents participants. Vivaces, annuelles, d''intérieur ou d''extérieur chaque plante compte. Le service des espaces verts de Luz est associé à ce projet. Il met à disposition des plantes en pot cultivées (Zinnia, Rose d''inde, Absinthe, Achillée, Graminées, Sedum) pour l''occasion qui seront offertes aux participants. Un stand conçu pour parler de plantes et de culture.<br>  <br>  <strong>Fanfare \"Les Tobrogoï\" :</strong> fanfare tziganafreecaine à mobylettes.<br>  Sur des rythmiques afro-américaines (afro-beat, jazz...) qui constituent leur culture commune, les Tobrogoï ont ajouté la vivacité et la fougue des mélodies de l''est et de l''orient pour créer le \"tziganafricansound\" : un répertoire instrumental ouvert, énergique, toujours axé sur la danse, où règne un esprit d''improvisation jubilatoire. A chaque concert, les gens sortent d''eux-mêmes et nous manifestent leur amour. Afin de les combler, nous transpirons sur nos instruments pour que la musicalité donne lieu à la libération corporelle : HOT and FREE !<br>  <a href=\"https://tobrogoi.com/www.youtube.com/watch?v=8vKCbpC-aUU\">Lien musical Tobrogoï</a><br>  <br>  <strong>Spectacle de Mât Chinois : « Ce qui doit arriver… arrive. »</strong><br>  Spectacle de cirque poétique avec Andréa Shulte, circassienne formée au Lido.<br>  Arriver.… Partir … et notre vecu entre : les incontrôlables habitudes, un quotidien dompté...et...ça qui doit arriver , arrive...<br>  Douce danse des événement sauvages, toi et moi…<br>  <br>  Buvette sur place.<br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f99b8bd8-d294-4ab4-aa9c-de2f744c5898');
