INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CRIEE PUBLIQUE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<table class=\"Table\" style=\"width:100.0%; border:undefined\" width=\"100%\">  <tbody>   <tr>    <td>     <p style=\"padding:.75pt .75pt .75pt .75pt\"><strong><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Une crieuse dans les rues de Luz Saint-Sauveur !!!</span></span></strong></p>    </td>   </tr>   <tr>    <td>     <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">En ces temps de communication surdimensionnée sur des supports démultipliés, quoi de plus efficace que la parole elle-même ?</span></span></p>      <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Cet été, nous sommes très heureux d''inviter une crieuse pour la première fois de son histoire. L''idée originelle émerge d''un constat simple : la parole est un outil formidable pour favoriser le lien social et l''expression de la liberté. Pour porter ce projet, nous avons fait appel à Cali Hays, circassienne de profession, formée à l''équilibre, à la voltige, et au travail de clown. </span></span></p>    </td>   </tr>   <tr>    <td style=\"padding:.75pt .75pt .75pt .75pt\"></td>   </tr>   <tr>    <td>     <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">La criée est avant tout une démarche culturelle au service des habitants et des visiteurs. Elle met en valeur les richesses humaines. Ainsi chacun peut, par des moyens simples, passer des messages à ses concitoyens. Les règles sont tout aussi simples que le concept lui-même : tous les messages sont acceptables tant qu''ils sont rédigés sans malveillance, de façon lisible et qu''ils n''ont pas un caractère publicitaire. Poèmes, citations, recettes de cuisine, conseils, petites annonces, coups de gueules, informations sur la vie publique... </span></span></p>      <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Tous les messages sont les bienvenus. </span></span></p>      <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Oyez ! Oyez ! La crieuse clamera au monde ce que l''on n''a jamais osé lui dire.</span></span></p>    </td>   </tr>   <tr>    <td>     <table class=\"Table\" style=\"padding:.75pt .75pt .75pt .75pt; border:undefined\">      <tbody>       <tr>        <td style=\"padding:.75pt .75pt .75pt .75pt\"></td>       </tr>      </tbody>     </table>    </td>   </tr>   <tr>    <td>     <p style=\"padding:.75pt .75pt .75pt .75pt\"><u><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Comment faire pour que Cali soit le porte-parole de votre message ?</span></span></u></p>      <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Il vous suffit de le déposer dans une des boites aux lettres à votre disposition à la Maison du Parc national et de la vallée, devant l''Office de Tourisme ou devant l''Eglise des Templiers.</span></span></p>    </td>   </tr>   <tr>    <td>     <table class=\"Table\" style=\"padding:.75pt .75pt .75pt .75pt; border:undefined\">      <tbody>       <tr>        <td style=\"padding:.75pt .75pt .75pt .75pt\"></td>       </tr>      </tbody>     </table>    </td>   </tr>   <tr>    <td>     <p style=\"padding:.75pt .75pt .75pt .75pt\"><u><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Où et quand retrouver Cali ?</span></span></u></p>      <p style=\"padding:.75pt .75pt .75pt .75pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Tous les mardis à 18h45 et les mercredis à 17h!</span></span></p>    </td>   </tr>  </tbody> </table> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a117105a-ab36-4eaf-8dba-7ac586798450');
