INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Tango aqui ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Cours de Tango gratuits aux thermes Luzéa les :</p>  <p>13, 14, 25 et 27 septembre à 16h pour les curistes et 20h pour les locaux.</p>  <p>16, 18 et 19 octobre à 16h pour les curistes et 20h pour les locaux.</p>  <p>Réservations à la Maison de la vallée ou aux thermes Luzéa.</p>  <p></p>  <p><strong>Samedi 20 octobre</strong>, au forum de luz à partir de 14h : cinéma, concert, exposition autour du Tango!</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '517cdef7-a51f-46c1-b90c-18ae9dac272c');
