INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('45a6260d-fbbf-4e36-93b9-50f9e4b3fc37', 'residence', true, false, false, NULL, '2018-09-02T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2018-09-02T22:00:00.000Z', '2018-09-02T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Racine', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Pour cette nouvelle saison 18-19, la Maison du Parc national et de la vallée est heureuse d’accueillir une série de résidences d''artistes. En soutenant des spectacles en création, la Maison de la vallée souhaite favoriser les spectacles en devenir mais aussi amener le public à découvrir le processus de création propre à chaque compagnie.</span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">L''attraction Cie ouvre le bal avec la première résidence de la saison autour du spectacle \"Racine\". </span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Ce projet, adressé au tout public, est né en extérieur avec un spectacle aérien et poétique dont un des acteurs principaux était un arbre. Le public du Pays Toy a d''ailleurs pu apprécier ce spectacle le 15 août dernier, au pied du beau merisier du verger, dans le cadre des mercredis artistiques. De retour en intérieur, toute l''équipe artistique est en recherche pour adapter le spectacle en salle. Le travail de création aborde les thématiques du voyage, de la mémoire, des origines, de la différence. L''univers poétique et scénographique joue également un rôle important dans la transposition du projet en salle. </span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Pour clôturer la résidence, la Maison de la vallée propose un rendez-vous, ouvert à tous, pour découvrir une étape de la création du spectacle le mercredi 12 septembre à 18h30. Un moment de rencontre privilégié avec l''équipe artistique pour découvrir l''univers de ce spectacle d''une poésie à toutes épreuves.</span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Coproduction Archaos Pôle National Cirque, Festival Scène de Cirque – Ville de Puget-Théniers, <b>Maison du Parc National et de la Vallée de Luz-Saint-Sauveur</b>, Ville de Valbonne Sophia Antipolis, Le Pré des Arts, Centre Régional des Arts du Cirque Sud – Piste d’Azur, Théâtre National de Nice avec le soutien de la Ville de Nice et du Conseil Départemental des Alpes-Maritimes.</span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '45a6260d-fbbf-4e36-93b9-50f9e4b3fc37');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Racine', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Pour cette nouvelle saison 18-19, la Maison du Parc national et de la vallée est heureuse d’accueillir une série de résidences d''artistes. En soutenant des spectacles en création, la Maison de la vallée souhaite favoriser les spectacles en devenir mais aussi amener le public à découvrir le processus de création propre à chaque compagnie.</span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">L''attraction Cie ouvre le bal avec la première résidence de la saison autour du spectacle \"Racine\". </span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Ce projet, adressé au tout public, est né en extérieur avec un spectacle aérien et poétique dont un des acteurs principaux était un arbre. Le public du Pays Toy a d''ailleurs pu apprécier ce spectacle le 15 août dernier, au pied du beau merisier du verger, dans le cadre des mercredis artistiques. De retour en intérieur, toute l''équipe artistique est en recherche pour adapter le spectacle en salle. Le travail de création aborde les thématiques du voyage, de la mémoire, des origines, de la différence. L''univers poétique et scénographique joue également un rôle important dans la transposition du projet en salle. </span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Pour clôturer la résidence, la Maison de la vallée propose un rendez-vous, ouvert à tous, pour découvrir une étape de la création du spectacle le mercredi 12 septembre à 18h30. Un moment de rencontre privilégié avec l''équipe artistique pour découvrir l''univers de ce spectacle d''une poésie à toutes épreuves.</span></p>  <p><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Coproduction Archaos Pôle National Cirque, Festival Scène de Cirque – Ville de Puget-Théniers, <b>Maison du Parc National et de la Vallée de Luz-Saint-Sauveur</b>, Ville de Valbonne Sophia Antipolis, Le Pré des Arts, Centre Régional des Arts du Cirque Sud – Piste d’Azur, Théâtre National de Nice avec le soutien de la Ville de Nice et du Conseil Départemental des Alpes-Maritimes.</span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '45a6260d-fbbf-4e36-93b9-50f9e4b3fc37');
