INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La pluie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>\"La Pluie\" Compagnie Les Jolies Choses<br>  Daniel Keene<br>  Traduction : Séverine Magois<br>  Éditeur : Éditions THEATRALES<br>  &nbsp;</p>  <p>\"Seule la poussière dure éternellement\"<br>  Beaucoup des Pièces Courtes de Daniel Keene parlent de mémoire et d’absence, de tous ces gens que l’on emmène, que l’on déplace, et l’Holocauste traverse l’oeuvre en filigrane, particulièrement Le Violon et La Pluie.<br>  La Pluie de Daniel Keene raconte l’histoire d’Hanna, vieille femme entre ciel et cendres. Au crépuscule de sa vie, Hanna raconte comment, il y a longtemps, alors qu''elle était encore jeune, des centaines de gens que l’on faisait monter dans des trains lui ont confié des objets de toutes sortes qu''elle a rangé dans sa maison, et comment, toute au long de sa vie, elle en a pris soin. Obsédée par le souvenir de ces silhouettes imprécises, elle finira par remettre un visage sur l''ombre de cet enfant qui lui avait donné une bouteille contenant de l''eau de pluie. Dans ce texte, le dramaturge australien évoque, avec une infinie pudeur, la biographie de poussière de ces voyageurs qui ne sont jamais revenus.</p>  <p><strong><u>Les intentions de mise en scène</u></strong> Partis-pris dramaturgiques et scénographiques</p>  <p>Hanna est de ces êtres qui vivent à la marge, en lisière du monde, dans un no man ‘s land où se croisent des ombres, des âmes errantes qui, sans en avoir conscience, ne sont pas guéris de l’Histoire, de leur histoire.<br>  Il y a de la douleur dans les pièces de Daniel Keene, douleur des humbles, des oubliés, voire des déjà morts, mais jamais il ne s’appesantit sur le sujet, tissant réel et poésie, banalité du quotidien et lyrisme fulgurant, fatalité et rédemption, tendresse, espoir.<br>  Alourdir son propos au delà des questions posées à l’humanité de l’homme serait en trahir l’élégance et la complexité.<br>  Les personnages de Daniel Keene sont des êtres ordinaires, ils nous ressemblent, ils sont très humains. Pour autant il n’y a rien de réaliste dans ce théâtre : c’est un tissage de quotidien et de poésie.<br>  Il nous appartient que n’existent sur scène que les choses nécessaires : le texte, les acteurs et l’espace.<br>  Chez Daniel Keene, le silence et la solitude sont la matière même d’où émerge la parole.<br>  Il nous faudra conjuguer les dualités silence/mots, présence/absence, ombre/lumière et orchestrer le rapport corps/espace. Hanna a passé toute sa vie à remplir cette mission qu’elle n’avait pas choisi : recueillir, trier, ranger, déplacer, préserver tous ces objets confiés par ceux qui partaient, pour quand ils reviendraient…<br>  Jeunesse, âge mur, vieillesse, toutes ces saisons de sa vie, nous avons choisi qu’elles s’incarnent dans trois interprètes, trois Hanna d’âge différent, qui s’inscriront de manière simultanée dans l’espace scénique, portant toutes trois ce monologue intérieur, habitant toutes trois ce monde extérieur aux contours à peine ébauchés, ce monde de silence, de solitude et de travail bien fait.<br>  Dans Porteuses de lumière, pièce courte du même recueil, Marion âgée et Marion adolescente dialoguent sur un banc, deux personnages pour un seul être ; dans notre mise en scène de La pluie, trois Hanna diront cette vie, sans que soient altérées en aucune façon intégralité et intégrité du texte de l’auteur.</p>  <p><u><strong>La distribution</strong></u><br>  <br>  <strong>Mise en scène et scénographie :</strong><br>  Metteur en scène : Mélia Bannerman<br>  Dramaturgie et regard : Janine Clos<br>  <strong>Interprétation :</strong><br>  Sophie Barros, danseuse et comédienne<br>  Françoise Delile - Manière, comédienne<br>  Nathalie Lhoste - Clos, comédienne<br>  <strong>Création lumière :</strong><br>  Laurent Aranda</p>  <p></p>  <p><u><strong>Univers musical</strong></u><br>  Pistes d’inspiration musicale (non exhaustive)<br>  Avishai Cohen: Remembering. Album At Home<br>  Agnès Obel: Tokka. Album Aventine<br>  Red Virgin Soil. Album Citizen Of Glass<br>  Grasshopper. Album Citizen Of Glass<br>  Aphex Twin: Jynweythek. Album Drukqs<br>  Isabelle Olivier: Gps. Album Dodecasongs<br>  Mendelssohn : Songs Without Words interprété par Alexandre Tharaud dans l''album Autograph<br>  Et aussi : Eric Satie, Jozef van Wissem, Tchaikovsky</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5371babe-f3e7-4666-a064-b8eba5d6731c');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La pluie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>\"La Pluie\" Compagnie Les Jolies Choses<br>  Daniel Keene<br>  Traduction : Séverine Magois<br>  Éditeur : Éditions THEATRALES<br>  &nbsp;</p>  <p>\"Seule la poussière dure éternellement\"<br>  Beaucoup des Pièces Courtes de Daniel Keene parlent de mémoire et d’absence, de tous ces gens que l’on emmène, que l’on déplace, et l’Holocauste traverse l’oeuvre en filigrane, particulièrement Le Violon et La Pluie.<br>  La Pluie de Daniel Keene raconte l’histoire d’Hanna, vieille femme entre ciel et cendres. Au crépuscule de sa vie, Hanna raconte comment, il y a longtemps, alors qu''elle était encore jeune, des centaines de gens que l’on faisait monter dans des trains lui ont confié des objets de toutes sortes qu''elle a rangé dans sa maison, et comment, toute au long de sa vie, elle en a pris soin. Obsédée par le souvenir de ces silhouettes imprécises, elle finira par remettre un visage sur l''ombre de cet enfant qui lui avait donné une bouteille contenant de l''eau de pluie. Dans ce texte, le dramaturge australien évoque, avec une infinie pudeur, la biographie de poussière de ces voyageurs qui ne sont jamais revenus.</p>  <p><strong><u>Les intentions de mise en scène</u></strong> Partis-pris dramaturgiques et scénographiques</p>  <p>Hanna est de ces êtres qui vivent à la marge, en lisière du monde, dans un no man ‘s land où se croisent des ombres, des âmes errantes qui, sans en avoir conscience, ne sont pas guéris de l’Histoire, de leur histoire.<br>  Il y a de la douleur dans les pièces de Daniel Keene, douleur des humbles, des oubliés, voire des déjà morts, mais jamais il ne s’appesantit sur le sujet, tissant réel et poésie, banalité du quotidien et lyrisme fulgurant, fatalité et rédemption, tendresse, espoir.<br>  Alourdir son propos au delà des questions posées à l’humanité de l’homme serait en trahir l’élégance et la complexité.<br>  Les personnages de Daniel Keene sont des êtres ordinaires, ils nous ressemblent, ils sont très humains. Pour autant il n’y a rien de réaliste dans ce théâtre : c’est un tissage de quotidien et de poésie.<br>  Il nous appartient que n’existent sur scène que les choses nécessaires : le texte, les acteurs et l’espace.<br>  Chez Daniel Keene, le silence et la solitude sont la matière même d’où émerge la parole.<br>  Il nous faudra conjuguer les dualités silence/mots, présence/absence, ombre/lumière et orchestrer le rapport corps/espace. Hanna a passé toute sa vie à remplir cette mission qu’elle n’avait pas choisi : recueillir, trier, ranger, déplacer, préserver tous ces objets confiés par ceux qui partaient, pour quand ils reviendraient…<br>  Jeunesse, âge mur, vieillesse, toutes ces saisons de sa vie, nous avons choisi qu’elles s’incarnent dans trois interprètes, trois Hanna d’âge différent, qui s’inscriront de manière simultanée dans l’espace scénique, portant toutes trois ce monologue intérieur, habitant toutes trois ce monde extérieur aux contours à peine ébauchés, ce monde de silence, de solitude et de travail bien fait.<br>  Dans Porteuses de lumière, pièce courte du même recueil, Marion âgée et Marion adolescente dialoguent sur un banc, deux personnages pour un seul être ; dans notre mise en scène de La pluie, trois Hanna diront cette vie, sans que soient altérées en aucune façon intégralité et intégrité du texte de l’auteur.</p>  <p><u><strong>La distribution</strong></u><br>  <br>  <strong>Mise en scène et scénographie :</strong><br>  Metteur en scène : Mélia Bannerman<br>  Dramaturgie et regard : Janine Clos<br>  <strong>Interprétation :</strong><br>  Sophie Barros, danseuse et comédienne<br>  Françoise Delile - Manière, comédienne<br>  Nathalie Lhoste - Clos, comédienne<br>  <strong>Création lumière :</strong><br>  Laurent Aranda</p>  <p></p>  <p><u><strong>Univers musical</strong></u><br>  Pistes d’inspiration musicale (non exhaustive)<br>  Avishai Cohen: Remembering. Album At Home<br>  Agnès Obel: Tokka. Album Aventine<br>  Red Virgin Soil. Album Citizen Of Glass<br>  Grasshopper. Album Citizen Of Glass<br>  Aphex Twin: Jynweythek. Album Drukqs<br>  Isabelle Olivier: Gps. Album Dodecasongs<br>  Mendelssohn : Songs Without Words interprété par Alexandre Tharaud dans l''album Autograph<br>  Et aussi : Eric Satie, Jozef van Wissem, Tchaikovsky</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '5371babe-f3e7-4666-a064-b8eba5d6731c');
