INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Neige et avalanche" - Fête de la science', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom: 0cm;\">Conférence</p>  <p style=\"margin-bottom: 0cm;\"></p>  <p style=\"margin-bottom: 0cm;\">Par Frédéric Cabot</p>  <p style=\"margin-bottom: 0cm;\"></p>  <p style=\"margin-bottom: 0cm;\"></p>  <p style=\"margin-bottom: 0cm;\"></p>  <p>Neige et avalanches</p>  <p></p>  <p>La neige, ce don du ciel, change le visage de nos montagnes l''hiver venu. Source de bien des plaisirs mais aussi de quelques tracas. Elle est indispensable à l''écosystème montagnard ainsi qu''à l''économie de nos vallées. C''est un matériau particulièrement complexe, évoluant constamment, de la chute du premier flocon automnal jusqu''à la fonte du dernier névé en début d''été. Un manteau neigeux se constitue ainsi, au gré des chutes et des facteurs de métamorphoses. Il forme un empilement de couches successives aux propriétés bien différentes. Certains empilement offrent une cohésion parfaite d''autres au contraire sont particulièrement ou potentiellement instables et c''est alors l''avalanche d''origine naturelle ou bien accidentelle.</p>  <p>Cette conférence vous donnera quelques éléments de base pour mieux comprendre, appréhender et apprécier les différentes qualités d''un manteau. La neige, vous verrez, n''est pas seulement blanche et froide!</p>  <p></p>  <p></p>  <p>CABOT Frédéric</p>  <p></p>  <p>Passionné de neige et de montagne, il sillonne avec assiduité et toujours autant de plaisir, skis aux pieds, les massifs des Pyrénées depuis plus de 25 ans maintenant. Cette connaissance de terrain associée à un savoir professionnel lui permet en tant que nivologue et prévisionniste pour Météo-France de contribuer à la rédaction des bulletins d''estimation du risque d''avalanche pour l''ouest de la chaîne des Pyrénées. Désireux de faire partager passion et savoir, il est enfin auteur de topos de ski de randonnée, organisateur de stages et conférencier pour participer à la diffusion d''une meilleure connaissance sur la neige et les avalanches.</p>  <p></p>  <p></p>  <p style=\"margin-bottom: 0cm;\"></p>  <p style=\"margin-bottom: 0cm;\">Dans la salle de cinéma de la MAison du Parc national et de la vallée le mercredi 10 octobre à 18h30</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f3847c18-61d4-426f-b49f-776b2aae9ed3');
