INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Rendez-vous en famille" saison culturelle 2018/2019', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<h5>Une programmation culturelle décentralisée sur le territoire, en Plaines et Vallées de Bigorre d''octobre 2018 à Juillet 2019</h5>  <p>En Plaines et Vallées de Bigorre, la culture doit devenir une affaire de tous : c’est avec cet objectif&nbsp;que les deux territoires, Pays de Lourdes et des Vallées des Gaves et Cœur de Bigorre, se sont unis&nbsp;pour repenser la question <img alt=\"Les différents partenaires du projet RDV en famille\" src=\"https://www.lourdes.fr/images/actualites/P1020759.JPG\" style=\"margin: 10px; float: right;\" width=\"350\">culturelle en milieu rural.</p>  <p><strong>Les « Rendez-vous en famille » sont nés pour permettre aux habitants du territoire Plaines et Vallées&nbsp;de Bigorre d’avoir accès à une saison culturelle de proximité tout au long de l’année, et non&nbsp;uniquement en période estivale.</strong></p>  <p>L’objectif de ce projet est de permettre aux enfants dès le plus jeune âge et leur famille de se&nbsp;positionner en tant que spectateurs et d’aller à la rencontre des lieux culturels présents sur le&nbsp;territoire. Le contenu de cette programmation pluridisciplinaire décentralisée sur le territoire, de&nbsp;proximité, a été pensé afin de favoriser la découverte et de permettre aux familles de partager de&nbsp;beaux moments ensemble.</p>  <p><strong>26 spectacles sont au programme de cette 1ère édition : musique, théâtre, cirque, danse, lectures,... il y en&nbsp;aura pour tous les goûts. </strong></p>  <p>Une belle manière de prouver qu’une offre culturelle de qualité trouve&nbsp;toute sa place en milieu rural !</p>  <p></p>  <p><span class=\"wf_file_text\"><a class=\"wf_file\" href=\"https://www.lourdes.fr/images/LIVRET_rendez-vous_en_famille_WEB.PDF\" target=\"_blank\" title=\"Programme des Rendez-vous en famille\">Télécharger le programme &gt;&gt;</a>&nbsp;</span></p>  <p></p>  <p><span style=\"color:#000000;\">Ecoutez la présentation de cette initiative par les différents acteurs culturels avec Fréquence Luz : </span></p>  <p><a data-saferedirecturl=\"https://www.google.com/url?q=http://www.frequenceluz.com/index.php/podcasts/actions-culturelles/2246-qrendez-vous-en-familleq-une-nouvelle-programmation-culturelle-sur-le-territoire-&amp;source=gmail&amp;ust=1539089499379000&amp;usg=AFQjCNHpc6uf1-q9iyVrgyyBitfztAz3gw\" href=\"http://www.frequenceluz.com/index.php/podcasts/actions-culturelles/2246-qrendez-vous-en-familleq-une-nouvelle-programmation-culturelle-sur-le-territoire-\" target=\"_blank\">http://www.frequenceluz.com/<wbr>index.php/podcasts/actions-<wbr>culturelles/2246-qrendez-vous-<wbr>en-familleq-une-nouvelle-<wbr>programmation-culturelle-sur-<wbr>le-territoire-</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'af1af8b3-b0f7-44b1-aafa-59e63be27c38');
