INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition sur la flore et la géologie locale - Fête de la science 2018', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<br> \"Exposition :<br> <br> Les associations Montagne culture avenir (siège social Gèdre) et<br> Géo-patrimoine Pyrénéen (siège au SIVU du Pibeste à Agos-Vidalos)<br> associent leurs savoirs dans une exposition installée dans la salle de<br> réunion de la Maison du Parc national et de la vallée.<br> <br> Différents sujets de notre environnement y seront présentés comme : des<br> panneaux sur la flore locale, un ensemble de modèles illustrant la<br> géologie locale et bigourdane avec sa complexité.<br> <br> Cette exposition sera ouverte tous les jours de 14h à 17h à la Maison du<br> Parc national et de la vallée de Luz Saint Sauveur.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '19b76667-bc71-44e2-9507-deb6875ed929');
