INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Lucien Briet Voyageur photographe', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"line-height:normal\"><b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Lucien Briet, voyageur photographe dans la mouvance du XIXème siècle</span></span></b></span></p>  <p><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Contemporain du mouvement naturaliste, à la manière de Zola, il témoigne de son époque dans les Pyrénées centrales. Il photographie et décrit des lieux, des habitants de façon détaillée, sans artifices. Ses textes sont publiés dans des revues de Sociétés Savantes. </span></span></span></p>  <p>Conférence animée par Lise Laporte le jeudi 22 novembre à 17h30 dans la salle des voûtes.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '38a49af7-b5be-4aa3-ac7d-c86b03ea0fe5');
