INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Au père Lavictoire', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Compagnie \"L''Illustre corsaire\"</p>  <p style=\"margin-bottom:12.0pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Tout Public -1H</span></span></p>  <p style=\"margin-bottom:12.0pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">8 interprètes, Création 14-18, </span></span></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:115%\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Cabaret<br>  Théâtre, Musique et Chant<br>  Création 2014<br>  <br>  Au Cabaret Au Père Lavictoire, on joue et on chante jusqu''à en perdre haleine les mélodies qui permettent de supporter la Guerre. Quand on rentre dans l''intimité de chacun ce n''est plus la même chanson...Une sélection de textes, de chansons, de poésies, de documents administratifs nous offrent des témoignages de vécus, à travers le conflit de 14-18. Témoignages tantôt grivois, tantôt engagés, parfois libertaires et souvent austères...</span></span></span></p>  <p>TARIFS : 8€ / 5€ réduit.</p>  <p>(Dans le cadre des escales d''automne.)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c03e27bc-8a65-4f8e-8745-60f13298f207');
