INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La pluie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:.0001pt\"><span style=\"color:#000000;\">Compagnie \"Les jolies choses\"</span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"color:#000000;\">Théatre corporel - Création 2018 - 30 min</span></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Calibri Light&quot;,sans-serif\"><span style=\"color:black\">La Pluie</span></span></span><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Calibri Light&quot;,sans-serif\"><span style=\"color:black\"> de Daniel Keene raconte l''histoire d''Hanna, vieille femme entre ciel et cendres. Au crépuscule de sa vie, Hanna se souvient comment, il y a longtemps, alors qu''elle était encore jeune, des centaines de gens que l''on faisait monter dans des trains lui ont confié des objets de toutes sortes qu''elle a rangé dans sa maison, et comment, toute au long de sa vie, elle en a pris soin. Hanna est de ces êtres qui vivent à la marge, en lisière du monde, dans un no man ''s land où se croisent des ombres, des âmes errantes qui, sans en avoir conscience, ne sont pas guéris de l''Histoire, de leur histoire.</span></span></span></span></p>  <p><br>  <span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Calibri Light&quot;,sans-serif\"><span style=\"color:black\">Chez Daniel Keene, le silence et la solitude sont la matière même d''où émerge la parole.<br>  Dans cette mise en scène, la Cie Les Jolies Choses conjugue les dualités : silence/mots, présence/absence, ombre/lumière, mémoire/oubli. Le lien évident entre le corps et l''espace est utilisé pour mettre en valeur toute la poésie de ce texte qui dit la noblesse du quotidien et la force du souvenir.</span></span></span></span></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Calibri Light&quot;,sans-serif\"><span style=\"color:black\">A partir de 10 ans </span></span></span></span></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Calibri Light&quot;,sans-serif\"><span style=\"color:black\">TARIF : 4€ / -16 ans gratuit</span></span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5537e7ad-fb5b-4b3d-ae85-dc484cca6a86');
