INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Enfants de Sazos, morts pour la France', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<div style=\"text-align:center\">  <div style=\"text-align: left;\">Exposition retraçant les derniers combats des enfants morts au front:&nbsp;</div>   <div style=\"text-align: left;\">croquis et aquarelles d''artistes conbattants illustrant le quotidien du&nbsp; soldat.</div>   <div style=\"text-align: left;\">Réalisé par M. Haurine andré et M. Christian Dupire</div>   <div style=\"text-align: left;\"></div> </div>  <div><strong>Du 12 au 29 novembre de 14h à 19h tous les jours.</strong></div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '29d9b6a4-0a53-495f-9f9d-9e227c94e1e9');
