INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Marché d''art', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Pour Noël offrez (vous) de l''art.<br>  Noël approche, il est temps de trouver le cadeau. Un cadeau qui marque les esprits, particulier, unique… Avec la Maison de la vallée, « offrez (vous) de l''art » ! Plusieurs artistes locaux, d''horizons différents, sont invités à exposer avant les fêtes pour le plus grand plaisir de tous les amateurs d''originalité. Venez découvrir leur travail et dénicher la pièce de vos rêves.</span></span></span></p>  <p></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Portraits des artistes :</span></span></span></p>  <p></p>  <p><b><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Roxanne Lasserre – Céramiste</span></span></span></b></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Originaire du Pays Toy, Roxane Lasserre travaille dans son atelier situé à Ayrues, petit hameau du village de Gèdre.</span></span></span></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">« L’idée née du regard, l’angle déchiré d’une tapisserie, un lichen à peine visible… je les photographie, je les cadre je me les approprie. De ces cadrages naît l’inspiration. Je la projette dans la matière. Grès porcelaine ou terre papier sont mes matières de prédilection. Des sculptures, des tableaux ou de l’utilitaire chaque pièce est unique. Art ou artisanat ? La question appartient à l’histoire pour moi elle n’existe plus. »</span></span></span></p>  <p></p>  <p><b><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Loïc Ploteau – Sculpteur </span></span></span></b></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Né en 1975 à Orléans, Loïc Ploteau est géographe. Après des études classiques et des années d’enseignement, il revient s’installer à Bagnères de Bigorre en 2006, dans&nbsp; </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">la maison familiale. Il sculpte, sa grange atelier devenant un lieu où l’art et la nature </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">s’entremêlent. L’été 2016, il expose ses œuvres à la Galerie 88 de Bagnères de Bigorre.</span></span></span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Loïc Ploteau sculpte la vie. Sous l’impulsion d’un imaginaire foisonnant, poétique et musical, le fer rouillé renaît d’une mémoire oubliée, se tord, se dresse et reprend forme, </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">fragile et forte à la fois. D’un simple trait de métal, l’artiste fait chanter le fer ; le taureau </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">apparaît, immobile, le poisson respire, la sirène dialogue avec Oannès...et le marteau se </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">pose, surréaliste. Dans ce théâtre de repères, les sculptures émergent et interrogent, en </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">attente d’un prochain « jardin discussion ».</span></span></span></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"><strong><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Emmanuel Tessier - Photographe</span></span></span></strong></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"font-size:14.0px\"><span style=\"font-family:Arial,Helvetica,sans-serif\">Photographe de Tarbes, originaire du Mans. Passionné de musique et longtemps disquaire, il pratique la photographie depuis plusieurs années, et plus sérieusement depuis plus de 2 ans.&nbsp;Mettant tantôt en scène des modèles pour des portraits subtils ou décalés, tantôt juste pour capturer l''instant présent. Il porte un regard poétique sur nos paysages familiers ou plus lointains, nous proposant des images aux couleurs délicates ou en noir et blanc intenses.</span></span></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1feb0648-b6af-47b3-9f23-c8911e5b01c6');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Marché d''art', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Pour Noël offrez (vous) de l''art.<br>  Noël approche, il est temps de trouver le cadeau. Un cadeau qui marque les esprits, particulier, unique… Avec la Maison de la vallée, « offrez (vous) de l''art » ! Plusieurs artistes locaux, d''horizons différents, sont invités à exposer avant les fêtes pour le plus grand plaisir de tous les amateurs d''originalité. Venez découvrir leur travail et dénicher la pièce de vos rêves.</span></span></span></p>  <p></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Portraits des artistes :</span></span></span></p>  <p></p>  <p><b><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Roxanne Lasserre – Céramiste</span></span></span></b></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Originaire du Pays Toy, Roxane Lasserre travaille dans son atelier situé à Ayrues, petit hameau du village de Gèdre.</span></span></span></p>  <p><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">« L’idée née du regard, l’angle déchiré d’une tapisserie, un lichen à peine visible… je les photographie, je les cadre je me les approprie. De ces cadrages naît l’inspiration. Je la projette dans la matière. Grès porcelaine ou terre papier sont mes matières de prédilection. Des sculptures, des tableaux ou de l’utilitaire chaque pièce est unique. Art ou artisanat ? La question appartient à l’histoire pour moi elle n’existe plus. »</span></span></span></p>  <p></p>  <p><b><span style=\"font-size:12.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Loïc Ploteau – Sculpteur </span></span></span></b></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Né en 1975 à Orléans, Loïc Ploteau est géographe. Après des études classiques et des années d’enseignement, il revient s’installer à Bagnères de Bigorre en 2006, dans&nbsp; </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">la maison familiale. Il sculpte, sa grange atelier devenant un lieu où l’art et la nature </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">s’entremêlent. L’été 2016, il expose ses œuvres à la Galerie 88 de Bagnères de Bigorre.</span></span></span></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Loïc Ploteau sculpte la vie. Sous l’impulsion d’un imaginaire foisonnant, poétique et musical, le fer rouillé renaît d’une mémoire oubliée, se tord, se dresse et reprend forme, </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">fragile et forte à la fois. D’un simple trait de métal, l’artiste fait chanter le fer ; le taureau </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">apparaît, immobile, le poisson respire, la sirène dialogue avec Oannès...et le marteau se </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">pose, surréaliste. Dans ce théâtre de repères, les sculptures émergent et interrogent, en </span></span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">attente d’un prochain « jardin discussion ».</span></span></span></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"><strong><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">Emmanuel Tessier - Photographe</span></span></span></strong></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"><span style=\"font-size:14.0px\"><span style=\"font-family:Arial,Helvetica,sans-serif\">Photographe de Tarbes, originaire du Mans. Passionné de musique et longtemps disquaire, il pratique la photographie depuis plusieurs années, et plus sérieusement depuis plus de 2 ans.&nbsp;Mettant tantôt en scène des modèles pour des portraits subtils ou décalés, tantôt juste pour capturer l''instant présent. Il porte un regard poétique sur nos paysages familiers ou plus lointains, nous proposant des images aux couleurs délicates ou en noir et blanc intenses.</span></span></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '1feb0648-b6af-47b3-9f23-c8911e5b01c6');
