INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Oyez, oyez, les arbres à palabres"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"font-size:9.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">Exposition rétrospective de la criée publique.<br>  Cet été, la Maison du parc national et de la vallée était heureuse d''inviter une crieuse publique. Le principe était simple : laisser un mot dans une boite aux lettres afin que la crieuse puisse le dire sur la place de l''église. Au cours du mois de décembre, une exposition retrace l''épopée de la criée à travers une mise en volume et en espace des mots, poèmes, coups de gueules, citations, petites annonces et autres déclarations d''amour laissées dans les boites.</span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ebeb8103-000e-4930-ad80-58ce25e7cc24');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Oyez, oyez, les arbres à palabres"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"font-size:9.0pt\"><span style=\"line-height:107%\"><span style=\"font-family:&quot;Arial&quot;,sans-serif\">Exposition rétrospective de la criée publique.<br>  Cet été, la Maison du parc national et de la vallée était heureuse d''inviter une crieuse publique. Le principe était simple : laisser un mot dans une boite aux lettres afin que la crieuse puisse le dire sur la place de l''église. Au cours du mois de décembre, une exposition retrace l''épopée de la criée à travers une mise en volume et en espace des mots, poèmes, coups de gueules, citations, petites annonces et autres déclarations d''amour laissées dans les boites.</span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'ebeb8103-000e-4930-ad80-58ce25e7cc24');
