INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Racine(s)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"font-size:12.0pt;line-height:107%; font-family:&quot;Calibri&quot;,sans-serif;mso-ascii-theme-font:minor-latin;mso-fareast-font-family: &quot;Times New Roman&quot;;mso-hansi-theme-font:minor-latin;mso-bidi-theme-font:minor-latin; mso-ansi-language:FR;mso-fareast-language:FR;mso-bidi-language:AR-SA; mso-bidi-font-weight:bold\">Pièce de cirque poétique. Duo entre terre et ciel pour une cordiste et un chanteur musicien. </span></p>  <p><span style=\"font-size:12.0pt;line-height:107%; font-family:&quot;Calibri&quot;,sans-serif;mso-ascii-theme-font:minor-latin;mso-fareast-font-family: &quot;Times New Roman&quot;;mso-hansi-theme-font:minor-latin;mso-bidi-theme-font:minor-latin; mso-ansi-language:FR;mso-fareast-language:FR;mso-bidi-language:AR-SA; mso-bidi-font-weight:bold\">Attraction Compagnie.</span></p>  <p><span style=\"font-size:12.0pt;line-height:107%; font-family:&quot;Calibri&quot;,sans-serif;mso-ascii-theme-font:minor-latin;mso-fareast-font-family: &quot;Times New Roman&quot;;mso-hansi-theme-font:minor-latin;mso-bidi-theme-font:minor-latin; mso-ansi-language:FR;mso-fareast-language:FR;mso-bidi-language:AR-SA; mso-bidi-font-weight:bold\">Création 2018. A partir de 8 ans. Tarif unique 4€.</span></p>  <p></p>  <p><span style=\"font-size:12.0pt;line-height:107%; font-family:&quot;Calibri&quot;,sans-serif;mso-ascii-theme-font:minor-latin;mso-fareast-font-family: &quot;Times New Roman&quot;;mso-hansi-theme-font:minor-latin;mso-bidi-theme-font:minor-latin; mso-ansi-language:FR;mso-fareast-language:FR;mso-bidi-language:AR-SA; mso-bidi-font-weight:bold\">Coproductio Archaos Pôle Nacional Cirque, Festival Scène de Cirque - Ville de Puget-Théniers, Maison deu Parc national et de la vallée de Luz St Sauveur, ville de Valbonne Sophia Antipolis, Le Pré des Arts, Centre Régional des Arts du Cirque Sud - Piste d''Azur, THéâtre National Nice avec le soutien de la ville de Nice et du Conseil Départemental des Alpes-Maritimes.</span></p>  <div>  <p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Avec ces deux personnages se dessine une rencontre. Entre voix et corps, son et mouvement. Entre ici et ailleurs. Entre prise et lâcher prise, entre pieds sur terre et pieds en l’air, entre tête qui chute et mains qui s’ouvrent, ils nous livrent une fable poétique, visuelle et sonore, d’une pureté brute et organique.</span></span></span></p>   <p style=\"margin-bottom:.0001pt\"></p>   <p style=\"margin-bottom:.0001pt\"></p>   <p style=\"margin-bottom:.0001pt\"></p>   <p style=\"margin-bottom:.0001pt\"></p> </div>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7bfab5a0-f17c-4ed5-a788-d53cd95c6e69');
