INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('6dd7698e-7323-4b9b-91cf-8387bdb94dbd', 'exposition', true, false, NULL, '2019-01-31T23:00:00.000Z', '2019-02-27T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2019-01-31T23:00:00.000Z', '2019-01-31T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arbres - Philippe Pujo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Né en Genevois en 1980, Philippe Pujo passe son enfance au pied des Pyrénées, et dessine. Diplômé de philosophie, il suit une formation en architecture et découvre l’histoire&nbsp; </span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">de l’art. En 2009, il s’installe à Bagnères, crée Toiles de France, et participe à l’exposition&nbsp; </span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">collective parisienne « Les Grands maîtres de demain » au carrousel du Louvre. C’est le&nbsp; </span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">début d’une carrière artistique « nourrie ».</span></span></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Pour cette série des arbres, comme d’autres séries de dessins au stylo bille antérieures, il s’agit surtout de susciter un état contemplatif chez le spectateur, tant par la forme que par le fond.</span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Par le fond d’abord puisque l’arbre lui-même, pris hors contexte, en tant qu’élément en soi, suscite la paix, le respect devant une forme vivante complexe, grande et apaisante. Le motif, simple et brut, est une clé qui nous permet d’entrer dans un état de réflexion bénéfique et pousse naturellement le spectateur de l’arbre (ou du symbole/arbre) à un état méditatif et de contemplation de soi, d’un état des lieux de nous-même et du réel. Rodin lui-même disait avoir compris le monde et la sculpture en contemplant régulièrement des arbres, en les touchant… </span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Par la forme ensuite, puisque l’immersion, en se promenant dans les gribouillis des feuillages, en suivant la sinuosité des branches, permet un apaisement du spectateur (à la manière des labyrinthes chrétiens ou des symboles pré-Colombiens, pour ne citer qu’eux, qui permettaient l’entrée en transe dans la prière), renforcé par la sympathie et le sentiment d’une œuvre entière parce qu’impressionnante techniquement. </span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">En décontextualisant l’objet arbre, en assumant la place de la nature mise à distance de notre quotidien, vue par une vitre, ou utilitaire, le tableau fait un pas vers le spectateur pour lui faciliter le transfert, de ses pensées pratiques jusqu’à l’intérieur de lui-même. L’idée de simplicité, suscitée par le fait que le dessin soit au simple stylo bille, outil populaire par excellence, puisqu’on griffonne nos marges en téléphonant avec lui au quotidien, favorise encore l’appropriation de l’œuvre, pour l’oublier et penser au monde, qui la génère. </span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6dd7698e-7323-4b9b-91cf-8387bdb94dbd');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arbres - Philippe Pujo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"margin-bottom:.0001pt\"><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">Né en Genevois en 1980, Philippe Pujo passe son enfance au pied des Pyrénées, et dessine. Diplômé de philosophie, il suit une formation en architecture et découvre l’histoire&nbsp; </span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">de l’art. En 2009, il s’installe à Bagnères, crée Toiles de France, et participe à l’exposition&nbsp; </span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">collective parisienne « Les Grands maîtres de demain » au carrousel du Louvre. C’est le&nbsp; </span></span><span style=\"line-height:normal\"><span style=\"font-size:12.0pt\">début d’une carrière artistique « nourrie ».</span></span></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p style=\"margin-bottom:.0001pt\"></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Pour cette série des arbres, comme d’autres séries de dessins au stylo bille antérieures, il s’agit surtout de susciter un état contemplatif chez le spectateur, tant par la forme que par le fond.</span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Par le fond d’abord puisque l’arbre lui-même, pris hors contexte, en tant qu’élément en soi, suscite la paix, le respect devant une forme vivante complexe, grande et apaisante. Le motif, simple et brut, est une clé qui nous permet d’entrer dans un état de réflexion bénéfique et pousse naturellement le spectateur de l’arbre (ou du symbole/arbre) à un état méditatif et de contemplation de soi, d’un état des lieux de nous-même et du réel. Rodin lui-même disait avoir compris le monde et la sculpture en contemplant régulièrement des arbres, en les touchant… </span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">Par la forme ensuite, puisque l’immersion, en se promenant dans les gribouillis des feuillages, en suivant la sinuosité des branches, permet un apaisement du spectateur (à la manière des labyrinthes chrétiens ou des symboles pré-Colombiens, pour ne citer qu’eux, qui permettaient l’entrée en transe dans la prière), renforcé par la sympathie et le sentiment d’une œuvre entière parce qu’impressionnante techniquement. </span></span></span></p>  <p><span style=\"line-height:normal\"><span style=\"text-autospace:none\"><span style=\"font-size:12.0pt\">En décontextualisant l’objet arbre, en assumant la place de la nature mise à distance de notre quotidien, vue par une vitre, ou utilitaire, le tableau fait un pas vers le spectateur pour lui faciliter le transfert, de ses pensées pratiques jusqu’à l’intérieur de lui-même. L’idée de simplicité, suscitée par le fait que le dessin soit au simple stylo bille, outil populaire par excellence, puisqu’on griffonne nos marges en téléphonant avec lui au quotidien, favorise encore l’appropriation de l’œuvre, pour l’oublier et penser au monde, qui la génère. </span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '6dd7698e-7323-4b9b-91cf-8387bdb94dbd');
