INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Concert electro "Grolürg"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Garbure électronique.</p>  <p></p>  <p>Bienvenue dans un monde éclectique, artisanal à tendance expérimentale.</p>  <p>Les mains de Grolürg aiment faire, défaire, pétrir, tripoter, distordre, inverser, mélanger .... les sons.<br>  <br>  Ses oreilles se nourrissent d''influences diverses au gré de ses envies du jour (punk, indus, click''ncut, gnawa, jungle, dub, rock garage, blues touareg....)<br>  <br>  Autoproduction maison: il fabrique ses samples et mixe en direct avec sa rolande mc909 ou vielle korg électribe pour les premiers albums.<br>  <br>  Pour rajouter de la chaleur aux sons électros, il utilise des instruments traditionnels (crotales, darbouka, cruche,…) et des objets divers (ferraille, sèche-cheveux, bidon, instruments fait main ....)<br>  <br>  <br>  Salle des voûtes - Buvette - Entrée libre</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a14e7039-382d-4b10-8e6f-734baf68327d');
