INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Roxane Lasserre - Céramiste', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>VERNISSAGE : vendredi 5 avril 2019 à 18h.</p>  <p></p>  <p>Créations en grès et porcelaine, Roxane vous donne à voir ce qui mijote en son intérieur.</p>  <p>Venez découvrir une vaisselle en suspension, des sculptures en terre et papier, l''argile dans tous ses états !</p> De la finesse de la porcelaine à la rugosité d''une terre chamottée , de la terre nue au décors élancés, de l''art à l''utilitaire, de Gèdre à Luz , il n''y a plus qu''un pas à franchir celui de la Maison de la vallée !","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8dbfdccf-b621-43e9-9b1d-c80380cb4d64');
