INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Jérome Castex - Peintre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>VERNISSAGE : vendredi 5 avril 2019 à 18h.</p>  <p></p>  <p>Né en 1976 à Toulouse, Jérome Castex a débuté la peinture en autodidacte en 2002. Peindre est rapidement devenu une évidence pour restituer le flot d''émotions et de sensations qu''il traverse au gré des rencontres et des choses qu''il voit dans la vie de tous les jours. De l''abstrait à des choses plus figuratives, il laisse totalement libre court à son imagination et à ses envies, refusant de s''enfermer dans une case qui ne serait que trop étroite pour livrer tout ce qu''il souhaite.<br>  La collection 2019, inspirée par la nature qui nous entoure, est un appel au calme, à trouver le temps de se poser et de profiter en laissant un instant de côté le vacarme de nos vies</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f0c10c38-0836-43e9-accb-49124c793384');
