('81ec6826-2461-4476-a4b9-4ab0aee9d295', 'evenement', true, false, false, NULL, '2019-04-30T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2019-04-30T22:00:00.000Z', '2019-04-30T22:00:00.000Z');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('A la rencontre du tichodrome échelette, entre le rêve et l''imaginaire', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Nicolas Delon et Alain Dupuy, ornithologues et photographes animaliers vous invitent à découvrir un oiseau emblèmatique des montagnes du Haut Béarn, un des plus fabuleux joyaux de la nature inaccessible dans l''austérité de l''univers minéral de la haute vallée d''Aspe et de ses falaises verticales.</p>  <p>Ce n''est bien souvent qu''aux yeux des plus patients que l''ermitte varappeur relève sa présence en déployant ses ailes incandescentes de phénix, se tranformant en papillon géant virevoltant devant la paroi.</p>  <p>Chaque été Nicolas et Alain guettent son retour en montagne sur son lieu de reproduction....</p>  <p><strong>Conférence : vendredi 10 mai à 18h30. Entrée libre.</strong></p>  <p>Une exposition programmée par le Parc national des Pyrénées.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '81ec6826-2461-4476-a4b9-4ab0aee9d295');
