INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Chorale du Lac', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"line-height:normal\"><b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">La « Chorale du Lac », de Villenave d’Ornon (33140) propose un nouveau concert consacré à deux « monstres » de la chanson française : Jacques BREL et Charles AZNAVOUR.</span></span></b></span></p>  <p><span style=\"line-height:normal\"><b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\">20 titres exceptionnels, connus de tous, seront interprétés par 20 choristes en tournée dans la région avant de partir en Allemagne quelques jours</span></span></b><span style=\"font-size:12.0pt\"><span style=\"font-family:&quot;Times New Roman&quot;,serif\"> <b>plus tard</b>.</span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'cdd5ee2e-25c4-4cf3-a8e6-db9fe98ed9bb');
