INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Prémices"    Spectacle  annulé', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<h1><span style=\"color:#c0392b;\"><strong>Spectacle annulé</strong></span></h1>  <p></p>  <p>La Maison du Parc national et de la vallée accueillera en résidence les six circassiens de la Compagnie La Meute du 20 au 30 avril 2019. Plus précisement, les artistes travailleront dans le gymnase de Luz Saint Sauveur, leur création demandant beaucoup d''espace et de hauteur...</p>  <p>Une étape travail, plus communément appelée \"Sortie de résidence\" sera présentée <strong>dimanche 28 avril 2019 à 16h</strong> dans le majestieux hall thermal de Luzéa.</p>  <p>Tarif : 4.00€ - UNIQUEMENT EN ESPECES OU CHEQUES</p>  <p></p>  <p><em><strong>Le spectacle :</strong></em></p>  <p><em>Dans un espace où le passé et l’ère moderne s’entremêlent, le tout régi par une volonté de ne pas oublier, nous sommes partagés entre nos besoins et nos envies.<br>  Réunis par des goûts artistiques communs et le souhait de faire ensemble un spectacle mêlant humour, poésie, absurdité et réalité, nous cherchons à revenir à une certaine sobriété en partant de ce que nous sommes et de nos savoir-faire. En perpétuel questionnement entre la volonté d’un retour à l’essentiel et la quête du progrès, nous cherchons un équilibre, notre équilibre.<br>  L’enjeu n’est pas de faire un spectacle sur la thématique du monde rural mais de s’inspirer de ses outils pour évoquer notamment le rapport de l’homme au travail.<br>  <strong>C’est avec une fourche customisée en pole dance, une pelle branchée à un ampli, un chant de travail sur un beat électro rythmé par des sauts de plus en plus périlleux, que nous aborderons le spectacle comme des artisans.</strong></em></p>  <p>Un plateau parsemé d''îlots, la paille se déplace, s''amasse, s''empile, se balaye, se compacte, se déchiquette, s’éventre, s’éparpille sur le sol. Est-ce un champ, un chantier, un champ de foire, un enclos ou une prairie…?<br>  Des couleurs, de la paille, des fourches déclinées sous différents aspects (pole fourche fouche guitare), une brouette, une bascule, une charrette destale, une presse à bottes de paille et des corps...<br>  Au rythme des saisons, le décor est en mouvement, il en découle un espace de jeux infinis…</p>  <p></p>  <p><strong>L''acte acrobatique :</strong></p>  <p>Formés à l’école de la sueur et du travail, ils ont passé des années à répéter sans cesse les mêmes mouvements, à travailler les bases.<br>  Ils ont étudié un langage acrobatique qui leur semble naturel, comme une marche, vital et nécessaire, flirtant sans cesse avec le risque.<br>  L’acte acrobatique génère une tension, un moment hors du temps où tout peut arriver.<br>  Il est une manière de repousser les capacités de l’être humain, de braver ses peurs et de se faire confiance.<br>  Leur expérience de portés en collectif leur apprend à composer avec leurs gabarits disparates.<br>  La bascule permet d’accentuer le fait que tout le monde soit en mesure de voltiger et puisse être rattrapé.</p>  <p></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e86cd504-46c5-46e1-9308-52be0fb7086e');
