INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Déconnecté - Ou les imbéciles heureux', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Cie le Baluchon - Pièce de théâtre adaptée de sketchs écrits par Sébastien Thiéry.</p>  <p>Deux personnages, deux hommes, deux naïfs se rencontrent, se confrontent, s’entraident et tentent de se lier d’amitié, d’oublier un moment leur solitude en commentant les petites choses de la vie … A tour de rôle, les comédiens, Bruno Spiesser et Patrick Lode, endossent la peau du dominant et du dominé, dans un rire qui mêle avec brio les répliques cinglantes et la cocasserie des situations. Sous des allures de délire verbal, cette pièce aborde des thèmes essentiels tels que la solitude, le vide affectif, le fossé entre les sexes et l’incommunicabilité. Déconnecté ! Ou les imbéciles heureux, spectacle présenté par la Compagnie du Baluchon, est un montage de six saynètes extraites des deux recueils de sketchs de Sébastien Thiéry : Sans ascenseur et Dieu habite à Düsseldorf. Un univers théâtral comique, absurde et décalé.</p>  <p>Tarif : 8€ / Réduit : 5€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7b2efb3c-889d-4e03-8f5e-362bd29c8128');
