INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Funérailles', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Rift Compagnie</p>  <p>En résidence de création du 15 au 19 mai 2019 - Spectacle de sortie de résidence dimanche 19 mai à 16h.</p>  <p>Tarif unique : 4€</p>  <p></p>  <p><strong>Funérailles : Là où...</strong><br>  Comédie fantastique.<br>  Tout public.</p>  <p><br>  Avec Claudia Hugues et Amélie Gasparotto<br>  Lumière : Serena Andreasi<br>  Conception : Claudia Hugues, Amélie Gasparotto, Serena Andreasi<br>  Accompagnement écriture, dramaturgie: Laure Boutaud<br>  Accompagnement direction d''acteur: Julie Boucher.<br>  Administration de production: Marion Le Meut<br>  Avec le soutien en résidence de : L.I.T à Rivesaltes (66), Fep Alzonne (11), Mix''art Myrys à Toulouse (31), La Hangar à Toulouse (31), La Maison de la vallée à Luz Saint Sauveur (65), Un dimanche à la campagne - Mauvaisin (31) et en résidence de médiation avec Arlésie à Daumazan-sur-Arize (09).</p>  <p><br>  Au commencement, nous sommes dans un crématorium. Deux croque-morts, Monica et Léonie sont chacune dans l''attente de la crémation de leurs « clients » respectifs. Entre elles règnent la gêne, les silences, les incompréhensions. Toutes<br>  deux viennent de mondes que tout oppose, mais chacune porte à sa manière les traits de la solitude.<br>  Un événement fait basculer cette attente routinière et les emporte ensemble dans un voyage en bordure du fantastique.<br>  Dans un jeu de transformations perpétuelles du plateau, la comédie prend des allures de questionnements métaphysiques. Alors les masques tombent et les êtres se révèlent.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7b7117bf-1334-4a26-990e-d64c08e4281c');
