INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arnica 9CH', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Laure Gougeon</p>  <p>Solo circassien</p>  <p>En résidence de création du 20 au 25 mai 2019</p>  <p><strong>Arnica 9 CH - Histoire d''un coup...de foudre </strong></p>  <p>« Une femme dans les artères fémorales d''un match de boxe. Voix intimes et hématomes. Féminité et uppercut. Mélu vient nous raconter son match. C’est l’heure du coup et de la chute. Armée d’arnica et blindée d’adrénaline, elle nous entraine dans un monde poétique tout en sueur, en musicalité et en rires. »</p>  <p>Arnica 9ch est un spectacle qui allie le jeu d’acteur et le cirque avec la discipline de l’équilibre, dans un univers à la fois féminin et masculin. Le personnage, une boxeuse égocentrique, Mélu Percut, nous conduit dans son monde pour nous parler de ses coups de foudre, de ses coups de poings, de ses chutes et de de la manière dont elle est tombée amoureuse.<br>  Par ses gestes, ses rires, ses mots et son corps elle nous livre ses fragilités au fil du spectacle.</p>  <p>Équipe artistique :<br>  Écriture, jeu et fil : Laure Gougeon<br>  Ecriture poétique : Sabine Venaruzzo, Laure Gougeon<br>  Mise en scène : Jean Jacques Minazio<br>  Regard circassien : Loic Leviel, Chloé Bouzon,<br>  Regard chorégraphique: Violaine Arrouy<br>  Regard burlesque et humour physique: Elise Ouvrier Buffet<br>  Musique : Alice Huc<br>  Lumière et scénographie: Julien Sabato, Daniel Gonzales<br>  Costume: Véronique Strub</p>  <p><strong>Tarif : 8€ / 5€ réduit</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '3193611e-37a4-425e-8dd2-5a1dc5f510ce');
