INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''as-tu vu ?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La Ligue pour la protection des oiseaux et le Parc national des Pyrénées oeuvrent ensemble à la connaissance, au suivi et à la préservation des rapaces présents sur le territoire des Pyrénées béarnaises.</p>  <p>Réalisée par le service patrimoine de la Communauté de communes du Haut-Béarn, avec la collaboration du Parc national des Pyrénées, de la Ligue pour la protection des oiseaux et l''association Béarn Initiatives Environnement, cette exposition vous dévoile les caractéristiques des rapaces que l''on peut voir et entendre dans les plaines et les montagnes de nos Pyrénées béarnaises.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9c531e52-c4d3-4c9d-a7e9-33b8d3d63f8f');
