INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Couleurs de saison et paysages colorés', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Travail réalisé à la craie par Etienne Lavigne</p>  <p>Ces \"dessins\" de paysages ont été comme un apprentissage, le temps d''apprivoiser les craies, entrer dans la vie des couleurs toujours changeantes, aller jusqu''au point où le désir vient d''autres démarches....où peuvent naître des paysages intérieurs....</p>  <p><a href=\"https://letienne64.wixsite.com/etienne-lavigne\">Site Etienne Lavigne</a></p>  <p>Exposition programmée par la Parc national des Pyrénées.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '16f26e52-2eff-41a3-9409-c212129bfb30');
