('38328ca7-a5e8-4bb1-8e68-b3b2b5e23ef5', 'evenement', true, false, NULL, '2019-06-06T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2019-06-06T22:00:00.000Z', '2019-06-06T22:00:00.000Z');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Là haut ! Projet vidéo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La Maison du Parc national et de la vallée, le Parc national des Pyrénées et l''association Jazz Pyr s''associent à des artistes de cirque, danseurs et musicien pour mener le projet “Là haut”. Un projet artistique participatif et collaboratif, original, ouvert à tous, qui propose un regard nouveau sur le patrimoine naturel du Pays Toy. Une vidéo aérienne ambitieuse qui met en scène l''art et le paysage de montagne dans le plus grand théâtre qui soit : la nature, réalisé par <strong>Black fog Production.</strong></p>  <p></p>  <p>Il s’agit d’un projet vidéo-drone en haute montagne (vallée du Bergons), avec danse, cirque et musique.</p>  <p>Ce projet a&nbsp; pour but de concevoir une vidéo promotionnelle mettant en scène huit artistes, un musicien et&nbsp; des habitants de la vallée, avec une chorégraphie de mouvements simples.</p>  <p></p>  <p><strong>INSCRIPTIONS POSSIBLES JUSQU''AU 04 JUILLET 2019.</strong></p>  <p><strong>Calendrier : </strong></p>  <p>Présentation du projet : les premiers exercices de mouvement seront présentés afin que les intéressés puissent essayer et vraiment décider s’ils veulent s’inscrire au projet : vendredi 7 juin 2019 à 19h.</p>  <p>Répétitions :</p>  <p><strong>21 Juin 2019 </strong>- Travail de mouvement.</p>  <p><strong>5 Juillet 2019</strong> - Travail de mouvement.</p>  <p><strong>9Juillet 2019 </strong>-Création et enregistrement, groupe d''artistes musique, danse et cirque. Seulement une journée pour les participants.</p>  <p></p>  <p>PARTICIPATION GRATUITE, SUR INSCRIPTIONS, DANS LA LIMITE DES PLACES DISPONIBLES, A PARTIR DE 15 ANS.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '38328ca7-a5e8-4bb1-8e68-b3b2b5e23ef5');
