INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "Don Quichotte"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Cet été, du 25 juillet au 6 août, le Festival de Gavarnie célèbre les mots et la pensée, du grand roman universel de Miguel de Cervantès, Don Quichotte de la Manche. L’histoire de ce chevalier errant qui arrivant au bout du chemin veut continuer à vivre, à aimer, à se battre à n’importe quel prix. Une leçon de courage et de ténacité !</p>  <p>L’équipe du festival, musiciens, acteurs et metteur en scène, vous offrent un petit avant-goût du texte accompagné par un extrait musical dans l''ampithéâtre extérieur de la Maison du Parc national et de la vallée.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0fac2ffa-5130-48f1-80df-fb210f55d4e8');
