INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "Sous vide"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Danse par Compagnie Électrons libres.</p>  <p>Une image, un espace, un volume défini par une membrane, une danseuse, un musicien. L''histoire d''un être à fleur de peau traversé par un regard, une sensation, une émotion, se confronte aux limites, s''y appuie, les repousse, s''y blottit pour laisser son empreinte et sa trace. Un spectacle proche de la performance, en ce qu''il se fond dans l''environnement et échange directement avec le public. Un moment de partage entre écriture et improvisation qui peut se regarder sous tous les angles.</p>  <p>Danseuse : Sophie Barros</p>  <p>Musicien : Eric Brochard</p>  <p>Place de l''Univers à Luz Saint Sauveur.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '085ed1b1-f896-4b3d-a553-b2ba0ae7d8de');
