INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "Rosemonde"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Solo de clown par la Compagnie du vide.</p>  <p>Avec Rosemonde tout est possible !!!Puisqu''elle est là......elle va en profiter pour tester en avant-première mondiale, cette idée incongrue...celle qu''elle n''a jamais osée tester chez elle...même les volets fermés!!!!!<br>  Ici devant vos yeux, Rosemonde va prendre des risques, des vrais...<br>  De la peur, de l''émotion, de l''argumentation...comment repousser le moment fatidique ?<br>  Plus de temps pour ces simagrées...il faut sauter!!!!Rosemonde, c''est une sorte de solo clownesque, mais c'' est avant tout un moment de vie....désopilant! C''est gonflé, exagéré ...tout juste extravagant. Rosemonde nous désarçonne, nous amène à l’opposé du prévisible. L''imprévu est mis en scène, l''inopiné est roi.</p>  <p>Place de l''église.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2865cdd8-2ba0-4ada-b007-01a98e8f8938');
