INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le Lido no Brazil', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>• L e L i d o •</p>  <p>Le Lido, centre municipal des Arts du Cirque de Toulouse, est membre de la “Fédération Européenne des Ecoles de Cirque professionnelles”. (Fédération Européenne des écoles de cirque professionnelles). La pédagogie de la formation professionnelle est au service de l’artiste, à travers la recherche d’une signature artistique et d’une authenticité sur scène. Au Lido, l’objectif est de permettre aux élèves de créer un cirque frais avec leurs propres langages où l’importance est donné à la performance, le sens et l’approche théâtrale et au public. Nous travaillons donc, pendant ces deux années de formation, à découvrir le ridicule en nous, nos faiblesses et nos forces qui nous permettent finalement d’approcher notre propre sincérité sur scène. L’enseignement donné au Lido enrichit nos techniques de cirque à travail un travail physique, théâtral et vocal, nous menant à un corps expressif. A travers une recherche technique et performative de haut niveau, l’artiste montre une approche personnelle autour d’un engagement physique, d’une recherche gestuelle précise et d’un langage physique spécifique. En perpétuel état de réflexion, nous cherchons nos chemins artistiques, notre forme d’écriture distinctive malgré les frontières qui sont, trop souvent, établies entre les différentes formes d’art.</p>  <p></p>  <p>• L E&nbsp; S P E C T A C L E •<br>  Ce spectacle ainsi que son travail de création marquent la fin de deux années pour la dernière formation. Un dernier travail ensemble qui a pour but de laisser chacun s’exprimer tout en écoutant et respectant la force du collectif. Un spectacle où sont rassemblés sous le même drapeau les univers bien personnels de chaque projet.<br>  C''est egalement l''occasion de tester, d’essayer, toujours avec engagement et sincérité, de travailler à deux, trois ou plus. L’occasion d’évoquer des sujets qui leurs sont chers, en tant que circadiens ancrés dans notre époque et surtout en tant qu’êtres humains, accompagnés à la mise en scène par Sylvain Cousin.<br>  &nbsp;</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '69ae3470-fbc1-43ca-a7c2-880f8e7148f0');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le Lido no Brazil', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>• L e L i d o •</p>  <p>Le Lido, centre municipal des Arts du Cirque de Toulouse, est membre de la “Fédération Européenne des Ecoles de Cirque professionnelles”. (Fédération Européenne des écoles de cirque professionnelles). La pédagogie de la formation professionnelle est au service de l’artiste, à travers la recherche d’une signature artistique et d’une authenticité sur scène. Au Lido, l’objectif est de permettre aux élèves de créer un cirque frais avec leurs propres langages où l’importance est donné à la performance, le sens et l’approche théâtrale et au public. Nous travaillons donc, pendant ces deux années de formation, à découvrir le ridicule en nous, nos faiblesses et nos forces qui nous permettent finalement d’approcher notre propre sincérité sur scène. L’enseignement donné au Lido enrichit nos techniques de cirque à travail un travail physique, théâtral et vocal, nous menant à un corps expressif. A travers une recherche technique et performative de haut niveau, l’artiste montre une approche personnelle autour d’un engagement physique, d’une recherche gestuelle précise et d’un langage physique spécifique. En perpétuel état de réflexion, nous cherchons nos chemins artistiques, notre forme d’écriture distinctive malgré les frontières qui sont, trop souvent, établies entre les différentes formes d’art.</p>  <p></p>  <p>• L E&nbsp; S P E C T A C L E •<br>  Ce spectacle ainsi que son travail de création marquent la fin de deux années pour la dernière formation. Un dernier travail ensemble qui a pour but de laisser chacun s’exprimer tout en écoutant et respectant la force du collectif. Un spectacle où sont rassemblés sous le même drapeau les univers bien personnels de chaque projet.<br>  C''est egalement l''occasion de tester, d’essayer, toujours avec engagement et sincérité, de travailler à deux, trois ou plus. L’occasion d’évoquer des sujets qui leurs sont chers, en tant que circadiens ancrés dans notre époque et surtout en tant qu’êtres humains, accompagnés à la mise en scène par Sylvain Cousin.<br>  &nbsp;</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '69ae3470-fbc1-43ca-a7c2-880f8e7148f0');
