INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE Concert Willow', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Né d''une rencontre évidente autour de la guitare et du chant un soir de concert, le duo WILLOW livre désormais une folk inspirée, tantôt moderne, tantôt imprégnée des codes originaux des traditionnels outre-atlantiques. Influencé par le blues et la soul, Willow fait le pari de proposer une écriture anglo-saxonne au service des paysages sonores qu''évoque sa musique .</p>  <p>Oli, 31 ans, auteur compositeur interprète originaire de région parisienne, nourrit son inspiration au grès des voyages dans un style authentique. Issu d''une famille de musiciens, Il partage aujourd''hui ses envies de liberté au fil de ses compositions.</p>  <p>Cécile, 33 ans, interprète vocaliste, partage son temps entre la musique et la montagne. C''est auprès de divers groupes qu''elle s''est forgée une expérience de la scène pour finalement retourner à un style brut et épuré en duo avec Willow.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'be31aee8-ab27-4de8-aa3c-784e5e651da5');
