INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE " Passe par la fenêtre et cours"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Jonglage, danse, théâtre par la Compagnie Happy Face.</p>  <p>Quelque part entre la danse, le jonglage et le théâtre, ils cherchent à exprimer les petites (grandes) peurs de la vie. Ils jonglent comme ils esquivent, comme on évite des obstacles. Ils s''animent à remuer ce qu''ils ont dans les tripes pour trouver un moyen de s''en sortir, de faire face à la réalité qui les entoure. Parce que le drame ne se joue pas forcément là où l''on croit, peut être que se perdre pour de bon n''est pas une si mauvaise chose que ça.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '55f6616a-b705-41ef-b84f-7c4733f473c5');
