INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fête des fleurs de St Sauveur', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Art végétal :</p>  <p style=\"margin-bottom: 0cm; line-height: 100%\">Dans le cadre du 150 ème anniversaire de la venue de Napoléon III à Luz St Sauveur, <font face=\"Calibri, sans-serif\">la Maison du Parc national et de la vallée a souhaité rendre hommage à l''Impératrice Eugénie. </font></p>  <p style=\"margin-bottom: 0cm; line-height: 100%\"><font face=\"Calibri, sans-serif\">Cette année, seront associés la fleur et le textile dans une création en echo à la féminité et au second empire.</font><font face=\"Calibri, sans-serif\">Ce projet a été conçu avec la participation de Nelly Ducamp, fleuriste et plasticienne Land Art originaire du pays Toy et Elsa Bergbeder, plasticienne bigourdane. A cette occasion, la Maison de la vallée invite la population à participer à la réalisation de l''installation végétale. Inscriptions possible jusqu''au 24 juillet 14h, directement à l''accueil le la Maison de la vallée ou par téléphone au 05 62 92 38 38. </font></p>  <p></p>  <p>Spectacles :</p>  <p>\"Ethno machine\"</p>  <p>Déambulation musicale par la Compagnie Nomad Men</p>  <p>La musique voyage à bord d''une machine exceptionnelle à la « Mad Max », fabriquéedans les ateliers Nomad Men, alliant surprise visuelle et musicalité. Des compositions ethniques avec des influences de tour du monde dans un groove dansant. Des Balkans en passant par l’Amérique du sud, le continent africain, les sommets de l’Himalaya et autres steppes mongoles, suivez-les en déambulation</p> &nbsp;  <p>\"Le Carré\"</p>  <p>Danse par la Compagnie Jafarson</p>  <p>Le Carré, c''est un espace de gesticulation ou tout les artifices ont été enlevés. Une ligne de craie qui, une fois franchie, devient un contour de scène. Les règles sont simples: on y rentre et on y danse la folie, la solitude, et on trouve un moyen de rendre ça beau. Les bruits de rue comme fond sonore, les passants comme inspiration, le Carré est un lieu d''improvisation, de travail, et de tout ce que le&nbsp;danseur veut vous faire voir. C''est l''exercice périlleux et nécessaire de faire beaucoup avec rien. Vous pouvez le regarder de loin, en écoutant de la musique... Les règles sont strictes pour les danseurs, pas pour le public.</p>  <p></p>  <p>\"Feu d''artifice\"</p>  <p>Comme depuis plusieurs années, Fabrice et son équipe nous préparent un feu d''artifice original et plein de surprises, tiré depuis le Parc thermal.</p>  <p></p>  <p>BUVETTE SUR PLACE</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0fe53e37-4da6-4b52-92f1-e9f18f1b59de');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fête des fleurs de St Sauveur', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Art végétal :</p>  <p style=\"margin-bottom: 0cm; line-height: 100%\">Dans le cadre du 150 ème anniversaire de la venue de Napoléon III à Luz St Sauveur, <font face=\"Calibri, sans-serif\">la Maison du Parc national et de la vallée a souhaité rendre hommage à l''Impératrice Eugénie. </font></p>  <p style=\"margin-bottom: 0cm; line-height: 100%\"><font face=\"Calibri, sans-serif\">Cette année, seront associés la fleur et le textile dans une création en echo à la féminité et au second empire.</font><font face=\"Calibri, sans-serif\">Ce projet a été conçu avec la participation de Nelly Ducamp, fleuriste et plasticienne Land Art originaire du pays Toy et Elsa Bergbeder, plasticienne bigourdane. A cette occasion, la Maison de la vallée invite la population à participer à la réalisation de l''installation végétale. Inscriptions possible jusqu''au 24 juillet 14h, directement à l''accueil le la Maison de la vallée ou par téléphone au 05 62 92 38 38. </font></p>  <p></p>  <p>Spectacles :</p>  <p>\"Ethno machine\"</p>  <p>Déambulation musicale par la Compagnie Nomad Men</p>  <p>La musique voyage à bord d''une machine exceptionnelle à la « Mad Max », fabriquéedans les ateliers Nomad Men, alliant surprise visuelle et musicalité. Des compositions ethniques avec des influences de tour du monde dans un groove dansant. Des Balkans en passant par l’Amérique du sud, le continent africain, les sommets de l’Himalaya et autres steppes mongoles, suivez-les en déambulation</p> &nbsp;  <p>\"Le Carré\"</p>  <p>Danse par la Compagnie Jafarson</p>  <p>Le Carré, c''est un espace de gesticulation ou tout les artifices ont été enlevés. Une ligne de craie qui, une fois franchie, devient un contour de scène. Les règles sont simples: on y rentre et on y danse la folie, la solitude, et on trouve un moyen de rendre ça beau. Les bruits de rue comme fond sonore, les passants comme inspiration, le Carré est un lieu d''improvisation, de travail, et de tout ce que le&nbsp;danseur veut vous faire voir. C''est l''exercice périlleux et nécessaire de faire beaucoup avec rien. Vous pouvez le regarder de loin, en écoutant de la musique... Les règles sont strictes pour les danseurs, pas pour le public.</p>  <p></p>  <p>\"Feu d''artifice\"</p>  <p>Comme depuis plusieurs années, Fabrice et son équipe nous préparent un feu d''artifice original et plein de surprises, tiré depuis le Parc thermal.</p>  <p></p>  <p>BUVETTE SUR PLACE</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '0fe53e37-4da6-4b52-92f1-e9f18f1b59de');
