INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE Concert "Microphonie"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Duo musique Jazz Microphonie&nbsp;est une cordée de deux musiciens-compositeurs, créé dans le silence des crêtes pyrénéennes. Leur musique, d’une difficile simplicité, se conjugue aisément à l’image et comporte beaucoup de lignes mélodiques épurées, qui se marient avec des environnements électro-acoustiques bruitistes. Ces musiciens se retrouvent aussi sur des esthétiques très diverses et leurs travaux respectifs sont souvent en lien avec les images qu’elles soient issues de films, du théâtre ou de la danse. Musicalement, ils se situent à la frontière de la musique de chambre - du Jazz, et tout une liste d’étiquettes dont ils se passent volontiers. Ils préfèrent dire : musique pour curieux.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7b4043ee-148b-4232-9ec1-1a6b708232d4');
