INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''homme dans tous ses états', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Exposition de sculptures par Jean-Claude Léon.</strong></p>  <p>Sculpter est pour lui la manière la plus forte d''exprimer le monde dans lequel j''évolue, un monde où la violence, l''injustice et la solitude explosent.</p>  <p>Sculpter, c''est être témoin, questionner la vie et obliger le spectateur à accomplir lui-même ce geste salvateur.</p>  <p>\"En sculptant, j''aime dominer la matière, me surprendre et surprendre les autres par le sérieux des problèmes abordés, le plus souvent possible avec une pointe d''humour...\" <em>Jean-Claude Léon</em></p>  <p></p>  <p><em>Une exposition programmée par le Parc national des Pyrénées.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ace061b0-9d33-4844-b4d9-6d8257670ae4');
