INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le renard au secours de l''homme', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<h1>Exposition</h1>  <p>Photographies réalisées par Patrick Boussieux.</p>  <p>Plusieurs études montrent l''importance des populations de prédateurs, notamment les renards roux, dans la réduction du risque de transmission de la maladie de Lyme par les tiques. C''est ce constat qui a amené Patrick Boussieux à observer puis à photographier les renards en milieu forestier sur le périmètre du Parc national des Pyrénées. Cet immense travail de patience et de persévérance trouve aujourd''hui sa récompense dans une exposition photographique qui permet un échange et un partage avec le public.</p>  <p></p>  <p></p>  <h1>Conférence vendredi 27 septembre 2019 à 18h<br>  &nbsp;</h1>  <p>« Responsable de la maladie de Lyme, la Borrelia est une bactérie très évoluée transmise par la piqure d''une tique infectée. Elle touche aussi bien de nombreux animaux que les humains...... »</p>  <p>Cette conférence vous seraz présentée par Patrick Boussieux.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7b98bf96-bf98-408e-98ad-4a7436bc849e');
