INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Une mouche (être ou ne pas être)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Cabaret de Hanokh Levin par Le Collectif Décomposé</strong></p>  <p></p>  <p>Auteur&nbsp;: Hanokh Levin / Textes en français de Laurence Sendrowicz</p>  <p>Editions Théâtrales, éditeur et agent de l’auteur</p>  <p>Metteur en scène&nbsp;: Eric Durand</p>  <p>Lumières&nbsp;: Guillaume Leclercq</p>  <p>Comédien, chanteur&nbsp;: Loïc Varanguien De Villepin</p>  <p>Piano&nbsp;: Vianney Oudart</p>  <p>Batterie&nbsp;: Fabien Duscombs</p>  <p>Chargée de production&nbsp;: Anne-Lise Blin</p>  <p></p>  <p><em>Quelques tables de bistro, un piano, une batterie, et de quoi boire un verre&nbsp;; bienvenue au cabaret du Collectif Décomposé&nbsp;!</em></p>  <p><em>Ce spectacle, réalisé à partir de textes d’Hanokh Levin, figure majeure du théâtre israélien, propose un cocktail détonnant de sketchs et chansons mélangeant provocation, humour aigre-doux et poésie.</em></p>  <p><em>«&nbsp;Une mouche (être ou ne pas être)&nbsp;» appartient à cette veine satirique caractérisée par un humour noir, y compris dans les pires situations.</em></p>  <p><em>Si dans ses textes, Levin cisèle chaque sketch en fable sur la condition humaine, il n’y a cependant pas de côté «&nbsp;anecdotique&nbsp;» dans ces histoires qui allient tragique et comique.</em></p>  <p><em>Textes et chansons évoquent des situations de tous les jours qui s’imbriquent les unes dans les autres, et qui bien au-delà de leur caractère parfois familier, prennent force dans l’existentiel, dans le philosophique…</em></p>  <p><em>Un spectacle jubilatoire&nbsp;!</em></p>  <p></p>  <p>Tarif : 8€ / 5€ réduit</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2d74d930-2cee-436e-bcf8-da9d4247cc26');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Une mouche (être ou ne pas être)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Cabaret de Hanokh Levin par Le Collectif Décomposé</strong></p>  <p></p>  <p>Auteur&nbsp;: Hanokh Levin / Textes en français de Laurence Sendrowicz</p>  <p>Editions Théâtrales, éditeur et agent de l’auteur</p>  <p>Metteur en scène&nbsp;: Eric Durand</p>  <p>Lumières&nbsp;: Guillaume Leclercq</p>  <p>Comédien, chanteur&nbsp;: Loïc Varanguien De Villepin</p>  <p>Piano&nbsp;: Vianney Oudart</p>  <p>Batterie&nbsp;: Fabien Duscombs</p>  <p>Chargée de production&nbsp;: Anne-Lise Blin</p>  <p></p>  <p><em>Quelques tables de bistro, un piano, une batterie, et de quoi boire un verre&nbsp;; bienvenue au cabaret du Collectif Décomposé&nbsp;!</em></p>  <p><em>Ce spectacle, réalisé à partir de textes d’Hanokh Levin, figure majeure du théâtre israélien, propose un cocktail détonnant de sketchs et chansons mélangeant provocation, humour aigre-doux et poésie.</em></p>  <p><em>«&nbsp;Une mouche (être ou ne pas être)&nbsp;» appartient à cette veine satirique caractérisée par un humour noir, y compris dans les pires situations.</em></p>  <p><em>Si dans ses textes, Levin cisèle chaque sketch en fable sur la condition humaine, il n’y a cependant pas de côté «&nbsp;anecdotique&nbsp;» dans ces histoires qui allient tragique et comique.</em></p>  <p><em>Textes et chansons évoquent des situations de tous les jours qui s’imbriquent les unes dans les autres, et qui bien au-delà de leur caractère parfois familier, prennent force dans l’existentiel, dans le philosophique…</em></p>  <p><em>Un spectacle jubilatoire&nbsp;!</em></p>  <p></p>  <p>Tarif : 8€ / 5€ réduit</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '2d74d930-2cee-436e-bcf8-da9d4247cc26');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Une mouche (être ou ne pas être)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Cabaret de Hanokh Levin par Le Collectif Décomposé</strong></p>  <p></p>  <p>Auteur&nbsp;: Hanokh Levin / Textes en français de Laurence Sendrowicz</p>  <p>Editions Théâtrales, éditeur et agent de l’auteur</p>  <p>Metteur en scène&nbsp;: Eric Durand</p>  <p>Lumières&nbsp;: Guillaume Leclercq</p>  <p>Comédien, chanteur&nbsp;: Loïc Varanguien De Villepin</p>  <p>Piano&nbsp;: Vianney Oudart</p>  <p>Batterie&nbsp;: Fabien Duscombs</p>  <p>Chargée de production&nbsp;: Anne-Lise Blin</p>  <p></p>  <p><em>Quelques tables de bistro, un piano, une batterie, et de quoi boire un verre&nbsp;; bienvenue au cabaret du Collectif Décomposé&nbsp;!</em></p>  <p><em>Ce spectacle, réalisé à partir de textes d’Hanokh Levin, figure majeure du théâtre israélien, propose un cocktail détonnant de sketchs et chansons mélangeant provocation, humour aigre-doux et poésie.</em></p>  <p><em>«&nbsp;Une mouche (être ou ne pas être)&nbsp;» appartient à cette veine satirique caractérisée par un humour noir, y compris dans les pires situations.</em></p>  <p><em>Si dans ses textes, Levin cisèle chaque sketch en fable sur la condition humaine, il n’y a cependant pas de côté «&nbsp;anecdotique&nbsp;» dans ces histoires qui allient tragique et comique.</em></p>  <p><em>Textes et chansons évoquent des situations de tous les jours qui s’imbriquent les unes dans les autres, et qui bien au-delà de leur caractère parfois familier, prennent force dans l’existentiel, dans le philosophique…</em></p>  <p><em>Un spectacle jubilatoire&nbsp;!</em></p>  <p></p>  <p>Tarif : 8€ / 5€ réduit</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '2d74d9