INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Funérailles', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>\"Je voulais parler de la mort, mais la vie a fait éruption, comme d''habitude\" Virginia Woolf</p>  <p>Monica et Léonie, deux conseillères funéraires, portent en elles deux mondes que tout oppose. Tout sauf leur condition de mortelles.</p>  <p>D''une banale situation de rencontre, elles basculent bientôt dans un road-trip absurde, un voyage en terre inconnue, sorte de limbes décadentes.</p>  <p>Par le biais du fantastique, les personnages sont toutes deux délogées de leurs certitudes. Elles passent de l''autre côté du miroir et deviennent les héroïnes de leur propre « Divine comédie », des « Alices » qui passent de l''ennui au chaos.</p>  <p>Dans un jeu de transformations perpétuelles du plateau, la comédie prend des allures de questionnements métaphysiques. Elle se transforme en une «danse macabre», farandole où s''entremêlent les vivants et les morts et où cohabitent parfaitement le tragique et le grotesque, afin de faire émerger comme une nécessité absolue, une fragile humanité.</p>  <p></p>  <p></p>  <p>Avec Claudia Hugues et Amélie Gasparotto</p>  <p>Lumière : Serena Andreasi</p>  <p>Conception : Claudia Hugues, Amélie Gasparotto, Serena Andreasi</p>  <p>Accompagnement écriture, dramaturgie: Laure Boutaud</p>  <p>Accompagnement direction d''acteur: Julie Boucher.</p>  <p>Administration de production: Marion Le Meut</p>  <p>Avec le soutien en résidence de : L.I.T à Rivesaltes (66), Fep Alzonne (11), Mix''art Myrys à Toulouse (31), La Hangar à Toulouse (31), La Maison du Parc national et de la vallée à Luz Saint Sauveur (65), Un dimanche à la campagne - Mauvaisin (31), La Cave Poésie à Toulouse (31), Le Moulin à Roques sur Garonne (31).</p>  <p>Avec l''aide à la création de la Région Occitanie et du Conseil Départemental de l''Ariege (09)</p>  <p><br>  &nbsp;</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1eb62b52-065a-4c3d-8470-befa3eb20a97');
