INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arise', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Compagnie Théâtre - Danse La Mandragore</p>  <p>En résidence à la Maison du Parc national et de la vallée du 28 octobre au 2 novembre.</p>  <p><em>Arise est une création, mêlant théâtre et danse, qui traite de l''expérience de l''exil et du déracinement. Création conçue à partir d''ateliers artistiques, de rencontres et de moments partagés, menés pendant plus d''une année auprès de personnes en situation de migration. Ce spectacle, veut montrer les histoires que l’on porte en soi, l’arrachement au pays, l’errance, la mémoire, ainsi que la confrontation des mondes passés et présents. La fuite et le voyage de personnes en situations de rupture, notamment les adolescents isolés arrivés sur notre territoire.</em></p>  <p><em>Le spectacle se décline en une suite de tableaux qui mettent en scène des moments du quotidien, évoquent les souvenirs d''enfance, les fables, les gestes, la mosaïque des langues et des chants. Mais aussi la traversée des mers, l''expression du désarroi ou de l''euphorie... ARISE met en lumière les raisons qui poussent des individus à partir et à \"Faire l''Aventure\". Montrer le rêve, le désir, et le jeu comme mouvement de la vie même...</em></p>  <p><em>Arise, «&nbsp;s''élever&nbsp;», signifie ici que l''on s''appuie sur les possibilités de création contenues dans les situations de marginalisation, au plus près des existences précaires.</em></p>  <p><em>Il s''agit d''être attentif à la présence d''autrui, aux nuances de sa parole, pour la restituer et, plus largement, la faire résonner dans l''espace public.</em></p>  <p><em>Ensemble, avec mesure, «&nbsp;On cherche ici un fil pour se guider dans le labyrinthe des désorientations contemporaines&nbsp;». (Plinio Prado)</em></p>  <p></p>  <p>Coproduction du Parvis scène nationale Tarbes Pyrénées</p>  <p>En partenariat avec le Conservatoire Henri Duparc de l''agglomération Tarbes-Lourdes-Pyrénées</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '25e8db78-6d4f-4955-b0a0-63027506f493');
