INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Blanche neige voit rouge', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre par la Compagnie Les réverbères.</p>  <p>À partir de 5 ans.</p>  <p></p>  <p><em>Il était une fois Blanche Neige, une princesse d’une très grande beauté, ce qui rendait folle de jalousie la méchante reine. Quand cette dernière ordonne sa mort, Blanche Neige s’enfuit et échoue dans une maison où habitaient sept nains… ou six, ou huit... enfin ils étaient beaucoup. Ce conte aurait pu se dérouler normalement si deux jeunes conteuses, plus maladroites l’une que l’autre, n’avaient pas décidé de s’en emparer... \"</em></p>  <p></p>  <p></p>  <p><em><img alt=\"\" src=\"https://www.maisondelavallee.org/sites/default/files/3._oc-1810-comarquagefe-ue-leader-reg-vect-page-001.jpg\" style=\"width: 1188px; height: 297px;\"></em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd65409f9-8ca8-4418-849b-c93d818ee689');
