INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La petite fabrique de notes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Rendez-vous le sur le front de neige de la Station de ski de l''Ardiden avec Hervé et sa Deuch de Barbarie à partir de 9h !!!</p>  <p></p>  <p>En fin d''après-midi... :</p>  <p>Contes par la Compagnie Itinérence</p>  <p>Tout public</p>  <p><em>Hervé et Gigi Carrère nous emmènent dans l''univers de l''orgue de Barbarie avec la bonne humeur qui les caractérise.</em></p>  <p>&nbsp;Suivie de :</p>  <p><strong>« La deuch de Barbarie » </strong></p>  <p>Musique – Tout public</p>  <p><em>Venez déambuler en suivant la 2CV de Barbarie d''Hervé et Gigi Carrère.</em></p>  <p><em>Malgré quelques libertés sur les paroles de certaines chansons, le public appréciera ces deux personnages qui évolueront de manière cocasse et burlesque dans les rues du village.</em></p>  <p>À 18h30 - Rendez-vous devant l''office de tourisme.</p>  <p></p>  <p><img alt=\"\" src=\"https://www.maisondelavallee.org/sites/default/files/3._oc-1810-comarquagefe-ue-leader-reg-vect-page-001.jpg\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'a21747b9-434b-40f8-a9bb-e513b9289656');
