INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Lou Casa, Barbara & Brel', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Musique - Tout public</p>  <p><em>La relecture contemporaine de Lou Casa ne cesse d''être saluée par des professionnels et publics de toutes générations, notamment pour ses partis pris d interprétation et ses arrangements originaux. Mathieu Amalric ne s’y est pas trompé, en l''intégrant, à l’image et au son, de son film “Barbara”. En tournée, le trio a notamment affiché \"complet\" lors de ses concerts à La Philharmonie de Paris ou à trois reprises au Café de la Danse avec le projet Chansons de Barbara. S''en sont suivis l''Opéra National de Strasbourg ou les arènes d''Amou autant que des lieux inattendus et petites salles, Lou Casa tenant à partager ces oeuvres partout et pour tous.<br>  Dans le nouveau concert Lou Casa, Barbara &amp; Brel, le trio mêle ses sensibilités et musiques actuelles aux répertoires croisés de ces deux artistes aux liens multiples. Lou Casa propose ses éclairages en échos à notre époque sur des textes fins et prenants, et leurs thèmes, et leurs personnages. Les questions de fraternité, d''amour, d''amitié, ou d''humour y sont au cœur.</em></p>  <p></p>  <p>Distribution :</p>  <p>Stéphane Gasquet : piano, orgue, tom bass, chœurs</p>  <p>Julien Aellion : basse électrique, chœurs</p>  <p>Marc Casa : chant, percussions, orgue, direction artistique</p>  <p></p>  <p>TARIFS : 8€ / 5€ (réduit)</p>  <p></p>  <p><img alt=\"\" src=\"https://www.maisondelavallee.org/sites/default/files/3._oc-1810-comarquagefe-ue-leader-reg-vect-page-001.jpg\" style=\"width: 1188px; height: 297px;\"></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd8494316-16e1-4ebe-a385-8ad26127d08c');
