INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Déambulation avec la Fanfare Toto', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Musique – Tout public</p>  <p>A l''occasion du carnaval, rendez-vous devant l''office de tourisme pour une déambulation musicale avec la fanfare Toto !</p>  <p><em>Cette fanfare serait-elle une illusion ? Une sorte de mirage cinématographique ? Assurément, c''est une fratrie qui semble tout droit sortie du fameux train qui creva l’écran en l’an 1886 … Six frères donc, aux allures de notables, se retrouvent ! </em></p>  <p><em>Ce sont les frères Locomotive !</em><em> Leur musique ? Un savant cocktail aux douces saveurs du siècle dernier : des mélodies foraines, cinématographiques, du vieux jazz, du classique , des vieux airs et des compositions.</em></p>  <p><em>Une contrefaçon bienveillante ou grinçante à la mode 1900 pour s’amuser à remonter les pendules de l’histoire, jouer à vous faire croire que c’était mieux avant et que demain ce sera pire... Même si aujourd’hui, c’est difficile ! Avec les frères Locomotive les boniments vont bon train : de la musique, des réclames et de nombreuses surprises sont au programme.</em></p>  <p></p>  <p>La fanfare jouera également sur le front de neige de la station de ski de l''Ardiden entre 13h et 14h !</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '96d6069a-0af5-4f06-8ed9-bb989aee3994');
