INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Celui qui a mal tourné, Brassens', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle musical et théâtral par la Compagnie Les pieds dans le plat</p>  <p>À partir de 10 ans</p>  <p><em>Le spectacle décline l’œuvre de Georges Brassens sous différentes formes : textes joués théâtralement, textes dits et accompagnés musicalement , chansons du poète « revisitées » et chansons originales.</em></p>  <p><em>Des chapitres, accompagnés d’extraits d’interviews de l’auteur, aborderont les thèmes récurrents chers à Brassens : les poètes (Paul Fort, Jean Richepin....), l''anarchie et le pacifisme, l’amour et les femmes, les copains, la mort...</em></p>  <p></p>  <p>Distribution :</p>  <p>Roland Abadie : comédien, guitare, chant<br>  Marcel Cazentre : contrebasse, chant<br>  Francis Ferrié: accordéon, saxophone, guitare, Percussions, chant, cajon<br>  David Levy : guitare, ukulélé, chant, dobro<br>  Mise en scène : Anna Mazzotti</p>  <p></p>  <p>TARIFS : 8€ / 5€ (réduit)</p>  <p></p>  <p><img alt=\"\" src=\"https://www.maisondelavallee.org/sites/default/files/3._oc-1810-comarquagefe-ue-leader-reg-vect-page-001.jpg\" style=\"width: 1188px; height: 297px;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b93d8950-2923-489b-bcdc-069388b73e15');
