INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Petits points de vie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre par la Compagnie Des Jolies Choses</p>  <p>&nbsp;À partir de 6 ans</p>  <p><em>D''après l''ouvrage de Catherine Verlaguet&nbsp; </em></p>  <p><em>Spectacle de quatre pièces courtes : la rencontre magique et musicale entre un enfant trop bavard et le fils adoptif d''une amie de sa maman, qui n''ouvre jamais la bouche; un garçon qui discute avec son frère imaginaire pas si réel logé dans son épaule; deux frères prêts à tout pour décrocher une étoile à leur mamie afin que sa mémoire ne s’efface pas; une petite fille partie à la recherche de son sourire, qu''elle a perdu entre la maison de son papa et celle de sa maman.</em></p>  <p><em>Une invitation à la découverte de l''autre et du monde, en poésie et en récit, en dialogue et en rêve.</em></p>  <p>Mise en scène collaborative - Création Avril 2020.</p>  <div class=\"page\" title=\"Page 2\">Distribution :</div>  <div class=\"page\" title=\"Page 2\">Mélia Bannerman : Metteur en scène, commédienne, plasticienne.</div>  <div class=\"page\" title=\"Page 2\">Sophie Barros : Chorégraphe, danseuse, comédienne.</div>  <div class=\"page\" title=\"Page 2\">Lucile Delamorena : Comédienne.</div>  <div class=\"page\" title=\"Page 2\">Laurie Montamat : comédienne, danseuse.</div>  <div class=\"page\" title=\"Page 2\">Mayline Petioch : Metteur en scène, chanteuse, comédienne, musicienne.</div>  <div class=\"page\" title=\"Page 2\">Bastien Sallaberry : Régie générale.</div>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6029cc96-48b2-487c-a11d-c50368ad9f89');
