('57845d34-91ff-4c3b-abbd-34b04ddc7e57', 'exposition', true, false, NULL, '2019-11-01T23:00:00.000Z', '2019-11-29T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2019-11-01T23:00:00.000Z', '2019-11-01T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''oeil d''Orane', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Orane est née le 8 juin 1991 à Tarbes, deux ans après sa soeur aînée Anouck. Très tôt, elle présente des signes de singularité : elle vit à son rythme, peu intéressée par le monde normal... Mais&nbsp; fascinée par le monde animal&nbsp;: elle peut passer des heures entières à regarder voler une mouche, souvent isolée et paradoxalement très attentive aux autres — en particulier à leur détresse ou leurs difficultés — ; elle développe un sens de l''observation et une sensibilité exacerbés.<br>  <br>  S’ensuit alors un parcours atypique. Ne pouvant suivre une scolarité ordinaire, elle est très vite orientée vers des classes adaptées, puis vers un IME (institut médico-éducatif) où elle ne se sent pas à sa place. Elle ne manifeste alors aucun intérêt pour l''art, quel qu''il soit, si ce n’est pour les films et dessins animés pour enfants qu’elle regarde en boucle; avant de découvrir, à l''âge de seize ans, le théâtre amateur. Un déclic qui développera son relationnel, sa diction et modifiera son regard sur sa différence. En 2012, elle rejoint la vie active, et travaille depuis dans le domaine des espaces verts.<br>  &nbsp;<br>  C’est à l’âge de vingt et un ans, et au moment où sa soeur diplômée d''un DNSEP quitte le milieu artistique, qu’Orane commence à dessiner pour la première fois de sa vie, comme pour prendre un relais. Elle effectue d''abord des dessins d''enfants, au stylo bille. Puis, petit à petit, elle agrandit son espace de travail. Son dessin s’organise toujours en fonction des yeux des personnages auxquels elle apporte une attention toute particulière. Elle recouvre minutieusement tout l’espace de la feuille ou de la figure humaine. Les dessins évoluent au gré de ses sentiments, de son quotidien, de l’actualité et de l’interprétation qu’elle en fait. Avec le temps, son trait évolue, se fait plus précis, les compositions s’enrichissent de symboles, deviennent plus complexes, plus chargées : Orane n’y laisse souvent aucun espace vide, aucune réserve. Elle travaille sans croquis ni esquisse, ne reprend pas son dessin, ne le corrige pas et ne fait preuve d''aucun repentir.</p>  <p>En 2013, Orane est repérée par Madame Lucienne Peiry, alors directrice de la recherche et des relations internationales de la Collection de l''Art Brut&nbsp; de Lausanne... avant d''y être admise fin 2015, au sein de la section \"neuve invention\".</p>  <p></p>  <p><strong>Aujourd''hui Orane est éditée pour la première fois par la maison d''édition Cabinet VOX SCRIBA \" Du simple conseil à la rédaction \", au sein d''une série d''ouvrages \"La Patte de l''Autre\", faisant place à la différence. </strong></p>  <p><strong>\"L''oeil d''Orane\" sera en vente tout le mois de novembre à la Maison de la vallée et sera dédicacé par Orane le samedi 30 novembre à l''occasion du décrochage de l''exposition.</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '57845d34-91ff-4c3b-abbd-34b04ddc7e57');
