INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Cabaret cirque " ¡ Là haut ! "', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Les artistes du court-métrage sont de retour avec un cabaret special \" ¡ Là haut ! \".</p>  <p>A programme :</p>  <p>Spectacle composé de numéros de cirque éphèmères par David, Laurette, Cali, Marta, Amanda, Otto, Noémie et Claire -</p>  <p>Musique d''Eric Brochard -</p>  <p>Diffusion du court métrage et de son making off -</p>  <p>Exposition photos du tournage - Rencontre avec les équipes ...</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '547b38f2-f8cb-4540-83ae-21adef6455e1');
