INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Piuma - Duo Cirla Trolonge', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>PIUMA, création 2019</strong></p>  <p><strong>Isabelle Cirla : Clarinette basse</strong></p>  <p><strong>Joël Trolonge : Contrebasse</strong></p>  <p>A travers des nouvelles pièces, au son et au style caractéristique, la clarinette basse et la contrebasse explorent un répertoire à la fois subtile, élégant et puissant. En privilégiant l’acoustique, le duo poursuit son choix d’une musique apaisante, lumineuse et aérienne.</p>  <p>En résidence du lundi 9 au vendredi 13 décembre, c''est l''occasion pour le duo d''enregistrer un troisième disque et de partager un moment avec le public pour lui faire découvrir en avant première une partie du contenu de ce nouvel opus. &nbsp;</p>  <p><strong>CONCERT SORTIE DE RÉSIDENCE : mardi 10 décembre à 19h</strong></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"></p>  <p dir=\"ltr\" id=\"docs-internal-guid-98423ddc-7fff-8bef-e9b0-399e1832a106\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"color:#000000;\"><span style=\"font-size: 14pt; font-family: Calibri, sans-serif; background-color: transparent; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Isabelle CIRLA</span></span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Saxophone soprano, clarinette basse, voix, paysages sonores acoustiques et numériques</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#918a7d;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Son parcours est fait de rencontres avec le théâtre, la danse, le cirque, le jazz, la musique électro acoustique (GMEA Albi) 1989, les musiques improvisées et contemporaine (Lux Nox Mix, Hors chant), les sciences (Festival Novela, Les chemins buissonniers&nbsp; Le cerveaurium ) 2008/2014.</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#918a7d;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Attirée par les aventures de la musique sous ses formes, elle arpente les différentes techniques de jeu dans l’improvisation, les propose à différents moyens d’expression, les approche dans toutes leurs diversités. Ce goût pour l’improvisation l’amène&nbsp; à rencontrer et jouer avec John Tchicaï 1989, Steve Lacy 1998, Hermeto Pascual 1993, Lindsay Cooper 1996, Bernard Lubat 1989, Kevan Chémirani 2003, Barre Philipps 2007, Fela Kuti 1994.</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#918a7d;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Elle prolonge sa pratique en pédagogie, avec des enfants, des enseignants, des écoles de musique et conservatoires. Elle est également responsable d’ateliers et de formation musicale.</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Calibri,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">&nbsp;</span></p>  <p dir=\"ltr\" id=\"docs-internal-guid-231c600a-7fff-5f40-0340-d6aeb8dadc0a\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"color:#000000;\"><span style=\"font-size: 14pt; font-family: Calibri, sans-serif; background-color: transparent; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Joël TROLONGE</span></span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Contrebasse, voix, paysages sonores acoustiques et numériques</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#918a7d;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Sa formation autodidacte est ponctuée de&nbsp; rencontres autour de l’apprentissage de la contrebasse et du jazz qui lui ont permis de croiser et de profiter de leur enseignement (Jean François Jenny Clark , Hein Van de Gein , Eddie Gomez).</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#918a7d;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">De 1993 à 2004, il fait partie du groupe Latcho Drom avec qui il tourne dans le monde entier. Ses choix artistiques et ses orientations musicales vont évoluer suite à des rencontres avec Joëlle Léandre, Georges Petit, Barre Philipps et il consacre alors de plus en plus de temps à la musique improvisée.</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:12pt;font-family:Calibri,sans-serif;color:#918a7d;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Titulaire du Diplôme d’Etat d’enseignement de la musique&nbsp; spécialité Jazz en 2002, il a enseigné à l’école Music’Halle à Toulouse (coordination pédagogique, cours d’instruments, ateliers), ainsi qu’au Conservatoire de Musique et de Danse de Blagnac (31). Il intervient également lors de stages et master-classes dans différents établissements de l’hexagone. Joël Trolonge est&nbsp; le contrebassiste de l''Orchestre de Chambre d''Hôte dirigé par Jean-Paul Raffit depuis 2009.</span></p>  <p dir=\"ltr\" style=\"line-height:1.38;text-align: justify;margin-top:0pt;margin-bottom:0pt;\"></p> <span style=\"font-size:10pt;font-family:Calibri,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Le duo est soutenu par La Région Occitanie, le Conseil Départemental 31, </span><span style=\"font-size:10pt;font-family:Calibri,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:italic;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">la Mairie de Toulouse et la Spedidam.</span>","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'b9265d71-602c-45e5-a343-7fcbdb379fa6');
