INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Gravir - Graver " Gravures pyrénéennes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Gravures par Thomas Girard</strong></p>  <p></p>  <p>Né en 1957 à St Gaudens, installé dans les Hautes Pyrénées depuis 8 ans.</p>  <p>Pratiquant graphismes, calligraphies et gravures depuis 15 ans dans divers ateliers : Naucelle (12), atelier «Le Calame et la Vigne » 2009-2011, Toulouse, atelier de La Main Gauche 2009 Pau, atelier gravure de l''Ecole Supérieure d''Arts depuis septembre 2017</p>  <p>Expositions :</p>  <p>«Au pied de la lettre» Saint Jean de Braye (45) novembre-décembre 2006</p>  <p>\"Gravir-graver\" Salon du livre pyrénéen Binaros, Bagnères de Bigorre, octobre 2019</p>  <p>Publications :</p>  <p>Illustration du recueil de nouvelles « Origines » (Editions du Castor Astral 2006)</p>  <p>Gravures dans le N°3 de la Revue Passe-Murailles (Maison de la Montagne, Pau 2019)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0617b62d-d92b-4926-b7ac-411f04e6de07');
