INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE DE RÉSIDENCE "ACIERS LIQUIDES"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Aciers liquides \" </strong></p>  <p><strong>Performance sonore, visuelle &amp; poétique - Compagnie La Wouakatchie de La Mélodie.</strong></p>  <p>En résidence du 15 au 18 janvier 2020.</p>  <p></p>  <p><strong>La compagnie :</strong></p>  <p>Créée en 1998 dans les Hautes Pyrénées, la compagnie de La Wouakatchie de la Mélodie regroupe plusieurs activités artistiques telles que le théâtre de rue participatif, la musique improvisée, la lutherie sauvage en métal et les performances.<br>  Les créations de la compagnie s’adressent à tous les publics, dans un maximum de lieux, dédiés ou non au spectacle.</p>  <p></p>  <p><strong>La performance</strong> :</p>  <p>La performance Aciers Liquides est portée par trois artistes qui unissent les univers de leurs recherches respectives dans le domaine de l’écriture, du son et des arts plastiques.</p>  <p>Eugène a écrit un poème en quatre stances qu''il interprète lors de la performance. Unitympal crée des instruments en acier atonaux (lutherie sauvage en métal) et produit des sonorités uniques. Soen propose des expérimentations picturales rétroprojectées, au gré des sons et des paroles ambiants.</p>  <p>Chacun des artistes enrichissant leurs interventions par cette interaction, chaque représentation est unique, en partie improvisée et performative.</p>  <p></p>  <p><a href=\"https://www.youtube.com/watch?v=gO6vtqT6XU4\">https://www.youtube.com/watch?v=gO6vtqT6XU4</a></p>  <p></p>  <p><strong>Les artistes :</strong></p>  <p>Eugène s''inspire de plusieurs auteurs, poètes et philosophes d''époques différentes pour composer des textes aussi hallucinés que fortement ancrés dans les questionnements de notre temps. Il développe une pratique d''écriture inspirée du groupe l''OuLiPo<br>  qu''il envisage comme une méthode essentielle de travail. Il met en exergue des charges poétiques comme de possibles réponses au monde moderne.</p>  <p>Unitympal, soudeur pendant 15 ans dans l''industrie métallique, en garde le goût du bruit et de la poussière dans la production de ce qu’il qualifie d’« une musique du vide », l’empreinte singulière de l’absence. Dans des mises en espace pleines de joie et de vacarme, c''est par les instruments en acier atonaux et injouables que le champ sonore parle au corps et aux émotions.</p>  <p>Soen aborde la peinture de manière instinctive, pratiquant des techniques mixtes, pour créer des compositions abstraites et spontanées. Plasticienne, elle collabore avec différentes formations de musique improvisée. Elle travaille sur un rétroprojecteur et varie les supports, les matières, les outils et les techniques, afin de proposer un visuel singulier.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0fcea3b8-0237-4d03-bba3-29eb0ba4dc9c');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE DE RÉSIDENCE "ACIERS LIQUIDES"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Aciers liquides \" </strong></p>  <p><strong>Performance sonore, visuelle &amp; poétique - Compagnie La Wouakatchie de La Mélodie.</strong></p>  <p>En résidence du 15 au 18 janvier 2020.</p>  <p></p>  <p><strong>La compagnie :</strong></p>  <p>Créée en 1998 dans les Hautes Pyrénées, la compagnie de La Wouakatchie de la Mélodie regroupe plusieurs activités artistiques telles que le théâtre de rue participatif, la musique improvisée, la lutherie sauvage en métal et les performances.<br>  Les créations de la compagnie s’adressent à tous les publics, dans un maximum de lieux, dédiés ou non au spectacle.</p>  <p></p>  <p><strong>La performance</strong> :</p>  <p>La performance Aciers Liquides est portée par trois artistes qui unissent les univers de leurs recherches respectives dans le domaine de l’écriture, du son et des arts plastiques.</p>  <p>Eugène a écrit un poème en quatre stances qu''il interprète lors de la performance. Unitympal crée des instruments en acier atonaux (lutherie sauvage en métal) et produit des sonorités uniques. Soen propose des expérimentations picturales rétroprojectées, au gré des sons et des paroles ambiants.</p>  <p>Chacun des artistes enrichissant leurs interventions par cette interaction, chaque représentation est unique, en partie improvisée et performative.</p>  <p></p>  <p><a href=\"https://www.youtube.com/watch?v=gO6vtqT6XU4\">https://www.youtube.com/watch?v=gO6vtqT6XU4</a></p>  <p></p>  <p><strong>Les artistes :</strong></p>  <p>Eugène s''inspire de plusieurs auteurs, poètes et philosophes d''époques différentes pour composer des textes aussi hallucinés que fortement ancrés dans les questionnements de notre temps. Il développe une pratique d''écriture inspirée du groupe l''OuLiPo<br>  qu''il envisage comme une méthode essentielle de travail. Il met en exergue des charges poétiques comme de possibles réponses au monde moderne.</p>  <p>Unitympal, soudeur pendant 15 ans dans l''industrie métallique, en garde le goût du bruit et de la poussière dans la production de ce qu’il qualifie d’« une musique du vide », l’empreinte singulière de l’absence. Dans des mises en espace pleines de joie et de vacarme, c''est par les instruments en acier atonaux et injouables que le champ sonore parle au corps et aux émotions.</p>  <p>Soen aborde la peinture de manière instinctive, pratiquant des techniques mixtes, pour créer des compositions abstraites et spontanées. Plasticienne, elle collabore avec différentes formations de musique improvisée. Elle travaille sur un rétroprojecteur et varie les supports, les matières, les outils et les techniques, afin de proposer un visuel singulier.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '0fcea3b8-0237-4d03-bba3-29eb0ba4dc9c');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE DE RÉSIDENCE "ACIERS LIQUIDES"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Aciers liquides \" </strong></p>  <p><strong>Performance sonore, visuelle &amp; poétique - Compagnie La Wouakatchie de La Mélodie.</strong></p>  <p>En résidence du 15 au 18 janvier 2020.</p>  <p></p>  <p><strong>La compagnie :</strong></p>  <p>Créée en 1998 dans les Hautes Pyrénées, la compagnie de La Wouakatchie de la Mélodie regroupe plusieurs activités artistiques telles que le théâtre de rue participatif, la musique improvisée, la lutherie sauvage en métal et les performances.<br>  Les créations de la compagnie s’adressent à tous les publics, dans un maximum de lieux, dédiés ou non au spectacle.</p>  <p></p>  <p><strong>La performance</strong> :</p>  <p>La performance Aciers Liquides est portée par trois artistes qui unissent les univers de leurs recherches respectives dans le domaine de l’écriture, du son et des arts plastiques.</p>  <p>Eugène a écrit un poème en quatre stances qu''il interprète lors de la performance. Unitympal crée des instruments en acier atonaux (lutherie sauvage en métal) et produit des sonorités uniques. Soen propose des expérimentations picturales rétroprojectées, au gré des sons et des paroles ambiants.</p>  <p>Chacun des artistes enrichissant leurs interventions par cette interaction, chaque représentation est unique, en partie improvisée et performative.</p>  <p></p>  <p><a href=\"https://www.youtube.com/watch?v=gO6vtqT6XU4\">https://www.youtube.com/watch?v=gO6vtqT6XU4</a></p>  <p></p>  <p><strong>Les artistes :</strong></p>  <p>Eugène s''inspire de plusieurs auteurs, poètes et philosophes d''époques différentes pour composer des textes aussi hallucinés que fortement ancrés dans les questionnements de notre temps. Il développe une pratique d''écriture inspirée du groupe l''OuLiPo<br>  qu''il envisage comme une méthode essentielle de travail. Il met en exergue des charges poétiques comme de possibles réponses au monde moderne.</p>  <p>Unitympal, soudeur pendant 15 ans dans l''industrie métallique, en garde le goût du bruit et de la poussière dans la production de ce qu’il qualifie d’« une musique du vide », l’empreinte singulière de l’absence. Dans des mises en espace pleines de joie et de vacarme, c''est par les instruments en acier atonaux et injouables que le champ sonore parle au corps et aux émotions.</p>  <p>Soen aborde la peinture de manière instinctive, pratiquant des techniques mixtes, pour créer des compositions abstraites et spontanées. Plasticienne, elle collabore avec différentes formations de musique improvisée. Elle travaille sur un rétroprojecteur et varie les supports, les matières, les outils et les techniques, afin de proposer un visuel singulier.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '0fcea3b8-0237-4d03-bba3-29eb0ba4dc9c');
