INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('C''EST PAS MOI, C''EST MÉDÉE ! - SUSPENDU', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong><span style=\"color:#e74c3c;\">Par mesure de précaution, le spectacle est reporté à une date ultérieure. Nous ne manquerons par de vous tenir informés et vous remercions de votre compréhension.</span></strong></p>  <p></p>  <p><strong>« C’EST PAS MOI, C’EST MÉDÉE ! » </strong></p>  <p><strong>Poésie mouvementée et musique expérimentale. Compagnie PAL(L)ADE</strong></p>  <p><strong>De et avec<br>  Annoïe-Anne ROY et Stéphanie BARBÉ</strong></p>  <p></p>  <p>UNE ATMOSPHÈRE PROFONDE ...</p>  <p>« C’est pas moi c’est Médée ! » est un spectacle de poésie mouvementée et musique expérimentale.<br>  Une création originale, naviguant entre le récit symbolique, la chanson, l’expression du corps.</p>  <p>Une atmosphère profonde, sensuelle et intempestive, d’où émergent des accents archaïques.</p>  <p>Anne Roy est chanteuse et musicienne. Sa voix insolite peut aller partout. Elle transporte dans des ambiances à la fois profondes et aériennes, du bruisme au chant lyrique, aux connotations parfois tribales. Elle manœuvre l’univers sonore de ce spectacle en utilisant avec justesse percussions, cordes frottées, pédales d’effets.</p>  <p>... INTEMPESTIVE</p>  <p>Stéphanie Barbé est poète et performeuse. Son écriture et sa présence corporelle traversent les codes. Contemporaine, certes. Intuitive, charnelle, elle n’hésite pas à bouleverser les mots et le sens commun. Il s’en dégage une parole libre, habitée, et un langage brut, poussés au corps. Une écriture-danse en quelque sorte, rythmée et sensuelle.</p>  <p></p>  <p>En résidence du 10 au 15 février 2020.</p>  <p>... AUX ACCENTS ARCHAÏQUES.</p>  <p>L’univers déployé dans « C’est pas moi, c’est Médée » évoque ces figures mythiques, à la fois inquiétantes et universelles, ces « déesses crues, habitées par l’héroïsme d’aimer comme on vit plus que vivre ».</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '40eed8e8-5a6f-4528-ac0b-d608761afcad');
