INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Horizons d''Antioche', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Série photographique prise entre La Rochelle et Port-Des-Barques, dans le Pertuis d’Antioche par <strong>Ugo Zamparo</strong>.</p>  <p>Photographe professionnel natif de Luz Saint Sauveur, et maintenant basé à La Rochelle, il réalise également des projets artistiques qui lui tiennent à cœur notamment autour de la mer.<br>  Adepte du minimalisme, du design et de l’architecture, il a confronté son regard à l’océan et son immensité.<br>  <br>  C’est ainsi que « Horizons d’Antioche » est né. Les photographies sont réalisées entre l’ile d’Oléron et l’ile de Ré, dans le fameux Pertuis d’Antioche.</p>  <p><strong>VERNISSAGE DÉCROCHAGE VENDREDI 28 FÉVRIER À 18H.</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '415e622a-be92-44fe-912d-80dd7a70ded2');
