INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''AIR DE RIEN / REPLI GYMNASE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Cirque acrobatique par la Compagnie Viens voir là-bas. <span style=\"color:#e74c3c;\">EN RAISONS DES MAUVAISES PRÉVISIONS MÉTÉO, LE SPECTACLE AURA LIEU AU GYMNASE.</span></strong></p>  <p>Elle est là, seule, face au public, dos à l''agrès. Au pied du mur, face à elle-même. L''air de rien, elle puisera assez de force en elle et dans le public, pour atteindre les hauteurs et, quoi qu''il arrive, virevolter. En tous cas elle y croit.</p>  <p>(Dans le cadre des mercredis artistiques)</p>  <p>L''artiste :</p>  <p>Violaine ARROUY – Auteure, Metteur en scène et Interprète</p>  <p>Acrobate aérienne formée au Centre Régional des Arts du Cirque Piste d''Azur, Violaine enrichie son univers circassien, par la danse, en France, auprès de Sabaline Fournier (Collectif Dantzaz), Anna Rodriguez (Danse de l''acteur) et au Bénin, auprès de Vincent Harisdo.</p>  <p>Elle est l''auteure-interprète de « Ne pas jeter sur la voie publique » , « Dualité rapprochée » et « Naturelle ».<br>  Parallèlement Violaine est acrobate au mât-chinois dans différents spectacles de l''Opéra National de Paris, et pour la Cie Pégaz Urbacircus. Elle travaille régulièrement en collaboration avec des musiciens, chorégraphes, conteurs ou encore pour des festivals comme le Jazz à Luz.</p>  <p>Convaincue que l''art est un formidable vecteur de développement et de lien, Violaine transmet ses compétences et son enthousiasme à travers des stages et participe régulièrement à des conventions de cirque et de danse .<br>  Diplômée, depuis 2016, en « Dramaturgie circassienne » , par le Centre National des Arts du Cirque de Châlons-en-Champagne. Elle écrit et met en scène « À ta place » pour le Collectif Rue de la scène, une création pour 8 jeunes artistes au plateau.</p>  <p>En 2018 elle se lance dans le projet et spectacle intergénérationnel, « Ce qu''il nous reste » , en duo avec l''acrobate Eugénie Carpentier. Soutenu par les départements du Gers et des Pyrénées-Atlantiques.</p>  <p></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p>  <p></p>  <p><img alt=\"\" src=\"https://www.maisondelavallee.org/sites/default/files/3._oc-1810-comarquagefe-ue-leader-reg-vect-page-001.jpg\" style=\"width: 1188px; height: 297px;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8ad6ecc3-d74d-4d27-a8ec-2c67c38f3828');
