INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SAXICOLA RUBI ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Ce duo est la rencontre de deux souffleurs compositeurs et improvisateurs, un dialogue en miroir entre sax soprano et clarinette basse, un palindrome musical parfait à deux faces.</p>  <p>Tels deux oiseaux sur une branche, <strong>Vogeler et Rochelle</strong> tissent d''infinis discours de joutes vocales colorées, acrobates sur les branches fragiles de l''improvisation.</p>  <p>(Dans le cadre des mercredis artistiques)</p>  <p></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p>  <p></p>  <p><img alt=\"\" src=\"https://www.maisondelavallee.org/sites/default/files/3._oc-1810-comarquagefe-ue-leader-reg-vect-page-001.jpg\" style=\"width: 1188px; height: 297px;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e5fbe526-26e9-4d01-a68a-22684e34f0ef');
