INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CHU TSAO', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Groupe emblématique de la scène alternative bigourdane, Chu Tsao se réinvente depuis plus de 15 ans. Devenu un véritable projet métamorphe, slalomant entre hip hop, dub, rock musclé et breakbeat, les membres changent au fil du temps construisant une palette sonore de plus en plus large et étonnante.<br>  La formation actuelle est composée de machines à grooves, de lourdes guitares, de basses profondes, de chants chamaniques et de rythmes décompléxés.</p>  <p>Pour ce concert événement, les membres du groupe s''associent à un duo de danseuses contemporaines pour une proposition artistique pluridisciplinaire.</p>  <p>TARIFS : 8€ / 5€ (réduit) -&nbsp; BUVETTE SUR PLACE</p>  <p><a href=\"https://www.youtube.com/watch?v=EUpdhPCR7E8\">https://www.youtube.com/watch?v=EUpdhPCR7E8</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b03c4752-ea64-44e1-9490-e0ccacfb5217');
