INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE DE RÉSIDENCE "C''EST PAS MOI , C''EST MÉDÉE !"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Après uen semaine de résidence à la Maison du Parc national et de la vallée, Annoïe et Stéphanie dévoileront une étape de création de leur spectacle.<br>  Une création originale, naviguant entre le récit symbolique, la chanson, l’expression du corps.<br>  L’univers déployé dans « C’est pas moi, c’est Médée » évoque ces figures mythiques, à la fois inquiétantes et<br>  universelles, ces « déesses crues, habitées par l’héroïsme d’aimer comme on vit plus que vivre ».</p>  <p><a href=\"https://www.maisondelavallee.org/cest-pas-moi-cest-medee\">https://www.maisondelavallee.org/cest-pas-moi-cest-medee</a></p>  <p></p>  <p>Tarif unique : 4€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b92e0813-11bd-4f5d-bc67-177a8ee8192d');
