INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('LE RADEAU / ANNULÉ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong><span style=\"color:#e74c3c;\">Par mesure de précaution, le spectacle est reporté à une date ultérieure. Nous ne manquerons par de vous tenir informés et vous remercions de votre compréhension.</span></strong></p>  <p>Pièce de théâtre écrite par Gloria Carreno :</p>  <p><em>Hélène se réveille, en tailleur bon chic bon genre, prête pour une journée au bureau. Sauf qu’elle se découvre à la dérive sur un radeau en plein océan.</em></p>  <p><em>Sans bagage mais avec un sac à main dans lequel elle découvre avec effroi un pistolet auquel il manquerait une balle, elle cherche à expliquer l’inexplicable.</em></p>  <p><em>Se joignent&nbsp;à elle un premier naufragé de passage, puis un autre.</em></p>  <p><em>La question qui les préoccupe devient vite à qui appartient le radeau, et qui a le droit de commander.</em></p>  <p><em>A quoi chacun est-il prêt à renoncer pour assurer sa survie&nbsp;? Où est la frontière entre l’illusion de l’un et la réalité nerveuse de l’autre&nbsp;? Les personnages, glauques ou glorieux, se défient à coups de verve ou de virulence. Ils se battent et débattent dans les chemins chaotiques de la raison et décochent les dards aigus des vrais désespérés.</em></p>  <p></p>  <p><strong>Mise en scène : </strong>Benjamin Haegel</p>  <p><strong>Distribution :</strong> Fanny Honoré, Mirabelle Maquet, Dominique Prunier</p>  <p><strong>Co-Production Cie Mosaïque / L''Equipe de Réalisation</strong></p>  <p></p>  <p>TARIFS : 8€ / 5€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f1e72404-82a0-41a4-b51a-80eedf02c5e2');
