INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('TERRITOIRE ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>TERRITOIRE - 2017</strong></p>  <p><strong>Acrylique sur panneaux gravés par Marie Démias-Koch.</strong></p>  <p><em>Qu''il soit petit ou vaste, peuplé ou désertique, ouvert sur la mer ou encré dans les terres, libre ou occupé, chaque territoire se détermine par une limite, une barrière, une enceinte, une frontière ... cette limite que l''Homme a déterminé, imposé, quelquefois avec absurdité ou inhumanité.</em></p>  <p></p>  <p>Née en 1958 à Chartres (28), y vit jusqu’à l‘âge de 11 ans.<br>  Adolescence à St Jean de Luz (64).<br>  1975 : rentre après concours au lycée pilote d’arts plastiques de Sèvres (92)<br>  1979 : école d’Arts Appliqués Olivier de Serre<br>  1979 : école Nationale Supérieure des Beaux Arts de Paris<br>  1981 : maquettiste dans une agence de publicité à Paris puis directrice artistique dans divers agences en packaging, éditions, promotion et communication publicitaire, à Paris, Biarritz, Bordeaux, Paris et Pau.<br>  2013 : illustratrice designer 3D, freelance, installée dans le Béarn et plasticienne.<br>  2017 : rejoins le collectif \"Les GraveuZes\" à Jurançon.<br>  2018 : première Fête de L''Estampe à Pau à l''initiative du collectif Les GraveuZes.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd6985a50-87ad-4c1a-a7b8-0bbcf81797dd');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('TERRITOIRE ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>TERRITOIRE - 2017</strong></p>  <p><strong>Acrylique sur panneaux gravés par Marie Démias-Koch.</strong></p>  <p><em>Qu''il soit petit ou vaste, peuplé ou désertique, ouvert sur la mer ou encré dans les terres, libre ou occupé, chaque territoire se détermine par une limite, une barrière, une enceinte, une frontière ... cette limite que l''Homme a déterminé, imposé, quelquefois avec absurdité ou inhumanité.</em></p>  <p></p>  <p>Née en 1958 à Chartres (28), y vit jusqu’à l‘âge de 11 ans.<br>  Adolescence à St Jean de Luz (64).<br>  1975 : rentre après concours au lycée pilote d’arts plastiques de Sèvres (92)<br>  1979 : école d’Arts Appliqués Olivier de Serre<br>  1979 : école Nationale Supérieure des Beaux Arts de Paris<br>  1981 : maquettiste dans une agence de publicité à Paris puis directrice artistique dans divers agences en packaging, éditions, promotion et communication publicitaire, à Paris, Biarritz, Bordeaux, Paris et Pau.<br>  2013 : illustratrice designer 3D, freelance, installée dans le Béarn et plasticienne.<br>  2017 : rejoins le collectif \"Les GraveuZes\" à Jurançon.<br>  2018 : première Fête de L''Estampe à Pau à l''initiative du collectif Les GraveuZes.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'd6985a50-87ad-4c1a-a7b8-0bbcf81797dd');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('TERRITOIRE ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>TERRITOIRE - 2017</strong></p>  <p><strong>Acrylique sur panneaux gravés par Marie Démias-Koch.</strong></p>  <p><em>Qu''il soit petit ou vaste, peuplé ou désertique, ouvert sur la mer ou encré dans les terres, libre ou occupé, chaque territoire se détermine par une limite, une barrière, une enceinte, une frontière ... cette limite que l''Homme a déterminé, imposé, quelquefois avec absurdité ou inhumanité.</em></p>  <p></p>  <p>Née en 1958 à Chartres (28), y vit jusqu’à l‘âge de 11 ans.<br>  Adolescence à St Jean de Luz (64).<br>  1975 : rentre après concours au lycée pilote d’arts plastiques de Sèvres (92)<br>  1979 : école d’Arts Appliqués Olivier de Serre<br>  1979 : école Nationale Supérieure des Beaux Arts de Paris<br>  1981 : maquettiste dans une agence de publicité à Paris puis directrice artistique dans divers agences en packaging, éditions, promotion et communication publicitaire, à Paris, Biarritz, Bordeaux, Paris et Pau.<br>  2013 : illustratrice designer 3D, freelance, installée dans le Béarn et plasticienne.<br>  2017 : rejoins le collectif \"Les GraveuZes\" à Jurançon.<br>  2018 : première Fête de L''Estampe à Pau à l''initiative du collectif Les GraveuZes.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'd6985a50-87ad-4c1a-a7b8-0bbcf81797dd');
INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('c70d0a1f-02cb-40bc-8d2e-d990cb698419', 'evenement', true, false, false, NULL, '2020-03-27T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2020-03-27T23:00:00.000Z', '2020-03-27T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE DE RÉSIDENCE "MONT" SUSPENDUE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong><span style=\"color:#e74c3c;\">Par mesure de précaution, le spectacle est reporté à une date ultérieure. Nous ne manquerons par de vous tenir informés et vous remercions de votre compréhension.</span></strong></p>  <p></p>  <p></p>  <p>Cirque - Danse par le Cirque Jafarson</p>  <p><em>\"C’est l’histoire de quelques uns qui cachent sous leurs costumes le fait qu’ils ne sont pas humains.</em></p>  <p><em>Nous avons deux cents milliards de neurones dans notre cerveau, et il y a deux cents milliards d’étoiles dans notre galaxie. Il est aussi facile de se projeter dans l’espace que dans les rêves. C’est pourquoi ici, les allers-retours entre l’espace et le centre du monde sont rapides, et le temps et l’espace s’inversent souvent. Donc il arrive de ne plus savoir si on se trouve dans les airs, ou sous terre. Parfois on est juste sur Terre, celle qu’on connait. Pendant ce cours répit, on prend une grande bouffée d’air, avant d’être propulsé à nouveau très haut ou très bas.</em></p>  <p><em>Ici, les expressions humaines sont devenues réelles. Il n’est pas rare de perdre les eaux, de sortir de son cocon, d’avoir quelque chose derrière la tête.</em></p>  <p><em>On voit ces deux soeurs, issues d’une vielle famille qui a passé longtemps sous la poussière. Elles essaient de trouver leurs points communs, leurs jeux, la façon dont elles se touchent. La joue oui, la bouche non. Elles cherchent l’échappatoire, se tiennent par la main et se fuient par leurs pieds. Il y a aussi celle qui a été recrachée par la mer. Une pieuvre blanche l’aurait déposée la. La grand mère détourne le regard. Forcément, c’est plus compliqué pour elle de s’adapter. Les yeux dans le vide, elle tente de reconnaitre.\"</em></p>  <p style=\"margin-bottom: 0cm\"></p>  <p><font size=\"2\">Le spectacle « Mont », c’est une grande équipe composée de quatre danseurs, deux artistes de cirque, deux architectes et scénographes, et un musicien sous la direction artistique de Rachel Cazenave.</font></p>  <p><font size=\"2\">Le travail de la compagnie à pour but d’oublier les frontières entre les différentes formes d’art pour présenter une oeuvre complète et immersive.</font></p>  <p><font size=\"2\">En résidence pour la seconde fois à la Maison du Parc national et de la vallée, cette sortie de résidence sera l’occasion de confronter à votre regard et à votre sensibilité l’univers sur lequel les artistes orientent leur travail. </font></p>  <p><font size=\"2\">Il s’agira pour eux d''offrir une porte d’entrée sur un monde en création, proche de la magie des histoires d’enfance.</font></p>  <p></p>  <p><strong>Distribution :</strong></p>  <p>Mellina Boubetra: danseuse</p>  <p>Charly Bouges: danseur, acrobate</p>  <p>Rachel Cazenave: danseuse, acrobate</p>  <p>Livia Jouan: mât chinois</p>  <p>Julien Ladenburger: jongleur, acrobate</p>  <p>Elsa Morineaux: danseuse</p>  <p>Fanny Padovani: mât chinois</p>  <p></p>  <p><strong>TARIF UNIQUE SORTIE DE RÉSIDENCE : 4€</strong></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c70d0a1f-02cb-40bc-8d2e-d990cb698419');
