INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le pass Culture en Occitanie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Ce projet gouvernemental vise à renforcer et diversifier les pratiques culturelles des jeunes Français, et à apporter à l’ensemble des acteurs culturels du territoire un nouveau canal de communication.</p>  <p>L’année de ses 18 ans, jusqu''à la veille de ses 19 ans, chaque jeune résidant en France pourra demander l’octroi d’une enveloppe de 500€ à dépenser pendant 24 mois sur le pass, parmi un large choix de spectacles, visites, cours, livres, musique, services numériques…</p>  <div class=\"row\">  <div class=\"col\">   <h2>Une politique publique en cours d’expérimentation</h2>  </div> </div>  <div class=\"row\">  <div class=\"col-md-7\">   <p>Le pass&nbsp;Culture est construit par et pour les utilisateurs et doit être en mesure de s’adapter à l’ensemble des réalités territoriales.</p>    <p>Pour répondre au mieux aux problématiques spécifiques à chaque territoire, le pass&nbsp;Culture est mis en oeuvre par phases, qui doivent prouver la pertinence de l’outil et permettre de l’adapter à l’ensemble des réalités.</p>    <p>Depuis le 1er février 2019, 12&nbsp;000 bénéficiaires de 18 ans et près de 1&nbsp;000 acteurs culturels testent l’application dans cinq départements et aident quotidiennement les équipes à améliorer le produit&nbsp;.</p>    <p>A compter de juin 2019, le dispositif s''étend à l''ensemble des jeunes volontaires de 18 ans dans les premiers territoires et dans neuf nouveaux départements d''expérimentation, soit près de 150&nbsp;000 jeunes !</p>    <p>Inscriptions sur le site <a href=\"https://pass.culture.fr/\">https://pass.culture.fr/</a></p>  </div>   <p></p>   <p></p>   <p></p> </div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ac4dff85-e03b-4bf5-9d64-fb2aeba203c9');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le pass Culture en Occitanie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Ce projet gouvernemental vise à renforcer et diversifier les pratiques culturelles des jeunes Français, et à apporter à l’ensemble des acteurs culturels du territoire un nouveau canal de communication.</p>  <p>L’année de ses 18 ans, jusqu''à la veille de ses 19 ans, chaque jeune résidant en France pourra demander l’octroi d’une enveloppe de 500€ à dépenser pendant 24 mois sur le pass, parmi un large choix de spectacles, visites, cours, livres, musique, services numériques…</p>  <div class=\"row\">  <div class=\"col\">   <h2>Une politique publique en cours d’expérimentation</h2>  </div> </div>  <div class=\"row\">  <div class=\"col-md-7\">   <p>Le pass&nbsp;Culture est construit par et pour les utilisateurs et doit être en mesure de s’adapter à l’ensemble des réalités territoriales.</p>    <p>Pour répondre au mieux aux problématiques spécifiques à chaque territoire, le pass&nbsp;Culture est mis en oeuvre par phases, qui doivent prouver la pertinence de l’outil et permettre de l’adapter à l’ensemble des réalités.</p>    <p>Depuis le 1er février 2019, 12&nbsp;000 bénéficiaires de 18 ans et près de 1&nbsp;000 acteurs culturels testent l’application dans cinq départements et aident quotidiennement les équipes à améliorer le produit&nbsp;.</p>    <p>A compter de juin 2019, le dispositif s''étend à l''ensemble des jeunes volontaires de 18 ans dans les premiers territoires et dans neuf nouveaux départements d''expérimentation, soit près de 150&nbsp;000 jeunes !</p>    <p>Inscriptions sur le site <a href=\"https://pass.culture.fr/\">https://pass.culture.fr/</a></p>  </div>   <p></p>   <p></p>   <p></p> </div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'ac4dff85-e03b-4bf5-9d64-fb2aeba203c9');
