INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('INTRO (Sous réserve)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Spectacle de danse par la Cie Etra programmé dans le cadre des mercredis artistiques.</strong></p>  <p>Au plateau un trio féminin s’engage timidement dans une conversation. Sans aucun mots, le corps comme seul interface de lecture de l’autre. Supporté par musique électronique rythmée en constante évolution, le dialogue se façonne, se découd devient plus intense, les résonances plus claires. A mesure que les identités se révèlent et s’ancrent dans cet échange, le regard posé sur soi change. L’introspection émerge simultanément à la volonté de reprendre possession de cette intériorité qui s’impose aux autres, loin des automatismes de réaction. Durée : 30 min</p>  <p>Teaser vidéo <a href=\"https://vimeo.com/401607698\">\"Intro\"</a></p>  <p><strong>Distribution : </strong></p>  <p>Chorégraphe : Mellina Boubetra<br>  Interprètes : Mellina Boubetra, Katia Lharaig, Allison Faye</p>  <p>Création &amp; régie lumière : Fabrice Sarcy<br>  Création musicale : Patrick De Oliveira</p>  <p></p>  <p>Production déléguée Cie Art-Track</p>  <p>Coproduction Prix HIP HOP GAMES 2018, Le FLOW – Ville de Lille, Initiatives d’Artistes en Danses Urbaines / La Villette, CCN de Créteil et du Val-de-Marne / Compagnie Kä g – direction Mourad Merzouki dans le cadre de l’Accueil Studio, CCN de Roubaix / Sylvain Groud, CCN de la Rochelle / Kader Attou, Pole Pik / Bron, Summer Dance / Hollande, Cie Victor B / Belgique.</p>  <p>Avec le soutien de l’ADAMI</p>  <p>Résidences La Briqueterie / Centre de développement chorégraphique national du Val-de-Marne, Théâtre Louis Aragon / Tremblay-en-France, La Fabrique de danse, Collectif ZOOOM / Clermont Ferrand, Le Cendre / Salle les Justes Puy de Dôme, La Manufacture / Incubateur chorégraphique Vendetta Mathea, Compagnie Dyptik, Trans’urbaines / Clermont Ferrand, MJC TC de Colombes</p>  <p>Prix et distinctions Lauréat PRIX HIP HOP GAMES 2018, Spectacle lauréat du Concours chorégraphique 2019 Prix CCN de Créteil / Festival Kalypso, Lauréat Trans’urbaines 2018, Label Passerelles 2019</p>  <p></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'bceaee5c-d0ec-4783-b2f2-2b2d37822fac');
