INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('STARSKY MINUTE ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Spectacle de cirque par la Cie La Dépliante programmé dans le cadre des mercredis artistiques.</strong></p>  <p>Starsky est un clown acrobate électrique à la fois fier et pudique, noble et prolétaire. Il travaille chez Starsky Minute, une entreprise de livraison de colis. Sa mission&nbsp;? Vous livrer un colis.</p>  <p>​Malheureusement, l’efficacité… c’est pas trop son truc. Bienvenu dans un monde où la bêtise est reine et dans lequel Starsky devient peu à peu le héros des histoires absurdes qu’il raconte. Une épopée moderne comme on les aime.</p>  <p>Durée : 50 mins / Tout public à partir de 10 ans</p>  <p></p>  <p>Distribution :</p>  <p>De et Avec : Antoine Nicaud</p>  <p>Regards extérieurs : Emmanuel Gil, Marek Kastelnick, Louis Marie Audubert, Vincent Gomez, Alain Gautré.</p>  <p>Production, diffusion et administration : L''Envoleur</p>  <p>Soutiens :</p>  <p>La Cascade, Pôle National des Arts du Cirque, Bourg St Andéo, SPEDIDAM</p>  <p></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '998a9a55-383c-4535-bc93-420856513dd8');
