INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('LA COPULE (Sous réserve)', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Performance Voix /Musique élèctroacoustique par la Cie des Limbes programmée dans le cadre des mercredis artistiques.</p>  <p></p>  <p>Mathieu Guillin&nbsp;et&nbsp;Loïc Varanguien de Villepin&nbsp;évoluent en duo dans&nbsp;des compositions électroacoustiques&nbsp;ou s''agrègent&nbsp;la voix&nbsp;et ses ersatz.</p>  <p>On serait bien en mal de ranger cette performance sonore dans la catégorie « musique » ou « poésie sonore », tellement La Copule fait jouer les sons, tout comme son nom même fait jouer les sens, et échappe aux genres.&nbsp;Des sons étranges, primitifs, sauvages, monstrueux parfois, érotiques aussi.<br>  Sur le plateau : sampleur, synthétiseur, tambour, main de poupée, appeau à cerf, canette de Pepsi, pour l’un, Matthieu Guillin; micro et voix de contre ténor pour l’autre, Loïc Varanguien de Villepin, voix qui se fait aussi borborygmes, brames, sifflements, hululements, craillements, crissements, et autres barrissements...<br>  Un plateau chargé aussi d’une présence scénique puissante et troublante qui donne corps à cette glossolalie d’un temps et d’un espace autre et qui fait résonner les propos du compositeur italien Fausto Romitelli :<br>  &nbsp;</p>  <p>Composition : Matthieu Guillin</p>  <p>Voix : Loïc Varanguien de Villepin</p>  <p>Production : Cie des Limbes, Théâtre le vent des signes, avec le soutien du studio Éole et par le Département de la Gironde et la Région Nouvelle-Aquitaine.</p>  <p></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '11069227-1e28-4811-a45a-1680622d3b26');
