INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('6847dcf7-5dd7-4ee1-89c6-3ea93546cd8e', 'exposition', true, false, NULL, '2020-06-11T22:00:00.000Z', '2020-06-29T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2020-06-11T22:00:00.000Z', '2020-06-11T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MONTAGNES DU MONDE ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Photographies de sommets ou de massifs montagneux du monde entier,&nbsp;situés dans des Parcs nationaux ou inscrits au Patrimoine mondial de&nbsp;l''Unesco.<br> Quelques&nbsp;photos des Alpes et des Pyrénées&nbsp;françaises et espagnoles côtoient les massifs prestigieux de&nbsp;l''Himalaya, des Montagnes Rocheuses d''Amérique du&nbsp;Nord, des sommets&nbsp;de la Cordillière des Andes et de Nouvelle Zélande.<br> Ces&nbsp;montagnes, par leur notoriété, leur beauté ou l''histoire parfois&nbsp;dramatique de leur conquête sont toutes désormais inscrites au&nbsp;patrimoine de l''Histoire de l''alpinisme.<br> <br> L''AUTEUR&nbsp;:&nbsp;Jean-Paul&nbsp;Azam<br> <em>Quand&nbsp;on naît dans le Tarn, dès que vous savez marcher, on ne vous met&nbsp;pas des skis aux pieds mais un ballon ovale entre les mains ! Ce&nbsp;n''est donc qu''à&nbsp;vingt&nbsp;deux&nbsp;ans, lors d''une première&nbsp;randonnée au pic Méchant (!) en vallée&nbsp;d''Aure, que j''ai découvert les Pyrénées ; elles ne m''ont plus&nbsp;lâché.&nbsp;Après&nbsp;une carrière de photographe dans l''édition touristique, aujourd''hui&nbsp;«retiré des voitures», je continue d''assumer mes&nbsp;deux&nbsp;passions, la montagne et la photographie qui m''attirent vers les&nbsp;grands massifs montagneux de la planète. Mais c''est vers les&nbsp;Pyrénées - les plus belles - que je reviens sans cesse !&nbsp;</em> <div><em>Membre de&nbsp;l''agence&nbsp;photos Hemis, je continue de les parcourir et je viens de&nbsp;les&nbsp;traverser par le&nbsp;GR10.<br>  Je&nbsp;m''intéresse désormais à leur histoire ; après avoir publié en&nbsp;2017&nbsp;le livre&nbsp;«&nbsp;Les stations thermales des Pyrénées à la Belle Epoque »&nbsp;(Ed.&nbsp;Cairn), je prépare actuellement un livre associant&nbsp;photos et textes&nbsp;d''écrivains sur les Pyrénées,&nbsp;vagabondage&nbsp;<wbr>littéraire du&nbsp;Pays&nbsp;Basque&nbsp;à la Côte Vermeille.</em></div>  <div></div>  <div><em>Exposition programmée par la Parc national des Pyrénées. </em></div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6847dcf7-5dd7-4ee1-89c6-3ea93546cd8e');
