('1336b0e5-fa3c-4674-b534-8b1bcbf10798', 'exposition', true, false, NULL, '2020-07-05T22:00:00.000Z', '2020-07-30T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2020-07-05T22:00:00.000Z', '2020-07-05T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les vallées des Gaves au clair de Lune - Pierre Vincent', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La Lune, si éclatante à la nuit tombée vient lisser les reliefs, vient illuminer le paysage. Elle vient aussi atténuer la vision des étoiles dans le ciel. C’est donc un véritable challenge que Pierre Vincent, photographe Lourdais a relevé en capturant<br>  les Vallées des Gaves au clair de Lune. Créant une ambiance nocturne très particulière, la Lune, par son éclat nous donne parfois l’impression, dans cette exposition, de jouer le rôle du Soleil. Troublantes sont les photos que l’on pourrait imaginer être prise de jour… alors que l’on distingue des étoiles dans le Ciel… Découvrez les Vallées des Gaves aux couleurs de la Lune…</p>  <p><em>Exposition proposée par l''association Nightscapade.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1336b0e5-fa3c-4674-b534-8b1bcbf10798');
