INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('D''EUX - 2  / REPORTÉ À LA MAISON DU PARC NATIONAL ET DE LA VALLÉE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle musical par le Collectif Décomposé&nbsp; programmé dans le cadre des mercredis artistiques et de la fête des fleurs de Saint Sauveur.</p>  <p>De Fauré à Sabine Paturel, en passant par Satie, Poulenc ou bien encore Piaf et Bourvil, D''eux-2 vous propose un voyage musical onirique et intimiste à travers la chanson française populaire ou classique. Entre moments improvisés et re-créations, sur de la musique en continu, laissez-vous surprendre par l''univers de D''Eux-2.</p>  <p>Chant: Simon Ferrari<br>  Piano: Vianney Oudart</p>  <p><span style=\"color:#e74c3c;\"><strong>EN RAISON DES CONDITIONS MÉTÉO ANNONCÉES, LE CONCERT AURA LIEU DANS LA SALLE DES VOÛTES DE LA MAISON DU PARC NATIONAL ET DE LA VALLÉE.</strong></span></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '83348fda-b3cf-45d7-81ca-1adab4b87715');
