INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('ATELIERS DE STONE BALANCE AVEC MANU TOPIC', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><em>Amoureux de la nature, Emmanuel Fourcarde, alias <strong>Manu Topic</strong>, découvre le stone balancing grâce à celui qui a popularisé cet art aux Etats-Unis, Michael Grab. </em></p>  <p><em>Cette discipline consiste à créer des structures de pierres en jouant sur les points de pressions, la gravité et le contrepoids pour un résultat final à la fois spectaculaire et esthétique. </em></p>  <p><em>Manu en donne sa définition&nbsp;: «&nbsp;Le stone balancing est un art, un hobby, une façon de méditer, un art de vivre. C’est tout ça à la fois !&nbsp;»</em></p>  <p><em>Pour exercer le stone balancing, Manu joue sur son terrain de jeu favori, dans les Hautes-Pyrénées, à Esparros, au pied des montagnes. Il passe un nombre incalculable d’heures dans les rivières, en quête de nouveaux spots&nbsp;les plus insolites les uns que les autres : «&nbsp;J’ai le besoin vital d’être au contact de la faune et de la flore. Je peux partager un bel instant avec la nature… sans laisser de traces.&nbsp;»</em></p>  <p><em>En effet, ses œuvres ne résistent pas à l’épreuve du&nbsp;temps. Quelques heures suffisent pour que Mère Nature&nbsp;reprenne le dessus.</em></p>  <p></p>  <p>Manu sera présent pour animer des ateliers dans la parc thermal de Luz, à partir de 14h30 pour les enfants puis 16h30 pour les adultes, à l''occasion de la fête des fleurs de Saint Sauveur.</p>  <p>Renseignements et inscriptions à l''accueil de la&nbsp; Maison du Parc national et de la vallée ou par téléphone au 05 62 92 38 38.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1d979704-2fc7-4c3e-9b96-419dbc915eee');
