INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('AUTREMENT QU''AINSI', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Solo de danse contemporaine par Yann Lheureux programmé dans le cadre des mercredis artistiques.</p>  <p></p>  <p>Un repli dans la ville, un recoin, une impasse. Un lieu qui n’offre pour perspective que soi ou l’autre. Une quasi impossibilité d’ échapper l’arbitraire de la situation. Cet espace urbain fera écho à sa boite cranienne.</p>  <p><em>J’oscille entre désir de fuite et nécessité d’ être contenu. Une surface partagée.</em></p>  <p></p>  <p><strong>Une maman qui chante...</strong></p>  <p>Elle qui était un cordon bleu a raccroché son tablier. Elle qui cousait bien volontiers et adorait faire des con tures d’orange ne touche plus ni aiguille, ni chaudron. Elle qui nourrissait parfois ce chat errant, passe maintenant ses soirées et parfois ses nuits à le chercher dehors pour qu’il rentre se coucher auprès d’elle.</p>  <p>Croyant peut-être le tenir, elle s’invente un présent, maintenant que le passé lui échappe. Mais déjà ce présent se dérobe lui aussi et à mesure que s’évanouissent présent et futur: il inquiète... Que reste-t-il ? Lorsque le maintenant n’existe plus très bien ? Que reste-t-il quand le socle de l’identité disparaît? Que restera-t-il d’elle - ma maman - lorsqu’elle aura oublié jusqu’à mon nom ?</p>  <p>Longtemps, j’ai pensé qu’oublier était un atout : celui des mots, des gestes, des autres, des situations. Aujourd’hui que c’est un peu de ma mémoire qui s’en va avec celle de ma mère, diagnostiquée Alzheimer en 2011, je loue cette faculté de se souvenir, car elle dit qui l’on est, en rapport à soi, en rapport aux autres et au Monde.</p>  <p>Je ne peux pas non plus pourtant, la plaindre totalement quand elle semble parfois si profondément heureuse d’avoir à vivre en l’instant : elle chantonne en souriant les premières phrases de cet air chanté par Line Renaud Ma cabane au Canada.</p>  <p></p>  <p>PORT DU MASQUE OBLIGATOIRE</p>  <p><strong>... un homme, son fils, qui danse.</strong></p>  <p>Danseur, chorégraphe, j’ai depuis toujours été fasciné par les questions de l’identité et du territoire : elles sont le coeur même de mon travail. Aujourd’hui, me voici face à cette pathologie, qui prend de plus en plus de place entre ma mère et moi. Elle n’a plus de passé sur les talons hormis de lointaines et entêtantes bribes. Le seul avenir qu’elle peut concevoir se compte en heures. Ma Mère est entrée dans une maison dont elle ne ressortira pas.</p>  <p>Alors je m’interroge quand je pressens que malgré tous les manques et amoindrissements que génère cette maladie, elle occasionne des disparitions qui sont également des sources d’apparition...</p>  <p></p>  <p>Pour Autrement qu’ainsi &nbsp;Yann Lheureux convie les spectateurs au plus proche du sujet. Une immersion au cœur de la cité, une immédiateté précieuse, nécessaire et déroutante.</p>  <p>En tant qu’artiste, que créateur, que fils, citoyen, Yann Lheureux apprivoise ce drame de la maladie par l’expression qui lui est propre : l’art chorégraphique.</p>  <p>Outre cet abord personnel lié à son expérience propre dont il tente d’appréhender les enjeux, Yann Lheureux et son équipe sont allés à la rencontre des différentes personnalités, qui travaillent au cœur même de cette maladie et des problématiques qu’elle engendre : chercheurs en neurosciences, gériatres, psychologues, acteurs associatifs, soignés, soignants…</p>  <p>C’est sur la base de ces échanges, de résidences en EHPAD et de ces rencontres, que s’étayent les axes de son travail. Différentes étapes de recherche et de laboratoire ont déjà donné lieu à la création du dispositif chorégraphique Les Eblouis, et à un solo en salle Ici soit-il.</p>  <p></p>  <p>Distribution :</p>  <p>Conception chorégraphique et interprétation : Yann Lheureux</p>  <p>Création sonore : Arnaud Bertrand</p>  <p></p>  <p><strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE</strong></p>  <div class=\"page\" title=\"Page 2\">  <div class=\"layoutArea\">   <div class=\"column\"></div>  </div> </div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '30675742-4602-433e-946e-8328d04be9a7');
