INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('« HISTOIRES D''EAUX AU PAYS TOY » - Maggy Vincent Brandicourt', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dès qu''elle s''y est installée en 1983, Maggy Vincent-B est tombée sous le charme du Pays Toy. Elle aime le partager dans la presse ou à travers ses photos.<br>  «&nbsp;Les photos, je les laisse venir à moi. Les paysages ici sont magiques, pleins de surprises. Le jeu est de saisir leurs lumières fugaces.&nbsp;»<br>  Des cinq éléments, l''eau est le plus changeant. «&nbsp;Elle est insaisissable comme la vapeur d''un nuage, douce comme la plume d''un flocon de neige, dure comme la glace, effrayante comme un torrent en colère, caressante comme la vaguelette d''un lac, apaisante comme une cascade, elle est la VIE. Sans elle et la lumière, les arcs-en-ciel, symboles d''espoir, n''existeraient pas.&nbsp;»</p>  <p><em>Exposition programmée par la Parc national des Pyrénées.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8ff72021-a860-4591-9839-06e8fad0a5ed');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('« HISTOIRES D''EAUX AU PAYS TOY » - Maggy Vincent Brandicourt', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dès qu''elle s''y est installée en 1983, Maggy Vincent-B est tombée sous le charme du Pays Toy. Elle aime le partager dans la presse ou à travers ses photos.<br>  «&nbsp;Les photos, je les laisse venir à moi. Les paysages ici sont magiques, pleins de surprises. Le jeu est de saisir leurs lumières fugaces.&nbsp;»<br>  Des cinq éléments, l''eau est le plus changeant. «&nbsp;Elle est insaisissable comme la vapeur d''un nuage, douce comme la plume d''un flocon de neige, dure comme la glace, effrayante comme un torrent en colère, caressante comme la vaguelette d''un lac, apaisante comme une cascade, elle est la VIE. Sans elle et la lumière, les arcs-en-ciel, symboles d''espoir, n''existeraient pas.&nbsp;»</p>  <p><em>Exposition programmée par la Parc national des Pyrénées.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '8ff72021-a860-4591-9839-06e8fad0a5ed');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('« HISTOIRES D''EAUX AU PAYS TOY » - Maggy Vincent Brandicourt', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dès qu''elle s''y est installée en 1983, Maggy Vincent-B est tombée sous le charme du Pays Toy. Elle aime le partager dans la presse ou à travers ses photos.<br>  «&nbsp;Les photos, je les laisse venir à moi. Les paysages ici sont magiques, pleins de surprises. Le jeu est de saisir leurs lumières fugaces.&nbsp;»<br>  Des cinq éléments, l''eau est le plus changeant. «&nbsp;Elle est insaisissable comme la vapeur d''un nuage, douce comme la plume d''un flocon de neige, dure comme la glace, effrayante comme un torrent en colère, caressante comme la vaguelette d''un lac, apaisante comme une cascade, elle est la VIE. Sans elle et la lumière, les arcs-en-ciel, symboles d''espoir, n''existeraient pas.&nbsp;»</p>  <p><em>Exposition programmée par la Parc national des Pyrénées.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '8ff72021-a860-4591-9839-06e8fad0a5ed');
