INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les oiseaux de Guyane - Tanguy Deville', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Cette exposition est basée sur le livre de Tanguy Deville «&nbsp;Les oiseaux de Guyane&nbsp;», publié en mai 2018 aux éditions Biotope. Le travail de photographie et de rédaction s’est étalé sur une quinzaine d’année et la plupart des images ont été prises en canopée, dans de nombreux sites de Guyane. À travers vingt photographies, l’exposition présente le travail réalisé et quelques grands thèmes de l’écologie des oiseaux tropicaux&nbsp;: la forêt guyanaise, son sous-bois et sa canopée, la grimpe d’arbres, la diversité des oiseaux de Guyane, les oiseaux migrateurs guyanais, les relations entre les oiseaux et les plantes (la pollinisation des fleurs et la dispersion des graines), la couleur des fleurs, les couleurs et les motifs du plumage des oiseaux, le chant des oiseaux, les leks, la nidification des oiseaux, la protection des espaces naturels et la protection des espèces.</p>  <p><em>Exposition programmée par la Parc national des Pyrénées.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'fa65fc9c-288f-4d20-bcba-ce879a61c9fe');
