INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Surgissement(s) / Sortie de résidence', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Texte en chantier de Eric Durand<br>  Lecture / Musique par le Collectif Décomposé<br>  Interprétation de Eric Durand – Musique de Vianney Oudart</p>  <p><em>Enfant il y a un rêve… Enfant, il y a un cauchemar…<br>  Adulte il y a un rêve… Adulte, il y a un cauchemar…<br>  Un texte qui trouve sa source d’inspiration, tard, la nuit, lorsque les enfants dorment et que les adultes se lèvent… Un texte qui trouve son inspiration, tard, la nuit, lorsque les enfants n’arrivent pas à trouver le sommeil…</em><br>  Après quatre jours de résidence, Eric Durand, auteur dramatique et metteur en scène présente ici son dernier travail d’écriture entre réalités du monde et onirisme… Un texte incisif qui trouve son inspiration dans nos rêves et nos cauchemars… Un texte qui propose de faire se rencontrer l’adulte que nous sommes et l’enfant que nous étions…<br>  Mise en musique en direct par Vianney Oudart, compositeur et musicien.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5107df33-9f75-4a88-86b3-9bb7d737b7a8');
