INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie accompagnée "Écoute et découverte des oiseaux"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Randonnée dans la vallée d’Ossoue pour observer et écouter les oiseaux avec un garde-moniteur.</p>  <p>Renseignements au 05 62 92 42 48.</p>  <p>Rendez-vous à l''Office de Tourisme de Gèdre.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '46767fff-175b-4945-b358-fa2d658d8f89');
