INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie accompagnée "Incursion au monde des plantes pyrénéennes"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Nadine Sauter, chargé de conservation, propose de guider une balade botanique qui empruntera un petit sentier menant au belvédère de Tési en vue d''y découvrir quelques raretés végétales. Au coeur d''un milieu naturel riche en biodiversité, qu''il s''agisse de flore ou de faune, cette randonnée commentée sera l''occasion d''observer des plantes typiques des pelouses rocailleuses ou bien l''emblématique ramonde des Pyrénées, inattendue ici compte tenu des conditions chaudes et sèches du milieu.</p>  <p>Aller-Retour : +/- 3 heures</p>  <p>Difficulté : moyenne</p>  <p>Inscription obligatoire, sortie gratuite organisée par le Conservatoire Botanique national des Pyrénées et de midi-Pyrénées.</p>  <p>Renseignements : 05 62 92 42 48.</p>  <p>Rendez-vous : Maison du Parc national à Gavarnie pour covoiturage.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0c39ef21-24e2-4ddb-b722-6083574bfdec');
