INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence sur la géologie en hommage à Jean Knobel', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Hommage à Jean Knobel, personnage reconnu dans le milieu de la géologie, cette rencontre sera l''occasion pour son ami et collègue Claude Gaudin d''évoquer, en son souvenir, son travail en Afrique entre 1959 et 1966 « Des oasis sahariennes au masif du Hoggar ». 140 diapositives commentées à travers le désert.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ec6d7e21-7497-4b30-874a-9bca6d124eab');
