INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Gomera', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Duo de danse par Noé Chapsal et Chey Jurado programmé dans le cadre des mercredis artistiques.<br> <br> Des notes dans un carnet, un vieux bateau, une île, deux individus, pleins de questions... Cette pièce est née en décembre 2018 sur la petite île de La Gomera, dans les îles Canaries. L’intention première était simplement de créer quelque chose entre Chey et Noé avec l’oeil extérieur de Patti. Cette rencontre honnête et bienveillante fut ce qui inspira Chey et Noé pour transformer ce voyage à La Gomera en une oeuvre dansée.<br> <br> <strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE.</strong>","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'fdc81ef2-75ee-4185-858c-58a41b80cbf1');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Gomera', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Duo de danse par Noé Chapsal et Chey Jurado programmé dans le cadre des mercredis artistiques.<br> <br> Des notes dans un carnet, un vieux bateau, une île, deux individus, pleins de questions... Cette pièce est née en décembre 2018 sur la petite île de La Gomera, dans les îles Canaries. L’intention première était simplement de créer quelque chose entre Chey et Noé avec l’oeil extérieur de Patti. Cette rencontre honnête et bienveillante fut ce qui inspira Chey et Noé pour transformer ce voyage à La Gomera en une oeuvre dansée.<br> <br> <strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE.</strong>","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'fdc81ef2-75ee-4185-858c-58a41b80cbf1');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Gomera', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Duo de danse par Noé Chapsal et Chey Jurado programmé dans le cadre des mercredis artistiques.<br> <br> Des notes dans un carnet, un vieux bateau, une île, deux individus, pleins de questions... Cette pièce est née en décembre 2018 sur la petite île de La Gomera, dans les îles Canaries. L’intention première était simplement de créer quelque chose entre Chey et Noé avec l’oeil extérieur de Patti. Cette rencontre honnête et bienveillante fut ce qui inspira Chey et Noé pour transformer ce voyage à La Gomera en une oeuvre dansée.<br> <br> <strong>EN RAISON DU COVID-19 LE PORT DU MASQUE EST OBLIGATOIRE.</strong>","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'fdc81ef2-75ee-4185-858c-58a41b80cbf1');
