INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Concert "El Communero" ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong><em>En partenariat avec La Gespe - Scène de musiques actuelles Tarbes. </em></strong></p>  <p>Les chanteurs et musiciens de L’Air de rien, Les Hurlements d''Léo, Anakronic Electro Orkestra, Elektric Geïsha font revivre, en hommage au combat antifranquiste, les chants de lutte de la République Espagnole. Le groupe (ré) interprète, dans les sonorités, les tempos, les rythmes actuels, le répertoire républicain espagnol. Ces chansons de lutte sont le plus souvent calquées sur d''anciennes mélodies populaires, du XIXe et du début du XXe siècle.</p>  <p><em>\"Il y a dans El Comunero une part de magie de pierre philosophale, cette capacité à changer la mémoire en or nous la rend si vivante qu''il nous semble qu''au gré d''une chanson nous tenons dans nos bras la belle république, la beauté des justes, la force des utopies.\" Pierre Domenges<br>  \"Enraciné dans la verve anti-franquiste des chants républicains de la guerre d''Espagne, le groupe toulousain ouvre son répertoire rebelle aux hymnes protestataires mexicains et aux chants de lutte sud-américains : un son frondeur et rageur à la Mano Negra, avec guitare flamenca, bouzouki et clarinette punk.\" Anne Berthod, Telerama.fr</em></p>  <p><a href=\"http://elcomunero.fr/\"><strong><span>Site internet El Comunero</span></strong></a></p>  <p><a href=\"https://www.lagespe.com/p23-concert-c410-el-comunero.html\">Tarifs et réservations</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '11a928c5-3392-48b0-921a-b3a47fb85183');
