INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Patient', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Solo en équilibre et en mouvement / Compagnie Jusqu''ici tout va bien à partir de 8 ans.</p>  <p>PATIENT c’est un carré de néons, un artiste, du bruit et de la lumière.<br>  Un solo de cirque contemporain, mêlant équilibres sur les mains, acrobatie et mouvement.<br>  Imaginé pour tous types de lieux de représentations dédiés ou non au spectacle, PATIENT crée son propre espace, sa propre géométrie, autour duquel se place le public, en quadrifrontal.<br>  <br>  PATIENT se place sur le temps d’un basculement, d’un vertige.<br>  C’est un corps qui se soulève, un esprit qui prend la fuite : une libération jubilatoire où l’on rit de nos propres angoisses.<br>  Sur le plateau, c’est aussi des crissements, des glissades et du rock’n’roll.<br>  PATIENT c’est l’histoire de quelqu’un qui n’attendra plus rien.<br>  <br>  La rencontre constitue l’un des points essentiels du projet PATIENT et s’inscrit au cœur de la démarche de la compagnie. Au-delà des salles et pistes dédiées au spectacle, c’est aussi au sein des établissements de santé et de formation que le projet prend sens. Des actions de médiation peuvent être mises en place : Rencontres, discussions bord de plateau, ateliers de pratique... Les possibilités sont multiples et à imaginer ensemble.</p>  <p></p>  <p><strong>Distribution</strong><br>  A l’écriture et au plateau : Adrien TAFFANEL<br>  Regard complice : Bernadette GRUSON<br>  Regard chorégraphique : Maud PAYEN<br>  Univers sonore : David PAYCHA<br>  Conception technique : Arnaud et Adrien TAFFANEL<br>  Aide à la scénographie : Fabiana MANTOVANELLI<br>  Production, diffusion, médiation : Elodie MICHALSKI</p>  <p><strong>Co-producteurs &amp; partenaires</strong><br>  Centre Régional des Arts du cirque -Lille-Lomme /Dispositif «pépinière»<br>  CHRU - Lille<br>  DRAC et ARS Hauts-de-France / Programme Culture – Santé<br>  Agréé par le Département du Nord au titre de l’aide à la diffusion.</p>  <p></p>  <p>Spectacle programmé dans le cadre des escales d''automne (Hautes-Pyrénées - Département).</p>  <p>Nombre de places limitées.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ce46834d-ee9d-4f46-abd3-19339f8e6134');
