INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Graine - Sortie de résidence', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle créé par la Compagnie de la Tong et la Compagnie Electrons Libres destiné à la petite enfance et aux classes de maternelles.</p>  <p><em>Comment naît une graine ?<br>  Pourquoi il faut de la terre, de l''eau, du soleil ?<br>  Et pourquoi il y a des abeilles et des papillons ?<br>  Et la pluie, elle fait quoi ?<br>  Et les fleurs ?</em><br>  Ce spectacle poétique et ludique a pour intention de remettre le vivant au cœur des priorités, notamment auprès des tout-petits. Deux interprètes posent leur regard naïf sur les vers de terre, l''humus, les racines, les éléments... Elles plongent leurs mains dans la terre, la malaxent, la respirent, saisissent et goûtent des herbes, caressent des feuilles, écoutent les insectes et admirent les pétales des fleurs multicolores... Sollicitant les cinq sens, elles partagent cette aventure sensorielle avec les enfants. La danse et le son en direct s''associent au jeu des interprètes. L''idée d''un tapis d''éveil sensoriel sera le support d''exploration.Le principe de ce simple décor sur lequel les artistes évolueront est d''intégrer des matériaux aux textures, couleurs, sonorités ou odeurs nuancés. La superposition des couches de tissus et variantes permet un jeu de « coucou-caché », de manipulation et de modelage de matériaux . Les deux personnages transforment ainsi les matières en objets vivants au service de l''histoire racontée.</p>  <p><br>  <strong>Interprètes : </strong>Maya Paquereau et Sophie Barros<br>  <strong>Mise en scène : </strong>Nathalie Lhoste Clos<br>  <strong>Décor et costumes : </strong>Caroline Laroche</p>  <p></p>  <p>Tarif : 4€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '29f846dd-e0da-4cce-b341-972d7ba6d95a');
