INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mont - Sortie de résidence', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>MONT, c’est le premier spectacle de Rachel Cazenave. C’est une grande équipe composée de cinq danseurs, deux artistes de cirque, deux architectes-scénographes, une costumière et un musicien. Chacun de ces savoirs faire participent à l’élaboration d’une oeuvre complète et immersive, ou la pluridisciplinarité n’est pas un but, mais un moyen de rattraper la magie des histoires d’enfance.</p>  <p>Victor Kastel, originaire de Pau, est un musicien autodidacte et producteur qui fabrique ses propres synthétiseurs. Passionné d’art, son univers oscille entre bricolage électronique et performances d’arts sonores, créant un mélange entre différents styles musicaux et la personnalité de ses instruments.</p>  <p>Rachel Cazenave a grandi dans les montagnes Pyrénéennes. Enfant, entre deux potions concoctées dans le jardin de ses parents, elle court entre les classes de danse, de théâtre et de musique. A ses 18 ans, elle part vivre à Bordeaux, ou après quelques années de formation dans la danse, elle s’oriente vers le cirque pour émouvoir sa mère, amatrice de lampion et de roulottes. Fascinée par les univers complexes, elle cherche le sien: un monde autour d’une petit maison, ou le temps et l’espace s’inversent souvent, accompagné de son oiseau-garde-du-corps.</p>  <p>Pour cette sortie de résidence, Victor Kastel et Rachel Cazenave proposeront une performance reprenant les recherches corporelles et sonores qu’ils développent dans le projet MONT. Ils construisent une proposition évolutive ou le son et le corps s’influencent l’un et l’autre.</p>  <p>Crédit photo: Virginie Terroitin</p>  <p>Tarif : 4€</p>  <p><br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1748b3db-6b47-4fc3-886c-0250be185e09');
