INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('O.L.G.A - sortie de résidence', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Le projet est la rencontre de deux êtres :&nbsp;</p>  <p>&nbsp;Cali Hays :</p>  <p>Née le 27 août 1987, 48 kg. Nom latin&nbsp;: Calinus Haysnus. Flexivore. 1m43 au garrot. Batarde à la peau blanche et au pelage un peu roux. Non LOF. Non pucée. Vaccinée.</p>  <p>Olga :</p>  <p>(Olgouch pour les intimes)Née le 23 mai 2018, 9,2 Kg, 40cm au garrot, batarde noire et feu issue de l’accouplement réussi* entre un Jack Russel «&nbsp;à pattes hautes&nbsp;» et une Pincher.&nbsp;</p>  <p>Elle adore&nbsp;: la discipline. Développe de grosses capacités de comédienne, sa recherche est basée sur un travail clownesque et use souvent du comique de répétition. Elle rêve de renifler le monde avec sa maitresse, de vivre d’amour et de croute fraîches.</p>  <p></p>  <p>En résidence de création du 28 septembre au 02 octobre, Cali et Olga vous dévoileront une étape de travail du projet.</p>  <p>Tarif : 4€</p>  <p><br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '28e7316e-82cb-4862-96e5-a61f20a642c7');
