INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Hamlet speak to me', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Clown – Théâtre Cie Les improsteurs</p>  <p>Contemporaines d’Hamlet et de son histoire, Mouch, Adèle et Moâ font partie du petit personnel du Château d’Elseneur. Elles vivent au quotidien le drame avec leur sensibilité de femmes, leurs conditions et leurs expériences personnelles : elles racontent Hamlet, celui dont elles sont si proches depuis toujours.</p>  <p><em>Programmé dans le cadre des rendez-vous en famille (programme Leader).</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'fc198569-90ea-4c89-8d99-462cc1f843f0');
