INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('C''est pas moi c''est Médée', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>C’est pas moi c’est Médée ! » est un spectacle de poésie mouvementée et musique expérimentale. Une création originale, naviguant entre le récit symbolique, la chanson, l’expression du corps. Une atmosphère profonde, sensuelle et intempes ve, d’où émergent des accents archaïques.</p>  <p>Anne Roy est chanteuse et musicienne. Sa voix insolite peut aller partout. Elle transporte dans des ambiances à la fois profondes et aériennes, du bruitisme au chant lyrique, aux connotations parfois tribales. Elle manœuvre l’univers sonore de ce spectacle en utilisant avec justesse percussions, cordes frottées, pédales d’effets.</p>  <p>Stéphanie Barbé est poète et performeuse. Son écriture et sa présence corporelle traversent les codes. Contemporaine, certes. Intuitive, charnelle, elle n’hésite pas à bouleverser les mots et le sens commun. Il s’en dégage une parole libre, habitée, et un langage brut, poussés au corps. Une écriture-danse en quelque sorte, rythmée et sensuelle.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2c47d57d-698b-4d3b-95b5-ee737971411e');
