INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Petits points de vie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre - Cie Les Jolies Choses</p>  <p>Florilège de trois pièces courtes : la rencontre magique et musicale entre un enfant trop bavard et le fils adoptif d''une amie de sa maman, qui n''ouvre jamais la bouche; deux frères prêts à tout pour décrocher une étoile à leur mamie afin que sa mémoire ne s’efface pas; une petite fille partie à la recherche de son sourire, qu''elle a perdu entre la maison de son papa et celle de sa maman. Une invitation à la découverte de l''autre et du monde, en poésie et en récit, en dialogue et en rêve.</p>  <div class=\"a3s aiL \" id=\":3b3\">  <div class=\"adM\"><strong>Distribution :</strong> Maryline Petioch, Laurie Montamat, Sophie Barros, Mélia Bannerman</div>   <div>   <p>Régie Lumière : Bastien Sallaberry</p>    <p>Musique : Laurent Rochelle (pour l''histoire \" Eloïs et Léon \")</p>    <p>Mise en scène : collective</p>  </div> </div>  <p></p>  <p><em>Programmé dans le cadre des rendez-vous en famille (programme Leader).</em></p>  <p><br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'f9bbc172-bc61-422f-93a1-c5d4289abeda');
INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('db68d67c-3099-4c52-bdcb-60e5e052f0f8', 'exposition', true, false, NULL, '2020-09-30T22:00:00.000Z', '2020-12-04T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2020-09-30T22:00:00.000Z', '2020-09-30T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Photographies picturales par Raphaël Paya', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>J’ai toujours recherché dans l’art une autre vision du monde. Une vision plus profonde mais aussi plus belle, plus sensible. Mes photographies sont une quête de cet « autre réel ».</p>  <p>&nbsp;Dans le temps suspendu, dans les détails inaperçus, elles sont une invitation à changer de regard et à saisir l’insaisissable. Tirées sur papier d’art, leur beauté « picturale » s’exprime pleinement.</p>  <p><a href=\"http://www.photographiespicturales.com/\">http://www.photographiespicturales.com/</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'db68d67c-3099-4c52-bdcb-60e5e052f0f8');
