INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Opa - Cie Vasistdas SORTIE DE RÉSIDENCE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<div class=\"page\" title=\"Page 1\">  <div class=\"layoutArea\">   <div class=\"column\">    <p><strong>Un spectacle et un film de mémoire</strong></p>   </div>  </div> </div>  <p>Une femme, allemande, revient sur son passé familial, empli des mutismes honteux des actes criminels de son grand-père nazi, ... Par hasard, en France, elle croise une des victimes de son Opa, Jean, revenu du plus terrible des camps et lui aussi, pour d’autres raisons dans un silence douloureux... Son regard de femme, lucide et compassionnel éclaire un nouveau chemin, partagé entre son sentiment de culpabilité et sa responsabilité de transmission.</p>  <p>« Contrairement à l''idée souvent énoncée aujourd''hui que nous avons épuisé le sujet, j''ai l''impression qu''avec la montée de l''extrême-droite partout en Europe, il est grand temps de regarder d''où nous venons.» Ilka Vierkant, comédienne.</p>  <p>Une femme en conflit avec le passé de son grand-père allemand enquête sur celui-ci pour mieux accepter ce e lia on. ElIe est partagée entre son sentiment de culpabilité et sa responsabilité dans la transmission.</p>  <p>D''après Boris Cyrulnik, le silence traumatise et le \"trop parler\" aussi. Alors que faut-il faire ? Des conférences? Des expositions ? Des spectacles, pour mettre en lumière sans recréer le trauma ?</p>  <p>C''est ce qu''ont décidé de faire sur scène la comédienne-marionnetiste et la musicienne, jouant sur l''espace sonore en direct avec une installation électro-acoustique. Ensemble, elles posent un nouveau regard sur l''Histoire et leurs histoires pour tenter de construire un avenir plus éclairé, pour mieux l’affronter.</p>  <p></p>  <p><strong>En résidence du 11 au 16 janvier 2021.</strong></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a00c51d8-cd43-469e-bcde-e925079f646a');
