INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('O.L.G.A - sortie de résidence', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>O.L.G.A (titre provisoire) est une pièce circassienne en cours d''écriture. C''est avec une sensibilité clownesque que Cali (équilibriste clowne) et Olga (chienne de cirque) vous invite à parler de domination, d''animalité, de désobéissance et de féminisme avec humour et sensibilité... Knackis et acrobaties sont au rendez-vous. Ce duo de chiennes cherche à réveiller les êtres sauvages qui se cachent en nous !</p>  <p>En résidence du 18 au 21 janvier 2021.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7e287e57-3c5f-4683-9e81-bbd4ba3facd2');
