INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('FESTIVAL RADIOPHONIQUE JAZZ À LUZ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"C’est contre vents et confinements quele festival Jazz à Luzorganisé (habituellement en été) par l''association Jazz Pyr''s’invitera cet hiver dans les \"foyers\"<strong> les mardi 29, mercredi 30 et jeudi 31 décembre 2020</strong> avec son premier festival radiophonique sur les ondes de sa radio locale associative <strong>Fréquence Luz</strong> (et plus si affinités!). Un évènement inédit à découvrir en direct et à l’oreille ! <p></p>  <p>Au programme de ces 3 jours de 11h00 à minuit : des concerts live, des interviews, des bords de scène, des discussions et débats, et des conférences sur la musique.</p>  <p>Un festival à la radio comme si on y était (mais sans public ) et en attendant de se retrouver pour de vrai... à écouter sur Fréquence Luz :</p>  <p>99.6 à Luz</p>  <p>103.4 à Lourdes et Tarbes</p>  <p>104.2 à Argelès-Gazost</p>  <p>104.9 à Cauterets</p>  <p>et www.frequenceluz.com partout sur la planète !</p>  <p></p>  <p></p>  <p><strong>PROGRAMME</strong></p>  <p></p>  <p><strong>Mardi 29 décembre 2020</strong></p>  <p>12h00 / 13h00 - Emission en direct \"Vue d''ici\"</p>  <p>Pour commencer cette première plongée dans l''aventure du festival radiophonique, l''association Jazz Pyr'' invitera au micro de Fréquence Luz, Arnaud &amp; Jean-Marie Larrieu (réalisateurs et scénaristes), habitués du festival Jazz à Luz. Ils reviendront sur le dernier tournage et la préparation de leur comédie musicale \"Tralala\" qui sortira en 2021 (coproduit par Arte).</p>  <p>18h00 / 19h30 - Emission en direct \"Inauguration du festival radiophonique\"</p>  <p>Tout en respectant les mesures sanitaires de rigueur, plusieurs invités de l''association Jazz Pyr'', partenaires et artistes se retrouveront chacun leur tour derrière le micro pour lancer \"les festivités sans public\"... Une occasion aussi de s''expliquer sur l''importance de \"dire\" et de \"faire\" via le média radio.</p>  <p>20h30 - Concert live : BY THE SKET</p>  <p>Alima Hamel : voix<br>  Vincent Ferrand : contrebasse</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>22h30 - Concert live : CELLE QUI HABITAIT LA MAISON AVANT MOI</p>  <p>Lecture et mise en musique des textes de Rasha Omran, poète syrienne<br>  Flore Audebeau : voix<br>  Nanda Muhammad : voix off en arabe<br>  David Chiesa : contrebasse</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p></p>  <p><strong>Mercredi 30 décembre 2020</strong></p>  <p>11h00 / 12h00 - Emission en direct \"Quand des artistes se rencontrent\"<br>  Le trompettiste Timothée Quost prend les commandes de la radio et invite le contrebassiste David Chiesa pour palabrer, improviser et jouer...<br>  <br>  15h00 / 16h00 - Emission en direct \"Passions et discussions\"<br>  Les conférences d''Alexandre Pierrepont.</p>  <p>Anthropologue, ethnologue, chercheur, poète et conteur, il viendra nous présenter son dernier ouvrage : \"Chaos, Cosmos et musique\".</p>  <p>18h00 - Concert live : TARZAN &amp; TARZAN<br>  Sarah Brault : voix<br>  Marion Jo : violon</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>20h30 - Concert live : SINGE DE L''ENCRE \"Steve Lacy Songbook\"<br>  Catherine Jauniaux : chant, voix, objets<br>  Betty Hovette : claviers<br>  Benoît Burello : basse, chant<br>  Marc Démereau : saxophones baryton et alto, scie musicale, chant<br>  Fabien Duscombs : batterie</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>22h30 - Concert live : TIMOTHEE QUOST SEUL<br>  Timothée Quost : trompette, microphone, mixer, speaker</p>  <p>Suivi d''une discussion avec les artistes et les invités présents.</p>  <p></p>  <p><strong>Jeudi 31 décembre 2020</strong></p>  <p>11h00 / 12h00 - Emission en direct \"Quand des artistes se rencontrent\"<br>  Timothée Quost reprend les commandes de la radio et invite le duo Tarzan &amp; Tarzan composé de Sarah Brault et Marion Jo pour palabrer, improviser et jouer...<br>  <br>  15h00 / 16h00 - Emission en direct \"Passions et discussions\"<br>  Les conférences d''Alexandre Pierrepont.</p>  <p>Anthropologue, ethnologue, chercheur, poète et conteur, avec son invité mystère, il nous concocte des discussions et réflexions autour de la musique et de l''actualité.</p>  <p>18h00 - Concert live : OURS<br>  Romain Baudoin : vielle à roue électrique<br>  Adrien Chennebault : batterie, bestiole<br>  Florian Satche : percussions, boîtes à bourdons</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>20h30 - Concert live : PISCINE OLYMPIQUE<br>  Xavier Camarasa : Fender Rhodes, effets<br>  Laurent Paris : batterie</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>22h30 - Concert live : LA MARMAILLE<br>  Anaïs Andret-Cartini : voix, trompette<br>  Carla Gaudré : saxophone baryton<br>  Nathanaël Renoux : tuba<br>  Loris Pertoldi : batterie<br>  Kevin Balzan : voix, basse électrique<br>  Frédéric Monnier : saxophones</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '601ab247-bcd2-4238-bc8e-05fb297d3c37');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('FESTIVAL RADIOPHONIQUE JAZZ À LUZ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"C’est contre vents et confinements quele festival Jazz à Luzorganisé (habituellement en été) par l''association Jazz Pyr''s’invitera cet hiver dans les \"foyers\"<strong> les mardi 29, mercredi 30 et jeudi 31 décembre 2020</strong> avec son premier festival radiophonique sur les ondes de sa radio locale associative <strong>Fréquence Luz</strong> (et plus si affinités!). Un évènement inédit à découvrir en direct et à l’oreille ! <p></p>  <p>Au programme de ces 3 jours de 11h00 à minuit : des concerts live, des interviews, des bords de scène, des discussions et débats, et des conférences sur la musique.</p>  <p>Un festival à la radio comme si on y était (mais sans public ) et en attendant de se retrouver pour de vrai... à écouter sur Fréquence Luz :</p>  <p>99.6 à Luz</p>  <p>103.4 à Lourdes et Tarbes</p>  <p>104.2 à Argelès-Gazost</p>  <p>104.9 à Cauterets</p>  <p>et www.frequenceluz.com partout sur la planète !</p>  <p></p>  <p></p>  <p><strong>PROGRAMME</strong></p>  <p></p>  <p><strong>Mardi 29 décembre 2020</strong></p>  <p>12h00 / 13h00 - Emission en direct \"Vue d''ici\"</p>  <p>Pour commencer cette première plongée dans l''aventure du festival radiophonique, l''association Jazz Pyr'' invitera au micro de Fréquence Luz, Arnaud &amp; Jean-Marie Larrieu (réalisateurs et scénaristes), habitués du festival Jazz à Luz. Ils reviendront sur le dernier tournage et la préparation de leur comédie musicale \"Tralala\" qui sortira en 2021 (coproduit par Arte).</p>  <p>18h00 / 19h30 - Emission en direct \"Inauguration du festival radiophonique\"</p>  <p>Tout en respectant les mesures sanitaires de rigueur, plusieurs invités de l''association Jazz Pyr'', partenaires et artistes se retrouveront chacun leur tour derrière le micro pour lancer \"les festivités sans public\"... Une occasion aussi de s''expliquer sur l''importance de \"dire\" et de \"faire\" via le média radio.</p>  <p>20h30 - Concert live : BY THE SKET</p>  <p>Alima Hamel : voix<br>  Vincent Ferrand : contrebasse</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>22h30 - Concert live : CELLE QUI HABITAIT LA MAISON AVANT MOI</p>  <p>Lecture et mise en musique des textes de Rasha Omran, poète syrienne<br>  Flore Audebeau : voix<br>  Nanda Muhammad : voix off en arabe<br>  David Chiesa : contrebasse</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p></p>  <p><strong>Mercredi 30 décembre 2020</strong></p>  <p>11h00 / 12h00 - Emission en direct \"Quand des artistes se rencontrent\"<br>  Le trompettiste Timothée Quost prend les commandes de la radio et invite le contrebassiste David Chiesa pour palabrer, improviser et jouer...<br>  <br>  15h00 / 16h00 - Emission en direct \"Passions et discussions\"<br>  Les conférences d''Alexandre Pierrepont.</p>  <p>Anthropologue, ethnologue, chercheur, poète et conteur, il viendra nous présenter son dernier ouvrage : \"Chaos, Cosmos et musique\".</p>  <p>18h00 - Concert live : TARZAN &amp; TARZAN<br>  Sarah Brault : voix<br>  Marion Jo : violon</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>20h30 - Concert live : SINGE DE L''ENCRE \"Steve Lacy Songbook\"<br>  Catherine Jauniaux : chant, voix, objets<br>  Betty Hovette : claviers<br>  Benoît Burello : basse, chant<br>  Marc Démereau : saxophones baryton et alto, scie musicale, chant<br>  Fabien Duscombs : batterie</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>22h30 - Concert live : TIMOTHEE QUOST SEUL<br>  Timothée Quost : trompette, microphone, mixer, speaker</p>  <p>Suivi d''une discussion avec les artistes et les invités présents.</p>  <p></p>  <p><strong>Jeudi 31 décembre 2020</strong></p>  <p>11h00 / 12h00 - Emission en direct \"Quand des artistes se rencontrent\"<br>  Timothée Quost reprend les commandes de la radio et invite le duo Tarzan &amp; Tarzan composé de Sarah Brault et Marion Jo pour palabrer, improviser et jouer...<br>  <br>  15h00 / 16h00 - Emission en direct \"Passions et discussions\"<br>  Les conférences d''Alexandre Pierrepont.</p>  <p>Anthropologue, ethnologue, chercheur, poète et conteur, avec son invité mystère, il nous concocte des discussions et réflexions autour de la musique et de l''actualité.</p>  <p>18h00 - Concert live : OURS<br>  Romain Baudoin : vielle à roue électrique<br>  Adrien Chennebault : batterie, bestiole<br>  Florian Satche : percussions, boîtes à bourdons</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>20h30 - Concert live : PISCINE OLYMPIQUE<br>  Xavier Camarasa : Fender Rhodes, effets<br>  Laurent Paris : batterie</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p>22h30 - Concert live : LA MARMAILLE<br>  Anaïs Andret-Cartini : voix, trompette<br>  Carla Gaudré : saxophone baryton<br>  Nathanaël Renoux : tuba<br>  Loris Pertoldi : batterie<br>  Kevin Balzan : voix, basse électrique<br>  Frédéric Monnier : saxophones</p>  <p>Suivi d''une discussion avec des artistes et invités présents.</p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '601ab247-bcd2-4238-bc8e-05fb297d3c37');
