INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('fd6e4ad0-7739-484e-b206-86c389e70be6', 'evenement', true, false, false, NULL, '2021-06-02T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2021-06-02T22:00:00.000Z', '2021-06-02T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Bateau ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Poésie gestuelle, théâtre d''objets, cirque sensible.</strong></p>  <p>C''est un bout d''enfant qui est resté coincé dans un adulte et qui s''est accroché à une douce rage de vivre. L''adulte oublie souvent l''enfant qu''il était, l''enfant qui est en lui. Que reste-t-il de cet enfant ? Du jeu ? Du simple ? Des monstres sous le lit ? De la nostalgie et des rêves ?.. L''émerveillement. Tout cela est enfoui dans une malle en bois, sous le sable d''une plage abandonnée d''une mer polluée. Cette mer accueille notre voyage simple et direct dans notre imaginaire, dans nos émotions et nos sens, nos corps sont l''eau qui la compose. Sur cette plage abandonnée, subsistent l''enfance, le jeu, la joie, la solitude et la mort. L''imaginaire né du manque... sa nécessité.</p>  <p>La compagnie :</p>  <p>Les Hommes Sensibles est une compagnie de cirque qui mélange acrobatie, danse, théâtre, musique, culture urbaine et magie (au sens large... très large). Ses artistes ont comme points communs leurs sensibilités. Bien que différentes, elles se rejoignent et ensemble deviennent force au service du spectacle vivant.<br>  Représentant ainsi l''évolution contemporaine de la virilité, où l''homme est en crise identitaire, devenant simplement un homme de sens, poétique, un Homme Sensible. L''Homme Sensible n''est ni masculiniste ni féministe, il n''est pas révolutionnaire mais, est ce qu''il est un homme nouveau, avec toute sa bêtise et toute sa beauté.<br>  A l''initiative des Hommes Sensibles se trouvent les failles et les doutes de ses artistes interprètes, leur confiance, leur auto-dérision, mais surtout leur désir. Désireux de déplacer les esprits, de partager des émotions et de la simplicité, rire à n''en plus finir (si possible). Faire une pause dans une vie bien agitée. Accepter sa sensibilité et se sentir vivant autant pour les femmes, les hommes, les personnes transsexuelles, les enfants, les animaux, les personnes âgées, les super héros etc.</p>  <p><em>Programmé dans la cadre des rendez-vous en famille (programme Leader).</em></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\"><em>Tarif spectacle</em></a></p>  <p>Crédit photo : <span class=\"d2edcug0 hpfvmrgz qv66sw1b c1et5uql oi732d6d ik7dh3pa ht8s03o8 a8c37x1j keod5gw0 nxhoafnm aigsh9s9 d3f4x2em fe6kdd0r mau55g9w c8b282yb iv3no6db jq4qci2q a3bd9o3v knj5qynh oo9gr5id\" dir=\"auto\">@gabymerz</span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'fd6e4ad0-7739-484e-b206-86c389e70be6');
