INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Contes entre deux eaux', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Conte par Florant Mercadier</p>  <p>Une invitation à descendre le cours de la Garonne, de la montagne à l’océan, pour une traversée de l’Occitanie où se croisent des princesses espagnoles qui n’aiment pas les fruits, des lutins malicieux qui voudraient bien apprendre à voler, des notes de musiques …</p>  <p></p>  <p>À partir de 9 ans.</p>  <p><em>Programmation \"Contes en hiver\" en partenariat avec la ligne de l''enseignement.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ce752956-8b1b-479b-9ae8-4d4674f81b46');
