INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Jan des merveilles', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Conte par Gigi Bigot.</p>  <p>En Bretagne, dans le pays de la conteuse Gigi Bigot, ceux qu’on appelle Jan des Merveilles, ce sont les conteurs.<br>  Ils racontent des histoires incroyables, on y croit pourtant, même après quand les mots flottent encore entre les rêves et la peau.<br>  En amour, dans le pays du tout au tout, pas besoin de conteurs, on invente des merveilles, surtout quand il n’y a pas d’histoires. Des fois, c’est la seule façon de ne pas mourir.<br>  Entre amour et folie, entre la vie et la mort, entre une fille et son père, le récit de Jan des Merveilles est là pour faire battre le cœur, parce que comme le dit Jan : quand on ne sent pas son cœur battre, ni dans la tristesse, ni dans la joie, on n’est pas tout à fait vivant.</p>  <p>À partir de 10 ans.</p>  <p><em>Programmation \"Contes en hiver\" en partenariat avec la ligne de l''enseignement.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '63d70790-77d3-4f64-9550-5ec8f6e112aa');
