INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Chamad', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Le Quartet Chamad prépare son deuxième album. De nouvelles compositions entre jazz, funk et balades viennent compléter Sillage 1. Formé en Occitanie en 2012 autour de compositions instrumentales originales teintées de mélodies populaires et de rythmiques magistrales, Chamad lance une tournée à la rencontre de nouveaux publics.</p>  <p>Les musiciens de Chamad viennent du classique, du contemporain, du rock, de la chanson, et du groove. Ils ont pratiqué le studio, l''improvisation, l''enseignement, et les scènes au plus haut niveau : conservatoires, orchestres nationaux, groupes d''envergure internationale. Après plus de 20 ans de cheminement intense et varié, voici réunis quatre amis et partenaires pour le plus beau de leurs projets professionnels et musicaux.</p>  <p>Le quartet a expérimenté l’ambiance intimiste de scènes jazz (club ou festival), comme celle de salles rock plus importantes. Le public est unanime, des plus jeunes qui trouvent leurs pas dans les accords rythmés, jusqu''aux plus expérimentés, connaisseurs des scènes jazz actuelles : CHAMAD vous emmène irrémédiablement dans ses voyages intimes et pourtant universels.</p>  <p>Après Jazz in Marciac, Le Bikini, la SMAC Victoire II, Andorra Sax Fest, Pastel en scène ou la cité de l’Espace, les quatre musiciens se retrouvent pour une semaine de résidence à Luz Saint Sauveur et proposerons un concert pour clôturer cette période de création.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7fbdc7d2-77fe-48ee-88ca-3ad467ec81cd');
