INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le diner de cons', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"color:#e74c3c;\">ATTENTION</span></p>  <p><span style=\"color:#e74c3c;\">Réservation sur place et paiement préalable à compter du lundi 10 mai 2021.</span></p>  <p></p>  <p>Si par hasard Pierre Brochant, le grand éditeur parisien, vous invite à dîner, méfiez-vous. Si ce dîner est un mercredi soir, déclinez l’invitation. Pierre et ses amis ont une spécialité, Le Dîner de cons. Un dîner qui a lieu une fois par semaine et dont le principe est tout simple : Chaque invité doit amener un con qu’on écoutera parler de sa passion. Celui qui a amené le plus spectaculaire est déclaré vainqueur. Ce soir Pierre est ravi. Il a mis la main sur un champion du monde, François Pignon. Pierre s’apprête à passer un grand moment. Il ne se doute pas de ce qui l’attend. Il va vite découvrir qu’avec François les soirées sont toujours imprévisibles.</p>  <p></p>  <p>Notes de mises en scène :</p>  <p>Quel gros challenge de reprendre Le Diner de Cons au théâtre… car le spectateur n’a déjà pas la surprise du texte et des situations cocasses. Tout repose donc sur le reste : une mise en scène efficace et une interprétation des rôles qui ne doit rien à voir avec les différentes versions de la pièce. Les 7 comédiens embarquent le spectateur dans un tourbillon de rires mais aussi de tendresse car ce \"con\" par la vertu de sa naïveté à la plus belle des qualités celle de relier les êtres en acceptant d''être le bouffon de tous. et n''est-ce pas là l''essence même de notre art Le théâtre.</p>  <p></p>  <p>Distibution :</p>  <p>YVES HUET / PATRICK LODE / ANNA MAZZOTTI / JEAN PHILIPPE ALVAREZ / CAROLE GANTHEIL / ERIC FEVRIER.</p>  <p></p>  <p><em>Programmé dans la cadre des rendez-vous en famille (programme Leader)</em></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarif spectacle</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0105c452-112d-436e-98ef-c8c05f728c81');
