INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Shakespeare / Triptyque', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Entresorts bouffons pour la cour ou le jardin : Hamlet - Macbeth - Roméo et Juliette par l''Attraction</strong>. <em>Création 2021.</em></p>  <p></p>  <p><em>Au fin fond d’un jardin sauvage, d’une cour reculée ou de n’importe quel espace un peu inattendu et isolé , le public découvre un minuscule théâtre abandonné sur lequel la nature a repris le dessus. Dans une attente « beckettienne », Prosper et Mira, comédiens autrefois ambulants, aujourd’hui immobiles, y végètent dans une expectative indéterminée. Surpris par l’improbable mais réelle présence de spectateurs, ils s’essaient à jouer une fois de plus et improvisent du Shakespeare avec les moyens dont ils disposent. Autour du même cérémonial beckettien de début et de fin d’entresort, en quelques minutes, à l’aide d’accessoires de théâtre ou de quelques objets usuels ils évoquent Roméo et Juliette dans une rivière de larmes, jouent Macbeth dans une nuit de sang, inventent Hamlet autour d’une tasse de thé. </em></p>  <p></p>  <p>Les trois entresorts seront des mélanges de registres, des compositions d’improvisations bouffonnes et de morceaux lyriques ou dramatiques, un cocktail shakespearien de collages, de fragments choisis attendus ou oubliés, de contrastes, de tragédie et de comédie, d’amour et d’action, d’obscénités et de philosophie.</p>  <p>A l’origine, dans le monde des saltimbanques, l’entresort était une baraque foraine, un théâtre en toile ou en planche où l’on montrait des phénomènes, des monstres, et dans lequel le public entrait, regardait et sortait.<br>  Dans ce projet, la baraque foraine prend la forme d’un théâtre miniature ; leurs monstres sont deux personnages aux profils beckettiens ; le phénoménal se trouve dans la représentation de trois pièces shakespeariennes en quelques minutes...</p>  <p></p>  <p>En résidence du 05 au 10 avril 2021.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '96be9891-1dc2-4a5d-8bfd-25b243df761f');
