INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Nuits 21', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Aphélie Compagnie / Cycle Les pures coïncidences / Création 2021</p>  <p></p>  <p><em>\"Entre octobre 2018 et mars 2019, j’ai travaillé comme veilleuse de nuit auprès de huit personnes porteuses d’une Trisomie 21 et accueillies, pendant cinq mois, dans un appartement dans lequel ils ont pu expérimenter la colocation. J’ai accompagné ces jeunes adultes sur les temps du soir, de la nuit et du matin dans l’acquisition d’une autonomie plus grande. L’enjeu de ces séjours d’apprentissage est de donner à ces jeunes adultes les moyens d’envisager à terme de vivre seuls, dans leur propre appartement. Sur ces temps de nuit et de réveil, j’ai écouté et recueilli les confidences, les peurs, les coups de gueule de ces huit personnes sur lesquelles je « veillais ».</em><em> Je me suis rendu compte que, dans la plupart des récits que j’ai écouté, ces personnes évoquaient sans cesse « le dehors » et « les autres ». Les autres, ce sont ceux qui ne sont pas dans la structure. qui les regardent. Qui ne comprennent pas, qui ne font pas attention. Qui sont parfois dangereux.</em><em> Ce sont ceux qui sont hors de leurs chambres, hors de leurs vies, hors du Cadre. Ce « dehors » se faisait tour à tour, dans leurs mots, menaçant, désirable, fascinant.</em><em> L’idée serait de rassembler ces témoignages dans un objet artistique qui puisse faire écho à ces moments crépusculaires et matinaux. Il s’agirait de faire apparaître, avec la même honnêteté qu’en ces moments de confidences, la singularité des personnes rencontrées au-delà de la pathologie qui, trop souvent, suffit à leurs interlocuteurs pour les identifier.</em><em> Cet objet artistique constituera le nouvel opus de la série des Pures Coïncidences.\"</em></p>  <p></p>  <p>En résidence du 19 au 24 avril 2021.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5ef01a69-9831-4d8a-aaa6-1be2976e3916');
