INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Racynthe', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Racynthe par le cirque Jafarson.</p>  <p>Racynthe, c’est l’ensemble des liens fondateurs omniprésents dans la couche profonde de ce monde. C’est le vecteur de l’énergie cosmique, de la mémoire et du souvenir.</p>  <p>A cet endroit de la carte se trouvent deux personnages: Edwige et Leopolde.</p>  <p>Racynthe est un spin-off de MONT* autour de leur rencontre. Ensemble, ils cherchent les souvenirs perdus. Ils tentent des rituels pour les invoquer et faire re-vivre ce qui n’existe plus. Ils ouvrent des livres, des boites, des racines à la recherche d’informations sur le fonctionnement de cet endroit. Il s’agit de retracer, de faire l’inventaire, au sein de ce centre névralgique. Ils appellent la foule, invisible. Ils captent et matérialisent le moindre signe d’énergie, pour lui donner une forme, un son.</p>  <p>Ils sont arrêtés à une sorte de terminaison centrale: c’est le bord et en même temps c’est le centre. C’est à la fois en dessous, au dessus et entre. Ce sont des strates resserrées, où les corps ouvrent des espaces et se contorsionnent pour circuler. Ils bougent de façon instinctive, déployant leurs extrémités comme des antennes dans cet espace où ils sont presque aveugles.</p>  <p>Ici, il s’agit de percevoir.</p>  <p></p>  <p></p>  <p><em>* Le spectacle « Mont », c’est une grande équipe composée de quatre danseurs, deux artistes de cirque, deux architectes et scénographes, et un musicien sous la direction artistique de Rachel Cazenave. Le travail de la compagnie à pour but d’oublier les frontières entre les différentes formes d’art pour présenter une oeuvre complète et immersive...</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '24c95b28-d223-48b8-b8a0-c9a447766a83');
