INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Qui a cueilli ma crème de jour? Histoires des cueillettes dans les Pyrénées ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Conférence animée par Raphaële Garreta, chargée de mission à l''ethnologie au Conservatoire botanique national des Pyrénées et de Midi-Pyrénées.</p>  <p>Etude des phénomènes de cueillette : comment elle s''organise ? Cueillette secrète ? Volume prélevé insoupçonné : impacts sur la ressource.</p>  <p>Diaporama sur la gentiane, l''arnica, le thé d''Aubrac.</p>  <p>Durée : 1h30.</p>  <p>En partenariat avec le Parc national des Pyrénées et le conservatoire botanique national des Pyrénées et de Midi-Pyrénées.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5d3747b7-e60f-4922-acd5-30c62e8e1303');
