INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Balade découverte des plantes sauvages', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Jardinière cueilleuse dans nos vallées, Muriel vous propose de l''accompagner à la découverte, la reconnaissance et la dégustation des plantes les plus courantes. Aussi appelées \"les simples\" vous pourrez les retrouver autour de chez vous. Une balade autour de Luz Saint Sauveur au coeur de pratiques ancestrales pour renouer le lien avec votre nature.</p>  <p>Les médicinales du Bergons - Muriel Clément</p>  <p>Inscriptions à l''accueil ou au 05 62 92 38 38.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ae27d298-a12a-4d29-bbf3-8c0e060cac4c');
