INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Couleurs de plantes, plantes à couleurs / Initiation teinture végétale', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Technique d''empreinte de feuille (noir ou vert) sur tissu, travail sur le chou rouge, technique de teinture végétale...Partons à la découverte de la palette colorée que nous offrent quelques plantes communes avec Béatrice Morisson.</p>  <p>Durée de l''atelier de 2h30.</p>  <p>Inscriptions à l''accueil (05 62 92 38 38).</p>  <p>Programmé en partenariat avec le Parc national des Pyrénées, le CPIE et le CBN de Bagnères de Bigorre.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'adfcc034-2dd1-4ebe-9aa7-147ca73aea4c');
