INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Réchauffement climatique et flore pyrénéenne', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Conférence sur la flore pyrénéenne et les changements climatiques par Guy&nbsp;Dussaussois, botaniste.</p>  <p>Le chaud et le froid vont encore souffler dix mille ans sur la flore pyrénéenne, cette intervention vous fera voyager dans le temps...</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8b9cc70e-2ca1-4bd5-8b02-272700536924');
