INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Visio-conférence : Histoire de la botanique pyrénéenne', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Depuis plusieurs siècles, des botanistes parcourent les Pyrénées pour décrire et inventorier l’extraordinaire richesse de la flore. Ils ont écrit une page essentielle de l’histoire de la découverte scientifique du massif que nous tenterons de relire.</p>  <p>Viso-conférence animée par David penin disponible sur Youtube à partir de 18h30 sur le lien suivant :</p>  <p><a href=\"https://www.youtube.com/channel/UCaPIokcosoeb1QyB5Yyo9_g\">Chaîne Youtube de la Maison du Parc national et de la vallée</a></p>  <p></p>  <div>En raison d''un problème technique lié au réseau, la qualité d''image de la conférence a dû être réduite.</div>  <div>Vous pourrez profiter de cette conférence en haute définition dès demain, jeudi 22 avril 2021 à partir de 18h.</div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '183ef17f-c6c1-45b1-8246-3b1156d40a13');
