INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Visio-conférence  "Que fait le Parc national des Pyrénées en matière de flore ?"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Depuis plusieurs décennies le Parc national travaille pour une meilleure connaissance de la flore de son territoire. De récentes réflexions lui ont permis de faire évoluer le travail de terrain.</p>  <p>Viso-conférence animée par Olivier Jupille, disponible sur Youtube sur le lien suivant :</p>  <p><a href=\"https://www.youtube.com/channel/UCaPIokcosoeb1QyB5Yyo9_g\">Chaîne Youtube de la Maison du Parc national et de la vallée</a></p>  <p></p>  <div data-contents=\"true\">  <div data-block=\"true\" data-editor=\"fa98m\" data-offset-key=\"4kj8g-0-0\">   <div class=\"_1mf _1mj\" data-offset-key=\"4kj8g-0-0\"><span><span data-offset-key=\"4kj8g-0-0\"><span data-text=\"true\">Nouvelle</span></span></span><span data-offset-key=\"4kj8g-1-0\"><span data-text=\"true\"> galère technique, nous sommes désolés. Nous vous donnons rendez-vous demain jeudi 6 mai 2021 à 18h sur notre chaîne Youtube. </span></span></div>  </div>   <div data-block=\"true\" data-editor=\"fa98m\" data-offset-key=\"1pt4t-0-0\">   <div class=\"_1mf _1mj\" data-offset-key=\"1pt4t-0-0\"></div>  </div>   <div data-block=\"true\" data-editor=\"fa98m\" data-offset-key=\"9ccr8-0-0\">   <div class=\"_1mf _1mj\" data-offset-key=\"9ccr8-0-0\"><span data-offset-key=\"9ccr8-0-0\"><span data-text=\"true\">Merci de votre compréhension.</span></span></div>  </div> </div> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '235ac7ef-c2b4-4963-86cb-7bd747cf18fe');
