INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Ateliers  intinérants de gravure', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Atelier itinérant de gravure par La presse Nomade</p>  <p>Tout public</p>  <p></p>  <p><strong>17h : Réalisation d''une gravure sur linoléum.</strong></p>  <p>1 atelier de 2 heures pour 8 personnes.</p>  <p></p>  <p><strong>19h : FLEURS SAUVAGE : incrustation en gravure de fleurs sur papier.</strong></p>  <p>3 ateliers de 30 minutes pour 12 personnes (par atelier)</p> &nbsp;  <p></p>  <p>Informations et réservations à la Maison du Parc national et de la vallée (05 62 92 38 38)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ed5924b3-404d-4245-baa8-7a8d714673b5');
