INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Plantes prioritaires des Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Le Conservatoire Botanique national des Pyrénées et de Midi-Pyrénées vous propose de découvrir sa nouvelle exposition \"Plantes prioritaires des Pyrénées\".<br>  De l’Ariège au Pays basque, en passant par les Pyrénées centrales, laissez-vous guider à la découverte de la flore rare et menacée des Pyrénées centro-occidentales françaises&nbsp;!</p>  <p></p>  <p><em>Exposition proposée dans le cadre de la résidence de territoire \"Pais de flors\".</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '321bf7fb-2a7d-4dad-be17-4bf96de591a0');
