INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Tu viens ! ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Duo clownesque jonglé par la Cie \"Toi d''abord\"<br>  <br>  Il y a deux gars, un minutieux et un fougueux. Enfin… c’est comme ça que je les reconnais.<br>  L’un est tout timide et l’autre complètement lunaire. Tous les deux, ils s’adorent mais ils ne se le disent pas. S’ils se séparent, je pense qu’ils meurent.<br>  Ils ne parlent pas, mais on les comprend très bien.<br>  Leur truc à eux c’est la jongle. Ça vole et ça rebondit de tous les côtés !<br>  Les balles, les corps, les gestes et les sentiments nous mènent au coeur d’une relation forte et aussi très fragile…<br>  Je vous dis que tenir à l’autre… C’est pas rien !<br>  Durée : 60 min.<br>  Tout public, à partir de 6 ans</p>  <p></p>  <p>Auteurs et interprètes : Jérémy Olivier et Thomas Lafitte.<br>  Aide précieuse à la mise en scène : Johan Lescop<br>  Soutenu par la PACT pépinière des arts du cirque Toulouse, la Grainerie Fabrique des arts du cirque Balma, le Lido Centre des arts du cirque Toulouse et l’Ecole de cirque de Lyon.</p>  <p><em>Programmé dans le cadre des rendez-vous en famille (programme Leader) et&nbsp; des mercredis artistiques.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '270ca695-01b3-4aeb-b108-d93f4c2a04b8');
