INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Cabanes et refuges - Aquarelles par Daniel Cahuzac', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Voyage d''un amoureux inconditionnel de ces montagnes qui voit le beau partout, le déniche là où on ne l''attend pas et le révèle sur ses toiles. Loin des clichés \"carte postale\" les aquarelles de Daniel Cahuzac révèlent et illustrent l''âme de ce pays. Elles portent la marque du randonneur contemplatif. De ces journées à arpenter le pays, à pied ou à vélo, sous le soleil ou sous la pluie, dans le froid de l''hiver ou la chaleur de l''été, elles exhalent la ferveur de celui qui marche et pédale le regard haut et l''esprit ouvert, pour mieux accueillir le beau et le singulier.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '26ea10da-462d-458e-a0cb-71b54bae3801');
