INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Week-end Haïkus cinématographiques / Pais de flors / Résidence de territoire', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans le cadre de la résidence de territoire, le collectif invite la population à partager un moment cinématographique autour de la résidence les 22 et 23 mai 2021 en participant à un atelier de réalisation de très courts métrages.</p>  <p>Au cours de l’atelier, les participants pourront expérimenter de nombreuses étapes liées à la réalisation d’un film autour de la botanique : comment utiliser une caméra vidéo, un trépied, un enregistreur audio et les micros, imaginer des plans, un story-board, filmer des paysages et des détails durant une sortie naturaliste, enregistrer des sons de la nature, assurer la post-production. Entre film documentaire et expérimentation, entre immersion dans le réel et poésie, entre narration et contemplation, chacun pourra proposer une vision subjective des végétaux de ce pays, berceau du pyrénéisme.</p>  <p>Scilles, Grassettes, Androsaces, Gentianes, Primevères, le printemps est là et les sujets passionnants ne manquent pas ! Fleurs, feuillages, milieu de vie, tout est prétexte à la narration poétique. La curiosité est de mise, l’expérience est garantie, les inscriptions sont ouvertes !</p>  <p>Point de rendez-vous donné à la maison du parc national et de la vallée à 9h, retour vers 18h. Prévoir un pique-nique pour les deux jours.</p>  <p>Inscriptions et informations sur place ou au 05 62 92 38 38.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7925d085-fb1b-444b-a15d-3e51ace724fb');
