INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Regard sur le projet cinématographique "Pais de flors"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Cette exposition se veut un reflet photographique du travail accompli par le collectif KOVisuel au cours des premières étapes de la résidence de territoire science et cinéma « Pais de Flors ».</p>  <p>Durant cette période, en parallèle des actions de médiations, l’équipe artistique, riche de nombreuses rencontres botaniques et pyrénéistes, a avancé sur le tournage de son court métrage.</p>  <p>Les prises de vues, réalisées par l’équipe artistique au cours des étapes de travail, racontent comment chaque membre de cette dernière s’est emparé du projet pour l’emporter au-delà des frontières du documentaire.</p>  <p>Une fois sorti de la « zone de confort », la créativité devient essentielle, l’ouverture d’esprit est de mise et l’imagination fait le reste ! Scilles, Grassettes, Androsaces, Gentianes, Primevères, le printemps est là et les sujets passionnants ne manquent pas ! Fleurs, feuillages, milieu de vie, tout est prétexte à la narration poétique.</p>  <p><em>Pour cette résidence, la Maison du Parc et de la vallée est associée à Occitanie film et au Parc national de Pyrénées. Le projet bénéficie du soutien de la DRAC Occitanie.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '43d85728-2540-4327-bd2e-880006e47b9e');
