INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('GIC / Groupe d''intervention chorégraphique', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<div class=\"page\" title=\"Page 1\">  <div class=\"layoutArea\">   <div class=\"column\">    <p><em>Cie Rêvolution</em></p>     <p>De la douce émotion à la transe jouissive, ces impromptus aux saveurs urbaines, parfois fixes, parfois déambulatoires, habillent de paroles dansées l’espace public. Un tendre ouragan qui emporte les passants dans une nouvelle géométrie du spectacle. Une forme artistique élastique, réunissant 5 interprètes en solos, duos ou des chorégraphies d’ensemble qui questionnent le rapport de l’individu au collectif et à son espace environnant.</p>     <p>Chorégraphie : Anthony EGEA<br>     Interprètes : Antoine BOUIGES, Manuel GUILLAUD, Simon DIMOURO, Aurélien VAUDEY et Maxim TACH</p>   </div>  </div> </div>  <p>PLACE DES TEMPLIERS</p>  <p><em>Programmé en partenariat avec l''association Jazz pyr'', dans le cadre du festival \"Jazz à Luz\".</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5f322ac8-c77a-4638-b450-6170d7df28d6');
