INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('On avait dit qu''on se touchait pas !', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<em>Duo acrobatique et jeu clownesque par le Cirque Compost. </em> <p><em>Ils sont deux, ils s’adorent, ils sont un peu perdus mais ensemble ils avancent, et surtout : ils ne doivent pas se toucher. Ils sont obsédés par cette idée. S’ils se touchent, ils doivent tout recommencer. Ils sont touchants mais n’ont pas le droit de se toucher. Lorsque leurs corps s’expriment, s’opère un mélange entre adresse et tendresse. Ils se nouent, se dénouent, se jettent, se propulsent, roulent, sautent avec plaisir et douceur. Ils voyagent dans les possibles de leurs deux corps sans se toucher, ou presque... Émerge une réflexion sur le contact, entre eux, entre vous, entre nous. Qu’est-ce que toucher ? Qu’est-ce que ça fait ? Qu’est-ce qu’on en fait ?&nbsp;&nbsp;</em></p>  <p>Tout public. Durée 45mn&nbsp;&nbsp;</p>  <p></p>  <p>Le Cirque Compost</p>  <p>Simon Laporte-Daube et Samuel Maugin se rencontrent à l’École Nationale de Cirque de Châtellerault en 2012, ils décident rapidement de travailler ensemble, et continuent leur formation à l’École de Cirque d’Amiens en duo d’acrobatie jusqu’en 2017. Ils développent un langage corporel entre l’acrobatie, la danse et les portés ; et une fraternité qui est à la source de leur création. Ils se nourrissent aussi du clown, des arts de la parole à travers des stages, et de leur expérience dans le spectacle de rue. En 2018, ils créent la compagnie Le Cirque Compost et leur premier spectacle, « On avait dit qu’on se touchait pas ». Simon Laporte-Daube, originaire du Limousin, continue à se former en stage de clown avec Cédric Paga (Ludor Citrik) et Maëlle Perotto. Samuel Maugin, originaire du Gers, continue à se former en clown et en danse avec Maëlle Perotto. En 2018, il développe le projet « La Renverse » avec Isabelle Avid de la compagnie Le Corps Sage.&nbsp;</p>  <p></p>  <p>Spectacle programmé dans le cadre des mercredis artistiques.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '47919f97-f021-42a4-9b10-311d917479a4');
