INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE BOTANIQUE   "Incursion au monde des plantes de la vallée"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Nadine Sauter, chargée de conservation, propose de guider une balade botanique qui empruntera la piste du quartier des granges de Larbèze, aux abords des villages de Vizos et Saligos, en vue d’y observer la flore qui s’offrira en chemin et, peut-être, d’y découvrir quelques raretés végétales... Au cœur d’un milieu naturel diversifié, entre espaces urbanisés, campagne et sous-bois, cette marche commentée sera l’occasion d’observer des plantes, tantôt ordinaires ou plus spécifiques aux bords de route, aux murets, aux milieux agricoles ou forestiers...</p>  <p><em>Sortie proposée par le Conservatoire botanique national de Bagnères de Bigorre dans le cadre de la résidence de territoire \"Pais de flors\".</em></p>  <p>aller-retour : +/- 3 h</p>  <p>Nombre de places limité - Rdv 9h à la mairie de Saligos<br>  INSCRIPTION au 05 62 92 38 38</p>  <p></p>  <p><em>Crédit photo : KOVisuel</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a00ca87e-7576-42bc-a51e-2b100d0fea01');
