INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Pais de flors', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Rétrospective de la résidence de territoire \"Pais de Flors\" menée par le collectif KOVisuel avec la participation des habitants et des élèves des vallées de Luz Saint Sauveur et d''Argelès-Gazost.</p>  <p><em>Ce projet, porté par la maison du Parc national en partenariat avec Occitanie Films et le Parc national des Pyrénées a été soutenu par la DRAC Occitanie.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '846d9717-1805-4a3b-9a73-463ec21330c5');
