INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Concert sans gluten / Mamzel Bou', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Comédienne-chanteuse multirécidiviste et femme-orchestre nouvelle génération, la cheffe Bou vous propose une cuisine hétéroclite de notes et de mots concoctée en direct. Reprises ou recettes originales à base de piano, Looper, percussions, shrutti-box... pour de savoureux menus musicaux sélectionnés par le public. Une voix unique, un concert plein d''humour, léger et rafraîchissant, idéal pour l''apéritif : régalez l''âme avant les papilles ! Marlène Bouniort se balade de concerts intimistes en appartements, en festivals d''humour ou de chant de grande renommée, et débarque à Luz Saint-Sauveur pour une représentation exceptionnelle!</p>  <p>Joyeux appétit !</p>  <p><font size=\"2\"><span style=\"font-family:&quot;trebuchet ms&quot;,sans-serif\">Compagnie D.N.B / </span></font>Création 2016 / Spectacle musical et gastronomique / Tout public à partir de 12 ans / Durée 1h10</p>  <p>Programmé dans le cadre des mercredis artistiques.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a15f72f7-f233-4bf6-adb1-e2a36e28c283');
