INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arrehar / Romain Baudoin solo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La vielle à roue est un instrument millénaire qui a su traverser les époques en s''adaptant aux modes grâce à une évolution organologique et technique permanente.<br>  Au fil des siècles, elle a souvent été considérée comme un instrument moderne (Vivaldi, Mozart...) mais elle a étrangement disparu du milieu savant pour ne persister que sous une forme populaire dans diverses régions d''Europe, comme par exemple dans les Landes. Dans les années 80 la vielle a retrouvé de l''intérêt notamment auprès de musiciens audacieux qui développèrent de nouvelles pratiques à travers un répertoire contemporain, poussant la lutherie vers un très haut niveau technologique.</p>  <p><em>Romain Baudoin participe depuis plus de 20 ans à cette évolution aux cotés de maîtres comme Valentin Clastrier, travaillant sur l''amplification de l''instrument, proposant des innovations comme la roue mobile permettant des nuances d''archet, imaginant des vielles novatrices comme la « ARTÚS » (vielle électrique) ou le « Torrom Borrom », instrument chimérique, hybride, combinant une vielle et une guitare électrique.</em></p>  <p><em>Pourtant il y a 5 ans, il achète une vielle à roue traditionnelle, fabriquée en 1930 à Jenzat dans l''Allier par un luthier renommé : « Pimpare cousin ». Une vielle « bateau de femme », à 6 cordes avec un accordage standard en ré, très bien conservée, d''une marqueterie noble et subtile. Elle offre une qualité de jeu incroyable et un son plein, caractéristique des vielles anciennes. Son apparente simplicité lui semble être à l''opposé des codes de la vielle « moderne » alors qu''elle en est le point de départ.</em></p>  <p><em>Cette réflexion l''habite : Peut on développer une autre forme de jeu contemporain sur cet instrument, à contre courant des pratiques actuelles ?<br>  En parallèle de cette recherche, il travaille sur « l''origine » de la pratique viellistique dans les Landes, ayant de nombreux documents écrits et sonores, via des collectes de famille et des collectes publiques comme par exemple « la mission Landes du musée des arts et traditions populaires ».</em></p>  <p>Programmé dans le cadre des mercredis artistiques.</p>  <p>©CamilleLaranJazzALuz</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2e0f3bf3-5bfa-4f77-9dc8-8f46718be7b7');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arrehar / Romain Baudoin solo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La vielle à roue est un instrument millénaire qui a su traverser les époques en s''adaptant aux modes grâce à une évolution organologique et technique permanente.<br>  Au fil des siècles, elle a souvent été considérée comme un instrument moderne (Vivaldi, Mozart...) mais elle a étrangement disparu du milieu savant pour ne persister que sous une forme populaire dans diverses régions d''Europe, comme par exemple dans les Landes. Dans les années 80 la vielle a retrouvé de l''intérêt notamment auprès de musiciens audacieux qui développèrent de nouvelles pratiques à travers un répertoire contemporain, poussant la lutherie vers un très haut niveau technologique.</p>  <p><em>Romain Baudoin participe depuis plus de 20 ans à cette évolution aux cotés de maîtres comme Valentin Clastrier, travaillant sur l''amplification de l''instrument, proposant des innovations comme la roue mobile permettant des nuances d''archet, imaginant des vielles novatrices comme la « ARTÚS » (vielle électrique) ou le « Torrom Borrom », instrument chimérique, hybride, combinant une vielle et une guitare électrique.</em></p>  <p><em>Pourtant il y a 5 ans, il achète une vielle à roue traditionnelle, fabriquée en 1930 à Jenzat dans l''Allier par un luthier renommé : « Pimpare cousin ». Une vielle « bateau de femme », à 6 cordes avec un accordage standard en ré, très bien conservée, d''une marqueterie noble et subtile. Elle offre une qualité de jeu incroyable et un son plein, caractéristique des vielles anciennes. Son apparente simplicité lui semble être à l''opposé des codes de la vielle « moderne » alors qu''elle en est le point de départ.</em></p>  <p><em>Cette réflexion l''habite : Peut on développer une autre forme de jeu contemporain sur cet instrument, à contre courant des pratiques actuelles ?<br>  En parallèle de cette recherche, il travaille sur « l''origine » de la pratique viellistique dans les Landes, ayant de nombreux documents écrits et sonores, via des collectes de famille et des collectes publiques comme par exemple « la mission Landes du musée des arts et traditions populaires ».</em></p>  <p>Programmé dans le cadre des mercredis artistiques.</p>  <p>©CamilleLaranJazzALuz</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '2e0f3bf3-5bfa-4f77-9dc8-8f46718be7b7');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arrehar / Romain Baudoin solo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La vielle à roue est un instrument millénaire qui a su traverser les époques en s''adaptant aux modes grâce à une évolution organologique et technique permanente.<br>  Au fil des siècles, elle a souvent été considérée comme un instrument moderne (Vivaldi, Mozart...) mais elle a étrangement disparu du milieu savant pour ne persister que sous une forme populaire dans diverses régions d''Europe, comme par exemple dans les Landes. Dans les années 80 la vielle a retrouvé de l''intérêt notamment auprès de musiciens audacieux qui développèrent de nouvelles pratiques à travers un répertoire contemporain, poussant la lutherie vers un très haut niveau technologique.</p>  <p><em>Romain Baudoin participe depuis plus de 20 ans à cette évolution aux cotés de maîtres comme Valentin Clastrier, travaillant sur l''amplification de l''instrument, proposant des innovations comme la roue mobile permettant des nuances d''archet, imaginant des vielles novatrices comme la « ARTÚS » (vielle électrique) ou le « Torrom Borrom », instrument chimérique, hybride, combinant une vielle et une guitare électrique.</em></p>  <p><em>Pourtant il y a 5 ans, il achète une vielle à roue traditionnelle, fabriquée en 1930 à Jenzat dans l''Allier par un luthier renommé : « Pimpare cousin ». Une vielle « bateau de femme », à 6 cordes avec un accordage standard en ré, très bien conservée, d''une marqueterie noble et subtile. Elle offre une qualité de jeu incroyable et un son plein, caractéristique des vielles anciennes. Son apparente simplicité lui semble être à l''opposé des codes de la vielle « moderne » alors qu''elle en est le point de départ.</em></p>  <p><em>Cette réflexion l''habite : Peut on développer une autre forme de jeu cont