INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Arnica 9ch', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Solo circassien sur le bleu, la boxe et l''amour / Compagnie La Féroce</p>  <p>« Une femme dans les artères fémorales d''un match de boxe. Voix intimes et hématomes. Féminité et uppercut. Mélu vient nous raconter son match. C’est l’heure du coup et de la chute. Armée d’arnica et blindée d’adrénaline, elle nous entraine dans un monde poétique tout en sueur, en musicalité et en rires. »</p>  <p>Arnica 9ch est un spectacle qui allie le jeu d’acteur et le cirque avec la discipline de l’équilibre, dans un univers à la fois féminin et masculin.<br>  Le personnage, une boxeuse égocentrique, Mélu Percut, nous conduit dans son monde pour nous parler de ses coups de foudre, de ses coups de poings, de ses chutes et de de la manière dont elle est tombée amoureuse. Par ses gestes, ses rires, ses mots et son corps elle nous livre ses fragilités au fil du spectacle.</p>  <p>ÉQUIPE ARTISTIQUE :</p>  <p>Écriture, jeu et fil : Laure Gougeon</p>  <p>Ecriture poétique :<br>  Sabine Venaruzzo, Laure Gougeon</p>  <p>Mise en scène :<br>  Jean Jacques Minazio</p>  <p>Regard circassien :<br>  Loic Leviel, Chloé Bouzon,</p>  <p>Regard chorégraphique: Violaine Arrouy</p>  <p>Regard burlesque et humour physique: Elise Ouvrier Buffet</p>  <p>Musique : Alice Huc</p>  <p>Lumière et scénographie: Julien Sabato, Daniel Gonzales</p>  <p>Costume: Véronique Strub</p>  <p></p>  <p><em>Programmé dans le cadre de la fête de Saint Sauveur (mercredis artistiques) et dans le cadre des \"Rendez-vous en famille\" (programme Leader) .</em></p>  <p>PASS SANITAIRE OBLIGATOIRE</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5744d346-7a30-4a08-9f67-27143acc23ee');
