('0a61e77f-c129-4fe6-961f-f6b87d885556', 'evenement', true, false, false, NULL, '2021-08-03T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2021-08-03T22:00:00.000Z', '2021-08-03T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('FORÊT', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Nicolas Lafourest - Guitare éléctrique</p>  <p><em>La guitare seule, sans additifs, exprime l’émotion dans sa forme la plus réduite, à l’os, par les cendres. Si l’ornement est mis de côté ici, où ne subsistent qu’armatures et formes brutes, la musique n’en est que plus directe et suggestive. Un son brut, aride, à la fois mélancolique et rassurant, comme de longues promenades en solitude accompagnée. La trame rêche et ronde des cordes, tantôt grondantes, roulantes, saillantes, frémissantes ou chuchotantes, déploie un panel d’expressivité qui emporte l’auditeur vers ses propres paysages décharnés ou sublimes.</em></p>  <p></p>  <p>Guitariste autodidacte, Nicolas Lafourest est un musicien à la pratique instrumentale singulière et instinctive, à l’énergie brute, âpre et impulsive. Un mode de jeu intime et direct où les intentions oscillent entre atmosphères sentimentales, déconstructions expérimentales et rengaines brisées, distordues. Une musique aux motifs répétitifs, bruitistes, mélodiques mêlant sans cesse tension et fragilité, douceur et rugosité. Nicolas Lafourest joue actuellement dans Coddiwomple (G.W. Sok, O.Mellano), Choc Gazel (avec Lila Fraysse) en solo Forêt, The And, Cannibales &amp; Vahinés et La Cachette (avec la compagnie Baro d’evel).</p>  <p><em>Programmé dans le cadre des mercredis artistiques.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0a61e77f-c129-4fe6-961f-f6b87d885556');
