INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('DES PARCS ET DES HOMMES', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Projection / Débat</p>  <p>Vous saurez tout sur la biodiversité du Parc national des Pyrénées grâce à ce film qui vous emmènera à la rencontre de la faune et de la flore emblématiques des Pyrénées. Vous pourrez également découvrir la vie de l’homme en montagne. Un échange avec un garde-moniteur complétera la projection de ce film.</p>  <p><em>Animation gratuite proposée par la Parc national des Pyrénées.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '488b9910-0613-4e41-8a34-47cc070c1ce5');
