INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('BOÎTES À PAYSAGES ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle Boîte à Paysages</p>  <p>Venez assister à une création originale de théâtre de rue du collectif « Les livreurs de mots ». En interaction avec le public, les artistes questionnent les évolutions des paysages et vous invitent à vous exprimer grâce à des cartes postales un peu spéciales...</p>  <p>Cet événement s’inscrit dans le cadre du projet « Cartes Blanches » qui étudient les perceptions des habitants et visiteurs vis-à-vis des changements paysagers et climatiques du territoire des vallées des Gaves. »</p>  <p>Rendez-vous à Millaris à Gèdre</p>  <p>Renseignement au 05 62 92 42 48</p>  <p>Animation gratuite</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a2c1b1ba-245a-4b8c-a1e3-dd42bd62143f');
