INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rando festival Gavarnie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Balade d’un impossible ailleurs : la forêt est un état d’âme.<br>  Dans le cadre du Festival de Gavarnie 2021 et du thème des paysages en merveilles, partez à la découverte du milieu forestier de montagne et des arbres, source de vie, de stabilité et d’inspiration.<br>  Balade itinérante de 2 h 30 animée par un garde-moniteur du Parc national des Pyrénées et Bruno Spiesser, comédien et metteuren scène du Festival de Gavarnie et de la compagnie Fébus.</p>  <p>Rendez-vous à la Maison du Parc national de Gavarnie. Prévoir des chaussures adaptées, gourde et chapeau.</p>  <p>Renseignements et inscriptions à l’office de tourisme de Gavarnie au 05 62 92 49 10</p>  <p>Animation payante.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1870f32a-54bb-4ee2-9974-d79fe25c23d5');
