INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rando / Découverte de la faune de Troumouse', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Accompagné d’un garde-moniteur du Parc national des Pyrénées, partez pour une courte randonnée d’une demi-journée à la rencontre des animaux du cirque de Troumouse. Alimentation, reproduction, habitudes, n’auront plus de secret pour vous.</p>  <p>Rendez-vous à Héas au niveau du péage du Maillet à Gèdre.</p>  <p>Renseignements et inscriptions au 05 62 92 42 48.</p>  <p>Animation payante.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4ee5ef75-25fd-48dd-ba6f-340e76802ad7');
