INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rando / Découverte de la faune du Barrada', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Accompagné d’un garde-moniteur du Parc national des Pyrénées, partez pour une courte randonnée d’une demi-journée à la rencontre des animaux du Barrada. Alimentation, reproduction, habitudes, n’auront plus de secret pour vous.</p>  <p>Rendez-vous au parking de la centrale EDF de Pragnères.</p>  <p>Renseignements et inscriptions au 05 62 92 42 48.</p>  <p>Animation payante.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1482671f-58cd-4eb2-82fc-1e9c0308f84d');
