INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Legraux Tobrogoï', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Jazz populaire acharné.</p>  <p>Sur des rythmiques afro-américaines (afro-beat, jazz...) qui constituent leur culture commune, les Tobrogoï ont ajouté la vivacité et la fougue des mélodies de l''est et de l''orient pour créer le \"tziganafreecansound\": un répertoire instrumental ouvert, énergique, toujours axé sur la danse, où règne un esprit d''improvisation jubilatoire. « Legraux Tobrogoï » une version orchestrale de jazz populaire! Soudés artistiquement et en confiance, ils sont unis par une solide amitié et une approche commune de la musique: énergie et liberté !</p>  <p>Programmé dans le cadre de la fête des fleurs de St-Sauveur (quartier thermal).</p>  <p>PASS SANITAIRE OBLIGATOIRE</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '33296ee2-1bf3-432a-b5f6-8239f8c046d9');
