INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Avec vue... côté mer', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Musique - Danse par la cie Les Âmes fauves.</p>  <p>Cette pièce courte créée par le chorégraphe Alain Abadie pour les danseurs Claire Cauquil et Olivier Nevejans, est un clin d’œil à son premier duo « Hôtel Sirocco », écrit une trentaine d’année en amont.</p>  <p>Dans ce probable rendez-vous de chambre d’hôtel, le chorégraphe croise les univers poétiques et joueurs qui font sa renommée.</p>  <p>Ici les deux protagonistes font et défont l’écriture en course-poursuite. Ils tricotent, dialoguent, sans finalement réussir à déterminer qui de lui ou d’elle mènera le bal, donnera le ton, sera du chat la souris.</p>  <p></p>  <p>Olivier Nevejans, danseur chorégraphe de la compagnie Les Âmes Fauves, a travaillé de nombreuses fois dans son parcours d’interprète, aux côtés du chorégraphe Alain Abadie. Leurs sensibilités partagées les a amenés à développer une forme de création en connivence. Aujourd’hui encore, leur complicité se poursuit avec la proposition d’Olivier faite à Alain de créer pour la Compagnie, une pièce constituée d’oeuvres courtes, avec pour seule contrainte le duo et le temps (entre 1mn et 15 mn). Dans leur travail de création, Claire Cauquil et Olivier Nevejans ont souvent revendiqué un propos politique - entendu ici dans son sens large comme ce qui a trait au collectif, et à son cadre général de gestion (la société, le groupe social...) - comme point d’origine de leurs pièces chorégraphiques. De l’œuvre d’Alain Abadie est retenue en premier lieu l’engagement poétique. Or les frontières entre les œuvres de ces deux compagnies ne se révèlent finalement pas si étanches...</p>  <p></p>  <p>Programmé dans le cadre des mercredis artistiques.</p>  <p><span data-offset-key=\"8233e-0-0\"><span data-text=\"true\">Jauge limitée à 49 places sans Pass sanitaire.</span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '16033f7f-4423-46bf-a4d7-3307f3928e9f');
