INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Petits points de vie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre - Cie les Jolies Choses</p>  <p>D''après l''ouvrage de Catherine Verlaguet - Mise en scène collaborative - Création Avril 2020.</p>  <p>Spectacle de quatre pièces courtes : la rencontre magique et musicale entre un enfant trop bavard et le fils adoptif d''une amie de sa maman, qui n''ouvre jamais la bouche; un garçon qui discute avec son frère imaginaire pas si réel logé dans son épaule; deux frères prêts à tout pour décrocher une étoile à leur mamie afin que sa mémoire ne s’efface pas; une petite fille partie à la recherche de son sourire, qu''elle a perdu entre la maison de son papa et celle de sa maman.</p>  <p>Une invitation à la découverte de l''autre et du monde, en poésie et en récit, en dialogue et en rêve.</p>  <p>À partir de 6 ans.</p>  <p><strong>Distribution :</strong></p>  <p>Mélia Bannerman : Metteur en scène, comédienne, plasticienne.</p>  <p>Sophie Barros : Chorégraphe, danseuse, comédienne.</p>  <p>Lucile Delamorena : Comédienne.</p>  <p>Laurie Montamat : Comédienne, danseuse.</p>  <p>Maryline Petioch : Metteur en scène, chanteuse, comédienne, musicienne.</p>  <p>Bastien Sallaberry : Régisseur général</p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarif spectacle</a></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '64a3bde4-3e6c-4a59-896f-94b2c2f2d6a6');
