INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Déracinés / Cie Alas Negras', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle visuel de marionettes - Marionnettes sur table et ombres&nbsp; - Cie Alas Negras (Les Ailes Noires) Occitanie - Création 2018/2021 - Sortie Octobre 2021.</p>  <p>Tout Public à partir de 11 ans.</p>  <p></p>  <p>Dans la ville des anonymes se croisent. Quelles sont leurs histoires ? D''où viennent-ils ? Pourquoi sont-ils là ?<br>  Yuma, un adolescent d’origine Innu (peuple autochtone du Canada) se sent suspendu entre deux mondes. Il est tiraillé entre le monde de ses origines, attrapé à l''intérieur de lui, caché dans le passé, et le monde dans lequel il a grandi. Maka, sa voisine originaire d''Amazonie, réveille l''intérêt de Yuma pour ses racines.</p>  <p>Un voyage à l''intérieur de la recherche et l''acceptation d''identité d''un adolescent.</p>  <p></p>  <p><strong>L''équipe artistique :</strong><br>  Marionnettistes : Daniel Blander, Tamar Rojas et Elsa Gire Péchayre</p>  <p>Construction marionnettes et décors : Daniel Blander</p>  <p>Dessins ombres : Damien Gonzales<br>  Composition et musique originale : Célyne Baudino</p>  <p>Régisseure.se : en cours<br>  Dramaturgie et mise en scène : Elsa Gire Péchayre</p>  <p></p>  <p><strong>La Compagnie :</strong></p>  <p>La compagnie démarre professionnellement en Argentine dans la ville de Buenos Aires en 2014. Son premier spectacle est un spectacle de marionnettes, danse et théâtre pour adultes, autour de l''histoire d''une famille qui vit le deuil d''un enfant (« El camino del Erizo »). Ce spectacle est nommé au prix national de marionnettistes Javier Villafañe, en Argentine, pour la meilleure chorégraphie et la meilleure musique originale. Il gagne le prix de meilleure mise en lumière.</p>  <p>A l''été 2015, le noyau de la compagnie, Elsa Gire.P et Daniel Blander s''envolent vers la France, avec deux petites formes pour la rue. Ils sillonnent maintenant les routes de France et d’Europe.</p>  <p>Les spectacles de la compagnie sont, pour l''instant, sans texte, dans le but de partager leurs spectacles à travers le monde sans la « barrière » de la langue. Et surtout car le langage visuel fascine Elsa et Daniel. Raconter sans mots, avec très peu ou avec des mots décousus est un défi qu''ils aiment se donner. Ils aiment aussi transporter les spectateurs dans des espaces symboliques plus que des espaces concrets. Et proposer à ceux qui écoutent, regardent et goûtent leurs spectacles, d''être des spectateurs actifs.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c1e01267-b1ce-4e85-a1c2-73c90f109e65');
