INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Petits points de vie / Cie Les Jolies Choses', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Catherine Verlaguet - Éditions Théâtrales Jeunesse Mise en scène collaborative - Création Avril 2020</p>  <p>Cet ouvrage est un recueil de quatre pièces courtes. La rencontre magique et musicale entre un enfant trop bavard et le fils adoptif d''une amie de sa maman, qui n''ouvre jamais la bouche; un garçon qui discute avec son frère imaginaire pas si réel logé dans son épaule; deux frères prêts à tout pour décrocher une étoile à leur mamie afin que sa mémoire ne s’efface pas; une petite fille partie à la recherche de son sourire, qu''elle a perdu entre la maison de son papa et celle de sa maman.</p>  <p>Ces quatre textes sont une invitation à la découverte de l''autre et du monde. Tout en poésie et en récit, tout en dialogue et en rêve, Catherine Verlaguet crée un univers accessible à tout âge.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4f92a8e6-f93c-4d35-89ad-78dafff038ce');
