INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('ANNULÉE Sortie de résidence : Déracinés / Cie Alas Negras', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle visuel de marionettes - Marionnettes sur table et ombres&nbsp; - Cie Alas Negras (Les Ailes Noires) Occitanie - Création 2018/2021 - Sortie Octobre 2021.</p>  <p>Tout Public à partir de 11 ans.</p>  <p></p>  <p><em>Dans la ville des anonymes se croisent. Quelles sont leurs histoires ? D''où viennent-ils ? Pourquoi sont-ils là ?<br>  Yuma, un adolescent d’origine Innu (peuple autochtone du Canada) se sent suspendu entre deux mondes. Il est tiraillé entre le monde de ses origines, attrapé à l''intérieur de lui, caché dans le passé, et le monde dans lequel il a grandi. Maka, sa voisine originaire d''Amazonie, réveille l''intérêt de Yuma pour ses racines.</em></p>  <p><em>Un voyage à l''intérieur de la recherche et l''acceptation d''identité d''un adolescent.</em></p>  <p></p>  <p><strong>L''équipe artistique :</strong><br>  Marionnettistes : Daniel Blander, Tamar Rojas et Elsa Gire Péchayre</p>  <p>Construction marionnettes et décors : Daniel Blander</p>  <p>Dessins ombres : Damien Gonzales<br>  Composition et musique originale : Célyne Baudino</p>  <p>Régisseure.se : en cours<br>  Dramaturgie et mise en scène : Elsa Gire Péchayre</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '63d874c5-a5f1-442b-9a1c-2fa32acd246b');
