INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence Rizòm / Cie La Ravi', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Danse contemporaine-musique-marionnette pour les enfants à partir de 10 mois, sur le thème de la transmission du mouvement et du son dans différentes cultures.</p>  <p>\"Mon travail en direction de l’enfance, de la crèche à la maternelle, m’a amené à questionner la relation de l’homme au monde physique et poétique, la place du corps et son langage sensoriel, de l’écoute au toucher, dans une société de plus en plus virtuelle. Pour Rizom, je me suis interrogée sur l’importance du mouvement et du son selon les cultures qui conduit à des modes de communication différenciés. Les racines, « ryz’hommes », autant de liens souterrains entre les êtres humains, donnent à voir, à entendre et percevoir la richesse de l’humanité de demain.\"</p>  <p>Mémoires sensorielles, sons, odeurs, chants, mouvements, guident l’apprentissage du tout petit vers sa découverte du monde.<br>  Deux femmes, porteuses d’une transmission artistique de la danse au chant, un accordéon, des valises de toutes tailles enfermant leurs trésors, odeurs, objets, matières d’où sortiront des petites marionnettes, sons des voix mêlées insérées dans des climats liés aux différentes parties du globe emmènent les enfants et leurs parents dans un voyage intemporel, puisant dans les origines et les racines, la richesse du présent. Un dispositif en cercle, rond comme le monde, accueillera ce voyage sensoriel, permettant une proximité aux enfants. Il s’agit dans cette exploration à travers différentes cultures de chercher des gestuelles à la racine de notre motricité, afin d’inventer une partition corporelle évolutive. Les marionnettes se manipulent à vue, intégrées à la danse.</p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0dd4e968-0d51-4bd4-93d7-c7c2b9519aa6');
