INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence Quelque part dans l''ouest / Cie Acmé', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre par la Cie Acmée.</p>  <p>Étape de création présentée à l''issue de la semaine de résidence.</p>  <p></p>  <p>Que ce soit clair.</p>  <p>Qui, petit garçon ou petite fille, n’a pas été fasciné par la dégaine de John Wayne dans La dernière séance d’Eddy Mitchell ne comprendra rien à ce projet.</p>  <p>Qui, homme ou femme, ne s’est jamais demandé quel trouble érotique le saisissait quand Steve McQueen et Yul Brynner chevauchaient côte à côte, les cuisses moulées dans des chaps en cuir, le revolver à portée de main, devrait passer son chemin.</p>  <p>Qui, à l’adolescence, n’a senti l’impérieuse nécessité de prendre une douche après avoir jeté un œil dans le décolleté de Claudia Cardinale malmenée par Henry Fonda peut refermer ce dossier.</p>  <p>Illico presto.</p>  <p><br>  Le Western nous a faits. Homme ou femme.</p>  <p>Le masculin et le féminin sont entrés en nous à coups de revolver et de grandes chevauchées, de duels virils et de gambettes levées bien haut.</p>  <p>Vous allez me dire : mais notre histoire n’est-elle pas celle de TOUT le cinéma ?</p>  <p>Bien sûr que oui. Mais surtout celle des cowboys d’opérette.</p>  <p>Parce que c’est une histoire qui, plus que celle de tout autre genre cinématographique, à travers la galerie archétypale de ses personnages, héros monolithiques ou modèles vacillants, héroïnes énamourées ou amazones redoutables, met en question ce qui nous fait homme et ce qui nous fait femme – et met en jeu notre désir.</p>  <p></p>  <p><em>Après Petite Musique de Filles, premier spectacle autofictionnel sur le théâtre et la féminité, ACMé poursuit son exploration des arts et des identités avec Quelque part dans l''Ouest. Partant des phénomènes d''identification qui ont jalonné leurs vies de spectateurs, 2 acteurs et 3 actrices vont remettre en jeu les codes du western et tendre un miroir sur les violences de notre époque, où les liens entre domination masculine, misogynie, capitalisme et xénophobie sont toujours prégnants.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '91db1a8d-e817-4d8a-aad1-99fa9b90029b');
