INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Orage à quatre voix', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Musique classique - Quatuor de clarinettes \"Les Anches hantées\"</p>  <p>Dans quel état d''esprit les enfants sont-ils invités au concert de musique classique ?<br>  Souvent ils ont été prévenus, menacés : il ne faut pas parler, pas bouger, pas faire de bruit... en bref l''enfer !<br>  Les Anches Hantées, quatuor de clarinettistes, vont leur montrer qu''ils peuvent bouger si ça danse, parler si on les interpelle, que le concert est vivant et, tout naturellement, ils les amèneront à écouter attentivement si on joue un morceau pour La Belle au Bois Dormant... Chuuuuut...<br>  On entend le bruit du souffle faisant vibrer les anches. Soutenus par un choix minutieux des œuvres, Élise, Bertrand, Romain et Nicolas, les quatre musiciens, mêlent à leur prestation musiques classique, folklorique et contemporaine, forme théâtrale, gestes comiques et surtout engagent avec leur jeune public, le dialogue, élément sine qua non pour accaparer les yeux et les oreilles de ces spectateurs si aisément distraits. Et ça marche !<br>  <br>  <em>Programmé dans le cadre des rendez-vous en famille ( programme Leader ).</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b59fe0d5-1025-43fe-ba3d-7d69a10b5be6');
