INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le chant du pied, voyage en Kathakalie - Kathakali Girls', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Le Chant du pied, voyage en Kathakalie.</p>  <p>Une création originale pour trois voix et six pieds, imaginée, écrite, chorégraphiée, jouée et dansée par Les Kathakali Girls : Nathalie Le Boucher, Annie Rumani, Catherine Schaub Abkarian.<br>  Regard extérieur et collaboration artistique : Simon Abkarian<br>  Création lumière : Jean-Michel Bauer<br>  Régie son : Laurent Clauwaert</p>  <p>Que se passe-t-il quand trois jeunes femmes occidentales traversent le monde jusqu’au fin fond de l’Inde du Sud pour aller puiser aux sources même du théâtre, le Kathakali ?<br>  Qu’advient-il de cette rencontre surprenante entre trois femmes modernes qui transgressent les règles dans leur quête d’enseignement et de pratiques, et un monde exclusivement masculin aux traditions millénaires ?</p>  <p>Dans un univers résolument contemporain, un spectacle se dessine entre danse, mythe et confidence, une balade drôle et profonde, un périple inclassable.<br>  «&nbsp;Le Chant du Pied&nbsp;» est une invitation au voyage, dans l’intimité de leurs souvenirs, dans l’épique de leurs aventures, dans le merveilleux de cet exil. C’est là que ces trois femmes se dévoilent et se racontent : la folie de l’Inde, l’exigence des classes, les nuits enivrantes de Kathakali, l’écriture de ses codes et ses rouages…Être femme dans un monde d’hommes et de traditions, découvrir « l’autre », devenir « l’autre », jusque dans tous ces petits riens du quotidien indien… Là, le sacré croise le trivial et le respect, l’effronterie.<br>  <br>  Soutenu par Miléna Salvini du centre Mandapa, Ariane Mnouchkine et le Théâtre du Soleil, et l’ARTA, &nbsp;le spectacle est accueilli dans ses premières versions au Mandapa à Paris puis dans sa version finale au Théâtre du Soleil pendant trois semaines, deux années consécutives (juin 2018 et 2019). Crédit photo : Shakuntala</p>  <p>Programmé dans le cadre des Rendez-vous en famille (Programme Leader).</p>  <p>À partir de 8 ans.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a72fc5f0-c370-4e08-8ea9-ae19c37b7f6e');
