INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence Mandiwa ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Diwa, la racine du mot mandiwa, signifie esprit, âme, idée, pensée.</p>  <p>La finesse et la limpidité des compositions de Mandiwa permettent à l''auditeur de se laisser dériver dans un univers qui navigue entre exotisme et classicisme, allant de l''Afrique centrale à l''Europe de l''est en passant par le gnawa ...</p>  <p>La guitare de David Clavel et le saxophone de Dirk Vogeler créent une alchimie entre rythmes d’ailleurs et mélodies personnelles, dans laquelle s’immiscent les vocalises des musiciens.</p>  <p>Le percussionniste toulousain Jean-Loup Perry s''est joint aux deux fondateurs du groupe en été 2019.</p>  <p>La rencontre riche en énergie des trois musiciens fait naître des échanges musicaux improvisés et authentiques : Mandiwa est une invitation au voyage à la fois poétique et débridé, entre exotisme et classicisme.</p>  <p>Après le premier album « Songes », les nouvelles compositions du groupe sont plus axées sur l’improvisation et le placement des voix des trois choristes. Un nouvel album est en préparation avec le projet d’un enregistrement courant 2021. Cet album prendra le nom du nouveau spectacle « ojibwé ».</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e6673e10-be5d-41fe-8f55-5ee8b0a0c73b');
