INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Hamlet speak to me', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Clown – Théâtre Cie Les improsteurs</p>  <p>Contemporaines d’Hamlet et de son histoire, Mouch, Adèle et Moâ font partie du petit personnel du Château d’Elseneur. Elles vivent au quotidien le drame avec leur sensibilité de femmes, leurs conditions et leurs expériences personnelles : elles racontent Hamlet, celui dont elles sont si proches depuis toujours.</p>  <p><em>Programmé dans le cadre des rendez-vous en famille (programme Leader).</em></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd9742d2a-bdac-4c15-8d44-c2b237db1d47');
