INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Prima Kanta', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Une formation mixte (trois femmes, trois hommes), sans basse, ni batterie, aux couleurs boisées, où clarinette basse, piano, vibraphone, violon, harpe électro-acoustique et vocalises, s’entremêlent avec bonheur et harmonie au niveau des timbres, autour d’un concept qui associe écriture et liberté. <p>En effet, il s’agit d’une musique entièrement écrite, composée de plusieurs modules, mais jamais jouée de la même façon, car les musiciens interviennent quand ils veulent au rythme où ils l’entendent.</p>  <p>Le résultat est passionnant car une grande liberté se joue à l’intérieur d’une écriture très précise, ce qui reflète parfaitement bien l’état d’esprit du taoïsme qui traverse cet album.</p>  <p>Fasciné par la liberté et la fantaisie de Michel Portal, ainsi que par la transe et la force de la musique de Nik Bärtsch, Laurent Rochelle et son ensemble Prima Kanta élaborent une musique complètement originale et prégnante, qui ne ressemble à rien d’autre, et qui a le grand mérite d’être facile d’accès.</p>  <p>Une musique simple, mais élégante et raffinée, qui se refuse à toute démonstration car le propos est ailleurs.</p>  <p><br>  Laurent Rochelle : clarinette basse, sax soprano, compositions et direction<br>  Juliette Carlier : vibraphone, percussions<br>  Arnaud Bonnet: violon<br>  Rébécca Féron : harpe électro-acoustique<br>  Frédéric Schadoroff : piano, samples<br>  Fanny Roz : voix</p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1c6d628a-66e2-4297-8c8f-8e4e003ca31b');
