INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Orage', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Une performance cinématographique immersive de Naïs Van Laer &amp; Pali Meursault.</strong></p>  <p>En face du public : un écran. A droite et à gauche de l’écran, à vue du public, un performeur-son et une performeuse-image. Sur leurs tables : des ordinateurs, des claviers, une table de mixage, des câbles. Tout autour du public et des performeurs : des enceintes.</p>  <p>Le noir se fait.</p>  <p>Dans une forêt des Hautes-Pyrénées, le tonnerre gronde. C’est un soir d’été, la terre exhale une brume légère. L’orage éclate et se déchire en éclairs de chaleur. Au creux d’un rocher, une araignée frémit sous la houle des coups de vent sur sa toile. Une renarde se faufile entre les feuillages et rejoins sa tanière où ses petits sont à l’abri. Une chouette, du haut d’un chêne noueux, s’éveille, observe et s’envole.</p>  <p>Le public est plongé successivement dans le regard subjectif de ces trois animaux. Perceptions visuelles étranges, parfois très précises, parfois angulaires, parfois pâles, extrêmement rapides ou floues. Les perceptions sonores de chaque animal sont aussi restituées dans leur étrangeté, peuplées d’infra-basses, de froissements au loin, de glapissements, de chuintements.</p>  <p>Tout autour du public et dans les images : l’orage.</p>  <p></p>  <p>Pour cette première phase de création dans le cadre de la résidence les artistes accompliront un travail de documentation sur les trois animaux choisis pour la performance, en étroite collaboration avec les scientifiques naturalistes du Parc National qui connaissent parfaitement la faune en présence et pourront aiguiller les artistes dans leurs recherches...</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8e367a2b-55fa-45cb-bdc2-5496faa04144');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Orage', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Une performance cinématographique immersive de Naïs Van Laer &amp; Pali Meursault.</strong></p>  <p>En face du public : un écran. A droite et à gauche de l’écran, à vue du public, un performeur-son et une performeuse-image. Sur leurs tables : des ordinateurs, des claviers, une table de mixage, des câbles. Tout autour du public et des performeurs : des enceintes.</p>  <p>Le noir se fait.</p>  <p>Dans une forêt des Hautes-Pyrénées, le tonnerre gronde. C’est un soir d’été, la terre exhale une brume légère. L’orage éclate et se déchire en éclairs de chaleur. Au creux d’un rocher, une araignée frémit sous la houle des coups de vent sur sa toile. Une renarde se faufile entre les feuillages et rejoins sa tanière où ses petits sont à l’abri. Une chouette, du haut d’un chêne noueux, s’éveille, observe et s’envole.</p>  <p>Le public est plongé successivement dans le regard subjectif de ces trois animaux. Perceptions visuelles étranges, parfois très précises, parfois angulaires, parfois pâles, extrêmement rapides ou floues. Les perceptions sonores de chaque animal sont aussi restituées dans leur étrangeté, peuplées d’infra-basses, de froissements au loin, de glapissements, de chuintements.</p>  <p>Tout autour du public et dans les images : l’orage.</p>  <p></p>  <p>Pour cette première phase de création dans le cadre de la résidence les artistes accompliront un travail de documentation sur les trois animaux choisis pour la performance, en étroite collaboration avec les scientifiques naturalistes du Parc National qui connaissent parfaitement la faune en présence et pourront aiguiller les artistes dans leurs recherches...</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '8e367a2b-55fa-45cb-bdc2-5496faa04144');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Orage', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Une performance cinématographique immersive de Naïs Van Laer &amp; Pali Meursault.</strong></p>  <p>En face du public : un écran. A droite et à gauche de l’écran, à vue du public, un performeur-son et une performeuse-image. Sur leurs tables : des ordinateurs, des claviers, une table de mixage, des câbles. Tout autour du public et des performeurs : des enceintes.</p>  <p>Le noir se fait.</p>  <p>Dans une forêt des Hautes-Pyrénées, le tonnerre gronde. C’est un soir d’été, la terre exhale une brume légère. L’orage éclate et se déchire en éclairs de chaleur. Au creux d’un rocher, une araignée frémit sous la houle des coups de vent sur sa toile. Une renarde se faufile entre les feuillages et rejoins sa tanière où ses petits sont à l’abri. Une chouette, du haut d’un chêne noueux, s’éveille, observe et s’envole.</p>  <p>Le public est plongé successivement dans le regard subjectif de ces trois animaux. Perceptions visuelles étranges, parfois très précises, parfois angulaires, parfois pâles, extrêmement rapides ou floues. Les perceptions sonores de chaque animal sont aussi restituées dans leur étrangeté, peuplées d’infra-basses, de froissements au loin, de glapissements, de chuintements.</p>  <p>Tout autour du public et dans les images : l’orage.</p>  <p></p>  <p>Pour cette première phase de création dans le cadre de la résidence les artistes accompliront un travail de documentation sur les trois animaux choisis pour la performance, en étroite collaboration avec les scientifiques naturalistes du Parc National qui connaissent parfaitement la faune en présence et pourront aiguiller les artistes dans leurs recherches...</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '8e367a2b-55fa-45cb-bdc2-5496faa04144');
