INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Pourquoi les poules préfèrent être élevées en batterie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Pourquoi les poules préfèrent être élevées en batterie.</strong></p>  <p><strong>Jérôme Rouger/La Martingale</strong></p>  <div class=\"champ genre\">  <div class=\"champ duree\"><strong>Théâtre humour</strong> <strong>/ Dès 14 ans / Durée 1h10</strong></div>   <div class=\"champ duree\"></div> </div>  <p>Le professeur Rouger, directeur de l''École d''agriculture ambulante, aborde les questions des droits de la poule et des conditions de vie de l''œuf. Mais pourquoi donc les poules ressentent-elles le besoin de se coller les unes aux autres, dans des conditions qui paraissent pourtant peu enviables ?</p>  <p>Si votre désir ardent est d’être convié à un colloque savant où s’élaboreraient thèses, antithèses et synthèses, autant rester à la maison… Mais si vous avez envie d’un moment dont l’enjeu est de vous traîner par le bec au royaume de l’absurde et de la métaphysique, arrivez toutes pattes devant.<br>  En effet, entre informations scientifiques et propos plus discutables, poule mouillée et chair de poule, cette pseudo-conférence investit à la fois le champ de l''absurde et de la métaphysique pour refléter par un regard aigu et décalé des problématiques très actuelles...<br>  En spécialiste des allocutions détournées, Jérôme Rouger offre ici un discours d''une drôlerie sans faille, une joyeuse métaphore de la condition humaine. Une conférence déplumante pour des fous rires garantis !<br>  NB : En fin de séance, si le niveau des élèves le permet, il tentera de résoudre le paradoxe de l’œuf et de la poule.</p>  <p><em>Programmé en partenariat avec le Parvis (scène nationale Tarbes Pyrénées).</em></p>  <p></p>  <p><a href=\"https://parvis.notre-billetterie.net/billets?kld=2122\">Billeterie en ligne</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '641ef422-b0af-4d8b-9d04-2b43c53cd325');
