INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Traversée / Rift Cie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre gestuel, masqué, marionnettique dès 7 ans / La Rift Compagnie</p>  <p></p>  <p>Traversée - La fable</p>  <p>Gran''Ma a les os qui grincent, elle vit seule dans son appartement, la plupart du temps elle attend. Elle attend quoi ? Elle attend que quelque chose se passe, ou que le temps passe, elle ne sait plus trop... Chaque mercredi, sa petite flle, que l''on surnomme Là, lui rend visite. Là est une « petite flle éponge », qui s''imbibe de toutes les tristesses et peurs qui l''entourent. De plus en plus désemparée face à la mélancolie de sa grand mère, elle lui propose de s''échapper. Là, pourtant à priori peu aventurière, ne voit qu''une solution, partir en voyage pour lui redonner goût à la vie. Gran''Ma accepte mais refuse catégoriquement de se déplacer en avion. Elles partiront en bateau ! Toutes deux embarquent. Gran''Ma se révèle être une matelot avertie, Là une co-équipière hors pair. Nous assistons à leur relation, à leurs complicités, leurs ingéniosités et leurs diffcultés, leurs incompréhensions, leurs réconciliations dans un univers où l''humain est insignifant face à son environnement, où une erreur de navigation peut être fatale.<br>  Epuisées mais heureuses, elles amarrent au port de la réalité : il fait déjà nuit, Là doit rentrer chez elle, la partie de jeu est terminée. L''appartement de Gran''Ma est maintenant sans dessus-dessous mais quelle importance. Au bras de sa petite flle, Gran''Ma regagne sa chambre avec une joie retrouvée.</p>  <p>« Traversée » est une peinture en mouvement sur le pouvoir de l''imagination. Gran''Ma avec l''âge subit une perte de mobilité qui vient altérer son moral et le sens qu''elle donne ou a pu donner à sa vie. Là a une émotivité débordante. De sa posture d''enfant, avec l''amour qu''elle porte à sa grand-mère, ses capacités à entrer dans le jeu, à construire une histoire et de son exigence à faire comme si c''était vrai, Là permet à Gran''Ma de s''échapper de sa condition physique de vieille femme et redevenir, elle aussi, l''instant de quelques heures, une aventurière, une personne qui fait des choix, qui rebondit, qui dialogue et trouve des solutions, se retrouve en mouvement : à nouveau vivante.</p>  <p>Gran'' Ma et Là sont deux protagonistes qui tissent une histoire d''entre-aide entre deux générations, un dialogue entre le mouvement et l''empêchement, entre l''aisance et le déséquilibre, entre l''aventure et l''intime, entre l''immensité et l''imperceptible, entre ce qui est enfoui et ce qui jaillit.</p>  <p></p>  <p>Écrit et mis en scène par Laure Boutaud<br>  Accompagnement à la mise en scène et à la direction d''acteur : Amélie Gasparotto Création marionnettes et accompagnement à la manipulation : Jo Smith<br>  Jeu Claudia Hugues, Anne Violet<br>  Lumières Serena Andreasi<br>  Univers sonore : en cours<br>  Accessoires et costumes : Julie Roussillon<br>  Scénographie : Roxane Chabbal<br>  Chargée de production : Marion Le Meut</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c448d791-dc13-4c56-9c5e-27e81c9c2d20');
