INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence "Traversée" / Rift Cie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre gestuel, masqué, marionnettique dès 7 ans / La Rift Compagnie</p>  <p></p>  <p>Traversée nous raconte comment la relation d''une petite fille et de sa grand-mère a modifié leurs trajectoires de vie.</p> Au jour de la représentation, Là est adulte. Elle partage avec nous, un souvenir d''enfance. Elle se revoit à 8 ans, inquiète et peu sûre d''elle. Elle se souvient de ces mercredis après-midi passés chez sa grand-mère et particulièrement du jour où tout a basculé.  <p>Sa grand-mère s''enfermait petit à petit dans le champ de fleurs de sa tapisserie. Un brouillard épais s''est infiltré dans l''appartement et le cœur de Gran''Ma. Là ne voulait pas le voir s''installer ici. Elle veut agir, elle propose à sa grand-mère de partir à l''aventure. Gran''Ma accepte, à condition que ce voyage se fasse en bateau.</p>  <p>Traversée arrive en chantier à la Maison du Parc National et de la vallée. Il s''agira pour l''équipe de créer les scènes d''ombre qui viennent s''imbriquer dans le récit.</p>  <p><strong>Lors de la sortie de résidence la compagnie partagera avec vous, ces moments d''ombre et de lumière fraîchement construits.</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '16c4adc5-53ed-4ef5-90eb-660849136b7d');
