INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Contes en hiver " Contes entre deux eaux "', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Florant Mercadier.</p>  <p>Une invitation à descendre le cours de la Garonne, de la montagne à l’océan, pour une traversée de l’Occitanie où se croisent des princesses espagnoles qui n’aiment pas les fruits, des lutins malicieux qui voudraient bien apprendre à voler, des notes de musiques…&nbsp;</p>  <p>À partir de 9 ans.</p>  <p>Durée : 1h.</p>  <p></p>  <p><em>Programmé en partenariat avec la Ligue de l''Enseignement des Hautes Pyrénées dans le cadre du 26ème festival Contes en Hiver.</em></p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd9915ef5-bab4-4a21-819e-9604317afe9c');
