INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Nos Pyrénées" par Francis Annet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>« PHOTODIDACTE »</p>  <p>Depuis l’âge de 12 ans j’ai toujours pratiqué la photographie.<br>  Comme amateur jusqu’aux années 80 où j’ai franchi le pas du professionnalisme.</p>  <p>Puis, dans les années 90, je me suis orienté principalement vers la photo d’illustration.<br>  Je suis alors devenu l’éditeur de mes propres images.</p>  <p>1992 : Parution de mon premier livre consacré aux Pyrénées, déjà !<br>  1993 : Premier prix diapos au Festival Mondial de l’Image de Montagne de Briançon.</p>  <p>Depuis j’ai édité 14 ouvrages avec mes photos, principalement consacrés au Périgord et aux Pyrénées.<br>  De nombreuses expositions ponctuant régulièrement ce parcours.</p>  <p>Cette exposition est un condensé des images de mon dernier livre : « Nos Pyrénées »<br>  Parmi celles qui m’ont procuré le plus d’émotions. Des instants fragiles et furtifs volés, figés à jamais dans ma mémoire et sur ces tirages.</p>  <p>Cinquante ans de pratique de la haute montagne sur tous les massifs de la chaîne ont permis cette complicité avec la nature par des rendez-vous improbables, des rencontres avec les caprices de la</p>  <p>météo, toujours en quête de la belle lumière. Je vous invite à partager mon regard...</p>  <p>Francis Annet</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ff87eadd-2c6e-450f-a905-4632c626ce26');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Nos Pyrénées" par Francis Annet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>« PHOTODIDACTE »</p>  <p>Depuis l’âge de 12 ans j’ai toujours pratiqué la photographie.<br>  Comme amateur jusqu’aux années 80 où j’ai franchi le pas du professionnalisme.</p>  <p>Puis, dans les années 90, je me suis orienté principalement vers la photo d’illustration.<br>  Je suis alors devenu l’éditeur de mes propres images.</p>  <p>1992 : Parution de mon premier livre consacré aux Pyrénées, déjà !<br>  1993 : Premier prix diapos au Festival Mondial de l’Image de Montagne de Briançon.</p>  <p>Depuis j’ai édité 14 ouvrages avec mes photos, principalement consacrés au Périgord et aux Pyrénées.<br>  De nombreuses expositions ponctuant régulièrement ce parcours.</p>  <p>Cette exposition est un condensé des images de mon dernier livre : « Nos Pyrénées »<br>  Parmi celles qui m’ont procuré le plus d’émotions. Des instants fragiles et furtifs volés, figés à jamais dans ma mémoire et sur ces tirages.</p>  <p>Cinquante ans de pratique de la haute montagne sur tous les massifs de la chaîne ont permis cette complicité avec la nature par des rendez-vous improbables, des rencontres avec les caprices de la</p>  <p>météo, toujours en quête de la belle lumière. Je vous invite à partager mon regard...</p>  <p>Francis Annet</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'ff87eadd-2c6e-450f-a905-4632c626ce26');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Nos Pyrénées" par Francis Annet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>« PHOTODIDACTE »</p>  <p>Depuis l’âge de 12 ans j’ai toujours pratiqué la photographie.<br>  Comme amateur jusqu’aux années 80 où j’ai franchi le pas du professionnalisme.</p>  <p>Puis, dans les années 90, je me suis orienté principalement vers la photo d’illustration.<br>  Je suis alors devenu l’éditeur de mes propres images.</p>  <p>1992 : Parution de mon premier livre consacré aux Pyrénées, déjà !<br>  1993 : Premier prix diapos au Festival Mondial de l’Image de Montagne de Briançon.</p>  <p>Depuis j’ai édité 14 ouvrages avec mes photos, principalement consacrés au Périgord et aux Pyrénées.<br>  De nombreuses expositions ponctuant régulièrement ce parcours.</p>  <p>Cette exposition est un condensé des images de mon dernier livre : « Nos Pyrénées »<br>  Parmi celles qui m’ont procuré le plus d’émotions. Des instants fragiles et furtifs volés, figés à jamais dans ma mémoire et sur ces tirages.</p>  <p>Cinquante ans de pratique de la haute montagne sur tous les massifs de la chaîne ont permis cette complicité avec la nature par des rendez-vous improbables, des rencontres avec les caprices de la</p>  <p>météo, toujours en quête de la belle lumière. Je vous invite à partager mon regard...</p>  <p>Francis Annet</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'ff87eadd-2c6e-450f-a905-4632c626ce26');
