INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le système Ribadier de Georges Feydeau', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre par la Compagnie du Baluchon.</p>  <p>Apprenant que son premier mari qu''elle aimait aveuglément l''avait déshonorée par 365 fois en 8 ans de mariage, Angèle, sa veuve, est aujourd''hui sur ses gardes.</p>  <p>Et c''est son nouvel époux, Ribadier qui subit chaque jour sa suspicion et sa rancoeur. Mais Ribadier a un secret : toutes les nuits il a un système infaillible pour sortir discrètement de la maison et échapper à la surveillance de sa femme.</p>  <p>L''arrivée impromptue de Thommereux, ami de la maison revenu d''un long exil à Batavia, vient perturber cette savante organisation. Car Thommereux est secrètement amoureux d''Angèle depuis toujours. Et pour arriver à ses fins et posséder enfin celle qu''il aime, il est prêt à faire imploser le système Ribadier.</p>  <p>« Il faut être très crédule et même pousser la crédulité au maximum. Il faut croire à tout ce qui arrive. Sinon rentrez chez vous, ce n’est pas la peine ! ». disait Georges Feydeau .</p>  <p>En effet, suivant les caractéristiques du vaudeville, l’intrigue de Le Système Ribadier, écrit à la fin du 19ème siècle, enchaîne les rebondissements rocambolesques, les quiproquos et autres apparitions inopinées à un rythme frénétique. Pour prendre du plaisir à suivre ces péripéties, comme le faisaient les spectateurs friands de ce théâtre au 19ème siècle, le spectateur contemporain se doit de les croire vraisemblables, comme il s’autorise à ne pas déceler les incohérences des aventures vécues par les héros de ses séries télévisées préférées.</p>  <p>Au-delà de la question évidente du divertissement cette pièce de Feydeau permet de poser différentes problématiques quant à l’étude du texte théâtral et de sa mise en scène.</p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'aefebb71-e4ce-4588-b49f-6fb7cbda0d03');
