INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('OKIDOKI', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Créateur de musiques cinématiques et polymorphes, le combo franco-allemand Okidoki présente son nouvel EP, voyage fantasmé au pays du Soleil Levant.</p>  <p>Inspiré par l''oeuvre de l''écrivain japonais Haruki Murakami, cet EP ouvre les portes d''un imaginaire où l''improbable devient possible, où la poésie se mèle à l''étrange et le sensible se pare d''une douceur lumineuse.</p>  <p></p>  <p>Laurent ROCHELLE (clarinette basse, sax soprano) :<br>  Musicien en grande partie autodidacte, saxophoniste-clarinettiste puis compositeur, sa nature éclectique et ouverte, son goût de la rencontre lui permettent de se sentir chez lui dans tous les univers. Auteur de musiques toujours originales et très personnelles, ses compositions portent la marque d'' un musicien influencé par la musique classique et le jazz alliant rigueur de l''écriture et douce fantaisie expérimentale. Fortement inspiré par le courant artistique des surréalistes (Magritte, Bunuel, Svankmajer...), sa musique est souvent imagée et empreinte de poésie.<br>  <br>  Frédéric SCHADOROFF (piano, samples) :<br>  Après une formation initiale de piano classique à l’American School of Modern Music à Paris, le parcours de Frédéric Schadoroff croise les routes du jazz et de la chanson française.<br>  Titulaire d’une licence en musicologie, il se passionne pour la pédagogie et enseigne à Music’Halle, l’école des musiques vivantes&nbsp; à Toulouse. Il rejoint l’équipe de Gilles Ramade au théâtre de Pibrac pour plusieurs créations (le Barbier de Séville,les Misérables et West Side Story) et continue sa route avec de nombreux stages et spectacles avec Voix Express dirigés par Hervé Suhubiette. Plus tard il rencontre Catherine Vaniscotte et devient son pianiste-arrangeur dans Magasin ZINZIN et sur le spectacle« Princesses oubliées ou inconnues » (Naïve&nbsp; 2008).<br>  <br>  ANJA KOWALSKI (voix, clavier) :</p>  <p>A effectué sa formation musicale dans différentes écoles: le Jazz-Studio d’Anvers, le Conservatoire de Bruxelles et le Conservatoire de Liège; elle a étudié le chant jazz,la guitare et l’improvisation.</p>  <p>Elle travaille/a travaillé comme chanteuse avec différentes formations et musiciens dont:</p>  <p>Flat Earth Society ( Peter Vermeersch ), David Bovée, Theun Verbruggen, Bart Maris, Giovanni Barcella, Ben Sluis...</p>  <p>Anja chante et joue de la guitare avec ses propres projets musicaux, Wolke, Zwiebel, Seven Stumbling Poets. Elle utilise des ingrédients du jazz, de la pop, de la chanson et de l''improvisation pour développer son style très personnel.</p>  <p>Ces projets l’ont portée sur des scènes nationales (belges) telles que le Middelheim, Blue Note, Brosella, Dranouter, Gaume Jazz, AB, Vooruit, et internationales: Allemagne, Autriche, France, Hollande, Suisse, Angleterre, Norvège, Burkina Faso, Niger.</p>  <p></p>  <p>JEAN-DENIS RIVALEAU (batterie) :</p>  <p>Jean-denis Rivaleau commence à jouer de la batterie dans les clubs bordelais dès l''âge de 13 ans.Il poursuit ses études musicales notamment à la Berklee School à Boston (E-U). Il s''installe à Toulouse en 1988 multipliant les rencontres musicales : Jazz (Ernie Watts, Richard Bona) Musiques du Monde (B.Sandoval) Pop (Zebda) Compositions personnelles (avec le pianiste G.De Chassy et bien d''autres). Il développe parallèlement une carrière pédagogique (prof à Music''Halle depuis 1999, Collège de Marciac, Conservatoire de Colomiers).</p> ​","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '736c87a3-aba2-4a0e-b51a-2a90204d685f');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('OKIDOKI', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Créateur de musiques cinématiques et polymorphes, le combo franco-allemand Okidoki présente son nouvel EP, voyage fantasmé au pays du Soleil Levant.</p>  <p>Inspiré par l''oeuvre de l''écrivain japonais Haruki Murakami, cet EP ouvre les portes d''un imaginaire où l''improbable devient possible, où la poésie se mèle à l''étrange et le sensible se pare d''une douceur lumineuse.</p>  <p></p>  <p>Laurent ROCHELLE (clarinette basse, sax soprano) :<br>  Musicien en grande partie autodidacte, saxophoniste-clarinettiste puis compositeur, sa nature éclectique et ouverte, son goût de la rencontre lui permettent de se sentir chez lui dans tous les univers. Auteur de musiques toujours originales et très personnelles, ses compositions portent la marque d'' un musicien influencé par la musique classique et le jazz alliant rigueur de l''écriture et douce fantaisie expérimentale. Fortement inspiré par le courant artistique des surréalistes (Magritte, Bunuel, Svankmajer...), sa musique est souvent imagée et empreinte de poésie.<br>  <br>  Frédéric SCHADOROFF (piano, samples) :<br>  Après une formation initiale de piano classique à l’American School of Modern Music à Paris, le parcours de Frédéric Schadoroff croise les routes du jazz et de la chanson française.<br>  Titulaire d’une licence en musicologie, il se passionne pour la pédagogie et enseigne à Music’Halle, l’école des musiques vivantes&nbsp; à Toulouse. Il rejoint l’équipe de Gilles Ramade au théâtre de Pibrac pour plusieurs créations (le Barbier de Séville,les Misérables et West Side Story) et continue sa route avec de nombreux stages et spectacles avec Voix Express dirigés par Hervé Suhubiette. Plus tard il rencontre Catherine Vaniscotte et devient son pianiste-arrangeur dans Magasin ZINZIN et sur le spectacle« Princesses oubliées ou inconnues » (Naïve&nbsp; 2008).<br>  <br>  ANJA KOWALSKI (voix, clavier) :</p>  <p>A effectué sa formation musicale dans différentes écoles: le Jazz-Studio d’Anvers, le Conservatoire de Bruxelles et le Conservatoire de Liège; elle a étudié le chant jazz,la guitare et l’improvisation.</p>  <p>Elle travaille/a travaillé comme chanteuse avec différentes formations et musiciens dont:</p>  <p>Flat Earth Society ( Peter Vermeersch ), David Bovée, Theun Verbruggen, Bart Maris, Giovanni Barcella, Ben Sluis...</p>  <p>Anja chante et joue de la guitare avec ses propres projets musicaux, Wolke, Zwiebel, Seven Stumbling Poets. Elle utilise des ingrédients du jazz, de la pop, de la chanson et de l''improvisation pour développer son style très personnel.</p>  <p>Ces projets l’ont portée sur des scènes nationales (belges) telles que le Middelheim, Blue Note, Brosella, Dranouter, Gaume Jazz, AB, Vooruit, et internationales: Allemagne, Autriche, France, Hollande, Suisse, Angleterre, Norvège, Burkina Faso, Niger.</p>  <p></p>  <p>JEAN-DENIS RIVALEAU (batterie) :</p>  <p>Jean-denis Rivaleau commence à jouer de la batterie dans les clubs bordelais dès l''âge de 13 ans.Il poursuit ses études musicales notamment à la Berklee School à Boston (E-U). Il s''installe à Toulouse en 1988 multipliant les rencontres musicales : Jazz (Ernie Watts, Richard Bona) Musiques du Monde (B.Sandoval) Pop (Zebda) Compositions personnelles (avec le pianiste G.De Chassy et bien d''autres). Il développe parallèlement une carrière pédagogique (prof à Music''Halle depuis 1999, Collège de Marciac, Conservatoire de Colomiers).</p> ​","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '736c87a3-aba2-4a0e-b51a-2a90204d685f');
