INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('NOMADES  par Funambule Trio & Alaoua Idir', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Jazz &amp; Musiques du Monde</p>  <p>Nomades ! En route pour un périple entre Maghreb et Europe, empreint de musiques traditionnelles. Reliés par le jazz contemporain, Funambule Trio et le oud d''Alaoua Idir se rencontrent et l''alchimie se produit. Leurs intonations sont différentes, leurs histoires sont différentes. De ces différences, la magie opère.<br>  Rassemblés, les musiciens inventent leur musique, proposent de nouveaux horizons. Cet ensemble improbable aux allures d''orchestre de kiosque nous transporte. Chaque concert est une fête d''où se dégage une envie de partage.<br>  Dialogues, mélanges des cultures, pont entre l''Orient et l''Occident, nos esprits vagabondent par ces compositions originales aux parfums de voyages.</p>  <p style=\"margin-bottom: 0cm\"></p>  <p style=\"margin-bottom: 0cm\">Etienne Lecomte - flûte<br>  Alain Angeli – saxophone alto<br>  Laurent Guitton – tuba<br>  Alaoua Idir, oud</p>  <p style=\"margin-bottom: 0cm\"></p>  <p style=\"margin-bottom: 0cm\"><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '96dde946-2a99-4852-b48a-a6cdeb4548e3');
