INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La Marmaille / Résidence Jazz Pyr''', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans une volonté de poursuivre une histoire commune et de permettre au groupe de poursuivre leur travail scénique et de valoriser ce&nbsp;répertoire, l''association Jazz Pyr'' accueillera La Marmaille pour une semaine de travail en résidence artistique à la Maison du Parc national et de la vallée.</p>  <p><strong>Le vendredi 21 janvier 2022, le groupe sera en concert en itinérance au bar Chez Pierrot à Arcizans-Avant ! </strong></p>  <p></p>  <p>La Marmaille,&nbsp;c’est un brillant carrousel aux sonorités classes et cuivrées, c’est un grand-huit aux grooves abondants, aux drums percutants, c’est un train fantôme qui voyage au pays du jazz tordu et du rock velu.&nbsp;Une «post-fanfare»&nbsp;donc, friande de perles rares issues de répertoires aussi divers que le jazz, le surf, la musique des balkans, le rock bizarre, l’improbable rencontre entre le musette de Jo Privat et le groove de James Brown, une promenade de l’univers de Duke Ellington à celui des B52’S et même&nbsp;de la chanson droit sortie d’un mégaphone,&nbsp;résonances de Kurt Weil, David Bowie ou bien Tom Waits…</p>  <p>Anaïs Andret-Cartini&nbsp;:&nbsp;trompette, chant</p>  <p>Carla Gaudré&nbsp;:&nbsp;saxophone baryton</p>  <p>Nathanaël Renoux :&nbsp;bugle basse</p>  <p>Fréderic Monnier&nbsp;:&nbsp;saxophones ténor et soprano</p>  <p>Kévin Balzan :&nbsp;basse électrique, chant</p>  <p>Loris Pertoldi&nbsp;:&nbsp;batterie</p>  <p>Christophe Calastreng : sonorisation</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '339eff15-a0cf-4ad4-8ca8-aa93e2f4f2ac');
