INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Contes entre deux eaux ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Une invitation à descendre le cours de la Garonne, de la montagne à l’océan, pour une traversée de l’Occitanie où se croisent des princesses espagnoles qui n’aiment pas les fruits, des lutins malicieux qui voudraient bien apprendre à voler, des notes de musiques…</p>  <p>Conteur : Florent Mercadier</p>  <p>À partir de 9 ans.</p>  <p><em>Programmé dans le cadre du festival Contes en hiver.</em></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\"><em>Tarifs</em></a></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f90d9b92-623c-473f-87c7-611b957852e4');
