INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('FANFARE KAR HA PISTOUILL''', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><em>À l''occasion du carnaval, déambulation musicale au départ de l''office de tourisme de Luz.</em></p>  <p>Prenez une grande louchée de surdos et de saxos, rajoutez une cuillerée de clarinettes et de trombones, relevez avec une pincée d''accordéons, saupoudrez de tambourins et de caisses claires, laissez fermenter puis dégustez une musique revisitant les pays de l''Est, l’Afrique, l''Amérique Latine et la Bretagne! Kar Ha Pistouill’, c’est la batucabreizh du Goëlo, des musiciens qui mêlent énergie, amitié, bazar et fantaisie, pour une potion éclectique, joyeuse et détonante.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e785b0ef-51a9-4ec6-84db-9d107bcf6cef');
