INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Abelha - Guillaume Malaret', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>‘Abelha’ (abeille en occitan) est le nom d’une série de pièces de musiques expérimentales et audio-naturalistes utilisant des enregistrements de ruches, d’abeilles et de synthétiseurs. Les diffusions seront effectuées en quadriphonie, sur quatre enceintes disposées autour du public. La performance se déroulera en deux parties.</p>  <p>La première sera la pièce audio-naturaliste, composition créée à partir d’assemblage d’enregistrements d’abeilles et sans apport d’instruments musicaux. Par le montage des prises de sons et leur mise en espace, le but est d’immerger complètement l’auditeur dans cet écosystème sonore riche, comme si nos oreilles se plaçaient à l’intérieur d''une ruche.</p>  <p>La seconde pièce, quant à elle, optera pour le parti pris opposé. Cette composition sera créée à partir de transformations des enregistrements d’abeilles, modifiés et assemblés selon la pratique de composition de Guillaume Malaret, utilisant différents outils tels que l''ordinateur, des synthétiseurs et des magnétophones à bandes.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '64eba323-cf8b-4604-955f-7ec0d639c67a');
