INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Cartes blanches', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Compagnie Les Jolies Choses</p>  <p>Conscient de l’état d’urgence face aux évolutions climatiques et paysagères qui fragilisent les milieux de montagne, le Parc national des Pyrénées, maître d’ouvrage du projet, et ses partenaires s’engagent dans une campagne de sensibilisation des habitants et des visiteurs des vallées des Gaves.</p>  <p>Le Parc national des Pyrénées souhaite expérimenter une approche de ce sujet par le sensible.</p>  <p>La prise de parole sous différentes formes de collectage tout autant que leur restitution théâtrale est ainsi un moyen de régénérer un lien inter-vallées autour de préoccupations sociétales et environnementales qui nous concernent tous.</p>  <p>La parole n’est pas ici celle des experts, mais bien la parole de ceux qui font notre quotidien.</p>  <p>Une fois recueillis, tous les témoignages écrits et sonores des vallées sont transmis, à trois compagnies professionnelles locales d’arts vivants dont la Cie Les Jolies Choses qui ont ensuite « Cartes Blanches » pour livrer leur interprétation et restituer la parole du territoire. Une façon immersive, sensible et participative de prendre conscience de la thématique du changement climatique.</p>  <p>Un projet porté par la Cie La Tong en collaboration avec Paroles Paroles et Fréquence Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9c997f95-b18e-49f3-999d-6e7443808051');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Cartes blanches', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Compagnie Les Jolies Choses</p>  <p>Conscient de l’état d’urgence face aux évolutions climatiques et paysagères qui fragilisent les milieux de montagne, le Parc national des Pyrénées, maître d’ouvrage du projet, et ses partenaires s’engagent dans une campagne de sensibilisation des habitants et des visiteurs des vallées des Gaves.</p>  <p>Le Parc national des Pyrénées souhaite expérimenter une approche de ce sujet par le sensible.</p>  <p>La prise de parole sous différentes formes de collectage tout autant que leur restitution théâtrale est ainsi un moyen de régénérer un lien inter-vallées autour de préoccupations sociétales et environnementales qui nous concernent tous.</p>  <p>La parole n’est pas ici celle des experts, mais bien la parole de ceux qui font notre quotidien.</p>  <p>Une fois recueillis, tous les témoignages écrits et sonores des vallées sont transmis, à trois compagnies professionnelles locales d’arts vivants dont la Cie Les Jolies Choses qui ont ensuite « Cartes Blanches » pour livrer leur interprétation et restituer la parole du territoire. Une façon immersive, sensible et participative de prendre conscience de la thématique du changement climatique.</p>  <p>Un projet porté par la Cie La Tong en collaboration avec Paroles Paroles et Fréquence Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '9c997f95-b18e-49f3-999d-6e7443808051');
