INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('ANNULÉ - COVID / Sortie de résidence - Horizon à la hache ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"color:#e74c3c;\"><strong>ANNULÉ - COVID</strong></span></p>  <p>La formation existe depuis 7 ans et reçoit le soutien de structures culturelles comme La Gespe ou Fréquence Luz.</p>  <p>Chacun des acteurs de ce projet a déjà œuvré à des créations musicales, scéniques, plastiques et littéraires. La démarche d’Horizon à la Hache est d’aligner des portraits comme on accroche des wagons à un transport de matériaux humains. Ils proposent de les mettre en voix et en musique, en donnant une couleur particulière aux travers épinglés de l’homme occidental. « Du Gravier sur les Rails » en est le titre.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd8403b5d-eb09-4369-b480-558042111092');
