INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Et les astres / Aphélie Compagnie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre musique par la Compagnie Aphélie.</p>  <p></p>  <p>Une salle de classe. Dans cet espace, un·e cosmonaute.</p>  <p>Difficile de dire si c''est un·e élève farfelu·e, un·e scientifique excentrique venu·e témoigner de son parcours professionnel ou simplement, une personne loufoque égarée... Difficile même de discerner le songe de la réalité, de nos jours ou d''hier... sommes-nous vraiment dans une salle de classe ?</p>  <p>Elle·il se met à parler, bien sûr, témoigne, slame, des pensées foutraques, des paroles analytiques sur ce qu''on est, ce qu''on fait, ce qu''on a en commun, ce qui nous empêche...</p>  <p>Au fur et à mesure, la pensée se structure. Une identité à la fois singulière et universelle se dessine sous ce costume étrange. Entre colère et ennui, avec \"l''amour du faire\" ou \"l''amour du beau\", le discours se déploie progressivement autour d''une question : comment se construire et espérer si l''on n''a pas de rêve ? Si l''on en est dépossédé·e ?</p>  <p><strong>Auteure et Interprète : </strong>Laurie Montamat</p>  <p><strong>Création musicale et interprétation :</strong> Laurent-Pierre Collette</p>  <p><strong>Direction d''actrice et regard extérieur:</strong> Charlotte Piarulli</p>  <p>Partenaires : Artcena (Aide Nationale à la création de textes dramatiques 2021), Aphélie Cie.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1dbb8edb-5363-4a63-b7dd-e7a7ba2573a6');
