INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence Toto et les sauvages', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Spectacle musical.</p>  <p>A l’origine ce groupe est issu d’un collectif d’artistes (“Les Sauvages Colorés”) qui forme une chorale autour des chansons de Thomas Skrobek (“Toto”)en 2015. La douzaine de choristes a, depuis, pris goût à l’aventure et s’est frayée un joli chemin dans la faune artistique bordelaise et d’ailleurs. Quand cet ensemble de musicien.ne.s, comédien.ne.s et danseur.euse.s se retrouve en concert, une folie douce émane de la scène... Dès lors, la présence de multiples voix est un élément central et la musique, une invitation à la réflexion et au lâcher prise, à la poésie et à la danse ! Ces voix s’harmonisent, se répondent, racontent des histoires et chantent en chœur, ou en solo, au point qu’un concert de “Toto et les Sauvages” se rapproche parfois d’un spectacle musical.</p>  <p>Stimulé par des collaborations pérennes avec des musiciens d’expériences, comme par la dynamique de création, le groupe s’ organise aujourd’hui en une formation collective et polymorphe pour créer un nouveau format qui lui ressemble et qui rassemble. La nouvelle création est coécrite par tou.te.s les membres du groupe: de nouvelles chansons (mêlant rock, folk, trip hop musique traditionnelles des Balkans et de Bretagne, et musiques d’Afrique), une nouvelle scénographie, et une dramaturgie qui font un peu plus basculer le concert vers une forme hybride à la croisée des arts vivants. Qu’il.elle.s jouent sur de grandes scènes dédiées ou sur de petites scènes, en extérieur ou en salle, les concerts sonnent à chaque fois comme un moment de communion festif avec les publics.</p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarif</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'dbc71fd3-c3ac-488c-ab26-0c3ca3958fa6');
