INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Microplastiques aux sommets des Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Les Pyrénées, chaîne de montagnes emblématiques entre Océan et Mer, ont peu d''activités industrielles ou minières actuellement sur leur territoire.</p>  <p>Toutefois les micropolluants comme les microplastiques parviennent jusqu''au sommet des montagnes et sont détectés par les chercheurs: en Ariège, au Pic du Midi.</p>  <p>Quelle est l''origine de ces microplastiques? Quel est l''impact potentiel sur les écosystèmes sensibles de montagne?</p>  <p>A travers des exemples issus des projets Plasticopyr et ATMO-PLASTIC, Gaël Le Roux et Jeroen Sonke, chercheurs CNRS de l''Observatoire Midi-Pyrénées se proposent de suivre le voyage et l''histoire des plastiques jusqu''aux sommets enneigés des Pyrénées.</p>  <p><i>Gaêl Le Roux-Jeroen Sonke CNRS Observatoire Midi-Pyrénées Toulouse.</i></p> &nbsp;  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9945e74f-ed74-4305-82fe-f2d0275ff0c8');
