INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('País de Flors - Exposition photographique - Jacob Redman', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>En écho à la résidence menée en 2021 autour de la création cinématographique du collectif Kovisuel, cette exposition photographique de Jacob Redman offre un regard artistique sur la flore vulnérable du Pays Toy.<br>  Un travail de textures et de matières qui renouvelle le regard que l''on porte sur des fleurs emblématiques du territoire.</p> &nbsp;  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '70ce7587-30ab-4706-9823-2f47ea791cfc');
