INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('(A) More', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Création solo 2021/2022 : danse, théâtre.&nbsp; Tout public à partir de 7 ans. </strong></p>  <p><strong>Chorégraphe, auteure, interprète : Claire Lamothe</strong></p>  <p><strong>Plasticienne : Charlotte Thomas</strong></p>  <p><strong>Musique : Damien Fleau</strong></p>  <p>Une femme, dans un monde en lambeaux portant ses noeuds, ceux dont on hérite, ceux que l’on se tisse, sous le poids elle tient.</p>  <p>Elle avance, dans l’action, attendant le prochain train, la prochaine destination, le prochain arrêt.</p>  <p>Errer, pourtant ne jamais s’arrêter de faire, le temps se déroule, les pieds trépignent l’envie d’être, déjà, ailleurs, l’oubli du là, l’absence du rien.</p>  <p>Peur de passer à coté de toutes ces choses, de ce que l’on pourrait faire.</p>  <p>Ne rien faire par peur de rater le fait de faire.</p>  <p>Elle voudrait.. sans trop savoir exactement, faire, ou défaire moins.</p>  <p>Rituels. Solitude. Défaire sans se taire.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '13f339ce-258e-4f88-a0a8-8480e430eaea');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('(A) More', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Création solo 2021/2022 : danse, théâtre.&nbsp; Tout public à partir de 7 ans. </strong></p>  <p><strong>Chorégraphe, auteure, interprète : Claire Lamothe</strong></p>  <p><strong>Plasticienne : Charlotte Thomas</strong></p>  <p><strong>Musique : Damien Fleau</strong></p>  <p>Une femme, dans un monde en lambeaux portant ses noeuds, ceux dont on hérite, ceux que l’on se tisse, sous le poids elle tient.</p>  <p>Elle avance, dans l’action, attendant le prochain train, la prochaine destination, le prochain arrêt.</p>  <p>Errer, pourtant ne jamais s’arrêter de faire, le temps se déroule, les pieds trépignent l’envie d’être, déjà, ailleurs, l’oubli du là, l’absence du rien.</p>  <p>Peur de passer à coté de toutes ces choses, de ce que l’on pourrait faire.</p>  <p>Ne rien faire par peur de rater le fait de faire.</p>  <p>Elle voudrait.. sans trop savoir exactement, faire, ou défaire moins.</p>  <p>Rituels. Solitude. Défaire sans se taire.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '13f339ce-258e-4f88-a0a8-8480e430eaea');
