INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Dictionnaire gascon - Conférence par Jean-Louis MASSOURE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<h3>Jean-Louis Massourre présente son Dictionnaire gascon de la Haute Bigorre.</h3> &nbsp;  <p>UN DICTIONNAIRE GASCON DE RÉFÉRENCE</p>  <p><br role=\"presentation\">  La maison d’édition de la Société de Linguistique Romane, les Éditions ELiPHI de Strasbourg1 viennent d’éditer la seconde édition, considérablement augmentée du Dictionnaire gascon de la Haute-Bigorre de Jean-Louis Massourre. Cet ouvrage fait désormais 620 pages en format-texte 17x24 cm au lieu de 280. Il réunit en 4 200 articles lexicologiques quelque 10 000 sens lexicaux et plusieurs milliers d’expressions qui structurent le dialecte ancestral des vallées de Luz-Saint-Sauveur, de Barèges et de Gavarnie.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '50d52503-4104-4455-8bb7-6313346ed213');
