INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie  de résidence Biso - Muziki', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Biso est le nouveau projet du jeune batteur Chacha Angela.</p>  <p>Il a développé sa propre musique en puisant dans ses racines congolaises et en s’inspirant des musiques actuelles : jazz + pop + funk + rock et bien d''autres styles…</p>  <p>Chacha chante en Lingala, sa langue natale, et joue aussi du balafon, instrument traditionnel fabriqué à partir de lattes de bois et de calebasses. Il nous raconte sa culture, la fraternité et la musique (muziki) qu’il considère comme la richesse de ses ancêtres.</p>  <p>Biso met l''accent sur la valorisation du métissage entre la musique de l''Afrique et celle de l''Occident.</p>  <p></p>  <p>Line up :</p>  <p>Chacha (percussions, chant, balafon) / Stéphane Lopez (contre-basse) / Nils Fréchilla (guitare) / Antoine Perrut (saxophone)</p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarif</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1da5f269-aac5-4dca-9b4d-00387a96c382');
