INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Bêtes de foire ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Cirque, à partir de 8 ans.</strong></p>  <p><strong>Lieu : au Verger de Luz.</strong></p>  <p>Prenez un (tout) petit chapiteau, un gradin pentu, ajoutez-y des rouleaux de tissus, des tas de chaussures et de chapeaux, des machines à coudre ou à autre chose, placez au centre deux circassiens entourés d’étranges personnages. Laissez la magie prendre pendant une heure, le temps que ce cirque miniature vous harponne, et savourez sans aucune modération.</p>  <p>Costumière mais aussi comédienne pour des compagnies de théâtre de rue, Elsa de Witte connaît bien le rafistolage, la bidouille et l’art du recyclage. Laurent Cabrol, passé par l’école d’Annie Fratellini, le cirque Romanès et cofondateur du cirque Trottola avec Titoune et Bonaventure Gacon, en a gardé un goût affirmé pour des spectacles maison à dimension humaine. En famille, ils nous parlent d’eux. Bêtes de foire n’est rien d’autre que leurs parcours de scène et de vie où s’emmêlent la marionnette, le théâtre, la danse, les arts du cirque et surtout la magie de créer du rêve avec deux bouts de ficelle et trois fois rien.<br>  Funambules, homme-orchestre, acrobates, homme élastique et tous leurs acolytes sont bricolés dans l’atelier installé en fond de scène. Elsa de Witte transforme une vieille fripe, un bout de métal et une paire de bottines en vedette du prochain numéro. Les personnages s’avancent alors dans la lumière et prennent vie entre les doigts experts de Laurent Cabrol, pour un tour de piste face au public. Sous ses airs de clown post-moderne qui travaille du chapeau, il compose avec toute cette clique de personnages fantasques, le ballet émouvant d’un cirque miniature et grandiose.<br>  Un univers chatoyant, loufoque et poétique, un petit théâtre de gestes qui ne s’oublie plus.</p>  <p></p>  <p><strong>DISTRIBUTION :</strong></p>  <p>en piste <strong>Laurent Cabrol, Elsa De Witte,</strong> et <strong>Sokha</strong><br>  sculpture personnages<strong> Steffie Bayer</strong><br>  construction personnages <strong>Ana Mano, Thierry Grand</strong><br>  création musicale <strong>Mathias Imbert, Natacha Muet, Piéro Pépin, Eric Walspeck</strong><br>  création son <strong>Francis Lopez</strong><br>  création lumières <strong>Hervé Dilé, Fabien Viviani</strong><br>  gradins <strong>Fred Sintomer</strong><br>  administration <strong>Les Thérèses</strong></p>  <p></p>  <p><strong>CO-ORGANISÉE AVEC LE PARVIS (Scène nationale Tarbes Pyrénées)</strong></p>  <p><a href=\"https://parvis.notre-billetterie.net/billets?kld=2122\">Billeterie en ligne</a></p>  <p>Le chapiteau de <em>Bêtes de Foire</em> accueillera aussi trois découvertes musicales, proposées en partenariat avec Jazz à Luz, qui témoignent de la créativité des musiciens installés en Occitanie et soutenus par le réseau Occijazz.<br>  - <a data-entity-substitution=\"canonical\" data-entity-type=\"node\" data-entity-uuid=\"d5a884ca-d12e-4083-a841-80d20741dae3\" href=\"https://www.parvis.net/spectacle-vivant/lila-bazooka\" title=\"Lila Bazooka\">Lila Bazooka</a>, le jeu. 5 mai, à Luz-Saint-Sauveur<br>  - <a data-entity-substitution=\"canonical\" data-entity-type=\"node\" data-entity-uuid=\"511c1745-03f1-4659-b227-c060cc92884b\" href=\"https://www.parvis.net/spectacle-vivant/tarzan-tarzan\" title=\"Tarzan &amp; Tarzan\">Tarzan &amp; Tarzan</a>, le jeu. 12 mai, à Séméac<br>  - <a data-entity-substitution=\"canonical\" data-entity-type=\"node\" data-entity-uuid=\"9ab4887a-be7c-4d58-bdb1-7b24b9cbe507\" href=\"https://www.parvis.net/spectacle-vivant/sket\" title=\"By the sket\">By the Sket</a>, le jeu. 19 mai, à Pouzac</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0e0195c4-b279-4e8b-9462-9db5510b1965');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Bêtes de foire ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Cirque, à partir de 8 ans.</strong></p>  <p><strong>Lieu : au Verger de Luz.</strong></p>  <p>Prenez un (tout) petit chapiteau, un gradin pentu, ajoutez-y des rouleaux de tissus, des tas de chaussures et de chapeaux, des machines à coudre ou à autre chose, placez au centre deux circassiens entourés d’étranges personnages. Laissez la magie prendre pendant une heure, le temps que ce cirque miniature vous harponne, et savourez sans aucune modération.</p>  <p>Costumière mais aussi comédienne pour des compagnies de théâtre de rue, Elsa de Witte connaît bien le rafistolage, la bidouille et l’art du recyclage. Laurent Cabrol, passé par l’école d’Annie Fratellini, le cirque Romanès et cofondateur du cirque Trottola avec Titoune et Bonaventure Gacon, en a gardé un goût affirmé pour des spectacles maison à dimension humaine. En famille, ils nous parlent d’eux. Bêtes de foire n’est rien d’autre que leurs parcours de scène et de vie où s’emmêlent la marionnette, le théâtre, la danse, les arts du cirque et surtout la magie de créer du rêve avec deux bouts de ficelle et trois fois rien.<br>  Funambules, homme-orchestre, acrobates, homme élastique et tous leurs acolytes sont bricolés dans l’atelier installé en fond de scène. Elsa de Witte transforme une vieille fripe, un bout de métal et une paire de bottines en vedette du prochain numéro. Les personnages s’avancent alors dans la lumière et prennent vie entre les doigts experts de Laurent Cabrol, pour un tour de piste face au public. Sous ses airs de clown post-moderne qui travaille du chapeau, il compose avec toute cette clique de personnages fantasques, le ballet émouvant d’un cirque miniature et grandiose.<br>  Un univers chatoyant, loufoque et poétique, un petit théâtre de gestes qui ne s’oublie plus.</p>  <p></p>  <p><strong>DISTRIBUTION :</strong></p>  <p>en piste <strong>Laurent Cabrol, Elsa De Witte,</strong> et <strong>Sokha</strong><br>  sculpture personnages<strong> Steffie Bayer</strong><br>  construction personnages <strong>Ana Mano, Thierry Grand</strong><br>  création musicale <strong>Mathias Imbert, Natacha Muet, Piéro Pépin, Eric Walspeck</strong><br>  création son <strong>Francis Lopez</strong><br>  création lumières <strong>Hervé Dilé, Fabien Viviani</strong><br>  gradins <strong>Fred Sintomer</strong><br>  administration <strong>Les Thérèses</strong></p>  <p></p>  <p><strong>CO-ORGANISÉE AVEC LE PARVIS (Scène nationale Tarbes Pyrénées)</strong></p>  <p><a href=\"https://parvis.notre-billetterie.net/billets?kld=2122\">Billeterie en ligne</a></p>  <p>Le chapiteau de <em>Bêtes de Foire</em> accueillera aussi trois découvertes musicales, proposées en partenariat avec Jazz à Luz, qui témoignent de la créativité des musiciens installés en Occitanie et soutenus par le réseau Occijazz.<br>  - <a data-entity-substitution=\"canonical\" data-entity-type=\"node\" data-entity-uuid=\"d5a884ca-d12e-4083-a841-80d20741dae3\" href=\"https://www.parvis.net/spectacle-vivant/lila-bazooka\" title=\"Lila Bazooka\">Lila Bazooka</a>, le jeu. 5 mai, à Luz-Saint-Sauveur<br>  - <a data-entity-substitution=\"canonical\" data-entity-type=\"node\" data-entity-uuid=\"511c1745-03f1-4659-b227-c060cc92884b\" href=\"https://www.parvis.net/spectacle-vivant/tarzan-tarzan\" title=\"Tarzan &amp; Tarzan\">Tarzan &amp; Tarzan</a>, le jeu. 12 mai, à Séméac<br>  - <a data-entity-substitution=\"canonical\" data-entity-type=\"node\" data-entity-uuid=\"9ab4887a-be7c-4d58-bdb1-7b24b9cbe507\" href=\"https://www.parvis.net/spectacle-vivant/sket\" title=\"By the sket\">By the Sket</a>, le jeu. 19 mai, à Pouzac</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '0e0195c4-b279-4e8b-9462-9db5510b1965');
