INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Femme de crobatie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Laboratoire de recherche - Acrodanse &amp; Montage</p>  <p>Sept femmes de la collective de Femmes de Crobatie ont été invitée par la Maison du Parc national et de la vallée.</p>  <p>Durant une semaine elles dérouleront un laboratoire de recherche basé sur la pratique commune de l’acrodanse. Cette semaine sera orientée sur une mise en espace particulière de leurs recherches puisqu’elles inscriront leurs danses et acrobaties entres les arbres &amp; les roches des montagnes des Pyrénées.</p>  <p>La résidence se déroulera au forum de Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '21783de4-cbc6-4c14-8622-91f5b4eb7c2d');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Femme de crobatie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Laboratoire de recherche - Acrodanse &amp; Montage</p>  <p>Sept femmes de la collective de Femmes de Crobatie ont été invitée par la Maison du Parc national et de la vallée.</p>  <p>Durant une semaine elles dérouleront un laboratoire de recherche basé sur la pratique commune de l’acrodanse. Cette semaine sera orientée sur une mise en espace particulière de leurs recherches puisqu’elles inscriront leurs danses et acrobaties entres les arbres &amp; les roches des montagnes des Pyrénées.</p>  <p>La résidence se déroulera au forum de Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '21783de4-cbc6-4c14-8622-91f5b4eb7c2d');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Femme de crobatie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Laboratoire de recherche - Acrodanse &amp; Montage</p>  <p>Sept femmes de la collective de Femmes de Crobatie ont été invitée par la Maison du Parc national et de la vallée.</p>  <p>Durant une semaine elles dérouleront un laboratoire de recherche basé sur la pratique commune de l’acrodanse. Cette semaine sera orientée sur une mise en espace particulière de leurs recherches puisqu’elles inscriront leurs danses et acrobaties entres les arbres &amp; les roches des montagnes des Pyrénées.</p>  <p>La résidence se déroulera au forum de Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '21783de4-cbc6-4c14-8622-91f5b4eb7c2d');
