INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Tôle Story, répertoire d’un chaos - Cie D''Elles', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Compagnie D''elles</p>  <p>Sarah Mathon&nbsp;: comédienne narratrice de haut vol<br>  Karita Tikka&nbsp;: aérienne rase-mottes<br>  Sophia Antoine&nbsp;: échassière bouineuse<br>  <br>  Tôle Story, c’est l’histoire mémorable et mythique du spectacle le plus démesuré du cirque contemporain&nbsp;: « Métal Clown ». Avec ses 120 artistes au plateau, ses 3000 spectateurs, son convoi de 1,5 km, « Métal Clown » a tout d''une légende ! Et quoi de plus jouissif pour les 3 artistes de la Compagnie d’Elles que de jouer sur les formats, en faisant entrer le plus gros spectacle du cirque contemporain, dans un format réduit ? Les rues de Luz-Saint-Sauveur n''ont plus qu''à trembler, la bourrasque va souffler, la tôle va siffler, la tronçonneuse va brailler, le chaos va débarquer, Tôle Story va se raconter, histoire et la fiction mêlées !</p>  <p></p>  <p>Rdv à 17h Place des Templiers / Programmation en collaboration avec l''association Jazz Pyr'' dans le cadre de l''inauguration du festival Jazz à Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '981538d9-fe73-42c9-952e-56141b809928');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Tôle Story, répertoire d’un chaos - Cie D''Elles', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Compagnie D''elles</p>  <p>Sarah Mathon&nbsp;: comédienne narratrice de haut vol<br>  Karita Tikka&nbsp;: aérienne rase-mottes<br>  Sophia Antoine&nbsp;: échassière bouineuse<br>  <br>  Tôle Story, c’est l’histoire mémorable et mythique du spectacle le plus démesuré du cirque contemporain&nbsp;: « Métal Clown ». Avec ses 120 artistes au plateau, ses 3000 spectateurs, son convoi de 1,5 km, « Métal Clown » a tout d''une légende ! Et quoi de plus jouissif pour les 3 artistes de la Compagnie d’Elles que de jouer sur les formats, en faisant entrer le plus gros spectacle du cirque contemporain, dans un format réduit ? Les rues de Luz-Saint-Sauveur n''ont plus qu''à trembler, la bourrasque va souffler, la tôle va siffler, la tronçonneuse va brailler, le chaos va débarquer, Tôle Story va se raconter, histoire et la fiction mêlées !</p>  <p></p>  <p>Rdv à 17h Place des Templiers / Programmation en collaboration avec l''association Jazz Pyr'' dans le cadre de l''inauguration du festival Jazz à Luz.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '981538d9-fe73-42c9-952e-56141b809928');
