INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('7463df3e-eb82-4682-b852-c0e88395482e', 'exposition', true, false, NULL, '2022-05-31T22:00:00.000Z', '2022-07-10T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2022-05-31T22:00:00.000Z', '2022-05-31T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Nature" par Martine Capdeville Lacomme', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Martine Capdeville-Lacomme, MCL, artiste plasticienne expose sur toiles un travail de composition en lien étroit avec la nature.</p>  <p>Au fil de ses longues marches méditatives en forêt, elle découvre au cœur des Hautes Pyrénées une belle matière naturelle : l’écorce d’arbre de bouleau, sa source d’inspiration.<br>  Sa texture, sa couleur, sa forme suscitent en elle l’idée de la travailler en lui inventant un autre univers, une nouvelle vie.</p>  <p>Ainsi démarre un long travail de recherche sur l’élaboration de sa propre technique (récolte, presse, séchage, fabrication pâte à coller, protection pour pérenniser l’œuvre) sur différents supports (toiles ou papiers de fabrication artisanale)</p>  <p>Au travers de l’écorce, des végétaux (lichens, champignons) et du sable de différents déserts de la planète MCL crée une mise en scène d’éléments naturels qui deviennent messages. Messages car l’écorce nous parle, l’arbre, la Terre, les racines, tout s’en mêle et s’entremêle. Cette écorce récoltée au sol dans sa forme initiale, sa couleur originelle, à l’endroit ou à l’envers, sans découpage, ni outil, pièce par pièce est fixée sur la toile par pur imaginaire. Une légère couche de pigments naturels colorés harmonise et finalise le tableau.</p>  <p>Intemporelles, authentiques, uniques et pourtant si délicates, les compositions de Martine Capdeville-Lacomme laissent libre cours à notre imaginaire éveillant tous nos sens.</p>  <p>Attirée par l’énergie des arbres, Martine Capdeville-Lacomme essaie de traduire au travers de ses toiles toute l’émotion qui la traverse face à la beauté, la magnificence de la Nature et plus précisément de ses forêts.</p>  <p>C’est un long travail, innovant, de créativité pure, basé essentiellement sur le ressenti au travers de cette matière naturelle.<br>  Et donc,<br>  L’écorce nous offre le décor...</p>  <p>À nous d’inventer l’histoire qui va avec...</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7463df3e-eb82-4682-b852-c0e88395482e');
