INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fanfare "Le Mystère des éléphants"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Ouvrez grandes vos oreilles, voici Le Mystère des Éléphants! Ne vous attendez pas à de la ... trompinette puisque, cornaqué par leur percussionniste, c''est aux saxophones qu''ils vont faire sonner leurs airs de fête, puisés dans la mémoire légendaire des peuples de la terre. Et tous les éléphants chanteront sous les étoiles et laisseront aller leurs corps lourds à la danse et la rêverie...</p>  <p>Florian Nastorg (saxophone baryton)</p>  <p>Loïc PAPILLON (saxophone soprano)</p>  <p>David Mimey (saxophone alto)</p>  <p>Florian TRIBY (batterie)</p>  <p></p>  <p>Programmée dans le cadre de la fête de St Sauveur au quartier thermal.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c4258714-6d8a-422a-8417-3d5c5f56b582');
