INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Wanted - Bruital Cie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Wanted est une parodie du western, entièrement mimée et sonorisée par une comédienne et un bruiteur. Il est la voix, elle est le corps et à eux deux ils jouent tous les personnages du Far West, du shérif orgueilleux au bandit sanguinaire en passant par le banquier, le prisonnier et la femme fatale. Avec une synchronisation précise, ils s’amusent des clichés à la façon du cartoon, et racontent entre les lignes du western une autre histoire, la leur, un peu absurde et un brin tragique.</p>  <p><strong>Distribution :</strong></p>  <p>De et par : Barnabé Gautier et Lorraine Brochet</p>  <p>Co-écriture : Anne Bouchard</p>  <p>Regard extérieur : Martin Votano</p>  <p></p>  <p>Durée : 50 min /&nbsp; À partir de 10 ans.</p>  <p></p>  <p><em>Programmé dans le cadre de la fête de St Sauveur au quartier thermal. </em></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1e44a388-bf91-41bc-a503-c86db8f82c89');
