INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Lichen - Cie L''envolée Cirque ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"color:#c0392b;\"><strong>REPLI AU GYMNASE DE LUZ EN RAISON DES CONDITIONS METEO ANNONCEES&nbsp;</strong></span></p>  <p></p>  <p>Spectacle aérien de et avec Pauline Barboux, Jeanne Ragu- acrobates aériennes et Mauro Basilio -violoncelliste.</p>  <p>« Lichen » est un spectacle qui invite à la contemplation. Trois individus évoluent dans un espace circulaire ou le sol se meut au gré du vent. Portées par la musique de l’un, l’une et l’autre vont jouer de leurs similitudes et de leur complémentarité pour s’extraire de cet univers indocile.</p>  <p>Au sol et en l’air, les corps usent d’agilité et de défis pour jouer avec la gravité, s’élever, s’offrir à l’autre, se confondre. Une évolution aérienne, à deux, entre équilibres, contre-poids et imbrications des corps, une danse ou l’une ne tient pas sans l’autre.</p>  <p>Tout en lenteur, les corps dessinent des évolutions acrobatiques, poétiques, qui font de ce duo une allégorie du caractère symbiotique du Lichen.</p>  <p>Tout public - Durée 30 minutes</p>  <p>Partenaires: avec le soutien de la Briqueterie - CDC du Val de Marne(94) et de L’Académie Fratellini (93)</p>  <p></p>  <p>Programmé dans le cadre des mercredis artistiques au Verger de Luz.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e5f97a4c-efa9-4174-9256-627d6219088e');
