INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mandiwa', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Trio jazz métissé</p>  <p>Diwa, la racine du mot mandiwa, signifie esprit, âme, idée, pensée.</p>  <p>La finesse et la limpidité des compositions de Mandiwa permettent à l''auditeur de se laisser dériver dans un univers qui navigue entre exotisme et classicisme, allant de l''Afrique centrale à l''Europe de l''est en passant par le gnawa ...</p>  <p>La guitare de David Clavel et le saxophone de Dirk Vogeler créent une alchimie entre rythmes d’ailleurs et mélodies personnelles, dans laquelle s’immiscent les vocalises des musiciens.</p>  <p>Le percussionniste toulousain Jean-Loup Perry s''est joint aux deux fondateurs du groupe en été 2019.</p>  <p>La rencontre riche en énergie des trois musiciens fait naître des échanges musicaux improvisés et authentiques : Mandiwa est une invitation au voyage à la fois poétique et débridé, entre exotisme et classicisme.</p>  <p>Dirk Vogeler : saxophones, clarinette basse, voix / David Clavel : guitare, voix / Jean-Loup Perry : percussions, voix</p>  <p>(Madiwa été en résidence à la Maison du Parc national et de la vallée en novembre 2021)</p>  <p></p>  <p><em>Programmé dans le cadre des mercredis artistiques, ampithéâtre extérieur de la Maison du Parc national et de la vallée. </em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e556b27f-774a-4b4b-b778-c1ee7f92e2cf');
