INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La mare où l''on se mire - Cie Chientdent Théâtre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Projet pour un opéra fantaisie avec canards répétiteurs.</p>  <p>\"Je vais monter un opéra, il sera prêt pour dans deux ans. En attendant, je me suis dit, que ce serait bien de faire un tour de France pour présenter une maquette de mon futur opéra, comme ça quand dans deux ans vous viendrez le voir, on sera plus ensemble. Pour mon 1er opéra, je me suis inspiré du Vilain petit canard d''Andersen, mais avec un point de vue résolument moderne, je vous en dis pas plus. Je suis accompagné par des canards qui me donnent la réplique pour comprendre, pas à pas, tout le déroulé dramatique et sensible de mon opéra. \" Norbert.</p>  <p>Écriture et jeu : Fabrice Groléat - Accompagnement à la mise en scène : Stéphanie Saint-Cyr Lariflette<br>  Table camping-maquette : Balthazar Voronkoff - Soudures sur canards : Gilles Grazilly -<br>  Photos : ©Edwige Pluchart-Maury et ©Sandrine De Pas / Diffusion : Lucie Ianno</p>  <p>Création soutenue par le Département des Alpes de Haute-Provence dans le cadre d''un conventionnement.</p>  <p>40 mins / Tout public à partir de 6 ans.</p>  <p></p>  <p><em>Programmé dans le cadre des mercredis artistiques au Parc Massoure.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '987ea551-ea5f-4a91-aecd-3c26c15c0cb4');
