INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Faces nord - Cie La Féroce', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>“Faces Nord” est une pièce en cours de création qui mêle les arts du cirque de Laurette Gougeon et la création sonore de Claire Lauzon.</p>  <p>Grâce à une série d’entretiens, les voix des habitants des territoires de montagne nourrissent le processus de création artistique pour venir interroger notre rapport intime à la montagne…<br>  <br>  Laurette Gougeon engage corps et voix, s’appuyant sur la pratique du cirque, du clown et du récit pour tenter d’appréhender cette fascination qu’ont les femmes et les hommes pour les sommets.<br>  Comment transmettre l''indicible bonheur d''être là haut ? Comment raconter l''attirance du vide et l''ivresse de l''altitude ?<br>  “Faces Nord” parle de notre rapport au risque, à l’accident, au deuil. De l’absence mais aussi, et surtout, de force.<br>  Solo d’une trentaine de minutes, le spectacle est pensé pour être joué dans les refuges de haute montagne. Il donnera lieu à trois tournées itinérantes à pied dans les hauteurs des parcs naturels des Ecrins, du Queyras et des Pyrénées cet été. Il sera joué en salle et lieu non dédié dès l’automne 2022.</p>  <p></p>  <p>Ecriture, jeu: Laurette Gougeon</p>  <p>Création sonore, récolte de témoignage: Claire Lauzon (Histoire de Dire)</p>  <p>Regard Extérieur: Manon Delage (Collectif Akalmie Celcius), Anaïs Blanchard (Collectif de La Méandre)</p>  <p>Musique: Alice Huc</p>  <p>Intervenant technique: Yannick Lataste</p>  <p>Chargée de production : Gitanjali Picovschi</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '39ddac87-534e-4cf3-92f0-c7bf2e88ff1f');
