INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Projection débat "Des parcs et des hommes"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Vous saurez tout sur la biodiversité du Parc National des Pyrénées grâce à ce film qui vous emmènera à la rencontre de la faune et de la flore emblématiques des Pyrénées. Vous pourrez également découvrir la vie de l’homme en montagne. Un échange avec un garde-moniteur complétera la projection de ce film.","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'cd82d5fc-f0b5-46e4-8849-1b5a46d13bdb');
