INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Échos" Cie Les Jolies Choses - Projet Cartes Blanches', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>\"ÉCHOS\" de théâtre, de corps et de paroles d''habitants.</p>  <p>Échos de paroles, Échos de la nature, Échos du monde... Comment les questions et les enjeux climatiques résonnent-ils ? La Cie les Jolies Choses vous emporte dans une randonnée immobile, immersive et sensible qui questionne l’écologie en s’inspirant de témoignages, comme une hybridation ethno-artistique à la croisée des chemins.</p>  <p>Théâtre &amp; texte : Mélia Bannerman / Conte : Nathalie Lhoste-Clos / Texte &amp; Danse : Sophie Barros</p>  <p></p>  <p><strong><em>Projet porté par la Cie La Tong et le Parc national des Pyrénées, en partenariat avec la Maison du Parc national et de la vallée.</em></strong></p>  <p>Spectacle réalisé à partir des témoignages de perceptions des habitants sur le changement climatique et paysager dans nos montagnes.</p>  <p>Ces témoignages ont été collectés depuis 2021 par Marie Ange Lasmène, ethnologue du \"Cabinet Paroles Paroles\", \"Radio Fréquence Luz vallée des Gaves\", ainsi que les \"Livreurs de mots\" lors des quinze représentations des spectacles Boites à paysages qui ont eu lieu de juin 2021 à janvier 2022, à Luz, Barèges, Gavarnie, Cauterets, Arrens Marsous, Aucun, Arras en Lavedan, à la maison de retraite \"las Ramondias\" grâce à de nombreux partenaires qu''on remercie grandement de leur implication...</p>  <p>Sous forme de Cartes postales écrites, de paroles enregistrées lors d''entretiens individuels ou d''ateliers pédagogiques dans les écoles et collèges, d''interviews variés, ce sont des flots de points de vue qui ont été récoltés précieusement.</p>  <p>Ces matières sensibles ont ainsi été transmises à trois équipes artistiques, la Compagnie les Jolies Choses, le Collectif Décomposé et la Compagnie de la TONG, à qui on a donné \"Carte Blanche\" pour inventer trois créations vivantes et originales de restitution de ces paroles, regards croisés pour la perception locale d''un changement global !</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '01a5ac27-ee26-471b-a5ca-3f6fbd1ff060');
