INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('SORTIE ANNULÉE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span style=\"color:#c0392b;\"><strong>SORTIE ANNULÉE</strong></span></p>  <p></p>  <p>Accompagnés d''un garde-moniteur du Parc national des Pyrénées, partez pour une randonnée à la rencontre des animaux et de la flore du cirque de Troumouse.<br>  Alimentation, reproduction, habitudes, n''auront plus de secret pour vous.<br>  <br>  Rendez-vous au parking du Maillet. Renseignements et inscriptions au 05 62 92 42 48.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c71a2056-25ff-4947-94fb-e8fd03c0958a');
