INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Points rencontre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Les agents du Parc national des Pyrénées partageront avec vous leurs savoirs et connaissances.<br>  L''occasion pour vous de découvrir leur métier et d''aiguiser votre curiosité quant aux patrimoines naturels, culturels et paysagers de la vallée.</p>  <p></p>  <p>Animation gratuite et annulation en cas d''intempéries.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e525c793-d233-4e14-abc2-0e857bb78b13');
