INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Orage', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Une installation immersive de Naïs Van Laer &amp; Pali Meursault</p>  <p>En collaboration avec Guillaume Stagnaro, produit par Constance Meffre - DDA Contemporary Art Production.</p>  <p>En partenariat avec la Maison du Parc national et de la vallée et le Parc National des Pyrénées.</p>  <p>Orage est une installation immersive ancrée dans le concept d’Umwelt*. Ce terme désigne l’environnement sensoriel propre à une espèce ou un individu, mieux rendu en français par l’expression de « monde propre ». Ainsi, Orage propose une expérience immersive dans le territoire et les perceptions de trois animaux emblématiques des Pyrénées : une ourse et ses oursons (Ours brun), un petit « rat-trompette » endémique appelé Desman des Pyrénées, et un hibou grand duc. Ces trois mammifères occupent respectivement trois strates d’un même milieu : l’air (hibou grand duc), l’eau (desman) et la terre (ourse).&nbsp;&nbsp;</p>  <p></p>  <p>Le public est invité à entrer dans une pièce plongée dans la pénombre. En entrant, on découvre que la pièce est vide, excepté du matériel de sonorisation sur les murs et au sol : octophonie d’enceintes, enceintes ultra-directionnelles motorisées sur pied, piezzos. Chaque élément est signalé par une petite diode de faible intensité qui brille doucement. L’espace est à nu, mais une image en mouvement est projetée au plafond, on y voit un ciel de fin de journée parsemé de quelques nuages. C’est la seule source de lumière dans la pièce presque vide et sombre. Mais le son est très présent, on est immergés dans l’ambiance sonore d’une nuit d’été en forêt : les grillons, le hululement d’un hibou au loin, le vent dans les feuillages. La vie animale au crépuscule est riche de sons, peuplée de chuintements, de cris brefs, de grattements d’écorces et de bruissements d’ailes. Être privés d’éléments visuels signifiants, à part le ciel, nous permet d’amorcer notre imagination grâce au son.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'caac6cc5-08af-4bb7-98d3-f5aca3f8cc94');
