INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Esprit de la forêt - Eela Laitinen', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Eela (Eveliina) Laitinen est une artiste finlandaise vivant dans le sud de la France. Après des premières études d’art au Lycée d’arts plastiques d’Helsinki, elle quitte sa ville natale pour partir en Écosse. Elle se forme en design textile (illustration, sérigraphie, mode…) et en 2014 elle sort diplômée de l’Université Heriot-Watt en Écosse. Dans la foulée elle décide de partir s’installer dans le sud de la France. Le folklore nordique et les paysages sauvages du Nord, mais aussi ceux des Pyrénées sont une source d’inspiration majeure pour son travail. Son art est imprégné de paysages magiques où les eaux bouillonnent et les forêts grouillent de mythes et de créatures oniriques.<br>  <br>  Pour donner vie à ses visions artistiques, elle utilise une multitude de techniques de dessin et de peinture, notamment l’encre de Chine, l’aquarelle, le collage ou encore la peinture sur soie. Eela trouve son bonheur en naviguant quelque part entre le dessin et le textile, la création graphique, la mode et le spectacle vivant… Elle partage aussi régulièrement son art et ses techniques à travers des projets de médiation variés.<br>  <br>  Dans les créations signées Eela Laitinen, en plus de son travail d’artiste peintre/dessinatrice, on peut compter des affiches de spectacles, des identités visuelles, des motifs textiles, des scénographies, des costumes de spectacle ou encore des performances de peinture en direct…<br>  <br>  Depuis 2016 elle travaille dans le collectif Freddy Morezon sur la communication et le graphisme. En 2019 elle intègre le collectif et boutique de créateurs Mano Facto à Toulouse où elle est exposante permanente et propose ses collections du prêt-à-porter et des tirages d’illustrations. Ses créations ont été exposées à Edimbourg (Royaume-Uni), à Savonlinna (Finlande) à Toulouse et dans d’autres villes dans la région Occitanie.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6fdc123c-c8be-4d61-be38-8f78a65f8f38');
