INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Enquête desmantifique', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Un desman a été retrouvé mort par un promeneur en bordure du Bastan. Il faut mener l''enquête ! Pour élucider cette affaire, vous devrez emettre des hypothèses, aller voir sur le terrain, rechercher des indices et trouver le coupable.&nbsp;</p>  <p>Rendez-vous à la Maison du Parc national à Gavarnie.</p>  <p>Animation gratuite / Renseignements au 05 62 92 32 48</p>  <p></p>  <p>Animation proposée en lien avec le projet Orage,&nbsp;<a href=\"https://www.maisondelavallee.org/orage-0\">cliquez ici pour plus d''informations</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '65e9170b-461d-482f-bb95-c6abcef8b7a7');
