INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La Finta Nonna - Tide Compagny ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La Finta Nonna (La Fausse Grand-Mère).</p>  <p>Les personnages de ce conte vont être représentés par différents instruments de musique. Par exemple, la grand-mère, sera jouée par la contrebasse. Sur les pas du chasseur résonnera le piano. Le grand-père, sera interprété par la guitare électrique. L’harmonica ! L''hamonica, précédera les apparitions du loup. Il nous reste qu''à vous présenter le héros de ce conte : la bambina. Hélas, nous n''avons plus assez d''instruments pour la jeune fille.<br>  Maintenant, ouvrez grand vos oreilles pour entendre l’histoire... Elle est ici, parmi nous, et elle veut nous parler.<br>  Entre danse, théâtre et magie, Tide Company revisite le conte de La Finta Nonna, version italienne du Chaperon rouge.</p>  <p>Spectacle familial, à partir de 6 ans.&nbsp;</p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '100d6aee-ab8b-4b07-9152-ba73ee5d201c');
