('6fdb9a83-88a5-4e02-8da9-cac9009647e1', 'exposition', true, false, NULL, '2022-08-21T22:00:00.000Z', '2022-08-26T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2022-08-21T22:00:00.000Z', '2022-08-21T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('ZÓRKA, recueil des pieuvres-chapiteaux - Exposition toujours participative', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>C’est un appel à celles et ceux qui dessinent, peignent, collent, gribouillent, crayonnent,&nbsp;ou qui ont le souhait de débuter une pratique artistique plastique.</p>  <p>Cet appel est un prétexte, une bonne raison \"de s''y mettre\".</p>  <p>C''est un point de départ, pour ceux qui ont besoin de départ.</p>  <p>C''est un point de rencontre, pour ceux qui ont besoin de rencontre.</p>  <p></p>  <p>Cet appel lancé en décembre 2020, d’abord sur les réseaux sociaux puis lors&nbsp;d’événements,&nbsp;propose à qui le souhaite de proposer sa version de « La Pieuvre Chapiteau » (une entité de l''univers de MONT, l''univers&nbsp;fictif&nbsp;sur lequel travaille la compagnie Le Cirque Jafarson).</p>  <p></p>  <p>Du 20 au 27 Août 2022, Le Cirque Jafarson&nbsp;investira la salle&nbsp;d’exposition pour y installer&nbsp;une scénographie incitative et mettra à disposition du matériel d''art plastique, afin que chacun se sente libre d''ajouter sa proposition à l’exposition. Toutes les participations sont les bienvenues, toutes les formes, toutes les esthétiques.</p>  <p>Ensuite, c’est à vous de jouer !</p>  <p>L’exposition trouvera sa fin le 27 Août 2022, lors de «&nbsp;La Fête du 34 Juillembre&nbsp;», festival organisé par la compagnie Le Cirque Jafarson à la Maison du Parc national et de la vallée.</p>  <p></p>  <p>Pour plus d’informations, rendez vous sur le site internet de la compagnie:<a href=\"http://&nbsp;www.lecirquejafarson.com\">&nbsp;www.lecirquejafarson.com</a></p>  <p></p>  <p><em>Crédit image : Sulian Rios</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6fdb9a83-88a5-4e02-8da9-cac9009647e1');
