INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('KT ADAMS Céramiques', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><span lang=\"fr\"><span><span>Basée à Londres, Katie Adams Ceramics était une artiste de renommée mondiale qui créait de superbes céramiques et poteries architecturales, texturales et jetées.</span></span><span><span> </span></span><span><span>Au fil des ans, Katie Adams a fait un contenu frais et passionnant, mettant en évidence son travail en tant que céramiste.</span></span></span></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '51485306-f2f7-4a55-8e56-1debb2a91bd0');
