INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rencontre avec Mélusine Gondon, Anthropologue de l’Invisible', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans le cadre d’une résidence de territoire partagée entre différents acteurs culturels du département, la Maison du Parc national et de la vallée et l’association JazzPyr'' (Festival Jazz à Luz) accueillent l’équipe artistique de la compagnie d’Elles dirigée par l’artiste Yaëlle Antoine et vous invite à rencontrer Melusine Gondon&nbsp;dans la salle des voûtes.</p>  <p>Dans le cadre de sa recherche anthropologique, Mélusine Gondon (Anthropologue de l’Invisible, Ethnoscénologue, Membre de la société de Géographie et de la Société des Exploratrices Françaises) vous invite à une première rencontre au cours de laquelle elle communiquera sur son sujet de recherche : « Apparitions récentes de Dames Blanches sur le territoire des 3 Vallées » et les différentes étapes de son enquête jusqu’à la fin du mois de janvier. Cette rencontre sera suivie d’un pot de l’amitié.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e82699a0-d80e-4754-93b4-6e5b33ab9ec2');
