INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Noctures - Cie des Musiques télescopiques', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>\"Nocturnes\" est un concert en immersion dans le monde de la nuit.</p>  <p>Joué dans des espaces naturels ou atypiques, le spectateur est invité à une expérience multisensorielle où la musique et les sons de la nuit se répondent.</p>  <p>L''auditeur, équipé d''un casque audio, voyage entre les vibrations des instruments et celles de la nature. Ce système de diffusion sonore a l''avantage de proposer un son de grande qualité sans nuire à l''écosystème.</p>  <p>Un bruissement de feuilles, le hululement d''une chouette hulotte, la contemplation de la voûte céleste nourrissent en direct le jeu des musiciens à l''affût.</p>  <p>Ce spectacle hors norme est accompagné d’une balade nocturne menée par un guide naturaliste pour découvrir la richesse biologique du site et sensibiliser le public à la pollution lumineuse.</p>  <p><em>Projet en partenariat avec le Parc national des Pyrénées, l''équipe artistique sera accueilli en résidence du 3 au 7 octobre 2022.&nbsp;</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '34f3ffe5-6867-44db-a072-7cee0e423061');
