INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Vavang - PPProd', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Ce projet a pour intention de puiser dans l''esthétisme et l''harmonie de la musique classique, les accents rythmiques du flamenco, les particularités des maqâms et des mélodies de la musique turque.</p>  <p>La musique actuelle est la résultante de l''histoire de différents courants musicaux. Ils continuent à exister et à évoluer à travers les artistes qui les font vivre car ils sont eux même influencés par d''autres conceptions contemporaines. C''est ainsi que Paco de Lucia a fait connaître une grande évolution au flamenco, en faisant fusionner différents styles aux flamenco (notamment le jazz).</p>  <p>Dans ce projet, la ligne artistique sera la fusion entre trois esthétiques : la musique classique, le flamenco et la musique turque.</p>  <p>L''objectif du projet Vavang est de créer une musique dont l''esthétique sera définie par les composantes de ces trois styles musicaux, tant aux niveaux des codes que des instruments.</p>  <p><strong>Le choix des instruments :</strong></p>  <p>La guitare flamenca negra est l''instrument harmonique de l''ensemble. Instrument percussif avec un grand panel de nuances possibles, le jeu flamenco développe toutes les possibilités de cet instrument. Le son produit par celle-ci permet aussi l''interprétation de pièces de musique classique.</p>  <p>La clarinette est un instrument mélodique dont la dimension du son soufflé est d''une grande richesse. Son timbre se distingue clairement de celui des instruments à cordes. Sa couleur se rapproche de celle de la voix humaine. L’utilisation respective d''une clarinette classique ainsi que d''une clarinette turque permettra de varier plus largement l''interprétation des différents morceaux.</p>  <p>La contrebasse ouvre l''univers des sons graves. Son potentiel mélodique sera exploité au service de la création. L''usage inhabituel d''un instrument grave pour la mélodie donnera tout son sens à sa présence. L’utilisation de l''archet apportera une sonorité faisant écho à la musique classique, celle du pizzicato renverra au monde du jazz, du flamenco et de la musique turque. Le mariage des timbres de la contrebasse, de la clarinette et de la guitare parachèveront une écriture originale et universelle. Des passages à l''unisson mettront en valeur la richesse possible des timbres de la formation.</p>  <p></p>  <p>A travers son écriture, Quentin utilise les différences entre chaque instrument et leurs spécificités pour enrichir ses pièces. Cette technique d''écriture permet de créer une sorte de scénario musical dans lequel chaque interprète peut tenir plusieurs rôles.</p>  <p>Grâce au travail de la résidence, une unité de style et un discours musical se préciseront.</p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1593ecba-64aa-44c5-8f70-1cad6c291a68');
