INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La femme du boulanger - Cie La Boîte à jouer', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Séduite par Dominique, berger et valet du châtelain, Aurélie, la femme du boulanger, quitte son mari pour suivre son amant. Le boulanger, Aimable Castanier, se laisser aller au désespoir et refuse de cuire le pain. Dès lors, son malheur devient celui de tous les habitants du village, qui vont se liguer pour ramener l''infidèle et lui obtenir le pardon de son mari.</p>  <p>Auteurs :&nbsp;Jean Giono &amp; Marcel Pagnol&nbsp;de l’académie française</p>  <p>Adaptation :&nbsp;Stéphane Dufau</p>  <p>Mise en scène :&nbsp;Pitto Campa</p>  <p>Costumes :&nbsp;Sophie Munoz</p>  <p>Décorateurs :&nbsp;Klod Pascal &amp;&nbsp;Gilles Brasseur</p>  <p>Distribution :&nbsp;Roland Abadie, Carla Bonnegarde Delisle, Pitto Campa, Victor Campa, Stéphane Dufau, Clothilde Huet, &nbsp;Yves Huet</p>  <p>Création lumière &amp; régie générale :&nbsp;Cédric Marc</p>  <p></p>  <p>À l''occasion de son trentième anniversaire, La Boîte à Jouer a choisi de s''attaquer à un monument du cinéma et du théâtre français en adaptant la célèbre pièce de Jean Giono et Marcel Pagnol -&nbsp; Depuis plus de 30 ans, la compagnie gersoise propose ses spectacles dans les grands théâtres et lors de tournée en France ou à l''étranger tout en défendant un accès au théâtre pour tous en milieu rural. Tout au long de l''année les comédiens investissent le moindre petit village, transformant une place, un cloître, une salle des fêtes en théâtre d''un jour. L''écriture de Pagnol est une déclaration d''amour à la France rurale, à la vie de village, la vie à la campagne. Ce spectacle convenait donc parfaitement à l''esprit de La Boîte à Jouer. Les personnages dépeints par Pagnol et Giono sont croustillants de vérité et de drôlerie et la figure du Boulanger, cocu malheureux, d''une magnifique sensibilité. Le résultat : une heure trente de rires et d''émotions. Le spectacle a été crée à Condom (GERS/32) au Théâtre des Carmes lors d''une résidence de création.</p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '267b034b-d8a7-4bfa-a317-04b0bca0e3c2');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La femme du boulanger - Cie La Boîte à jouer', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Séduite par Dominique, berger et valet du châtelain, Aurélie, la femme du boulanger, quitte son mari pour suivre son amant. Le boulanger, Aimable Castanier, se laisser aller au désespoir et refuse de cuire le pain. Dès lors, son malheur devient celui de tous les habitants du village, qui vont se liguer pour ramener l''infidèle et lui obtenir le pardon de son mari.</p>  <p>Auteurs :&nbsp;Jean Giono &amp; Marcel Pagnol&nbsp;de l’académie française</p>  <p>Adaptation :&nbsp;Stéphane Dufau</p>  <p>Mise en scène :&nbsp;Pitto Campa</p>  <p>Costumes :&nbsp;Sophie Munoz</p>  <p>Décorateurs :&nbsp;Klod Pascal &amp;&nbsp;Gilles Brasseur</p>  <p>Distribution :&nbsp;Roland Abadie, Carla Bonnegarde Delisle, Pitto Campa, Victor Campa, Stéphane Dufau, Clothilde Huet, &nbsp;Yves Huet</p>  <p>Création lumière &amp; régie générale :&nbsp;Cédric Marc</p>  <p></p>  <p>À l''occasion de son trentième anniversaire, La Boîte à Jouer a choisi de s''attaquer à un monument du cinéma et du théâtre français en adaptant la célèbre pièce de Jean Giono et Marcel Pagnol -&nbsp; Depuis plus de 30 ans, la compagnie gersoise propose ses spectacles dans les grands théâtres et lors de tournée en France ou à l''étranger tout en défendant un accès au théâtre pour tous en milieu rural. Tout au long de l''année les comédiens investissent le moindre petit village, transformant une place, un cloître, une salle des fêtes en théâtre d''un jour. L''écriture de Pagnol est une déclaration d''amour à la France rurale, à la vie de village, la vie à la campagne. Ce spectacle convenait donc parfaitement à l''esprit de La Boîte à Jouer. Les personnages dépeints par Pagnol et Giono sont croustillants de vérité et de drôlerie et la figure du Boulanger, cocu malheureux, d''une magnifique sensibilité. Le résultat : une heure trente de rires et d''émotions. Le spectacle a été crée à Condom (GERS/32) au Théâtre des Carmes lors d''une résidence de création.</p>  <p></p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '267b034b-d8a7-4bfa-a317-04b0bca0e3c2');
