INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('3d32d3c9-6318-4b4e-8d68-088da0df91ca', 'exposition', true, false, NULL, '2022-09-21T22:00:00.000Z', '2022-10-29T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2022-09-21T22:00:00.000Z', '2022-09-21T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Pastoralisme et traditions par Pierre Lavantes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Sitôt que l''on a franchi les gorges de Luz, on entre dans le Pays de Barège, qu''une pratique récente a appelé \"le Pays Toy\". Pays montagneux, autrefois d''accès difficile, l''économie essentiellement agro-pastorale, a permis de sauvegarder un mode de vie que certains peuvent juger \"ancestral\".</p>  <p>C''est ce Pays de son enfance, auquel il est particulièrement attaché, que parcourt, dans les années 70, Pierre Lavantès, artisan photographe. En fixant ces images d''une époque révolue, les gens au labeur, les attitudes et les modes de vie d''antan, Pierre Lavantès témoigne d''une vie quotidienne, âpre, difficile, laborieuse, mais remplie d''humanité.&nbsp;A travers ses photographies, il rend hommage à ces gens d''une autre époque.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '3d32d3c9-6318-4b4e-8d68-088da0df91ca');
