INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('RESTITUTION PROJET CARTES BLANCHES', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Cartes blanches // Perceptions locales d''un changement global paysagers et climatiques.</p>  <p>Un projet porté par le Parc national des Pyrénées, coordonné et porté artistiquement par le Cie de la Tong.&nbsp;</p>  <p>Trois spectacles réalisés sur la base des témoignages recueillis par : le Cabinet d''ethnologie Paroles, Paroles // Radio Fréquence Luz // la Cie de la Tong &amp; Les Livreurs de mots de la Cie L''Illustre Corsaire.&nbsp;</p>  <p></p>  <p><strong>19h : \"Echos\" par la Compagnies Les Jolies Choses / Théâtre&nbsp;</strong></p>  <p>Échos de paroles, Échos de la nature, Échos du monde... Comment les questions et les enjeux climatiques résonnent-ils ? La Cie les Jolies Choses vous emporte dans une randonnée immobile, immersive et sensible qui questionne l’écologie en s’inspirant de témoignages, comme une hybridation ethno-artistique à la croisée des chemins.</p>  <p><strong>19h45 : \"Charivari\" par la Compagnie de la Tong / Texte, diffision sonore, contrebasse et chant</strong></p>  <p>\"Quand la parole devient musique... Quand les témoignages se rassemblent d''un même souffle, se mêlent aux cordes pincées de la contrebasse, se transforment en un chant troublant pour partager, raconter, ressentir la place du vivant, regarder les paysages qui nous entourent, pleurer et rire ensemble des mots choisis, des idées évoquées d'' habitants d''ici ou d''ailleurs, d''enfants, de grands parents... Grâce à tous ces matériaux écrits, dessinés, enregistrés, collectés depuis 2021, la Cie de la TONG est heureuse de présenter un regard sensible de mots, de sons et de musique et contribuer au débat de l''urgence écologique.\"</p>  <p><strong>20h45 : \"Haïku\" par le Collectif Décomposé / Texte et clavier&nbsp;</strong></p>  <p>Nous sommes tous un haiku. Nous sommes le temps d''un souffle et comme lui, partagé entre émerveillement, mystère et séisme. Le haiku est un genre poétique exposé au changement climatique puisqu''il est axé par définition sur la nature et le passage des saisons. Nous sommes, tel un haiku, la vigie de tous les dérèglements des saisons.<br>  Le Collectif Décomposé propose ici un instant-poème, des mots choisis et rapportés par ceux qui fréquentent nos montagnes.</p>  <p></p>  <p><em>A partir de 17h30, un plateau radio sera animé par Fréquence Luz (99.6 au Pays Toy) en présence des artistes et des protagonistes du projet Cartes Blanches.&nbsp;</em></p>  <p><span style=\"color:#1abc9c;\"><strong>Apéritif servi entre les spectacles \"Echos\" et \"Charivari\" // Pas de restauration sur place !&nbsp;</strong></span></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ec7cf192-d84b-4ada-81f6-f7f2cd925b5f');
