INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('DANS LA SOLITUDE DES CHAMPS DE COTON / Collectif Décomposé ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>CRÉATION 2023</p>  <p>Dans la solitude des champs de coton, pièce de Bernard-Marie Koltès (1948-1989), un des plus célèbres auteurs de théâtre du XX e siècle, narre la rencontre entre un dealer et un client dans une ville, au fil d’une nuit pleine de mystère. Chacun est lié à l’autre par la dépendance. Entre eux s’engage un combat «entre chien et chat», de mots, de pensée, de nerfs, qui précède l''affrontement physique. Dans ce texte flamboyant, l’auteur magnifie le marchandage commercial en déclinant de façon métaphorique de multiples variations sur le désir. Eric Durand, metteur en scène du Collectif Décomposé, s’empare de cet affrontement magnifique entre deux solitudes et nous livre une mise en scène sobre, brute, cherchant à sublimer le long poème en prose de Koltès. Comme toujours dans le travail du Collectif, l’approche sonore et musicale occupe une place centrale, constituant une matière essentielle au déploiement dramaturgique. Sur le plateau, les deux comédiens et le musicien se répondent et entrent en tension, le verbe engendre la musique qui à son tour engendre le verbe, ou le mouvement, ou les deux, qui ensemble se répondent sans jamais perdre leur vie propre. Un spectacle à la fois intense, profond et accessible, où la condition humaine faite de vitalité, de hargne, d''attraction et de rejet se dévoile avec force et beauté</p>  <p>Coproduction Le Parvis scène nationale Tarbes Pyrénées</p>  <p>Mise en scène Eric Durand / Compositeur piano (musique en direct) Vianney Oudart / Comédiens Azeddine Benamara et David Morazin / Création des lumières et régie Guillaume Leclerq / Regard scénographique et constructeur Sylvain Dubun / Chargée d’administration et de production -collaboratrice artistique Anne-Lise Blin.</p>  <p>// En partenariat avec les communes d’Aureilhan, de Luz-Saint-Sauveur, de Cahors, le Festival des Maynats et la Maison du Parc national et de la Vallée. Production Collectif Décomposé.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ebab2055-71f7-48db-9ffb-1d9f686ccbff');
