INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('À La Bonheur !', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>À La Bonheur&nbsp;est un trio né dans les Hautes-Pyrénées en 2016. Une combinaison unique et originale de chansons à textes, de rock, de reggae et de ska. À&nbsp;travers des textes optimistes teintés d''humour, le groupe s''évertue à transmettre un message humaniste et réaliste sur les dérives de notre société actuelle. À La Bonheur totalise plus de 300 concerts à son actif et un premier album auto-produit. Le groupe est réputé pour ses lives explosifs qui ne manquent pas de marquer les esprits, notamment grâce au son de leur orgue Farfisa des années 70''s</p>  <p></p>  <p>- Liens de l''album :&nbsp;&nbsp;</p>  <p><a href=\"https://www.youtube.com/watch?v=LSFwbfCKCJ0&amp;list=OLAK5uy_ltpFrVwoBP0yYr-MfBUNqzz1QxsqZ10CI&amp;index=2\">https://www.youtube.com/watch?v=LSFwbfCKCJ0&amp;list=OLAK5uy_ltpFrVwoBP0yYr-MfBUNqzz1QxsqZ10CI&amp;index=2</a></p>  <p>&nbsp;- Chaine Youtube&nbsp; :&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>  <p><a href=\"https://www.youtube.com/channel/UCavfJ52FH107JroMDwogQtg\">https://www.youtube.com/channel/UCavfJ52FH107JroMDwogQtg</a></p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4f8021d7-debd-4470-ab81-e9f02e570416');
