INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Concert de musique électronique - Victor Kastel - Le Cirque Jafarson', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Le Cirque Jafarson est une jeune compagnie de création des Hautes-Pyrénées. Dans les projets qu’elle développe (spectacle, festival…), la place de la musique électronique est toujours importante. Victor Kastel, musicien de la compagnie depuis ses débuts, porte son identité musicale à travers un univers sonore poétique. Cette forme concert est un zoom sur sa pratique. Alliant accords mélancoliques et synthétiseurs déguisés, Victor décuple la portée de ses sons en travaillant une multi-diffusion immersive.</p>  <p>Composition et interprétation : Victor Kastel. Mise en scène : Rachel Cazenave.&nbsp;</p>  <p>Tout public /&nbsp;Durée approximative 45 minutes.&nbsp;</p>  <p><a href=\"https://www.maisondelavallee.org/informations-pratiques#tarifs\">Tarifs</a></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'baa23d18-37ad-42e7-a832-424e8f9cb6dc');
