INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence Fotomaton - Cie Histoire de chanter', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Pour ce nouveau spectacle de la Cie Histoire de chanter, la chanson est à l’honneur et le théâtre la met en scène.</p>  <p>D’accords en anecdotes et d’anecdotes en quiproquos, la musique dessine des vies et des souvenirs. Dix chansons pour dix flashs de vies rassemblées dans la onzième. Celle de l’enfant indomptable, celle de la femme tantôt objet, tantôt outil, tantôt fleur bleue, parfois bavarde, souvent cabossée, toujours femme et radicalement. Sous les yeux d’un photomaton qui en a vu d’autres.</p>  <p>C''est l’occasion de piocher des souvenirs dans une caisse ou l’autre pour composer une chanson. Tout donne l’impression d’une improvisation totale et d’un concert qui échappe de plus en plus au public… et aux acteurs.</p>  <p>Pour animer ce chaos hasardeux : une voix, entourée d’instruments (guitare, banjo, mélodica, percussions...) et des jeux de lumière qui photographient ces instants.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '60b011bb-056f-4520-a66d-9e48273aa0c3');
