INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Et maintenant ?"Résidence de territoire - Collectif des acteurs culturels du 65', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Suite à l’appel à projet 22/23, pour la deuxième édition de cette résidence partagée à l’échelle départementale, c’est En transition Cie qui a été retenue.</p>  <p>Dans quel monde vivrons-nous demain ? A quoi pourrions-nous renoncer ? Que deviendront les villes et les campagnes des Hautes Pyrénées ? Comment la société s’organisera-t-elle au sein de la région ? Quels changements cela impliquera-t-il dans nos modes de vie ? Quelles initiatives existent déjà localement et pourraient être étendues ? Autant de questions que En Transition Cie souhaite poser à celles et ceux qui font vivre ce territoire pour inventer ensemble des histoires du futur.</p>  <p>La compagnie sera présente sur l’ensemble du territoire de février à novembre 2023, durant quatre sessions d’immersion, avec quatre propositions distinctes qui se nourriront les unes des autres.</p>  <p>L’objectif de notre compagnie est de participer à la fabrique des nouveaux imaginaires. Dans un contexte de mutation de nos sociétés, de bouleversements environnementaux et climatiques, il nous semble indispensable de donner une vision désirable du futur. Par la pratique et la recherche artistique nous souhaitons faire découvrir, sensibiliser, défendre, imaginer un tournant radical exaltant. Ces nouveaux récits du futur nous voulons les inventer avec vous habitant.e.s ! Les modes de participation seront divers et variés, pas besoin d''avoir déjà fait du théâtre, pas besoin d''être expert.e, tout le monde pourra participer... On vous en dit plus très bientôt !</p>  <p>Voici un avant-goût des actions à venir sur la communauté de communes de Haute Bigorre de Mars à novembre 2023.</p>  <p>- C’est ma nature - Création d''un podcast à partir des témoignages sensibles récoltés sur de notre rapport à la nature, l’environnement, l''écologie.</p>  <p>- GreenWalk - Balade théâtralisée réalisée avec la complicité des habitant.e.s. A partir des connaissances sur la faune et la flore locales, l’histoire du territoire, récoltées auprès des naturalistes amateur.rice.s, laboratoires scientifiques, agriculteur.rice.s, associations en lien avec la nature… Les spectateur.rice.s sont invité.e.s, avec humour, à utiliser tous leurs sens pour découvrir le vivant qui les entoure.</p>  <p>- Le B.I.F (Bureau des Idées pour le Futur) - Installation scénographique itinérante, en espace public, qui invite les habitant.e.s et gens de passage à partager des idées, leurs initiatives, évoquer des changements nécessaires, proposer des projets de loi, pour contribuer au tournant écologique des Hautes Pyrénées.</p>  <p>- Ça y est ! - Création partagée. En s’appuyant sur la matière récoltée lors des précédentes résidences et en élargissant encore le nombre de participant.e.s, nous imaginons un futur désirable. C’est une fable écologique d’anticipation écrite et racontée par un groupe d’habitant.e.s complices. Alors, c''est comment 2043 ?</p>  <p>En Transition Cie, avec Alexandre Cafarelli - Metteur en scène / Ganaelle Maury - Plasticienne &amp; créatrice sonore / Virginie Nieddu - Comédienne / Roxane Delle-Vedove - Collaboratrice scientifique.</p>  <p></p>  <p><em>En partenariat avec Le collectif des acteurs culturels du 65 : le Collectif des acteurs culturels des Hautes-Pyrénées est un réseau informel et à géométrie variable regroupant une trentaine de structures artistiques et culturelles. Depuis février 2021, les acteurs et actrices culturels du département se réunissent régulièrement pour échanger sur leurs pratiques, leurs actions, leurs problématiques parfois très différentes vu l’hétérogénéité des structures présentes - responsables d’associations culturelles, programmateurs des structures culturelles, techniciens des collectivités - et de leurs champs d’action - spectacle vivant, arts plastiques, pratiques amateur - mais pouvant également trouver de nombreux points de convergence.&nbsp;</em></p>  <p><em>Structures partenaires sur le projet : Le Parvis (Tarbes) - Association Traverse (Bagnères de Bigorre) - La Soulade (Jézeau) - La Maison du savoir (St Laurent de Neste) - Tarbes en scènes - Festival Murmure du Monde (Val d''Azun) - Maison du Parc national et de la vallée (Luz St Sauveur) - Le Théâtre des 7 Chandelles (Maubourguet)</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a330bc88-069f-4cd6-ba12-8976b47a662b');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Et maintenant ?"Résidence de territoire - Collectif des acteurs culturels du 65', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Suite à l’appel à projet 22/23, pour la deuxième édition de cette résidence partagée à l’échelle départementale, c’est En transition Cie qui a été retenue.</p>  <p>Dans quel monde vivrons-nous demain ? A quoi pourrions-nous renoncer ? Que deviendront les villes et les campagnes des Hautes Pyrénées ? Comment la société s’organisera-t-elle au sein de la région ? Quels changements cela impliquera-t-il dans nos modes de vie ? Quelles initiatives existent déjà localement et pourraient être étendues ? Autant de questions que En Transition Cie souhaite poser à celles et ceux qui font vivre ce territoire pour inventer ensemble des histoires du futur.</p>  <p>La compagnie sera présente sur l’ensemble du territoire de février à novembre 2023, durant quatre sessions d’immersion, avec quatre propositions distinctes qui se nourriront les unes des autres.</p>  <p>L’objectif de notre compagnie est de participer à la fabrique des nouveaux imaginaires. Dans un contexte de mutation de nos sociétés, de bouleversements environnementaux et climatiques, il nous semble indispensable de donner une vision désirable du futur. Par la pratique et la recherche artistique nous souhaitons faire découvrir, sensibiliser, défendre, imaginer un tournant radical exaltant. Ces nouveaux récits du futur nous voulons les inventer avec vous habitant.e.s ! Les modes de participation seront divers et variés, pas besoin d''avoir déjà fait du théâtre, pas besoin d''être expert.e, tout le monde pourra participer... On vous en dit plus très bientôt !</p>  <p>Voici un avant-goût des actions à venir sur la communauté de communes de Haute Bigorre de Mars à novembre 2023.</p>  <p>- C’est ma nature - Création d''un podcast à partir des témoignages sensibles récoltés sur de notre rapport à la nature, l’environnement, l''écologie.</p>  <p>- GreenWalk - Balade théâtralisée réalisée avec la complicité des habitant.e.s. A partir des connaissances sur la faune et la flore locales, l’histoire du territoire, récoltées auprès des naturalistes amateur.rice.s, laboratoires scientifiques, agriculteur.rice.s, associations en lien avec la nature… Les spectateur.rice.s sont invité.e.s, avec humour, à utiliser tous leurs sens pour découvrir le vivant qui les entoure.</p>  <p>- Le B.I.F (Bureau des Idées pour le Futur) - Installation scénographique itinérante, en espace public, qui invite les habitant.e.s et gens de passage à partager des idées, leurs initiatives, évoquer des changements nécessaires, proposer des projets de loi, pour contribuer au tournant écologique des Hautes Pyrénées.</p>  <p>- Ça y est ! - Création partagée. En s’appuyant sur la matière récoltée lors des précédentes résidences et en élargissant encore le nombre de participant.e.s, nous imaginons un futur désirable. C’est une fable écologique d’anticipation écrite et racontée par un groupe d’habitant.e.s complices. Alors, c''est comment 2043 ?</p>  <p>En Transition Cie, avec Alexandre Cafarelli - Metteur en scène / Ganaelle Maury - Plasticienne &amp; créatrice sonore / Virginie Nieddu - Comédienne / Roxane Delle-Vedove - Collaboratrice scientifique.</p>  <p></p>  <p><em>En partenariat avec Le collectif des acteurs culturels du 65 : le Collectif des acteurs culturels des Hautes-Pyrénées est un réseau informel et à géométrie variable regroupant une trentaine de structures artistiques et culturelles. Depuis février 2021, les acteurs et actrices culturels du département se réunissent régulièrement pour échanger sur leurs pratiques, leurs actions, leurs problématiques parfois très différentes vu l’hétérogénéité des structures présentes - responsables d’associations culturelles, programmateurs des structures culturelles, techniciens des collectivités - et de leurs champs d’action - spectacle vivant, arts plastiques, pratiques amateur - mais pouvant également trouver de nombreux points de convergence.&nbsp;</em></p>  <p><em>Structures partenaires sur le projet : Le Parvis (Tarbes) - Association Traverse (Bagnères de Bigorre) - La Soulade (Jézeau) - La Maison du savoir (St Laurent de Neste) - Tarbes en scènes - Festival Murmure du Monde (Val d''Azun) - Maison du Parc national et de la vallée (Luz St Sauveur) - Le Théâtre des 7 Chandelles (Maubourguet)</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'a330bc88-069f-4cd6-ba12-8976b47a662b');
