INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('7394bd83-f9ad-4ec4-a3e3-1ab0af53678e', 'residence', true, false, false, NULL, '2023-03-26T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2023-03-26T22:00:00.000Z', '2023-03-26T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('True Truie - Compagnie La Lampe Tempete', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Théâtre&nbsp; / Une création d’Alice Lacharme inspirée du « Cochon » de Michel Pastoureau et de « Truismes » de Marie Darrieussecq (entre autres)</p>  <p>Il est vraiment temps qu’elle raconte, parce que si elle ne raconte pas maintenant, bientôt il sera trop tard, et désolé-e pour les âmes sensibles. Se montrer, c’est risqué, il ne faudrait pas effrayer. Déjà qu’il y a de la boue partout et qu’elle n’y voit pas très bien. Tout a commencé quand elle était au chômage ; elle ne sait pas trop comment ça a démarré, mais elle avait pris un peu de poids, ça lui donnait une allure remarquablement saine , « pneumatique », elle avait un succès fou avec sa belle chair rose qui tirait sur les coutures de sa blouse. Certes, elle aurait pu comprendre ce qui se tramait quand elle s’est mise à manger les fleurs qu’on lui offrait, ou les marrons du parc à l’automne, ou quand elle a eu tellement d’envies qu’elle sautait sur les clients de sa parfumerie. Oui, elle se transforme en truie. … Et l’autre, à côté d’elle? L’autre, elle mange, elle dévore, affamée, tout ce qui passe à sa portée.&nbsp;</p>  <p>Avec : Fanny Honoré, Alice Lacharme... (en cours) Lumières : Guilhem Rivals</p>  <p><em>Partenaires&nbsp;: Département de la Haute-Garonne, L’Escale (Tournefeuille), le Pari (Tarbes), Théâtre Jules Julien (Toulouse), Ville de Muret, Théâtre du Bazacle (Toulouse), Centre européen de Conques.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7394bd83-f9ad-4ec4-a3e3-1ab0af53678e');
