INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('DANS LA SOLITUDE DES CHAMPS DE COTON Éric Durand / Collectif Décomposé', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans la solitude des champs de coton, pièce de Bernard-Marie Koltès (1948-1989), un des plus célèbres auteurs de théâtre du XXe siècle, narre la rencontre entre un dealer et un client dans une ville, au fil d’une nuit pleine de mystères.</p>  <p>Chacun est lié à l’autre par la dépendance. Entre eux s’engage un combat « entre chien et chat », de mots, de pensées, de nerfs, qui précède l’affrontement physique. Dans ce texte flamboyant, l’auteur magnifie le marchandage commercial en déclinant de façon métaphorique de multiples variations sur le désir.</p>  <p>Éric Durand, metteur en scène du Collectif Décomposé, déjà accueilli au Parvis avec&nbsp;Une mouche (être ou ne pas être)&nbsp;d’Hanock Levin, s’empare de cet affrontement magnifique entre deux solitudes et nous livre une mise en scène sobre, brute, cherchant à sublimer le long poème en prose de Koltès. Comme toujours dans le travail du Collectif, l’approche sonore et musicale occupe une place centrale, constituant une matière essentielle au déploiement dramaturgique. Sur le plateau, les deux comédiens et le musicien se répondent et entrent en tension, le verbe engendre la musique qui à son tour engendre le verbe, ou le mouvement, ou les deux, qui ensemble se répondent sans jamais perdre leur vie propre.</p>  <p>Un spectacle à la fois intense, profond et accessible, où la condition humaine faite de vitalité, de hargne, d’attraction et de rejet se dévoile avec force et beauté.</p>  <p></p>  <p><em>En partenariat avec Le Parvis Scène nationale Tarbes Pyrénées.</em></p>  <p><strong>Tarifs : 8€ / 6€ (Réduit)</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd82141d4-542d-4701-8384-e7ece8e066a2');
