INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Concert Voz Y Bajo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Quand les bas noirs de la voix croisent la rondeur de la contrebasse le rauque adopte la douceur de l’intime. Le bolero devient swing, la ballade un concert. S''y rencontrent Astor Piazzola et Chavela Vargas, Lhasa et quelques standards pops. Mélodie duale sur un fil sans concession. La connivence persuade le fragile d''édifier un répertoire aux sonorités nouvelles. Le latino et le blues s''enchantent mutuellement.</p>  <p></p>  <p>Concert offert dans le cadre du 40ème anniversaire de la Maison !</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'bb5e75e6-52b5-4c33-b458-01a002e24b8b');
