INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence sur les thérapies psycho-corporelles avec François Lombardeau', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Un chemin de reconnexion entre le corps et l’esprit&nbsp;</p>  <p>Quel est l’intérêt d’une thérapie psycho-corporelle à notre époque ? En premier lieu, quand nous sommes déstabilisés voire blessés et en souffrance par un événement douloureux ou traumatique qui survient dans notre vie, ou qui a laissé une trace dans notre passé et ressurgit sous forme de symptômes ou schéma récurrent. Ensuite, malgré les difficultés de vie inhérentes à beaucoup d’entre nous, nous restons sur le constat que cela va plutôt bien. Mais, même si l’aisance matérielle et affective sont là, il existe la sensation que la vie pourrait être plus satisfaisante et pleine et qu’il persiste un manque à l’intérieur de nous. Apparaît alors le besoin d’expérimenter un goût plus authentique de la vie avec plus de sérénité, de profondeur et d’essentiel. Confrontés à l’évolution accélérée du monde et à des peurs collectives, au progrès des technologies et à l’envahissement de notre espace par les écrans et les réalités virtuelles, nos repères de vie sont sans cesse bousculés. Ce qui était vrai hier ne l’est plus aujourd’hui. Nous sommes sur-stimulés et pouvons avoir la sensation de ne plus pouvoir nous appuyer sur quelque chose de fiable et cela nous pousse à des efforts d’adaptation répétés vecteurs de stress et d’instabilité profonde. Comment alors guérir blessures passées et présentes ? Comment dépasser nos insatisfactions ? Pour beaucoup le concept de psychothérapie reste assez flou et s’y engager fait ressortir la crainte de ne pas être équilibré psychologiquement. La psychologie biodynamique, entre autre, a révélé la capacité du corps à digérer les charges émotionnelles accumulées. La guérison pouvant parfois s’obtenir directement par ce processus sans qu’il soit nécessaire de retrouver les causes originelles des souffrances ou du mal-être.</p>  <p>INTERVENANT : François LOMBARDO Thérapeute psycho-corporel</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5a0df02d-6993-4469-9ee1-11a1479363ad');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence sur les thérapies psycho-corporelles avec François Lombardeau', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Un chemin de reconnexion entre le corps et l’esprit&nbsp;</p>  <p>Quel est l’intérêt d’une thérapie psycho-corporelle à notre époque ? En premier lieu, quand nous sommes déstabilisés voire blessés et en souffrance par un événement douloureux ou traumatique qui survient dans notre vie, ou qui a laissé une trace dans notre passé et ressurgit sous forme de symptômes ou schéma récurrent. Ensuite, malgré les difficultés de vie inhérentes à beaucoup d’entre nous, nous restons sur le constat que cela va plutôt bien. Mais, même si l’aisance matérielle et affective sont là, il existe la sensation que la vie pourrait être plus satisfaisante et pleine et qu’il persiste un manque à l’intérieur de nous. Apparaît alors le besoin d’expérimenter un goût plus authentique de la vie avec plus de sérénité, de profondeur et d’essentiel. Confrontés à l’évolution accélérée du monde et à des peurs collectives, au progrès des technologies et à l’envahissement de notre espace par les écrans et les réalités virtuelles, nos repères de vie sont sans cesse bousculés. Ce qui était vrai hier ne l’est plus aujourd’hui. Nous sommes sur-stimulés et pouvons avoir la sensation de ne plus pouvoir nous appuyer sur quelque chose de fiable et cela nous pousse à des efforts d’adaptation répétés vecteurs de stress et d’instabilité profonde. Comment alors guérir blessures passées et présentes ? Comment dépasser nos insatisfactions ? Pour beaucoup le concept de psychothérapie reste assez flou et s’y engager fait ressortir la crainte de ne pas être équilibré psychologiquement. La psychologie biodynamique, entre autre, a révélé la capacité du corps à digérer les charges émotionnelles accumulées. La guérison pouvant parfois s’obtenir directement par ce processus sans qu’il soit nécessaire de retrouver les causes originelles des souffrances ou du mal-être.</p>  <p>INTERVENANT : François LOMBARDO Thérapeute psycho-corporel</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '5a0df02d-6993-4469-9ee1-11a1479363ad');
