INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('RIEN - CIE L''ATELIER DES SONGES', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Marionnette sur table&nbsp;à 4 mains - Tout public à partir de 6 ans.</p>  <p><em>Et si l’homme était aussi génial que médiocre, et si le rire ou bien le regard critique sur l’être humain pouvait nous faire entendre raison?</em></p>  <p><em>Possession, autorité, spiritualité, peur du vide, ennui...</em></p>  <p><em>Des archétypes qui sont en l’homme et le constituent depuis la nuit des temps.</em></p>  <p><em>\"Rien\" est un personnage qui découvre sa capacité à être humain, et dont on peut sourire car son parcours met en évidence de troublantes ressemblances.</em></p>  <p><em>Manipulation à 4 mains dans un décor minimaliste où la puissance de l’imaginaire place le « rien » très proche du « tout ».</em></p>  <p></p>  <p><strong>Mise en scène</strong></p>  <p>Une grande table blanche au milieu d’un plateau noir, comme un terrain de jeu suspendu dans l’air, sur laquelle vient se mouvoir une marionnette. Entourée de cubes, supports de notre imagination, le personnage traverse découvertes et émotions.</p>  <p>La scénographie, inspirée du carré blanc sur fond blanc de Malévitch, (art abstrait), donne la possibilité au spectateur d’être à son tour l’artiste, d’avoir sa propre lecture.</p>  <p></p>  <p><strong>La compagnie l’Atelier des songes</strong></p>  <p>Crée en 2006, la compagnie “L’atelier des songes” réunit plusieurs artistes qui travaillent collectivement autour de la marionnette, pour la petite-enfance et le tout public. Nos spectacles abordent des symboliques fondamentales de la vie : l’amour, la poésie, le temps, l’ennui, le rêve, la rencontre. Depuis 2018, nous travaillons sur le lien entre l’histoire de l’art et le théâtre d’objet et/ou marionnettique. Nous nous inspirons des courants de l’art moderne, constructiviste ou des artistes bruts…</p>  <p></p>  <p><strong>Création</strong></p>  <p>Durée: 45 minutes</p>  <p>Jeu/manipulation: Aurélie Gourvès et Délia Sartor</p>  <p>Scénographie et lumières: Henry Castres</p>  <p>Ecriture et mise en scène collective</p>  <p>Aide à la mise en scène Cristina Iosif et François Accard</p>  <p>Sur une musique de Emile Parisien (Album Belle époque)</p>  <p></p>  <p>Spectacle offert dans le cadre du 40ème anniversaire de la Maison !</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '3092b5cb-a6a9-44cb-abc3-23bf3c09d84e');
