INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Concert "Melle Nine  et le Petit Haïdouti"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Quand la musique de la fanfare balkanique Haïdouti Orkestar ( ici en version réduite) épouse la folie douce des chansons de Mlle Nine, c''est une source d''émotions festives rares dans le grand cirque de la vie !</p>  <p>Il y a chez Mlle Nine une énergie bouillonnante et sensuelles Rock and roll et mélancolique, une Marilyn brune tout droit sortie d''un film de Kusturica, aux chansons kaléidoscopes, poétiques et endiablées.</p>  <p>Elle nous ballade, non sans humour, sur les routes chaotiques et alambiquées de l''existence où la clairvoyance de la sorcière côtoie l''émerveillement de l''enfant.</p>  <p>Après de nombreuses collaborations, elle crée aujourd''hui Le Petit Haïdouti, avec des membres de la célèbre fanfare balkanique qui tourne notamment avec Ibrahim Maalouf , et ça fait des étincelles !</p>  <p></p>  <p>Concert offert dans le cadre du 40ème anniversaire de la Maison !</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '2481ce7a-7075-46ee-90b5-6ad91447608d');
