INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La diablesse et son enfant - Cie Les Jolies Choses', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La diablesse et son enfant ( de Marie N’Diaye)</p>  <p>à partir de 6 ans / Durée&nbsp;: 40 minutes</p>  <p>Partition pour deux interprètes : Une danseuse / Une comédienne-conteuse</p>  <p>Une diablesse va de maison en maison, réclamant son enfant qu’elle a perdu. Mais dès qu’on s’aperçoit qu’au lieu des pieds, la diablesse a des sabots, comme ceux d’une chèvre, les portes se referment, on éteint la lumière et on tremble dans le noir. Un conte de sagesse d’une envoûtante étrangeté qui donne à réfléchir sur la peur du handicap, la violence des préjugés, les ravages de la rumeur et la force de l’amour.</p>  <p></p>  <p>Distribution :</p>  <p>Mise en scène : Françoise Delile -Manière</p>  <p>Interprétation : Nathalie Lhoste-Clos et Sophie Barros</p>  <p>Création lumière : Laurent Aranda</p>  <p>Régie : Bastien Sallaberry</p>  <p></p>  <p><strong>Jauge limitée - Présence des écoles primaires de la vallée</strong></p>  <p><strong>Tarif unique : 4€</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '79bee1ab-fb54-4f8c-9f72-4acf2aaa54e5');
