INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''Ours brun dans les Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Venez à la découverte de l''un des plus grands mammifères sauvages existants sur le territoire des Pyrénées : L''ours brun&nbsp;! Cette exposition en partenariat avec le Parc national des Pyrénées présente cet animal emblématique, son évolution, son alimentation et son environnement.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '854e8a2f-8268-4b1c-b165-3395d6b716f5');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''Ours brun dans les Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Venez à la découverte de l''un des plus grands mammifères sauvages existants sur le territoire des Pyrénées : L''ours brun&nbsp;! Cette exposition en partenariat avec le Parc national des Pyrénées présente cet animal emblématique, son évolution, son alimentation et son environnement.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '854e8a2f-8268-4b1c-b165-3395d6b716f5');
