INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le Ciné - concert de Piro Piro', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Animation, Corée du Sud, 2023, 40 min / A partir de 3 ans.</p>  <p>Programme de 6 courts métrages<br>  Découvrez ces courts métrages poétiques, avec des dessins et de l’aquarelle, venus de la Corée du Sud, sur l’univers des oiseaux. Un beau voyage tout en douceur pour les petits.</p>  <p>Le pianiste Cyrille Aufaure nous offre une projection magique où la découverte, les rires et l’émerveillement s’entremêlent afin d’offrir de beaux moments de cinéma&nbsp;!</p>  <p><strong>Un Ciné Concert, qu’est-ce que c’est&nbsp;?</strong></p>  <p>Devant l’écran du cinéma et en simultanée pendant la projection, le pianiste Cyrille Aufaure pose ses accords sur les courts métrages et fait vivre les images projetées.</p>  <p>Le Ciné Concert était la norme à l’époque du cinéma muet. La musique était jouée en direct en même temps que la projection, souvent par un pianiste d’ailleurs.</p>  <p>Après le film, pose tes questions à Cyrille le musicien !&nbsp;</p>  <p></p>  <p>Tarif unique : 4€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5611760a-7250-4b18-afe5-d044a24771ef');
