INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Exposition Joachim SONTAG', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<table align=\"left\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" valign=\"top\" width=\"550\">  <tbody>   <tr>    <td>     <p>Découvrez les œuvres du musicien et artiste visuel Joachim Sontag.</p>      <p>Depuis maintenant deux ans, il travaille avec la technique de la sérigraphie, principalement pour les possibilités graphiques qu''elle favorise (plus que pour son aspect reproductible) : aplats monochromes uniformes, travail du trait en négatif, choix des couleurs...</p>      <p>La plupart de ses dessins sont le fruit de ses voyages oniriques, de thèmes proches du paysage, et de son attachement à tracer des lignes, à décrire de petites scènes, à créer des symboles et des atmosphères avec le minimum de moyens.</p>      <p>Il restructure alors ses thèmes favoris en y ajoutant un peu de passage, des silhouettes légères et du vent.</p>    </td>   </tr>  </tbody> </table> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7b0b53dc-1498-4497-8b4c-f1a391da7c98');
