INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence- Débat SOMATISATION ET THERAPIES PSYCHOCORPORELLES avec François Lombardeau', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Depuis longtemps la sagesse populaire et les médecines traditionnelles ont mis en évidence la notion de somatisation : « se faire du mauvais-sang », « de la bile », « ne pas digérer une situation », « en avoir les jambes coupées »...<br>  Du point de vue de la science, la neuro-endocrino-immunologie a étudié comment le cerveau transformait nos émotions et pensées en signaux chimiques qui influencent notre biologie et inversement.<br>  Pour autant, les troubles physiologiques et les maladies ne sont pas toujours psychosomatiques. Mais parfois, l’expérience vécue est trop douloureuse pour la psyché. Le système d’inhibition cherchera a<br>  occulter ces sensations pour préserver l’équilibre psychique et le conflit sera refoulé au niveau physiologique. Cela amène notre corps à se retrouver siège de souffrances et de blessures enkystées sous forme de tensions, contractions, spasmes, gonflements, inflammations... Tant que l’organisme n’a pas digéré l’information, le choc, la somatisation restera active, et&nbsp;tout du&nbsp;moins, latente.<br>  Alors cette mémoire enfouie pourra être réveillée par des situations de vie en analogie et ressurgira sous forme de somatisation qui va toucher une zone du corps, un organe ou une fonction en rapport avec le ressenti refoulé. Les symptômes ou maladies seront alors le résultat de l’effort de l’organisme pour réduire la souffrance psychique. Les thérapies psychocorporelles qui permettent de remettre en route la capacité d’auto-régulation du corps apparaîssent&nbsp;fondamentales pour apaiser les séquelles des traumas et souffrances accumulés. L’écoute des sensations corporelles permettra de résoudre le conflit sous-jacent au symptôme mais aussi de retrouver la présence à soi-même et la sensation d’exister pleinement.<br>  François vous invite à l’issue de la conférence à échanger librement sur ce sujet et éventuellement partager votre expérience.</p>  <p>INTERVENANT : François LOMBARDO Thérapeute psycho-corporel</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'cd199369-4584-4f4c-8915-0bc43a925b95');
