INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''oiseau ravage - Jazz déplumé', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Duo piano, saxophone &amp; voix</p>  <p>Durée 45 mins</p>  <p>Public scolaire présent / TARIF UNIQUE : 4€</p>  <p>À la croisée des jazz, Charlène Moura et Marek Kastelnik composent une musique sensible, entre rage, humour et mélancolie.</p>  <p>Entre ses prises de bec et un lyrisme de crécerelle, L’Oiseau Ravage étourdie et libère un plumage sauvage.<br>  Du haut, il plonge. Siffleur de rage, il racle le roc en jasant. Bête à plumes, il s’élève dans les vents contraires, se joue du souffle et du vertige.<br>  Il plane, il sent, il graille, il chute. Le silence, le cri. L’Oiseau Ravage surprend parce qu’il est surpris.</p>  <p></p>  <p>CHARLENE&nbsp;MOURA Musicus saxophonus vox<br>  Née dans l’univers d’Uzeste Musical, Charlène Moura découvre le fifre au sein des ripataoulères gasconnes. Le répertoire traditionnel lui offre le goût de la ritournelle comme une matière première à ses compositions, un lien entre ses racines et ses expérimentations. Elle découvre le saxophone alto et se plonge dans l’improvisation avec l’envie d’y confronter son univers personnel et ses influences musicales. Après une formation théâtrale et musicale, elle découvre sa voix, le chant lyrique, squatté, mâché, polyphonique. Elle arbore ainsi de nouveaux chemins artistiques en participant à des projets liant voix, corps et instruments.<br>  Membre fondatrice du Trio Anticyclone, elle est régulièrement présente sur les projets du label Freddy Morezon, elle vient de rejoindre la Fanfare d’occasion et travaille également pour le théâtre (Cie Famille Goldini, Les Voyageurs Immobiles, La muse).</p>  <p>MAREK KASTELNIK Musicus pianisticus vox<br>  Artiste polymorphe, Marek Kastelnik commence son apprentissage du piano dans un univers où le chant baroque et la musique de films font partie du quotidien ; une exploration mélodique, harmonique et théâtrale de la musique. Il suit une formation de comédien et accompagne alors de nombreux chanteurs et chanteuses. Il découvre le vaste répertoire du cabaret et de la chanson française du 20ème siècle. Il étudie ensuite la musique contemporaine au Conservatoire de Bordeaux ainsi que la musique dite impressionniste. Dans le même temps, il se dirige vers l’improvisation en explorant la nature atonale et expérimentale de la musique. Il plonge dans la manufacture de son instrument en se formant à l’accord et la réparation des pianos. Ces dernieres années, il sublime son intérêt pour la pop musique en créant le personnage de Mike<br>  Starnight, looser magnifique grâce auquel il réinterprète les chansons de Bowie ou Freddie Mercury. En 2013, il crée avec Charlène Moura le Groupe Anticyclone et travaille en tant que compositeur<br>  et comédien pour le spectacle vivant (Typhus Bronx, Cie 14:20, Blizzard Concept, Collectif Méchant Machin).</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '291d073c-7dae-47c4-9c4c-a4ca880eba49');
