INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('7ad50ab4-4a03-49d6-9356-7014fe633b07', 'exposition', true, false, NULL, '2023-04-11T22:00:00.000Z', '2023-05-11T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2023-04-11T22:00:00.000Z', '2023-04-11T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Hautes lumières - Photographies des Pyrénées par Denis Frossard', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans ce monde étrange et proche, fascinant et magnifique, chaque aventure est souvent la plus belle de toutes. Peut-être par une imprégnation familiale qui compte de nombreux montagnards, par goût personnel, ou tout simplement les deux. Il compte parmi ses aïeux le pasteur Émilien Frossard, qui fut, à la fin du XIXè&nbsp;s., créateur avec Henry Russel de la société Ramond, participa à la fondation de l''observatoire du pic de midi de Bigorre, et publia notamment des dessins lithographiés des Pyrénées Françaises salués par les pyrénéistes d''alors.</p>  <p>Du regard au dessin, du graphisme à la photographie, ce montagnard originaire d''Orthez et vivant aujourd''hui à Asson dans la vallée de l''Ouzoum, a toujours été captivé par les lumières et l''espace des altitudes qu''il parcourt en toute saison, à la recherche, comme tout photographe, des regards et des atmosphères qui rendent nos Pyrénées si belles.</p>  <p>Il vient de publier un livre de photos consacré à la vie pastorale du haut Béarn aux éditions Reclams / Escòla Gaston Febus, préfacé par Patrice Tesseire-Dufour, chef de la rubrique Montange et reporter à Pyrénées Magazine.</p>  <p>Cela ne l''empêche pas de faire des escapades en plaine ! Puisqu''il travaille également d''autres genres photographiques comme les paysages marins, la scène, la danse classique, traditionnelle, le portrait...</p>  <p>Entre les photos anticipées et issues de recherches minutieuses, parfois longues, sur le terrain, et les clichés imprévus qu''il faut savoir cueillir quand ils se présentent, cet auteur photographe nous livre ici ses souvenirs les plus vivants des beautés les plus élémentaires, de roche, de neige, de vent, de nuages et de soleil.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7ad50ab4-4a03-49d6-9356-7014fe633b07');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Hautes lumières - Photographies des Pyrénées par Denis Frossard', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans ce monde étrange et proche, fascinant et magnifique, chaque aventure est souvent la plus belle de toutes. Peut-être par une imprégnation familiale qui compte de nombreux montagnards, par goût personnel, ou tout simplement les deux. Il compte parmi ses aïeux le pasteur Émilien Frossard, qui fut, à la fin du XIXè&nbsp;s., créateur avec Henry Russel de la société Ramond, participa à la fondation de l''observatoire du pic de midi de Bigorre, et publia notamment des dessins lithographiés des Pyrénées Françaises salués par les pyrénéistes d''alors.</p>  <p>Du regard au dessin, du graphisme à la photographie, ce montagnard originaire d''Orthez et vivant aujourd''hui à Asson dans la vallée de l''Ouzoum, a toujours été captivé par les lumières et l''espace des altitudes qu''il parcourt en toute saison, à la recherche, comme tout photographe, des regards et des atmosphères qui rendent nos Pyrénées si belles.</p>  <p>Il vient de publier un livre de photos consacré à la vie pastorale du haut Béarn aux éditions Reclams / Escòla Gaston Febus, préfacé par Patrice Tesseire-Dufour, chef de la rubrique Montange et reporter à Pyrénées Magazine.</p>  <p>Cela ne l''empêche pas de faire des escapades en plaine ! Puisqu''il travaille également d''autres genres photographiques comme les paysages marins, la scène, la danse classique, traditionnelle, le portrait...</p>  <p>Entre les photos anticipées et issues de recherches minutieuses, parfois longues, sur le terrain, et les clichés imprévus qu''il faut savoir cueillir quand ils se présentent, cet auteur photographe nous livre ici ses souvenirs les plus vivants des beautés les plus élémentaires, de roche, de neige, de vent, de nuages et de soleil.</p> ","type":"text","version":