INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Avant première "Olga & Olga"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Olga et Olga sont venues pour vous faire rêver, vous faire frissonner, vous faire transpirer...</p>  <p></p>  <p>Solo clownesque et circassien d''une dresseuse de chienne&nbsp;déchue et de sa chienne libertaire.</p>  <p></p>  <p><em>Avec Cali Hays et Olga.</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4cf1b37f-2cd8-4edd-bbbb-9779f6f10eb3');
