INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('2fad0403-fadd-49b0-b7d6-7b304da61a8a', 'exposition', true, false, NULL, '2023-05-14T22:00:00.000Z', '2023-07-05T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2023-05-14T22:00:00.000Z', '2023-05-14T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Tout semble si" - Guillaume Noury', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Il y a des lieux auxquels nous sommes liés, peut-être parce que nous y avons grandi, que nous y vivons, il y aussi des lieux qui nous traversent où l’on cherche à revenir. De mon côté, il s’agit de les arpenter, de les explorer attentivement afin d’en faire ressortir des fragments de mon imaginaire, ce sont les allers-retours dans ses différents territoires que se construit ma pratique photographique, comme des échos à des souvenirs mais aussi comme une projection de ce qui sera, de ce qui pourrait être. Les Pyrénées et plus particulièrement les vallées des Gaves sont un vaste pays et ses différentes facettes résonnent en moi.</p>  <p><strong>VERNISSAGE LUNDI 15 MAI A 18H</strong></p>  <p></p>  <p>Guillaume Noury, photographe :</p>  <p>Après avoir découvert la photographie comme moyen d’expression au début des années 2000, Guillaume a longtemps exploré la pratique sous toutes ses formes avant un choc esthétique : ce fut la découverte du livre Transibériades de Klavdij Sluban à la librairie Coiffard de Nantes. Il a&nbsp;depuis une pratique exclusivement en noir et blanc autour d’une recherche sur les territoires qu''il&nbsp;traverse, notamment ligériens et pyrénéens, et leurs liens avec son&nbsp;imaginaire.</p>  <p>Cette écriture photographique lui a permis de devenir le premier lauréat du Vincennes Images Festival en 2015 et d’obtenir le prix du jury au festival Planche(s) Contact de Deauville en 2018. L’expérience de la création du livre « Terres obsidiennes » avec les éditions Sur La Crête paru en 2021 l’incite aujourd’hui à poursuivre dans cette voie, il&nbsp;travaille depuis 2020 sur un nouveau projet éditorial qui sera mené sur le long terme afin d’aller le plus loin possible dans la construction de son&nbsp;propre langage.</p>  <p><br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2fad0403-fadd-49b0-b7d6-7b304da61a8a');
