('1e871b4e-ca78-4e7c-86fa-acd2e144ee15', 'evenement', true, false, false, NULL, '2023-08-29T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2023-08-29T22:00:00.000Z', '2023-08-29T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "Rino" - Cie Two', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Duo radiophonique sur vélo acrobatique - Tout public à partir de 6 ans - Durée : 1h</p>  <p>A coups de pédales et de riffs de guitare, par leurs récits, chants et cris, ces deux acrobates armés de micros, casques et ampli vont faire resurgir un éventail de souvenirs absurdes et idéalisés. Les leurs, mais aussi les vôtres.</p>  <p>Ensemble, ils réécrivent nos rêves, tournent en rond, dansent, pédalent et luttent pour continuer à témoigner du chaos du monde… ou sauter en cours de route.</p>  <p></p>  <p><strong>La distribution du spectacle :</strong></p>  <p>De Noëmie Bouissou et Ricardo Gaiser</p>  <p>Par Noëmie Bouissou (ou Renata Aldegheri do Val) et Ricardo Gaiser</p>  <p>Technique : Bambou Monnet ou Raphaël Jourdain</p>  <p>Regard Extérieur: Benjamin de Matteïs</p>  <p>Conseil au Vélo Acrobatique: Claire Ruiz</p>  <p>Conseil Musical: Katja Andersen</p>  <p>Création Sonore: Charlotte Comte et Raphaël Jourdain</p>  <p>Costumes : Lydie Tarragon</p>  <p>Coproduction et Accueil en Résidence : La Cascade - Pôle National Cirque - Ardèche Auvergne Rhône-Alpes / Avant-Scène Cognac, Scène conventionnée / 6Mettre pôle de création transdisciplinaire dédié aux arts vivants</p>  <p>Aide à la résidence: Carré Magique - Pôle national cirque Lannion</p>  <p>Accueil en Résidence : La Grainerie / La Cave Coopérative Baro D''Evel / La Bouriette</p>  <p></p>  <p><strong>MICRO-TROTTOIR</strong></p>  <p>Nous cherchons aussi à intégrer le territoire et ses habitants à notre notre bande son. Un jour avant la présentation, nous faisons une intervention « micro-trottoir » pour récolter auprès des habitants leurs histoires, rêves, souvenirs anecdotes et leurs lien avec le lieu.</p>  <p>Juste avant le spectacle nous ferons le même procédé avec le public présent.</p>  <p>Avec ce matériel sonore récolté, nous allons remixer en direct leurs paroles, les travailler en musique, les intégrer dans une rythmique et créer la musique finale du spectacle. Plus qu’une simple bande sonore, le résultat est une carte postale sonore qui traverse les âges et milieux culturels, et qui résonnera bien différemment suivant les lieux et publics.</p>  <p>Rendez-vous : Place du&nbsp; 19 mars&nbsp;</p>  <p><em>Gratuit, programmé dans le cadre des mercredis artistiques.&nbsp;</em></p>  <p><em>Crédit photo : Caroline Fabre</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1e871b4e-ca78-4e7c-86fa-acd2e144ee15');
