INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Dark Mountains par Patrice Robert', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Patrice Robert, artiste local dont le travail mérite une attention particulière.</p>  <p>Patrice crée des œuvres captivantes qui attirent immédiatement le regard par leur présence saisissante et leur esthétique unique. Son approche abstraite monochrome se déploie devant vous avec une présence énigmatique, presque hypnotique dont les nuances profondes et vibrantes semblent s''animer sous la lumière ambiante. Les courbes se succèdent, se superposent et s''entrelacent, créant un jeu visuel dynamique et harmonieux. Les reflets délicats créent des effets changeants selon l''angle de vision, invitant ainsi l''observateur à se déplacer autour des œuvres pour en explorer toutes les nuances. Ces jeux subtils de lumières et d''ombres accentuent les volumes et ajoutent une dimension supplémentaire à l''œuvre.</p>  <p>Les mouvements organiques de sa peinture encouragent l''observateur à la contemplation et à la réflexion, lui offrant un espace pour se perdre dans les méandres de l''abstraction et de l''interprétation.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1a4cf196-b0fc-4800-bad7-fcc0761519a1');
