INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La maison est une femme de 40 ans par Adèle Daleas', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>La Maison est une femme de quarante ans : Portraits de femmes par Adèle Daléas.</strong></p>  <p style=\"text-align: justify;\">Cette exposition photographique rassemble (presque) toutes les femmes de quarante ans (ou plus) qui ont fait la Maison au fil du temps et depuis son ouverture. Elle met en lumière la beauté, la force et la persévérance de toutes celles qui ont travaillé dans l’ombre et défendu les valeurs de la culture au travers de leur métier au sein de la structure.</p>  <p style=\"text-align: justify;\">La Maison du Parc national et de la vallée à choisi de travailler avec Adèle Daléas car son travail créatif est empreint d’une grande sensibilité, ouvrant, par son approche, une fenêtre sur l’histoire de la structure. Avec ce projet, elle rend hommage aux femmes qui ont travaillé avec une détermination et une passion remarquables créant ainsi une maison « à leur image ».</p>  <p style=\"text-align: justify;\">Adèle, jeune photographe talentueuse fait de l’argentique noir et blanc. Le noir et blanc esthétise légèrement une photo et rend ainsi une petite distance avec le réel tel qu’on le perçoit. L''argentique demande également une prise de vue plus intuitive notamment parce que le résultat n’est pas visible directement, ce qui ouvre souvent de beaux et surprenants espaces de spontanéité. Le noir et blanc confère aux prises de vues une dimension intemporelle et authentique.</p>  <p style=\"text-align: justify;\">Adèle considère qu’une photo n’a pas la prétention de retranscrire entièrement et absolument l’essence d’une personne mais plutôt de témoigner d’une existence, en donner une trace. Un mouvement, un geste, les yeux fermés, une main, un objet peuvent tout autant être évocateurs/révélateurs de l’histoire tissée avec la Maison du Parc national et de la vallée.</p>  <p style=\"text-align: justify;\">Cette exposition célèbre ces femmes d’horizons différents mais également toutes les femmes qui ont contribué et qui continuent à contribuer à la société. Elle est une expérience visuelle captivante et émouvante, qui rend hommage à la force et à la beauté des femmes de plus de quarante ans.</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a70be165-6bde-46bf-a5b5-cd079dae36e3');
