INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "MAMIE JOTAX" ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Mamie Jotax c’est d’abord une joyeuse chimère syllabique, née d’un éternuement du hasard et d’une pincée d’onomatopées. Un sésame qui secoue l’imagination et insuffle des mondes envoûtants et insolites.</p>  <p>Et puis, Mamie Jotax est très vite devenu un esprit. Une bulle remplie d’idéal, de curiosité et de folie qui veille sur les deux musiciennes. Une sorte de manifeste en forme de vieille valise, où les deux exploratrices collectionnent tout ce qui sur leur route mérite d’être gardé, et tout ce qui n’existe pas encore. Mamie Jotax est aussi une muse fraternelle, maternelle, aussi rugueuse et ridée qu’un arbre millénaire, précieuse conseillère qui apporte sa philosophie et son grain de folie. Ou bien l’enfant éternel dont la malice et l’enthousiasme éclairent les labyrinthes parfois nébuleux de la création.</p>  <p>Mamie Jotax sait aussi revêtir les habits des personnages qui ont marqué nos vies par leur sagesse, leur audace, leur fantaisie ou leur génie. C’est le cortège de nos maîtres, de nos diables et de nos amours.</p>  <p>Camille Maussion | saxophones soprano et ténor - voix - compositions, arrangements.</p>  <p>Carmen Lefrançois | saxophones alto, soprano et baryton - flûte, voix - compositions, arrangements.</p>  <p></p>  <p>Lieu de rendez-vous : Carrous''ailes - Balade du Bastan</p>  <p><em>Programmé en partenariat avec l''association Jazz Pyr'' dans le cadre du festival \"Jazz à Luz\".</em></p>  <p><em>Crédit photo : Christophe Girard</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a3004e51-18a6-4378-8bab-a8e6fce858d9');
