INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi artistique" Le voyage de valise" - Cie Histoire de chanter', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Une petite valise part à Paris avec Alice pour les vacances. Valise se perd à l’aéroport. Une hôtesse de l’air la prend sous son aile et lui fait faire un tour du monde initiatique. En Louisiane, elle découvre Ali, l’alligator coquet sans dents qui rêve de découvrir Paris. En Afrique, elle rencontre Aminata. En Russie, elle se retrouve au cœur d’un ballet russe. Sur le retour, dans la soute à bagages, elle joue avec des musiciens tziganes et leur conte son périple en chansons.&nbsp;</p>  <p>Alice va-t-elle retrouver sa valise ?&nbsp; &nbsp;Un voyage vers la confiance en soi par les rencontres, le théâtre, la musique, la chanson, le rire...</p>  <p><em>Spectacle familial, à partir de 4 ans - Rendez-vous Place du 19 mars.</em></p>  <p><em>Gratuit, programmé dans le cadre des mercredis artistiques.&nbsp;&nbsp;</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '913244dd-3e64-4035-b123-b7d65f63ebb6');
