INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "arbres modestes'' - Cie Volpinex', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Arbres modestes - Théâtre d''objets par la Cie Volpinex.</strong></p>  <p>Une table de tapissier, un escabeau, quelques pots de peinture, des chiffons, cartons et autres vieux journaux… équipés de matériel et combinaisons de travail, une comédienne et un comédien reconvertis dans les travaux de peinture annoncent la couleur : ayant arrêté de faire des spectacles, ils proposent de mettre à profit le temps passé avec le public pour lui transmettre des connaissances utiles. Très vite, la démonstration vire au récit pseudo-scientifique : et si on reprenait tout depuis le début ? Des premières formes de vie sur Terre, premiers micro-organismes, espèces animales, végétales, jusqu’à l’apparition (et la disparition ?) de l’humanité... Les deux collègues illustrent leur propos avec les objets qu''ils ont sous la main : pinceaux, outils, rouleaux de scotch, papier journal, carton... Coûte que coûte et avec les moyens du bord, ne renonçant jamais car le ridicule ne tue pas, ils racontent la vie d''un chêne, depuis sa naissance jusqu''à sa longue traversée des siècles.</p>  <p>Écriture, jeu, mise en scène : Fred Ladoué et Marielle Gautheron&nbsp; / Aide à la mise en scène : Béla Czuppon / Regard extérieur : Sigrid Bordier / Construction : Fred Ladoué, Marielle Gautheron</p>  <p>Aide à la construction : Johann Schipper / Assistance technique son : Tony Bruneau / Création lumière : Christophe Mazet</p>  <p>Compagnie soutenue par la ville de Mauguio-Carnon, La Krèche-Fabrique Artistique.</p>  <p>Crédit photo : Philippe Rappeneau</p>  <p></p>  <p><em>Durée : 45 minutes / Tout public à partir de 6 ans - Rendez-vous au Parc de la Mairie.</em></p>  <p><em>Gratuit, programmé dans le cadre des mercredis artistiques.</em></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '12eb97a3-c04a-421f-90ce-b90c22c035e5');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('MERCREDI ARTISTIQUE "arbres modestes'' - Cie Volpinex', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Arbres modestes - Théâtre d''objets par la Cie Volpinex.</strong></p>  <p>Une table de tapissier, un escabeau, quelques pots de peinture, des chiffons, cartons et autres vieux journaux… équipés de matériel et combinaisons de travail, une comédienne et un comédien reconvertis dans les travaux de peinture annoncent la couleur : ayant arrêté de faire des spectacles, ils proposent de mettre à profit le temps passé avec le public pour lui transmettre des connaissances utiles. Très vite, la démonstration vire au récit pseudo-scientifique : et si on reprenait tout depuis le début ? Des premières formes de vie sur Terre, premiers micro-organismes, espèces animales, végétales, jusqu’à l’apparition (et la disparition ?) de l’humanité... Les deux collègues illustrent leur propos avec les objets qu''ils ont sous la main : pinceaux, outils, rouleaux de scotch, papier journal, carton... Coûte que coûte et avec les moyens du bord, ne renonçant jamais car le ridicule ne tue pas, ils racontent la vie d''un chêne, depuis sa naissance jusqu''à sa longue traversée des siècles.</p>  <p>Écriture, jeu, mise en scène : Fred Ladoué et Marielle Gautheron&nbsp; / Aide à la mise en scène : Béla Czuppon / Regard extérieur : Sigrid Bordier / Construction : Fred Ladoué, Marielle Gautheron</p>  <p>Aide à la construction : Johann Schipper / Assistance technique son : Tony Bruneau / Création lumière : Christophe Mazet</p>  <p>Compagnie soutenue par la ville de Mauguio-Carnon, La Krèche-Fabrique Artistique.</p>  <p>Crédit photo : Philippe Rappeneau</p>  <p></p>  <p><em>Durée : 45 minutes / Tout public à partir de 6 ans - Rendez-vous au Parc de la Mairie.</em></p>  <p><em>Gratuit, programmé dans le cadre des mercredis artistiques.</em></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '12eb97a3-c04a-421f-90ce-b90c22c035e5');
