INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CARTE CADEAU 40EME ANNIVERSAIRE : CIRQUE JAFARSON', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Dans le cadre de son quarantième anniversaire, la Maison du Parc national et de la vallée met en place une série de collaborations artistiques avec des artistes issues du spectacle vivant et qui ont marqué l’histoire récente de la maison. Ces « cartes cadeaux » sont l’occasion de collaborer avec des artistes qui connaissent et aiment le territoire. Afin d’offrir au public des performances uniques, nous avons donné à ces artistes talentueuses la liberté totale de s''exprimer, de créer, d''explorer de nouvelles frontières artistiques et de partager leur vision créative. Leur talent est notre plus grand cadeau. En offrant ces cartes blanches en forme de cadeau aux artistes, la Maison souhaite aussi remercier et témoigner sa gratitude au public sans lequel elle ne serait pas ce qu’elle est aujourd’hui. Faites place à la créativité et à la diversité avec des propositions artistiques aussi variées qu’originales et accessibles à tous.</p>  <p></p>  <p><strong>« Mont »</strong>&nbsp;</p>  <p>Le rendez-vous est donné devant la Maison du Parc national et de la vallée, dans le rectangle d’herbe, là où tout a commencé. Puis, il faudra rejoindre le spectacle ensemble, sur les hauteurs de Luz. Passer la passerelle, et atteindre le point culminant, le Mont. Suivre la carte. Là-bas, nous serons un groupe, attendant l’arrivée des regards pour nous réveiller. Nous existerons par le dessin de nos postures variées, chacun à son rythme, dans une vibration commune incessante. Nous chercherons sur tous les axes, fragmenterons le groupe pour mieux le retrouver, presque famille. Il y aura du cirque, de la danse, de la musique, ce sera vivant. On voudra rendre les choses moins réelles, les contours moins nets, et échapper à l’autoritaire sens pour créer un fragment onirique. Il s’agira de faire exister, là où tout nous a inspiré, Mont.</p>  <p>Le travail de la compagnie de spectacle vivant Le Cirque Jafarson est depuis plusieurs années axé sur la fiction et la création d’univers. Cette carte blanche sera l’occasion d’en proposer une version extérieure et in situe, inspirée des spectacles « Racynthe » et « Mont, pièce pour huit corps » et bien entendu, fêter les 40 ans de la Maison du Parc national et de la vallée ! »</p>  <p></p>  <p><em>Crédit photo : Virginie Terroitin</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '171dee7f-ea75-46b5-94dc-c60cd863623c');
