INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"LUTZ DE LUA" ESTELUM ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>PROGRAMMÉ DANS LE CADRE DES JOURNÉES MATRIMOINES</strong></p>  <p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Estelum est un ensemble féminin de chanteuses formées aux polyphonies d’Occitanie, sous la direction de Pascal Caumont. Cinq chanteuses ont entrepris de redonner vie au répertoire de chants sacrés et rituels du domaine culturel occitan : chants de rites calendaires et de coutumes, chants de prières populaires en occitan ou de la liturgie en latin et en grec dans la tradition vocale polyphonique pyrénéenne, ou bien encore de création plus récente. Des polyphonies ancrées « entre ciel et terre », témoins du sens du sacré populaire, aux chants de fonctions rituelles du cycle de la vie et des saisons, ces polyphonies trouvent une résonance universelle et immémoriale où chacun peut se laisser toucher par la magie des accords et la vibration des voix.</p>  <p style=\"text-align: justify;\">Pascal Caumont assure la direction artistique de ce projet : il a choisi cinq chanteuses dont les parcours servent le répertoire traditionnel occitan depuis de nombreuses années. Cinq voix ancrées, rompues à l’exercice de la polyphonie, complices et engagées. L’une d’elle, Nadèta Carita, est l’une des dernières dépositaires d’un répertoire sacré qui se chantait naturellement en polyphonie dans son village des Hautes-Pyrénées. Ces harmonisations propres à ce village constituent le cœur du répertoire dans une perspective de conservation et de transmission de ces chants, qui, qu’on soit croyant pratiquant ou agnostique invétéré, portent en eux une charge énergétique forte et communicative. D’autres pièces liées au chant de rite occitan (prières, quête, procession...) viennent enrichir le répertoire comme le magnifique Salve Regina du Rouergue ou le Oc Paire composé par Thierry Cornillon.</p>  <p style=\"text-align: justify;\">Créé en 2019 dans les Hautes-Pyrénées, l’ensemble est constitué de Nadèta Carita, formée depuis son enfance dans son village des chanteuses du Hautacam (Ayros Arbouix), d’Anne Enjalbert, issue d’une famille de chanteurs et danseurs du Rouergue, d’Hélène Bernard, formée au chant occitan à Toulouse, de Lutxi Achiary, issue elle aussi d’une famille de chanteurs, et de Virginie Ardaen, formée au chant occitan. Toutes ces personnalités sont également des transmetteuses, habitées par le désir de partager le répertoire et les sonorités caractéristiques.</p>  <p style=\"text-align: justify;\">Création cofinancée par la DRAC Occitanie, la Région Occitanie, la Ville de Tarbes et avec le soutien du COMDT.<em> </em></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>ARTISTES</strong><br>  Site Estelum : https://www.estelum-polifonia.com/<br>  Nadèta Carita<br>  Anne Enjalbert<br>  Hélène Bernard<br>  Lutxi Achiary<br>  Virginie Ardaen</p>  <p style=\"text-align: justify;\"><strong>CRÉDIT PHOTO</strong><br>  Suzy Noguès</p>  <p><strong>LIEU</strong><br>  Salle des voûtes</p>  <p><strong>TARIF</strong><br>  Offert dans le cadre du 40ème anniversaire de la Maison du Parc national et de la vallée</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ef5858d0-2d9f-4088-9d80-27c40d69fcb8');
