INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('mercredi artistique "Aèdes"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Aèdes est né en 2018 de la rencontre entre Lutxi Achiary &amp; Thomas Baudoin. Donnant la part belle aux voix, Aèdes s’accompagne d''un instrumentarium peu commun, à la fois léger et minimaliste : deux shruti box indiennes, deux tambourins à cordes du Béarn, dont les sonorités sont proches du timbre des chanteurs. Une femme et un homme, côte à côte, donnent à entendre des chants à l''unisson, des chants en polyphonies, issus du répertoire oral gascon. Mais en Béarn, chanter, c’est raconter. Chansons d''amour, épopées lancinantes ou chagrin brutal, entre fraîches litanies et lamentations lumineuses, on entend dans les chants d''Aèdes les résonances pyrénéennes des voix de Lutxi Achiary et Thomas Baudoin qui jouent et s''entremêlent sur le \"camin sobiran\", le chemin des crêtes, sur un fil dans un subtil équilibre poétique fait d’envolées et de rudesses, de douceur et de croche-pattes, délicat et sauvage. En 2023, la nouvelle scénographie de Thierry Moinet, et le travail de son de Romain « Pairbon » Colautti viennent sublimer le travail du duo. En 2024 avec sa nouvelle création « Gaves », Aèdes prendra le chemin de l’improvisation vocale avec de prestigieux guides puis explorera la piste électronique : Comment la machine pourra-t-elle se mettre au service de la matière pour donner à entendre ce qui parfois ne l’est pas.&nbsp;</p>  <p><em>Tout public - Rendez vous au Parc de la Mairie.</em></p>  <p><em>Offert - Programmé dans le cadre des mercredis artistiques.&nbsp;</em></p>  <p><em>Crédit photo : Anaël Garcia-Drieu</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5a6916ac-9a98-4b68-8103-324493c3941d');
