INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('mercredi artistique "bulldog"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>3 complices de 25 ans d’aventures musicales communes, qui se sont croisés, décroisés, recroisés, de concert en bal échevelés, de déambulations en manifestations farfelues, d’enregistrements en ciné-concerts débridés…</p>  <p>A tel point qu’on ne peut plus dire quelle toile ils vont tisser. Sera-t-elle festive, teintée de jazz, saupoudrés de « musiques du monde », tout à la fois, qui peut le dire ?</p>  <p>En tout cas, ces trois là se connaissent, s’apprécient, se respectent, à tel point que leur bonheur à construire la musique est communicatif, que leur enthousiasme déborde de la scène…</p>  <p>Didier Dulieux : accordina / Laurent Guitton : tuba / Éric Boccalini : batterie.</p>  <p></p>  <p><em>Tout public - Rendez-vous au Parc de la Mairie.</em></p>  <p><em>Offert - Programmé dans le cadre des mercredis artistiques.</em></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e6d59667-29bc-4b5e-acfd-59ca9f9d3d08');
