INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Atelier Land Art', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\">La culture est notre nature&nbsp;:&nbsp;création&nbsp;artistique participative autour du végétal</p>  <p style=\"text-align: justify;\">Nelly Ducamp,&nbsp;est une&nbsp;artiste végétale&nbsp;dont les créations naissent au fil des projets.&nbsp;Elle&nbsp;aime créer sur&nbsp;l’instant&nbsp;des œuvres uniques, sorte de \"sur mesure\" inspirées de la matière, des saisons, du lieu.&nbsp;Elle&nbsp;puise&nbsp;son inspiration dans l''environnement dans lequel&nbsp;elle a&nbsp;grandi…&nbsp;les&nbsp;Pyrénées,&nbsp;le&nbsp;Pays Toy. Fleuriste de formation&nbsp;elle&nbsp;imagine chaque œuvre comme un tableau vivant,&nbsp;et&nbsp;glane dans la nature environnante des formes, couleurs, textures d''éléments naturels.&nbsp;</p>  <p style=\"text-align: justify;\">Chaque événement est&nbsp;une&nbsp;occasion de créer quelque chose d’unique, instant de partage entre les participants… œuvre unique et éphémère.&nbsp;En utilisant des matériaux organiques et en mettant en valeur la beauté naturelle des végétaux, elle souhaite sensibiliser les participants à la richesse de la biodiversité et à l''importance de préserver notre environnement.</p>  <p style=\"text-align: justify;\">Sa proposition artistique sera l’objet d’une collaboration participative avec le public.</p>  <p style=\"text-align: justify;\">Laissez-vous guider par&nbsp;cette&nbsp;artiste spécialiste de la création végétale et&nbsp;vivez une expérience immersive artistique interactive et ludique qui éveillera votre créativité et votre lien avec le règne végétal.&nbsp;Une occasion pour prendre du temps, se reconnecter à la nature et partager un moment en famille et avec les autres.</p>  <p style=\"text-align: justify;\">Ateliers programmés dans le cadre du 40ème anniversaire de la Maison.</p>  <p style=\"text-align: justify;\">4 créneaux de 2 heures d''ateliers<br>  le Lundi&nbsp;14 ou le Mardi&nbsp;15 août de 10h à 12h ou de 14h à 16h – offerts – places limitées - sur inscription au 0562923838</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '670db5c7-2066-45a7-a15d-dc7a38832b3f');
