INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les points rencontres', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<section class=\"fiche-oi-description\" id=\"description\">  <div class=\"fiche-oi-description__text\">   <p style=\"text-align: center;\">Les gardes-moniteurs du Parc National partageront avec vous leurs savoirs et connaissances. L’occasion pour vous de découvrir leur métier et d’aiguiser<br>    votre curiosité quant aux patrimoines naturels, culturels et paysagers du Parc National des Pyrénées.</p>    <p style=\"text-align: center;\">Le rendez-vous du point rencontre sera matérialisé par un panneau Parc national.</p>    <p style=\"text-align: center;\"><strong>Points rencontres à Troumouse<br>    Tous les lundi<br>    du 03 juillet au 28 août de 10h à 12h</strong><br>    &nbsp;</p>    <p style=\"text-align: center;\"><strong>Points rencontres à Gavarnie - Chemin du Cirque<br>    Tous les mardi et jeudi<br>    du 04&nbsp;juillet au 31 août de 10h à 12h</strong><br>    &nbsp;</p>  </div> </section> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a3e7130e-f45d-47dc-85d7-270c836defed');
