INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('BOUILLON BRUME', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Anna Burlet et Camille Savoye réalisent des installations artistiques et culinaires.<br>  Leur récente collaboration est basée sur la recherche artistique culinaire autour du paysage en imaginant des installations et des dégustations. Pour leurs performances en Pays Toy, elles vont travailler à la mise en scène d’un service adapté à partir des matières premières collectées sur le territoire et utiliseront différentes techniques. Une installation à découvrir et à consommer sur place !<br>  Découvrez l’intégralité du programme de Jazz à Luz : www.jazzaluz.com</p>  <p><strong>Jeudi 13 juillet à partir de 10h30 et</strong><br>  <strong>Vendredi 14 juillet à partir de 10h30</strong></p>  <p>Lieu de rendez-vous : École d''Equièze-Sère</p>  <p><em>Programmé en partenariat avec l''association Jazz Pyr'' dans le cadre du festival \"Jazz à Luz\".</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8bbf16fd-311f-4ccd-9806-d4ebfab88508');
