INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CARTE CADEAU 40EME ANNIVERSAIRE : CALI', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>LA CARTE CADEAU</strong><br>  Dans le cadre de son quarantième anniversaire, la Maison du Parc national et de la vallée met en place une série de collaborations artistiques avec des artistes issues du spectacle vivant et qui ont marqué l’histoire récente de la maison. Ces « cartes cadeaux » sont l’occasion de collaborer avec des artistes qui connaissent et aiment le territoire. Afin d’offrir au public des performances uniques, nous avons donné à ces artistes talentueuses la liberté totale de s''exprimer, de créer, d''explorer de nouvelles frontières artistiques et de partager leur vision créative. Leur talent est notre plus grand cadeau. En offrant ces cartes blanches en forme de cadeau aux artistes, la Maison souhaite aussi remercier et témoigner sa gratitude au public sans lequel elle ne serait pas ce qu’elle est aujourd’hui. Faites place à la créativité et à la diversité avec des propositions artistiques aussi variées qu’originales et accessibles à tous.</p>  <p></p>  <p><strong>« CALI ET LA FANFOLLE&nbsp;»</strong><br>  &nbsp;Impromptu musical et circassien au coin de la rue</p>  <p style=\"text-align: justify;\">Cette joyeuse équipe artistique propose une expérience inédite et unique, une performance inattendue où le spectacle se mêle à la vie quotidienne et transforme les lieux publics en scènes éphémères. Cet impromptu fusionne les arts de la musique et du cirque avec la volonté de mettre de la poésie au détour d''une ruelle, d''un hall d''accueil, de faire vivre un moment célébrant la créativité avec les habitants de Luz. C''est une rencontre inspirée entre équilibres, portés acrobatiques et fanfare intimiste.<br>  Cette performance in situ est une invitation à s’arrêter un instant au coin de la rue, à laisser les notes de musique et les acrobaties s’entremêler dans un tourbillon d''émotions. Elle témoigne de la volonté d’apporter l''art au plus près des gens, de briser les barrières traditionnelles du théâtre et de rendre l''expression artistique accessible à tous.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>ARTISTES</strong><br>  Paul Quénée, Anna Bouchet, Marion Hergas, Maxime Suzan, Cali Hays</p>  <p><strong>LIEU</strong><br>  Déambulation - Départ de la Maison du Parc national et de la vallée</p>  <p><strong>TARIF</strong><br>  Offert - Cette forme est une carte blanche créée spécialement pour les 40 ans de la Maison du Parc national et de la vallée.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6a5b9be2-9322-482f-85c0-e7b16966c572');
