INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CARTE CADEAU 40EME ANNIVERSAIRE : LAURETTE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>LA CARTE CADEAU</strong><br>  Dans le cadre de son quarantième anniversaire, la Maison du Parc national et de la vallée met en place une série de collaborations artistiques avec des artistes issues du spectacle vivant et qui ont marqué l’histoire récente de la maison. Ces « cartes cadeaux » sont l’occasion de collaborer avec des artistes qui connaissent et aiment le territoire. Afin d’offrir au public des performances uniques, nous avons donné à ces artistes talentueuses la liberté totale de s''exprimer, de créer, d''explorer de nouvelles frontières artistiques et de partager leur vision créative. Leur talent est notre plus grand cadeau. En offrant ces cartes blanches en forme de cadeau aux artistes, la Maison souhaite aussi remercier et témoigner sa gratitude au public sans lequel elle ne serait pas ce qu’elle est aujourd’hui. Faites place à la créativité et à la diversité avec des propositions artistiques aussi variées qu’originales et accessibles à tous.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>\"RETOUR D''OUEST #PYRÉNÉES\"</strong><br>  Pour cette carte Cadeau Laurette Gougeon a eu envie d''offrir une pièce circassienne et sonore sous forme de \"portrait\" du Pays Toy. Après quelques années à avoir vécu dans les Hautes-Alpes, elle revient à \"l''ouest\" pour retransmettre avec humour, nostalgie et joie sa vision de la vallée des Gaves qui fut son pays d''accueil pendant cinq ans…<br>  Pendant une semaine, les artistes vont sillonner le pays, à la rencontre de ses habitants. Par le biais d’échanges et d’interviews Laurette et Claire seront amenées à se plonger dans la vie locale pour puiser leurs inspirations de création. Elles vont écouter les histoires et les souvenirs, donnant ainsi naissance à une mosaïque riche et vibrante de récits authentiques.<br>  Ce spectacle créé spécialement pour l’anniversaire de la maison est un voyage à travers le temps et l''espace, une métaphore visuelle, un hommage vibrant à l''histoire et à la diversité de notre territoire. Il est un témoignage vivant de notre identité collective, créé avec passion et dévouement par des artistes qui ont été touchées par le Pays Toy. Cette pièce hybride est une expérience unique, où les témoignages prennent vie et où le cirque devient un langage universel qui transcende les frontières et nous unit tous.</p>  <p><strong>ARTISTES</strong><br>  Laurette Gougeon -&nbsp;Fil, Jeu, textes et écriture<br>  Claire Lauzon -&nbsp;Création sonore et écriture<br>  Avec les voix des habitants du pays toy</p>  <p><strong>INFORMATIONS</strong><br>  40 minutes<br>  Tout public</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Offert - Cette forme est une carte blanche créée spécialement pour les 40 ans de la Maison du Parc national et de la vallée.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2b1f8803-60c2-4954-9bb9-c910db8d1825');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CARTE CADEAU 40EME ANNIVERSAIRE : LAURETTE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>LA CARTE CADEAU</strong><br>  Dans le cadre de son quarantième anniversaire, la Maison du Parc national et de la vallée met en place une série de collaborations artistiques avec des artistes issues du spectacle vivant et qui ont marqué l’histoire récente de la maison. Ces « cartes cadeaux » sont l’occasion de collaborer avec des artistes qui connaissent et aiment le territoire. Afin d’offrir au public des performances uniques, nous avons donné à ces artistes talentueuses la liberté totale de s''exprimer, de créer, d''explorer de nouvelles frontières artistiques et de partager leur vision créative. Leur talent est notre plus grand cadeau. En offrant ces cartes blanches en forme de cadeau aux artistes, la Maison souhaite aussi remercier et témoigner sa gratitude au public sans lequel elle ne serait pas ce qu’elle est aujourd’hui. Faites place à la créativité et à la diversité avec des propositions artistiques aussi variées qu’originales et accessibles à tous.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>\"RETOUR D''OUEST #PYRÉNÉES\"</strong><br>  Pour cette carte Cadeau Laurette Gougeon a eu envie d''offrir une pièce circassienne et sonore sous forme de \"portrait\" du Pays Toy. Après quelques années à avoir vécu dans les Hautes-Alpes, elle revient à \"l''ouest\" pour retransmettre avec humour, nostalgie et joie sa vision de la vallée des Gaves qui fut son pays d''accueil pendant cinq ans…<br>  Pendant une semaine, les artistes vont sillonner le pays, à la rencontre de ses habitants. Par le biais d’échanges et d’interviews Laurette et Claire seront amenées à se plonger dans la vie locale pour puiser leurs inspirations de création. Elles vont écouter les histoires et les souvenirs, donnant ainsi naissance à une mosaïque riche et vibrante de récits authentiques.<br>  Ce spectacle créé spécialement pour l’anniversaire de la maison est un voyage à travers le temps et l''espace, une métaphore visuelle, un hommage vibrant à l''histoire et à la diversité de notre territoire. Il est un témoignage vivant de notre identité collective, créé avec passion et dévouement par des artistes qui ont été touchées par le Pays Toy. Cette pièce hybride est une expérience unique, où les témoignages prennent vie et où le cirque devient un langage universel qui transcende les frontières et nous unit tous.</p>  <p><strong>ARTISTES</strong><br>  Laurette Gougeon -&nbsp;Fil, Jeu, textes et écriture<br>  Claire Lauzon -&nbsp;Création sonore et écriture<br>  Avec les voix des habitants du pays toy</p>  <p><strong>INFORMATIONS</strong><br>  40 minutes<br>  Tout public</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Offert - Cette forme est une carte blanche créée spécialement pour les 40 ans de la Maison du Parc national et de la vallée.</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '2b1f8803-60c2-4954-9bb9-c910db8d1825');
