INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES (' CARTE CADEAU 40EME ANNIVERSAIRE : SOPHIE', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>LA CARTE CADEAU</strong><br>  Dans le cadre de son quarantième anniversaire, la Maison du Parc national et de la vallée met en place une série de collaborations artistiques avec des artistes issues du spectacle vivant et qui ont marqué l’histoire récente de la maison. Ces « cartes cadeaux » sont l’occasion de collaborer avec des artistes qui connaissent et aiment le territoire. Afin d’offrir au public des performances uniques, nous avons donné à ces artistes talentueuses la liberté totale de s''exprimer, de créer, d''explorer de nouvelles frontières artistiques et de partager leur vision créative. Leur talent est notre plus grand cadeau. En offrant ces cartes blanches en forme de cadeau aux artistes, la Maison souhaite aussi remercier et témoigner sa gratitude au public sans lequel elle ne serait pas ce qu’elle est aujourd’hui.&nbsp;Faites place à la créativité et à la diversité avec des propositions artistiques aussi variées qu’originales et accessibles à tous.</p>  <p style=\"text-align: justify;\"><strong>DESCRIPTION</strong></p>  <p>Pour cette dernière carte cadeau de l’année du quarantième anniversaire, Sophie Barros s’associe avec Fanny Barrouquère et Francis Ferrié.</p>  <p><br>  Grâce à ce projet, les danseuses s’emparent de l’opportunité de créer ensemble pour travailler à déployer une danse fluide et viscérale. Toutes deux défendent une danse physique, organique, souvent théâtrale. C’est autour de ces trois piliers qu’elles s’associent pour questionner la ressemblance et de la gémellité. Chacun de leurs mouvements révèle une histoire, un dialogue silencieux entre les corps. La grâce et la puissance, semblent évoluer dans un univers parallèle, explorant l''espace avec une élégance envoûtante.</p>  <p><br>  Au centre de cet équilibre délicat, le musicien pluri-instrumentiste crée une toile sonore qui est pour le mouvement, à la fois, source d’inspiration et résonance. La musique live amplifie l''intensité des mouvements, créant une synergie puissante entre la danse et la musique.<br>  Les trois artistes investiront la Maison du Parc National et de la Vallée pour une création originale in situ, ponctuée de clins d’œil à ce lieu souvent porteur d’itinérances et de déambulations.</p>  <p><strong>ARTISTES</strong><br>  Sophie Barros - Danseuse et comédienne<br>  Fanny Barrouquère - Danseuse<br>  Francis Ferrié - Musicien</p>  <p><strong>LIEU</strong><br>  Dans la Maison du Parc national et de la vallée</p>  <p><strong>TARIF</strong><br>  Offert - Cette forme est une carte blanche créée spécialement pour les 40 ans de la Maison du Parc national et de la vallée.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4d2070c0-091b-4ad5-a438-11ff66fbad01');
