INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Mieux vaut en rire - Un leçon impertinente de Zou" Maëlle Mays - Le Thyase', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>COLLABORATION AVEC LE PARVIS – SCENE NATIONALE TARBES</strong><br>  <br>  <strong>DESCRIPTION</strong><br>  Zou, pédagogue nomade, enseigne à loisir des sujets qu’on n’apprend pas à l’école et pourtant essentiels au vivre-ensemble. Elle explique, décortique, analyse et en profite pour taper des coups de gueule, prendre à parti, rebondir, resserrer les rangs, faire des sondages, montrer et démontrer nos évidences conditionnées.</p>  <p style=\"text-align: justify;\">Son naturel désarme, sa classe improvisée et ses exemples touchent les coeurs ensommeillés.</p>  <p style=\"text-align: justify;\">Pour cette nouvelle leçon impertinente sur le rire, elle est accompagnée d’une grande chercheuse spécialiste de la question. Avec sa « caution universitaire », elle nous parle de ce mécanisme dont le nourrisson jouit naturellement, dont l''enfant use éhontément et que l''adulte rationne, raisonne, cantonne culturellement. Paraît-il qu''on peut rire de tout mais pas avec tout le monde, ni partout, ni à n''importe quel moment. Paraît-il que parfois rire ça ne se fait pas ; que le rire est une arme, que le rire est une défense, qu''il est indicateur social de joie, de moquerie, de gêne… Mais à quoi pense-t-on quand il devient fou ? Un spectacle joyeux et intelligent dont on sort revigoré !</p>  <p><strong>ARTISTES&nbsp;</strong><br>  Maëlle Mays / Le Thyase</p>  <p><b>LIEU</b><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Tarifs du Parvis<br>  Normal 12 €, réduit 6 €, -26 ans 6 €, abonné 8€</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b3f47215-e2c5-4dc7-a8f8-4ebaadf7dd1c');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Mieux vaut en rire - Un leçon impertinente de Zou" Maëlle Mays - Le Thyase', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>COLLABORATION AVEC LE PARVIS – SCENE NATIONALE TARBES</strong><br>  <br>  <strong>DESCRIPTION</strong><br>  Zou, pédagogue nomade, enseigne à loisir des sujets qu’on n’apprend pas à l’école et pourtant essentiels au vivre-ensemble. Elle explique, décortique, analyse et en profite pour taper des coups de gueule, prendre à parti, rebondir, resserrer les rangs, faire des sondages, montrer et démontrer nos évidences conditionnées.</p>  <p style=\"text-align: justify;\">Son naturel désarme, sa classe improvisée et ses exemples touchent les coeurs ensommeillés.</p>  <p style=\"text-align: justify;\">Pour cette nouvelle leçon impertinente sur le rire, elle est accompagnée d’une grande chercheuse spécialiste de la question. Avec sa « caution universitaire », elle nous parle de ce mécanisme dont le nourrisson jouit naturellement, dont l''enfant use éhontément et que l''adulte rationne, raisonne, cantonne culturellement. Paraît-il qu''on peut rire de tout mais pas avec tout le monde, ni partout, ni à n''importe quel moment. Paraît-il que parfois rire ça ne se fait pas ; que le rire est une arme, que le rire est une défense, qu''il est indicateur social de joie, de moquerie, de gêne… Mais à quoi pense-t-on quand il devient fou ? Un spectacle joyeux et intelligent dont on sort revigoré !</p>  <p><strong>ARTISTES&nbsp;</strong><br>  Maëlle Mays / Le Thyase</p>  <p><b>LIEU</b><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Tarifs du Parvis<br>  Normal 12 €, réduit 6 €, -26 ans 6 €, abonné 8€</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'b3f47215-e2c5-4dc7-a8f8-4ebaadf7dd1c');
