INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Soirée Halloween', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>SOIRÉE HALLOWEEN</strong><br>  Projections cinéma ! Une surprise vous attend au début des séances !<br>  Les séances sont indépendantes l''une de l''autre.</p>  <p style=\"text-align: justify;\"><br>  <strong>À 19h00 \"L''étrange Noël de Monsieur Jack\" VF</strong><br>  À partir de 8 ans.<br>  Durée :&nbsp;1h15min<br>  Réalisateur :&nbsp;Tim Burton, Michael McDowell<br>  Avec :&nbsp;Chris Sarandon, Danny Elfman, Catherine O''Hara<br>  Synopsis : Jack Skellington, roi des citrouilles et guide de Halloween-ville, s''ennuie : depuis des siècles, il en a assez de préparer la même fête de Halloween qui revient chaque année, et il rêve de changement. C''est alors qu''il a l''idée de s''emparer de la fête de Noël...<br>  Bande annonce :&nbsp;https://youtu.be/ck_20rVKt_4?si=phFhdyPYjcu9FJry</p>  <p style=\"text-align: justify;\"><strong>À 20h30 \"The Shining\" VOSTFR</strong><br>  Durée :&nbsp;2h23min<br>  Réalisateur :&nbsp;Stanley Kubrick<br>  Acteurs :&nbsp;Jack Nicholson,&nbsp;Jean-Louis Trintignant,&nbsp;Shelley Duvall<br>  Synopsis :&nbsp;Interdit aux moins de 12 ans.&nbsp;Écrivain, Jack Torrance est engagé comme gardien, pendant tout l’hiver, d’un grand hôtel isolé du Colorado – l’Overlook – où il espère surmonter enfin sa panne d’inspiration. Il s’y installe avec sa femme Wendy et son fils Danny, doté d’un don de médium. Tandis que Jack n’avance pas dans son livre et que son fils est de plus en plus hanté par des visions terrifiantes, il découvre les terribles secrets de l’hôtel et bascule peu à peu dans une forme de folie meurtrière où il s’en prend à sa propre famille…<br>  Bande annonce :&nbsp;https://youtu.be/7gQNjXJPlzc?si=s1ugceqIp26O5Ir9</p>  <p style=\"text-align: justify;\"></p>  <p>LIEU<br>  Salle de cinéma de la Maison du Parc national et de la vallée</p>  <p>TARIF<br>  Tarifs classiques cinéma :<br>  6€ adulte / 5€ étudiant / 4€ enfant de moins de 13 ans / 48 €carte abonnés 10 entrées</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4c241c82-9e15-4437-a2e0-3c27fb6c36c4');
