INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence Cie ACMé - "Quelque Part dans l''Ouest"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Wyoming, 1872. Un relais isolé en bord de rivière, au pied des Collines Noires, près de la réserve des Sioux Lakotas. Le soir tombe. Un violent orage menace.</p>  <p style=\"text-align: justify;\">Alors qu''elle s''apprête à fermer, Stella, ancienne communarde, armurière réputée et tireuse hors-pair, voit débarquer trois personnages avec lesquels elle va devoir passer la nuit : Debbie, son amie de toujours, jeune fermière têtue et intrépide ; Birdie, montagnarde acculturée à la vie indienne, taiseuse et solitaire ; Ulysse, dit \"la Truite\", bandit en cavale, poète à ses heures, menteur invétéré.</p>  <p style=\"text-align: justify;\">Qu''est-ce que ces trois-là viennent fabriquer dans son relais à cette heure-ci, tandis qu''un déluge est prêt de s''abattre sur la vallée ? S''il y a un lien avec le convoi de pionniers qui s''est arrêté de l’autre côté de la rivière, il va falloir qu''ils crachent le morceau, et vite ! D''autant que ce convoi est dirigé par le terrible Clayton, brute sanguinaire et as de la gâchette...</p>  <p style=\"text-align: justify;\"><strong>Bouleverser les codes du western en rebattant les cartes du masculin et du féminin, c''est le jeu auquel la compagnie ACMé se prête avec jubilation, marchant sur les traces de classiques du cinéma tels que Johnny Guitar (Nicholas Ray) ou Convoi de femmes (William Wellman) qui, bien avant les séries The English ou Django, ont mis les personnages féminins au premier plan.</strong></p>  <p style=\"text-align: justify;\"><strong>Un western féministe au théâtre ?</strong></p>  <p style=\"text-align: justify;\"><strong>... en selle !</strong></p>  <p></p>  <p><strong>DATE</strong><br>  Sortie de résidence le vendredi 03 novembre à 18h30</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Offert dans le cadre des quarante ans de la Maison du Parc national et de la vallée</p>  <p></p>  <p><strong>COMPAGNIE&nbsp;ACMé</strong><br>  Pour en savoir plus et soutenir la compagnie,<br>  Site internet : www.compagnie-acme.com<br>  Facebook : Compagnie ACMé</p>  <p><strong>ARTISTES</strong><br>  Pierre-Benoît Duchez<br>  Mélissa Ocana Molinero<br>  Laurie Montamat<br>  Charlotte Piarulli<br>  Manuel Le Velly</p>  <p><strong>CRÉDIT PHOTO</strong><br>  Compagnie ACMé</p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1efcdd27-8847-474f-bba4-2885db23e059');
