INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Ça y est !" Cie En Transition', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>EN PARTENARIAT AVEC LES ACTEURS CULTURELS DU 65</strong><br>  Résidence de territoire de décembre 2022 à novembre 2023.</p>  <p><strong>DESCRIPTION</strong></p>  <p>Les fictions d’anticipation proposées dans les livres, films et séries, livrent en général une vision peu désirable du futur. En transition Cie nous invite à décoloniser notre imaginaire et à nous projeter dans l’avenir. Ça y est ! est une expérience de pensée écrite et jouée avec la complicité d’un groupe d’habitants des Hautes-Pyrénées. À quoi pourrait ressembler demain ?</p>  <p>Nous sommes en 2043. Il y a 20 ans, ici, de grands bouleversements ont eu lieu. Afin de fuir les sécheresses, l’air irrespirable des grandes métropoles, ou pour mener une vie plus en lien avec la nature, des gens de partout ailleurs sont arrivés là... Économie locale, santé, réseaux de coopération et d’entraide, agriculture, école, transports... Les citoyens se sont saisis de tout et en quelques années seulement ont transformé leur territoire en un modèle pour les autres. Nous sommes en 2043, ils et elles sont fiers de dire « Ça y est, on a réussi! ».</p>  <p>En Transition Cie a mené une résidence de territoire de décembre 2022 à novembre 2023. En allant à la rencontre des publics, la compagnie a relevé le défi de collecter des idées et des propositions pour écrire cette polyphonie citoyenne.&nbsp;Ça y est !&nbsp;est un spectacle qui affirme l’importance de relier les êtres entre eux, de renouer avec le vivant et de célébrer la science. Un récit de la mutation, écrit en commun et qui entend affronter la complexité du monde grâce à l’intelligence collective.</p>  <p><strong>ARTISTES</strong><br>  Compagnie En Transition :&nbsp;https://www.entransitioncie.fr/<br>  Alexandre Cafarelli -&nbsp;Conception &amp; mise en scène<br>  Virginie Nieddu -&nbsp;Jeu<br>  Félix-Dupin-Meynard - Création &amp; interprétation musicale&nbsp;</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Normal 12 €, réduit 6 €, -26 ans 6 €, abonné 8€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b58b6f39-1b49-418c-93ff-e39e645fef63');
