INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('e143e8d4-67fc-4a3a-81dd-75de50eeb41f', 'evenement', true, false, false, NULL, '2024-02-02T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-02-02T23:00:00.000Z', '2024-02-02T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Travol''Time" La Panthère Blanche', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>EN PARTENARIAT AVEC LE PARVIS SCÈNE NATIONALE&nbsp;TARBES PYRÉNÉES</strong></p>  <p><strong>DESCRIPTION</strong><br>  Fantasmant sur l''<em>American Dream</em>, deux habitants de la campagne réalisent en direct la construction du show de leurs rêves.</p>  <p>Portés par leur admiration pour John Travolta et Quentin Tarantino, les deux compères mettent en scène leur quotidien agricole et décident que leur ruralité est une success story : « From The Farm To The Fame ». Dépassant leurs propres limites, ils donnent à leurs rêves la couleur de l’espoir. S’inventer un monde à partir de rien, rêver grand avec juste ce qu’on a, devient un enjeu pour récupérer sa propre histoire, sa propre puissance, et peut-être, forcer le destin. Les comédiens en profitent pour partager leurs interrogations sur la méritocratie, l''argent et les « transclasses »…</p>  <p>Danseuse, chorégraphe, comédienne, Adeline Fontaine est issue du monde paysan. Dans ses spectacles, elle a choisi d’explorer tout ce qu’il lui reste de cette vie-là, de se questionner sur ce que cela veut dire d’avoir vécu dans un monde en train de disparaître, et aussi de l’aimer. Aimer ce monde paysan parfois impossible à aimer quand on y vit. Accompagnée d''Alexis Ballesteros, elle nous livre avec&nbsp;<em>Travol’time</em>&nbsp;un spectacle drôle, profond et touchant.</p>  <p></p>  <p><strong>APPEL À BÉNÉVOLES</strong></p>  <p>Recherche de complices pour participer au spectacle Travol’Time !<br>  Nous recherchons 6 personnes de tous âges pour figurer différents personnages dans une scène de bal du spectacle Travol’Time.</p>  <p><strong>6 rôles sont proposés :</strong><br>  - Un couple hétérosexuel<br>  -&nbsp;Un.e John Travolta, homme ou femme<br>  -&nbsp;Un.e timide<br>  -&nbsp;Un.e danseureuse de twist<br>  -&nbsp;Un.e danseuse infatigable</p>  <p style=\"text-align: justify;\">La scène est courte, les mouvements très simples et vous serez accompagné.e.s du début à la fin par les deux comédien.nes au plateau. Venez nous rejoindre, ça va être fun et disco ! Vous avez le choix de participer à une ou plusieurs représentations selon vos disponibilités. Prévoir une arrivée 3h avant la première fois pour répéter ensemble (si vous participez à plusieurs représentations, une arrivée 1h à l’avance suffira). Retrouvez les annonces officielles :&nbsp;https://drive.google.com/drive/folders/1C9SSjAXKlL-Mp3HUo_wAIeXRT3b7vRNe?usp=sharing</p>  <p>Inscriptions à l''accueil de&nbsp;la Maison du Parc national et de la vallée ou par téléphone : 05 62 92 38 38</p>  <p></p>  <p><strong>ARTISTES</strong><br>  Adeline Fontaine - Danseuse<br>  Alexis Ballesteros - Comédien<br>  Elliott Stolz - Musicien&nbsp;<br>  Compagnie La panthère blanche :&nbsp;<br>  https://www.artcena.fr/sites/default/files/medias/TRAVOL%27TIME_%20La%20Panth%C3%A8re%20Blanche%20-%20Productions%20%28MAJ%20Dossier%20artistique%202021%29.pdf</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Tarif du Parvis scène nationale de Tarbes<br>  Normal 12 €<br>  Réduit 6 €<br>  -26 ans 6 €<br>  Abonné 8€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e143e8d4-67fc-4a3a-81dd-75de50eeb41f');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Travol''Time" La Panthère Blanche', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>EN PARTENARIAT AVEC LE PARVIS SCÈNE NATIONALE&nbsp;TARBES PYRÉNÉES</strong></p>  <p><strong>DESCRIPTION</strong><br>  Fantasmant sur l''<em>American Dream</em>, deux habitants de la campagne réalisent en direct la construction du show de leurs rêves.</p>  <p>Portés par leur admiration pour John Travolta et Quentin Tarantino, les deux compères mettent en scène leur quotidien agricole et décident que leur ruralité est une success story : « From The Farm To The Fame ». Dépassant leurs propres limites, ils donnent à leurs rêves la couleur de l’espoir. S’inventer un monde à partir de rien, rêver grand avec juste ce qu’on a, devient un enjeu pour récupérer sa propre histoire, sa propre puissance, et peut-être, forcer le destin. Les comédiens en profitent pour partager leurs interrogations sur la méritocratie, l''argent et les « transclasses »…</p>  <p>Danseuse, chorégraphe, comédienne, Adeline Fontaine est issue du monde paysan. Dans ses spectacles, elle a choisi d’explorer tout ce qu’il lui reste de cette vie-là, de se questionner sur ce que cela veut dire d’avoir vécu dans un monde en train de disparaître, et aussi de l’aimer. Aimer ce monde paysan parfois impossible à aimer quand on y vit. Accompagnée d''Alexis Ballesteros, elle nous livre avec&nbsp;<em>Travol’time</em>&nbsp;un spectacle drôle, profond et touchant.</p>  <p></p>  <p><strong>APPEL À BÉNÉVOLES</strong></p>  <p>Recherche de complices pour participer au spectacle Travol’Time !<br>  Nous recherchons 6 personnes de tous âges pour figurer différents personnages dans une scène de bal du spectacle Travol’Time.</p>  <p><strong>6 rôles sont proposés :</strong><br>  - Un couple hétérosexuel<br>  -&nbsp;Un.e John Travolta, homme ou femme<br>  -&nbsp;Un.e timide<br>  -&nbsp;Un.e danseureuse de twist<br>  -&nbsp;Un.e danseuse infatigable</p>  <p style=\"text-align: justify;\">La scène est courte, les mouvements très simples et vous serez accompagné.e.s du début à la fin par les deux comédien.nes au plateau. Venez nous rejoindre, ça va être fun et disco ! Vous avez le choix de participer à une ou plusieurs représentations selon vos disponibilités. Prévoir une arrivée 3h avant la première fois pour répéter ensemble (si vous participez à plusieurs représentations, une arrivée 1h à l’avance suffira). Retrouvez les annonces officielles :&nbsp;https://drive.google.com/drive/folders/1C9SSjAXKlL-Mp3HUo_wAIeXRT3b7vRNe?usp=sharing</p>  <p>Inscriptions à l''accueil de&nbsp;la Maison du Parc national et de la vallée ou par téléphone : 05 62 92 38 38</p>  <p></p>  <p><strong>ARTISTES</strong><br>  Adeline Fontaine - Danseuse<br>  Alexis Ballesteros - Comédien<br>  Elliott Stolz - Musicien&nbsp;<br>  Compagnie La panthère blanche :&nbsp;<br>  https://www.artcena.fr/sites/default/files/medias/TRAVOL%27TIME_%20La%20Panth%C3%A8re%20Blanche%20-%20Productions%20%28MAJ%20Dossier%20artistique%202021%29.pdf</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Tarif du Parvis scène nationale de Tarbes<br>  Normal 12 €<br>  Réduit 6 €<br>  -26 ans 6 €<br>  Abonné 8€</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'e143e8d4-67fc-4a3a-81dd-75de50eeb41f');
