INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence "Grande Ourse" Cie A Noise', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Onirique, expérimental, mélodique, tantôt brute et cru, tantôt électro ou suspendu, leur répertoire s’articule autour de poème et de textes de Grisélidis Réal, poétesse et prostituée. Les contours de la parole portée ici se dessinent progressivement…. De noir et de violet…&nbsp;Projet en lien avec le Résidence de Territoire «&nbsp;Voix Communes&nbsp;» qui sera accueilli le 18 décembre à la Maison de la Vallée pour une journée d’atelier d’écriture.<br>  En partenariat avec la DRAC / Ville de Lourdes / DDETSPP.</p>  <p><strong>DATE</strong><br>  Résidence du lundi 13&nbsp;novembre au vendredi 17&nbsp;novembre<br>  Sortie de résidence le vendredi 17 novembre à 18h30</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Offert dans le cadre des quarante ans de la Maison du Parc national et de la vallée</p>  <p><strong>ARTISTES</strong><br>  Compagnie A Noise<br>  Annoïe-Anne Roy : voix<br>  Yoann Piovoso : Rhodes – claviers ananlogiques</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'aba89650-72a6-4980-ae47-7c73d7663a6e');
