INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence Cie Voki Duo - "L''appel"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  La représentation de cette sortie de résidence donnera un avant goût du spectacle final sur lequel nous allons travailler tout le long de cette semaine au sein de la Maison du Parc national de La Vallée. «L’Appel» sera littéralement abordé sous deux axes, son sens premier (illustré par le téléphone, objet principal du décor) puis son sens imagé et symbolique (la vocation, l’invitation à suivre sa voix intérieure). Le spectacle vise à faire une transition d’un sens à l’autre menant à un voyage poétique et introspectif. La musique traverse la représentation, illustrant ces deux environnements et guidant la progression narrative.</p>  <p><strong>DATE</strong><br>  Résidence du lundi 09 octobre au vendredi 13 octobre<br>  Sortie de résidence le vendredi 13 octobre à 18h30</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Offert dans le cadre des quarante ans de la Maison du Parc national et de la vallée</p>  <p><strong>COMPAGNIE&nbsp;ACMé</strong><br>  Pour en savoir plus sur la compagnie,<br>  Youtube : https://www.youtube.com/@VokiDuo</p>  <p><strong>ARTISTES</strong><br>  Lucille Laguian<br>  Maeva Rabassa</p>  <p><strong>CRÉDIT PHOTO</strong><br>  Josselin Bastide</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ecf04f6c-7d0e-4323-8400-06dcc4c03f9f');
