INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence Parc national des Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Programmé dans le cadre de la semaine de l''environnement.</strong><br>  <strong>En partenariat avec le FREDD :&nbsp;Le Festival International du Film d''Environnement</strong></p>  <p><strong>CONFÉRENCE du Parc national des Pyrénées.</strong><br>  À 18h00,&nbsp;Éric, garde-moniteur, vous présentera l’érosion de la biodiversité, la montagne comme laboratoire et&nbsp;les espaces protégés comme outil de gestion.&nbsp;</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a8138804-c461-496c-a9d9-ddf0a375798b');
