INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Atelier sur les contraceptions masculines', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  <strong>Atelier sur les méthodes contraceptives masculines</strong><br>  Elle c''est Barbie, elle sait tou faire. Lui, c''est juste Ken. Il aimerait bien pouvoir aider Barbie, elle qui sait (doit) tout faire ...<br>  Comment, se demande t''il ? Commencer par prendre ses responsabilités de ses propres gamètes en se contraceptant !&nbsp;<br>  Thomas, vous propose un atelier de présentation autour de la contraception masculine. Tour d''horizon des différentes options de contraceptions de leurs enjeux, leurs accessibilité ...&nbsp;<br>  Avec un petit focus sur la méthode thermique avec un atelier DIY !&nbsp;<br>  On vous propose un format \"à l''auberge Espagnole\" lors de l''atelier, pensez à ramener quelque chose à grignotter et partager.<br>  Cette intervention vous est proposée par Thomas et l''association GARCON :&nbsp;<a href=\"https://garcon.link/\">https://garcon.link/</a></p>  <p><strong>DATE</strong><br>  Mardi 10 octobre<br>  18h30 Atelier sur les méthodes de contraception masculine<br>  20h30 Projection du film \"Barbie\"</p>  <p><strong>LIEU</strong><br>  Salle des voûtes</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p><strong>ASSOCIATION GARCON</strong><br>  Pour en savoir plus sur l''association :&nbsp;<br>  <a href=\"https://garcon.link/\">https://garcon.link/</a></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c9d5339f-055e-42e2-a957-8757a321f612');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Atelier sur les contraceptions masculines', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  <strong>Atelier sur les méthodes contraceptives masculines</strong><br>  Elle c''est Barbie, elle sait tou faire. Lui, c''est juste Ken. Il aimerait bien pouvoir aider Barbie, elle qui sait (doit) tout faire ...<br>  Comment, se demande t''il ? Commencer par prendre ses responsabilités de ses propres gamètes en se contraceptant !&nbsp;<br>  Thomas, vous propose un atelier de présentation autour de la contraception masculine. Tour d''horizon des différentes options de contraceptions de leurs enjeux, leurs accessibilité ...&nbsp;<br>  Avec un petit focus sur la méthode thermique avec un atelier DIY !&nbsp;<br>  On vous propose un format \"à l''auberge Espagnole\" lors de l''atelier, pensez à ramener quelque chose à grignotter et partager.<br>  Cette intervention vous est proposée par Thomas et l''association GARCON :&nbsp;<a href=\"https://garcon.link/\">https://garcon.link/</a></p>  <p><strong>DATE</strong><br>  Mardi 10 octobre<br>  18h30 Atelier sur les méthodes de contraception masculine<br>  20h30 Projection du film \"Barbie\"</p>  <p><strong>LIEU</strong><br>  Salle des voûtes</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p><strong>ASSOCIATION GARCON</strong><br>  Pour en savoir plus sur l''association :&nbsp;<br>  <a href=\"https://garcon.link/\">https://garcon.link/</a></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'c9d5339f-055e-42e2-a957-8757a321f612');
