INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('CONFÉRENCE ET OBSERVATION', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION<br>  Présenté par les gardes-moniteurs du Parc national des Pyrénées</strong><br>  À 20h00 Présentation<br>  Rentrez dans le monde de la nuit avec une présentation sur la réserve de ciel étoile ainsi que la faune nocturne.&nbsp;<br>  À 21h00 Observation<br>  Partezen en observation avec les gardes à la chappelle Solferino (10&nbsp;min à pieds de la Maison du Parc national et de la vallée). Utilisation d''un amplificateur sonore des sons de la faune nocturne et explication de la pollution lumineuse humaine.<br>  Avec un Quizz sonore des bruits de la nature : Brame du cerf, vent dans des branchages, chant de la hulotte ou encore bruits des pas d''un hérisson dans des feuilles, il faudra avoir l''ouïe finie !&nbsp;</p>  <p style=\"text-align: justify;\">Pensez à prendre des vêtements chauds si vous participez à la sortie en extérieur.<br>  Les deux animations peuvent être faites disctintement.<br>  En cas d''intempéries, la présentation et le quizz sont maintenus mais l''observation extérieure est annulée.</p>  <p style=\"text-align: justify;\">Crédit photo : Laurent Nedelec<br>  &nbsp;</p>  <p style=\"text-align: justify;\"><strong>DATE</strong><br>  Vendredi 13 octobre<br>  20h00 Conférence sur la réserve de ciel étoilé<br>  21h00 Observations à la chapelle Solferino</p>  <p><strong>LIEU</strong><br>  Salle de spectacle puis chapelle Solferino</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '161928f1-24a0-4e31-9627-c29cdfe1138f');
