INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Racynthe" Compagnie Le Cirque Jafarson', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\">SPECTACLE<br>  À travers « Racynthe », nous abordons la thématique de la mémoire, et plus précisément son caractère déformable et altérable. Une même histoire peut avoir plusieurs versions une fois qu’elle devient un souvenir, et tout appartient désormais à la subjectivité, à ce qu’on choisit d’en garder. Cette thématique est portée par la rencontre de deux personnages qui cohabitent dans un espace délimité. Ils évoluent sur des lignes temporelles parallèles. Parfois ils se rencontrent, parfois ils se manquent de peu, chacun vient retracer sa version de l’histoire.<br>  Ce spectacle pose une question ouverte: est ce que « se souvenir », c’est continuer de faire vivre ce qui n’existe plus ?</p>  <p style=\"text-align: justify;\">L''ESTHÉTIQUE&nbsp;<br>  « Racynthe » propose une ambiance poétique et suggestive qui s’appuie sur deux disciplines de l’art vivant: la danse et la musique électronique. Toutes deux se répondent et se lient. Nous avons cherché à faire de ces deux arts un langage unique et fondu, alliant des chorégraphies évolutives et une musique jouée en live pendant le spectacle. Le spectacle se déroule sur une scénographie qui délimite l’espace de jeu des deux personnages. C’est un planché aux alures de radeau, et dont les planches à leurs extrémitées se terminent par des racines. Cette scénographie raconte un autre monde, qui serait sortie de terre juste là, pour exposer les deux personnages et leur histoire aux yeux de tous.</p>  <p style=\"text-align: justify;\">COMPAGNIE LE CIRQUE JAFARSON<br>  Pour en savoir plus sur la compagnie :<br>  https://www.lecirquejafarson.com/</p>  <p><br>  LIEU<br>  Au forum de Luz-Saint-Sauveur</p>  <p>TARIF<br>  Offert dans le cadre des quarante ans de la Maison du Parc national et de la vallée</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ce785a03-11d8-4da9-b47e-84a4151f971f');
