INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Vernissage "Relief" Gilles Sage', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Arpenter la montagne. Gravir un col, s’arrêter. Descendre. Traverser le lac à la nage. Au loin, une lumière joue avec un sommet. Vite, déclencher. Ici, un brin de serpolet à coincer entre ses dents. Poursuivre sur le chemin, suivre les traits jaunes peints sur les rochers, chercher le prochain cairn, trouver un nouveau panneau directionnel jaune. L’herbe grasse pique les chevilles. Une marmotte siffle au loin.&nbsp;Déclencher. Surmonter le vertige pour arriver au sommet, relier d’un même coup d’œil deux vallées que l’on ne connaissait que séparément.</p>  <p style=\"text-align: justify;\">Depuis 2017, Gilles Sage délocalise son atelier dans les Pyrénées plusieurs semaines par an. Subrepticement, la montagne a percolé dans son champ de recherche plastique. Randonneur averti, il prélève en montagne des sensations, des matériaux de toutes sortes qui alimentent son travail dans un deuxième temps, quand il n’arpente plus les reliefs.&nbsp;Il rassemble des essais divers, de matières, de couleurs, des sons, des images en mouvement. Il additionne, il soustrais des éléments, il teste. Il passe de l’image au volume, et inversement.&nbsp;Ses céramiques décomposent puis recomposent un paysage de montagne numérisé. Ces pièces seront au cœur de l''exposition&nbsp;\"Relief\".</p>  <p><strong>DATE</strong><br>  Vernissage Samedi 28 novembre 18h00</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p><strong>ARTISTE</strong><br>  Gilles Sage<br>  https://gillessage.com/pyrenees/</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '359a176e-d5e4-4e86-b8fa-90e4e7b512cc');
