INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"TRANSMISSION" Laurie Montamat', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong></p>  <p style=\"text-align: justify;\">\"Il était une fois une petite fille qui s''appelait Mémoire. Cette&nbsp;petite fille s''endormit durant de nombreuses années à force de ne pas arriver à combler le « Grand Trou », celui qui oublia toutes les femmes qui participèrent à créer l''Histoire avec un grand H. Il était une fois, des portraits de femmes, des parcours de vie incroyablement courageux et ambitieux. Il était une fois, la transmission.\"</p>  <p style=\"text-align: justify;\">Conte théâtral et musical, \"Transmission&nbsp;ou l''histoire de la petite Mémoire\" vous plonge dans un univers poétique et drôle où l''histoire des femmes est à l''honneur. Inspiré du Best Seller \"Histoires du soir pour Filles Rebelles\", ce spectacle vous propose de découvrir ou re‐découvrir des héroïnes des temps modernes aux temps anciens dans une touchante et enthousiaste galerie de portraits, mettant au cœur de ce geste artistique l''importance de la transmission intergénérationnelle et des récits qui la composent. Munies de leur guitare et de leurs mots, Nathalie Carmouze et Laurie Montamat vous invitent à partager un moment de poésie en famille.</p>  <p><strong>ARTISTES</strong><br>  Nathalie Carmouze : Chanteuse, musicienne<br>  Laurie Montamat : Comédienne, autrice<br>  Mélissa Ocana : Regard extérieur</p>  <p><strong>LIEU</strong><br>  Maison du Parc national et de la vallée</p>  <p><strong>PUBLIC</strong><br>  Tout public dès 7ans. 35 minutes</p>  <p><strong>TARIF</strong><br>  Offert dans le cadre les 40 ans de la Maison du Parc national et de la vallée.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '86f55824-8d56-4dfe-a641-509a4fb2392a');
