INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Métamorfòsis" Leah Bosquet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  La nouvelle série de photographies de Leah Bosquet, Metamorfòsis, est le résultat d’une exploration introspective de différentes qualités de marbres dans les Pyrénées. En brisant les repères de perspective et d’échelle, le travail a été réalisé à partir de fronts de tailles de carrières abandonnées ou de blocs de marbres sortis de carrières en activité. A travers immuabilité et permanence géologique, l’artiste a creusé les profondeurs du marbre en cherchant une sorte de transmutation entre lumières et ténèbres. En passant par des résonances végétales ou aquatiques, elle transforme la pierre en verre, la plonge dans l’obscurité et exacerbe ses tonalités pour faire apparaître des scènes abstraites ou figuratives de vitraux profanes. Metamorfòsis est une invitation à créer ses propres temporalités et narrations. Une invitation au voyage alchimiste.</p>  <p><strong>DATE</strong><br>  Du vendredi 01 décembre au lundi 01 janvier<br>  Sur les horaires d''ouvertures de la Maison</p>  <p>Vernissage samedi 02 décembre à 18h00</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p><strong>ARTISTE</strong><br>  Leah Bosquet<br>  instagram :&nbsp;https://www.instagram.com/leahbosquet_photographe/</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0e45dcdd-7f08-4fc8-97cd-3cd41ad2b6dc');
