INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence "Manger un phoque" Cie Les jolies choses', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  La Cie les Jolies choses est en création pour son nouveau spectacle Manger un phoque, une pièce de Sophie Merceron.</p>  <p style=\"text-align: justify;\">Dans cette histoire deux univers se font échos. D’un coté, Picot, élevé par sa sœur et son frère, qui s’endort dans le bus de Monsieur Gustave tous les jours et qui, au lieu d’aller à l’école, descend au terminus pour errer dans un zoo désaffecté. Dans ce zoo il retrouve Madame Sue sur un banc, au milieu des cages ouvertes. De l’autre coté une bande d’animaux s’échappe d’un zoo en quête d’un avenir meilleur. Les deux histoires se répondent en questionnant les notions de voyage, de migration, de quête de soi et de vivre ensemble.</p>  <p style=\"text-align: justify;\">Dans son processus de création la compagnie accorde un temps conséquent à la recherche et défend une méthode de création basée sur : une mise en scène collective , un travail choral, spatial, corporel et rythmique, une approche sensible de la narration, qui traite de problématiques liées à l’enfance.</p>  <p><strong>DATE</strong><br>  Résidence du lundi 08 janvier au vendredi 19 janvier<br>  Sortie de résidence le vendredi 19 janvier à 18h30</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Tarif unique : 4,0€</p>  <p><strong>ARTISTES</strong><br>  Compagnie Les jolies choses<br>  Site inernet : http://www.compagnielesjolieschoses.fr/<br>  Crédit photo :&nbsp;Pixbynot</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '239a9248-2d63-4dfd-a984-f055976abcca');
