INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Pyrénées Étoilées" Parc national des Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Venez découvrir la beauté des cieux et des paysages nocturnes avec l’exposition « Pyrénées Etoilées ». Laissez-vous émerveiller par une « arche céleste » ou par le scintillement des étoiles au-dessus des sommets pyrénéens, rendus visibles grâce au talent des sept photographes ayant contribué à cette exposition (Jean-Daniel Cavaillé, Christophe Cieslar, Christophe Cuenin, Thomas Friedrich, Jean-François Graffand, Pierre Meyer, Laurent Nédelec). Ces paysages permettent également de prendre conscience des menaces concrètes qui pèsent sur ce patrimoine naturel nocturne par l’omniprésence de la pollution lumineuse de nos villes et nos villages.</p>  <p><strong>DATE</strong><br>  Du mercredi 03 janvier&nbsp;au mercredi 31 janvier<br>  Sur les horaires d''ouvertures de la Maison</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p><strong>PARC NATIONAL DES PYRÉNÉES</strong><br>  https://www.pyrenees-parcnational.fr/fr</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ad439ec7-ef35-4eac-830e-4696cc291bcc');
