INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Derrière chez nous" Cie AZURKAM', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  C’est l’histoire d’une femme qui danse et d’un homme qui grince. C’est le bourdonnement d’une vielle à roue, un trapèze fixe en plein naufrage. Ce sont deux corps qui suent, se collent et se fatiguent, dans l’énergie brute d’un bal traditionnel. C’est la joie de danser ensemble. C’est être seul alors qu’on pourrait être à plusieurs. C’est un moment passé face à la mer: on entend au loin les échos de la vie passée, et le bourdonnement de celle à venir ...</p>  <p style=\"text-align: justify;\">Derrière Chez Nous, c’est l’envie d’évoquer le départ, la séparation, l’absence. Dans une scénographie épurée se rencontrent l’exploit physique circassien, le chant, le texte, la danse, le folklore, la musique traditionnelle... Arrive alors l’émotion à fleur de peau, dans les choses qui nous dépassent, qui nous rassemblent.… Une histoire à tiroirs qui nous embarque au coeur d’une relation particulière. L’intimité, l’éloignement, la solitude, se dévoilent délicatement dans cet hommage à la vie.</p>  <p><strong>DISTRIBUTION</strong><br>  De et par : Amaël GESTIN et Marie VELA<br>  Regards extérieurs : Elouan HARDY, Magali BILBAO<br>  Accompagnement: Dominique HABOUZIT, Benjamin DE MATTEIS<br>  Regards Complices : Pierre DEAUX, Alejandro SOTO, Emmanuelle PEPIN<br>  Création lumière: Sophie LYON-CAEN<br>  Régie générale: Léandre PRIOULT</p>  <p style=\"text-align: justify;\"><strong>COMPAGNIE</strong><br>  Compagnie AZURKAM :<br>  La Compagnie AZURKAM est née dans un petit grenier mal rangé de Toulouse sous l’impulsion de Marie, trapèziste, et sa rencontre avec Amaël. C’est dans l’énergie de la danse traditionnelle et dans les bals folk que les corps forgent leur complicités. La compagnie développe des projets expressifs à la lisière de l’écriture, du son, des danses, du folklore, composés dans une esthétique épurée.&nbsp;<br>  Site internet :&nbsp;https://www.cie-azurkam.fr/<br>  Facebook :&nbsp;https://www.facebook.com/azurkam</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Normal &nbsp;8€<br>  Réduit (de 3 à 13 ans inclus + étudiants) 5€<br>  Offert (moins de 3 ans)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '937a8971-eddb-475f-8421-25644b918b64');
