INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Carnaval "L''ethno machine" Cie Nomad Nomad', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Pour célébrer le carnaval dans les rues de Luz-Saint-Sauveur, la Maison du Parc national et de la vallée a invité, l''Ethno Machine, c’est un engin fantastique, onirique, mélangeant l’univers des temps modernes, des mines de fer, à la délicatesse de la dentelle et du retro-chic des abats-jours de Mamie. La \"belle demoiselle\" fait tourner toutes les têtes et chavirer les cœurs en pulsant des rythmes et sonorités du monde entier. Après un passage par les ateliers Nomad Nomad, elle s’est fait gigantesque: toute en courbes métalliques élancées, elle est devenue aérienne, épique. Juchés sur son dos, un batteur, une saxophoniste et une joueuse de didjeridoo invoquent ensemble son âme, venue s’assembler depuis les entrailles de la Terre et les confins de l’Univers : une indomptable danseuse qui joue avec les fréquences, les sons, les éléments, l’air, le feu et l’énergie du public. Démesurément graphique, l’Ethno Machine n’en reste pas moins agile, se déplaçant à l’aide de deux Pédaleurses, deux Manuleurses et deux Rôdeurses volontaires, mis en condition avant le show pour prendre le rôle de “La Horde”. De jour comme de nuit, elle captive, envoûte et répand l’émerveillement partout où elle passe …&nbsp;</p>  <p style=\"text-align: justify;\"><br>  <strong>BÉNÉVOLES</strong><br>  Des volontaires pour participer au voyage, une belle expérience en art de rue s''offre à vous !<br>  Sur cette machine nous proposons à 6 personnes, taille adulte, de participer au voyage :<br>  - Deux pourront pédaler&nbsp;<br>  - Deux pourront manipuler&nbsp;la machine<br>  -&nbsp;Deux autres seront en gardien de la machine au sol afin de gérer la foule&nbsp;<br>  Les volontaires seront formés par un membre de la compagnie au minimum 1h00 avant le spectacle.<br>  Puis une fois costumés, nous ferons une mise en situation avec toute l’équipe avant de jouer.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>ARTISTES</strong><br>  Quentin Prysbyla : inventeur, sculpteur, batteur<br>  Alexis Pinheiro : ingenieur,&nbsp;soudeur&nbsp;<br>  Florian Denis : cascadeur, clown<br>  Léa N''Kaoua : choregraphe, échassière, danse<br>  Cécile Douchet : musicienne&nbsp;<br>  Priscilla Galvan : chanteuse<br>  Mina Pilet : costumière<br>  Benjo David : plasticien&nbsp;</p>  <p><strong>COMPAGNIE</strong><br>  Compagnie Nomad Nomad<br>  Site internet :&nbsp;https://www.nomadnomad.fr/<br>  Facebook :&nbsp;https://www.facebook.com/CompagnieNOMADMEN<br>  Instagram :&nbsp;https://www.instagram.com/cienomadnomad/</p>  <p><strong>LIEU</strong><br>  Départ de la déambulation à 18h&nbsp;de l''office de tourisme et retour au point initial à la fin du parcours.</p>  <p><strong>TARIF</strong><br>  Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '10deb581-51a1-4619-9950-4b83cc24dab0');
