INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Biso Muziki" Chacha Angela', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  BISO qui veut dire \"Nous comme ensemble\"&nbsp;est le projet du jeune batteur Chacha Angela, il a développé sa propre musique en puisant dans ses racines congolaises et en s’inspirant des musiques actuelles : Jazz, Pop, Funk, Gospel, Rock et bien d’autres styles… Chacha chante en Lingala, sa langue natale, et joue aussi du balafon, instrument traditionnel fabriqué à partir de latte de bois et de calebasse. Il nous raconte sa culture, la fraternité et la musique (MUZIKI) qu’il considère comme la richesse des ancêtres. BISO met l’accent sur la valorisation du métissage entre la musique de l’Afrique et celle de l’Occident. Il a su créer un mélange unique et un son contemporain.</p>  <p><strong>ARTISTES</strong><br>  Chacha Angela<br>  Gumiso Musendo<br>  Antoine Perrut<br>  Stephane Lopez<br>  Nils Frechilla</p>  <p>Samael Mielendeni&nbsp;</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Normal &nbsp;8€<br>  Réduit (de 3 à 13 ans inclus + étudiants) 5€<br>  Offert (moins de 3 ans)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4cc858e2-e3d5-46d2-9023-10c493d70a5b');
