INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Ice" Cie de la Tong', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Programmation&nbsp;en collaboration avec l''association Jazz Pyr''</strong></p>  <p style=\"text-align: justify;\"><strong>DESCRIPTION<br>  ICE, des Pyrénées au pôle nord : Photo concert texte</strong><br>  ICE est un spectacle, mélange de textes, de musiques et d’images proposé par Maya Paquereau. C''est un voyage au cœur d''écosystèmes bruts et fragiles, des glaciers Pyrénéens à la banquise arctique du Pôle Nord. On y fait le choix d''appartenir à ce corps vivant qu’est la terre, en essayant d’effacer toute tentative de possession, de domination ou de prédation. ICE est une invitation à (re)prendre sa place parmi la faune, la flore, les arbres, l''eau, le vent, la lumière, l''air, la glace, pour mieux comprendre la nécessité à préserver, tant qu''il est encore temps. Grâce à la musique de Julien Touéry au Fender Rhodes, Sébastien Bacquias à la contrebasse, Fabien Duscombs à la batterie, grâce aux textes de Maya Paquereau, aux photographies de Luc Bertrand, Julie Bayle, Eric Avondo, à la création vidéo de Paul Hemericq et à la création lumière de Dominique Prunier, on traverse les neiges et les forêts, les icebergs, les glaciers bleus arctiques tout en rencontrant la coque Mie ou le glouton, le phoque ou encore l’ours blanc. On découvre la légende Inuit de Sedna et la culture ancestrale animiste des peuples du Nord ; l’objectif constant étant la découverte, la contemplation, une éloge au vivant, en poésie, en musique et en image.</p>  <p style=\"text-align: justify;\"></p>  <p><strong>ARTISTES</strong><br>  Maya Paquereau : textes, voix<br>  Julien Touery : piano, clavier<br>  Sébastien Bacquias : contrebasse,effets, voix<br>  Fabien Duscombs : batterie, percussions</p>  <p>Jeff Manuel : son<br>  Dominique Prunier : lumière<br>  Paul Hemerick Bertrand : vidéo</p>  <p></p>  <p style=\"text-align: justify;\"><strong>COMPAGNIE de la TONG</strong><br>  La Cie de la Tong a pour objet de promouvoir les arts vivants de toutes disciplines. Du théâtre, à la danse, en passant par la voix, le son et finalement les musiques dans ses formes les plus diverses. C''est une association, loi 1901, crée en 2010 à Tarbes, dans les Hautes-Pyrénées, Occitanie. La Cie est dirigée par MAYA PAQUEREAU. Elle s''adresse aux plus petits comme aux plus grands par des projets variés, engagés et poétiques, ivertissants ou surprenants. Elle oriente sa recherche théâtrale vers les arts visuels et sonores et l''écriture sur le territoire de l''Occitanie. Elle s''allie à de nombreux partenaires pour enrichir pratiques et créations tout en gardant constamment la question de la place des arts vivants dans la société, leurs relations aux différents publics pour la construction de nouveaux projets en adéquation. Son engagement politique, écologique et social s''affirme devant les urgences qui se sont accentuées avec la crise sanitaire de 2020. ​Pour affirmer l''urgence écologique et sociale ! Pour participer à inventer une culture essentielle de proximité, accessible à tous ! Elle a&nbsp; produit plus d''une dizaine de spectacles.</p>  <p>Site internet :&nbsp;https://www.compagniedelatong.com/<br>  Facebook :&nbsp;https://www.facebook.com/compagniedelatong/</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Billetterie&nbsp;ligne :&nbsp;<a data-saferedirecturl=\"https://www.google.com/url?q=https://billetterie.festik.net/jazzaluz/tab/concerts&amp;source=gmail&amp;ust=1705752838160000&amp;usg=AOvVaw0Qhq9RC_eZWvHN4JecpZtU\" href=\"https://billetterie.festik.net/jazzaluz/tab/concerts\" target=\"_blank\">https://billetterie.festik.<wbr>net/jazzaluz/tab/concerts</a><br>  Plein tarif 10€<br>  Réduit 8€<br>  (Étudiant, demandeur d''emploi, adhérents Jazz Pyr'', jeunes de 13&nbsp;à 20 ans)<br>  Gratuit pour les moins de 12&nbsp;ans inclus</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '450d7ed3-4ebc-4c39-bf95-f97445e90f6a');
