INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence "Diptyque de Cas" Tide Company', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>RÉSIDENCE ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Diptyque de Cas propose, à la manière d''un double album, une double pièce de théâtre aux variations sur le thème de l''autorité. Le Cas de Nozomi la Grenouille, nous plonge dans le voyage initiatique d''une petite fille qui n''arrive pas à ouvrir sa main. Aux allures de conte japonais et de studio Ghibli, il s''adresse au jeune public ainsi qu''au tout public. Le Cas de Winston Smith, pour public averti, propose un thriller terrifiant qui a pour cadre un appartement londonien. Ces deux Cas sont portés par trois comédiennes qui livrent une grande palette d''interprétation. Mapping, magie et ventriloquie se mettent au service de ces histoires merveilleuses ou inquiétantes.</p>  <p style=\"text-align: justify;\">La Maison de la Vallée sera notre deuxième résidence de plateau. La compagnie travaille de la façon suivante : l''écriture du texte est faite en amont par Benjamin, puis, lors des résidences nous \"ouvrons\" des scènes en improvisation, que nous écrivons au fur et à mesure des propositions retenues. Les scènes travaillées lors de cette résidence seront les deux premières scènes du Cas de Winston Smith ainsi que quatre scènes du Cas de Nozomi la Grenouille. L''objectif étant d''avoir la construction et l''écriture&nbsp;globale de ces scènes afin de les peaufiner par la suite. Le travail de la semaine sera présenté lors de la présentation publique.</p>  <p><strong>Tide Company</strong><br>  Facebook :&nbsp;https://www.facebook.com/tidecompany/<br>  &nbsp;</p>  <p><strong>DATE</strong><br>  Résidence du lundi 21 avril au vendredi 27 avril<br>  Sortie de résidence le vendredi 26&nbsp;avril&nbsp;à 18h30&nbsp;</p>  <p><strong>LIEU</strong><br>  Forum de Luz-Saint-Sauveur</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5bb89a25-6b80-4e8d-a0ae-30ba93857c0d');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence "Diptyque de Cas" Tide Company', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>RÉSIDENCE ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Diptyque de Cas propose, à la manière d''un double album, une double pièce de théâtre aux variations sur le thème de l''autorité. Le Cas de Nozomi la Grenouille, nous plonge dans le voyage initiatique d''une petite fille qui n''arrive pas à ouvrir sa main. Aux allures de conte japonais et de studio Ghibli, il s''adresse au jeune public ainsi qu''au tout public. Le Cas de Winston Smith, pour public averti, propose un thriller terrifiant qui a pour cadre un appartement londonien. Ces deux Cas sont portés par trois comédiennes qui livrent une grande palette d''interprétation. Mapping, magie et ventriloquie se mettent au service de ces histoires merveilleuses ou inquiétantes.</p>  <p style=\"text-align: justify;\">La Maison de la Vallée sera notre deuxième résidence de plateau. La compagnie travaille de la façon suivante : l''écriture du texte est faite en amont par Benjamin, puis, lors des résidences nous \"ouvrons\" des scènes en improvisation, que nous écrivons au fur et à mesure des propositions retenues. Les scènes travaillées lors de cette résidence seront les deux premières scènes du Cas de Winston Smith ainsi que quatre scènes du Cas de Nozomi la Grenouille. L''objectif étant d''avoir la construction et l''écriture&nbsp;globale de ces scènes afin de les peaufiner par la suite. Le travail de la semaine sera présenté lors de la présentation publique.</p>  <p><strong>Tide Company</strong><br>  Facebook :&nbsp;https://www.facebook.com/tidecompany/<br>  &nbsp;</p>  <p><strong>DATE</strong><br>  Résidence du lundi 21 avril au vendredi 27 avril<br>  Sortie de résidence le vendredi 26&nbsp;avril&nbsp;à 18h30&nbsp;</p>  <p><strong>LIEU</strong><br>  Forum de Luz-Saint-Sauveur</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '5bb89a25-6b80-4e8d-a0ae-30ba93857c0d');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence "Diptyque de Cas" Tide Company', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>RÉSIDENCE ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Diptyque de Cas propose, à la manière d''un double album, une double pièce de théâtre aux variations sur le thème de l''autorité. Le Cas de Nozomi la Grenouille, nous plonge dans le voyage initiatique d''une petite fille qui n''arrive pas à ouvrir sa main. Aux allures de conte japonais et de studio Ghibli, il s''adresse au jeune public ainsi qu''au tout public. Le Cas de Winston Smith, pour public averti, propose un thriller terrifiant qui a pour cadre un appartement londonien. Ces deux Cas sont portés par trois comédiennes qui livrent une grande palette d''interprétation. Mapping, magie et ventriloquie se mettent au service de ces histoires merveilleuses ou inquiétantes.</p>  <p style=\"text-align: justify;\">La Maison de la Vallée sera notre deuxième résidence de plateau. La compagnie travaille de la façon suivante : l''écriture du texte est faite en amont par Benjamin, puis, lors des résidences nous \"ouvrons\" des scènes en improvisation, que nous écrivons au fur et à mesure des propositions retenues. Les scènes travaillées lors de cette résidence seront les deux premières scènes du Cas de Winston Smith ainsi que quatre scènes du Cas de Nozomi la Grenouille. L''objectif étant d''avoir la construction et l''écriture&nbsp;globale de ces scènes afin de les peaufiner par la suite. Le travail de la semaine sera présenté lors de la présentation publique.</p>  <p><strong>Tide Company</strong><br>  Facebook :&nbsp;https://www.facebook.com/tidecompany/<br>  &nbsp;</p>  <p><strong>DATE</strong><br>  Résidence du lundi 21 avril au vendredi 27 avril<br>  Sortie de résidence le vendredi 26&nbsp;avril&nbsp;à 18h30&nbsp;</p>  <p><strong>LIEU</strong><br>  Forum de Luz-Saint-Sauveur</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '5bb89a25-6b80-4e8d-a0ae-30ba93857c0d');
INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('975a1061-5dfd-491e-be99-8696c377b2e6', 'evenement', true, false, false, NULL, '2024-03-21T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-03-21T23:00:00.000Z', '2024-03-21T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence "Humanité" Cie Kaktus', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>RÉSIDENCE ARTISTIQUE - Étape de création</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Je veux vous parler d’humanité (titre provisoire) est un monodrame où les disciplines (théâtre,chant, musique) s’entrecroisent et dialoguent pour raconter l’exil comme un récit à la fois intime et universel. C’est une adaptation du texte de Mustapha Kharmoudi, L’humanité tout ça tout ça, le récit d’un périple d’une mère et d’une petite fille qui fuient la guerre et qui traversent clandestinement la frontière pour arriver en France. Ce texte sera mis en miroir avec une écriture de plateau inspirée de tout un travail de terrain et de territoire en lien avec l’Histoire de la Retirada (exil des Espagnols fin des années 30).&nbsp;Notre travail sera axé sur deux réalités : le corps et le mélange des temporalités. Raconter l’universalité de l’exil, c’est chercher et sonder la mémoire collective dans un travail sur le corps, habitat de nos émotions, de nos perceptions. La temporalité, quant à elle, peut exprimer un jeu de déséquilibre qui amène le spectateur à interroger sa réalité et son présent à travers le prisme du passé, par le biais de la mémoire et de la transmission. L’universalité du thème de la migration résonne avec l’intime dans l’évocation du déracinement, de l’exil, et de la reconstruction de soi.</p>  <p style=\"text-align: justify;\"><strong>COMPAGNIE KAKTUS</strong><br>  Facebook :&nbsp;<a href=\"https://www.compagniekaktus.com/\">https://www.compagniekaktus.com/</a></p>  <p style=\"text-align: justify;\"><strong>SORTIE DE RÉSIDENCE</strong><br>  Vendredi 22&nbsp;mars à 18h30</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p style=\"text-align: justify;\"><b>TARIF</b><br>  Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '975a1061-5dfd-491e-be99-8696c377b2e6');
