('7378d160-5d97-4b9a-a31e-66b5e1da0377', 'exposition', true, false, NULL, '2024-01-30T23:00:00.000Z', '2024-02-28T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2024-01-30T23:00:00.000Z', '2024-01-30T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"La voix du sauvage" Maël Morlhon', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong></p>  <p style=\"text-align: justify;\">Une prise de conscience<br>  Hissez-vous dans l’intimité de la faune pyrénéenne.</p>  <p style=\"text-align: justify;\">Maël signifie «&nbsp;petit prince&nbsp;», à en croire les récits de Saint-Exupéry, j''étais prédestiné à mieux comprendre les animaux que les hommes. À 21 ans, au moment où ma plume laisse couler l''encre pour écrire ces lignes … Passionné de photographie, mon appareil a fini par être le prolongement de mon bras. Semblable à une peinture à l''aquarelle, la photographie est selon moi le moyen de mettre en valeur «&nbsp;essentiel&nbsp;» de ce que l''on observe, sans artifice.</p>  <p style=\"text-align: justify;\">Une bonne photo permet à l’œil de l''observateur une lecture simple et intuitive. Je pars également du principe qu''il n''y a pas de règle en photographie. Maîtriser son matériel et les bases de la composition est certes essentiel, mais pour sortir du lot, pour créer quelque chose de différent, quelque chose qu vous ressemble, il me parait indispensable de suivre son intuition et de ne pas hésiter à aller à l''encontre de ces «&nbsp;règles de base&nbsp;».</p>  <p style=\"text-align: justify;\">Né&nbsp; dans le piémont des Pyrénées, cela fait désormais 20 ans que j''arpente les pentes de nos montagnes&nbsp;; toutes aussi abruptes les unes que les autres. Tout d''abord porté par les épaules de mon père, c''est sans voix que je découvris la beauté de notre onde, trop jeune pour laisser échapper le moindre mot. L''air de la montagne m''a gagné, comme contaminé. Désormais dépendant tel que je le serais à une drogue, il m''est aujourd''hui indispensable de rejoindre régulièrement les crêtes et les sommets pour prendre de grands inspirations, faites de calme et de sérénité.</p>  <p style=\"text-align: justify;\">Si en quelques mots, je devrais parler de ma façon de prendre des photos, je dirais que les mains sont guidées par mon cœur et orientés par un œil pur, qui ne fait que suivre la voix de la nature, de la douce brise des crêtes, du chants des oiseaux, du craquement des feuilles.</p>  <p style=\"text-align: justify;\">Qui suis-je … Personne&nbsp;! Juste un Être de passage sur cette terre …&nbsp;Je ne suis personne … Juste une vie parmi t''en d''autres sur cette planète verte et bleu. À moi de tracer mon chemin, de trouver le bonheur dans ce que je fais et ce que je suis, de profiter de l''instant, d''aujourd''hui&nbsp;! Demain est un autre jour, je ne serrais eut-être plus là. Donc j''ai décidé de faire aujourd''hui ce que je voulais faire demain. D''être aujourd''hui ce que je voudrais devenir.</p>  <p style=\"text-align: justify;\">Maël, jeune photographe habitant dans les Hautes-Pyrénées, vous emmène pour une aventure hors du commun. Il a quitté son confort et pris son matériel pour s’évader. Durant un mois, il a traversé montagnes, vallées et forets à la recherche d’un esprit sauvage. Période hors du temps, si magique et intense. Le voici dans une autre dimension, entourer de râles, de silence et de combat. Retrouvez une véritable confession dans son travail photographique. C''est à la fois un récit, un partage, des observations, des rencontres, des joies, des déceptions et un constat : l''incompréhension de l''artiste face à la bêtise de l’humain. Retrouvez les photographies de Maël ainsi que son ouvrage et son magazine en salle des voûtes.</p>  <p><strong>DATE</strong><br>  Du mercredi 31 janvier&nbsp;au jeudi 29 février<br>  Sur les horaires d''ouvertures de la Maison</p>  <p>Projection rencontre : Maël projettera son film documentaire \"Le chant du sauvage\" le mardi 20 février à 20h30 et le jeudi 29 février à 20h30.<br>  Proffitez de cet instant pour rencontrer l''artiste et découvrir son travail photographique dès 20h00.&nbsp;À la fin du film documentaire, vous pourrez échanger au bord du plateau avec Maël Morlhon sur vos remarques, impresssions et ressentis.</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p><strong>ARTISTE<br>  Mael Morhon</strong><br>  Site internet :&nbsp;https://www.morlhonpicture.com/<br>  Facebook :&nbsp;https://www.facebook.com/Morlhonpicture/<br>  Instagram :&nbsp;https://www.instagram.com/mael_morlhon/?hl=fr</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7378d160-5d97-4b9a-a31e-66b5e1da0377');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"La voix du sauvage" Maël Morlhon', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong></p>  <p style=\"text-align: justify;\">Une prise de conscience<br>  Hissez-vous dans l’intimité de la faune pyrénéenne.</p>  <p style=\"text-align: justify;\">Maël signifie «&nbsp;petit prince&nbsp;», à en croire les récits de Saint-Exupéry, j''étais prédestiné à mieux comprendre les animaux que les hommes. À 21 ans, au moment où ma plume laisse couler l''encre pour écrire ces lignes … Passionné de photographie, mon appareil a fini par être le prolongement de mon bras. Semblable à une peinture à l''aquarelle, la photographie est selon moi le moyen de mettre en valeur «&nbsp;essentiel&nbsp;» de ce que l''on observe, sans artifice.</p>  <p style=\"text-align: justify;\">Une bonne photo permet à l’œil de l''observateur une lecture simple et intuitive. Je pars également du principe qu''il n''y a pas de règle en photographie. Maîtriser son matériel et les bases de la composition est certes essentiel, mais pour sortir du lot, pour créer quelque chose de différent, quelque chose qu vous ressemble, il me parait indispensable de suivre son intuition et de ne pas hésiter à aller à l''encontre de ces «&nbsp;règles de base&nbsp;».</p>  <p style=\"text-align: justify;\">Né&nbsp; dans le piémont des Pyrénées, cela fait désormais 20 ans que j''arpente les pentes de nos montagnes&nbsp;; toutes aussi abruptes les unes que les autres. Tout d''abord porté par les épaules de mon père, c''est sans voix que je découvris la beauté de notre onde, trop jeune pour laisser échapper le moindre mot. L''air de la montagne m''a gagné, comme contaminé. Désormais dépendant tel que je le serais à une drogue, il m''est aujourd''hui indispensable de rejoindre régulièrement les crêtes et les sommets pour prendre de grands inspirations, faites de calme et de sérénité.</p>  <p style=\"text-align: justify;\">Si en quelques mots, je devrais parler de ma façon de prendre des photos, je dirais que les mains sont guidées par mon cœur et orientés par un œil pur, qui ne fait que suivre la voix de la nature, de la douce brise des crêtes, du chants des oiseaux, du craquement des feuilles.</p>  <p style=\"text-align: justify;\">Qui suis-je … Personne&nbsp;! Juste un Être de passage sur cette terre …&nbsp;Je ne suis personne … Juste une vie parmi t''en d''autres sur cette planète verte et bleu. À moi de tracer mon chemin, de trouver le bonheur dans ce que je fais et ce que je suis, de profiter de l''instant, d''aujourd''hui&nbsp;! Demain est un autre jour, je ne serrais eut-être plus là. Donc j''ai décidé de faire aujourd''hui ce que je voulais faire demain. D''être aujourd''hui ce que je voudrais devenir.</p>  <p style=\"text-align: justify;\">Maël, jeune photographe habitant dans les Hautes-Pyrénées, vous emmène pour une aventure hors du commun. Il a quitté son confort et pris son matériel pour s’évader. Durant un mois, il a traversé montagnes, vallées et forets à la recherche d’un esprit sauvage. Période hors du temps, si magique et intense. Le voici dans une autre dimension, entourer de râles, de silence et de combat. Retrouvez une véritable confession dans son travail photographique. C''est à la fois un récit, un partage, des observations, des rencontres, des joies, des déceptions et un constat : l''incompréhension de l''artiste face à la bêtise de l’humain. Retrouvez les photographies de Maël ainsi que son ouvrage et son magazine en salle des voûtes.</p>  <p><strong>DATE</strong><br>  Du mercredi 31 janvier&nbsp;au jeudi 29 février<br>  Sur les horaires d''ouvertures de la Maison</p>  <p>Projection rencontre : Maël projettera son film documentaire \"Le chant du sauvage\" le mardi 20 février à 20h30 et le jeudi 29 février à 20h30.<br>  Proffitez de cet instant pour rencontrer l''artiste et découvrir son travail photographique dès 20h00.&nbsp;À la fin du film documentaire, vous pourrez échanger au bord du plateau avec Maël Morlhon sur vos remarques, impresssions et ressentis.</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p><strong>ARTISTE<br>  Mael Morhon</strong><br>  Site internet :&nbsp;https://www.morlhonpicture.com/<br>  Facebook :&nbsp;https://www.facebook.com/Morlhonpicture/<br>  Instagram :&nbsp;https://www.instagram.com/mael_morlhon/?hl=fr</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '7378d160-5d97-4b9a-a31e-66b5e1da0377');
