INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence Parc National', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Les parcs nationaux français, de part leur caractère exceptionnel, sont responsables de la préservation de leurs territoires. Pour mener à bien cet objectif, ils doivent remplir des missions fondamentales. Parmi elles, la protection de la biodiversité est essentielle. Ainsi, ils contribuent, dans le cœur, à la bonne gestion et à la conservation des patrimoines, en aire d''adhésion, à la valorisation d''activités compatibles avec le respect de la nature.<br>  Cette conférence sur le réchauffement climatique et l’érosion de la biodiversité&nbsp;vous est proposée par les gardes-moniteurs du Parc national des Pyrénées et est animée par Célia, en service civique.</p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><b>TARIF</b><br>  Offert&nbsp;</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7a4925b2-ff72-4ad8-89c2-6940ab481798');
