('5b8388fa-9312-44e0-8c36-64d788ad92f0', 'evenement', true, false, false, NULL, '2024-02-18T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-02-18T23:00:00.000Z', '2024-02-18T23:00:00.000Z');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence Parc National', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Les gardes-moniteurs vous proposent une projection offerte du film \"Hors Pistes\", elle sera suivie par l’intervention d’un garde du Parc national pour échanger sur les gestes à adopter pour limiter notre dérangement hivernal auprès des espèces.&nbsp;Cette événement vous permettra de rencontrer et d''échanger avec ces acteurs agissant au cœur du Parc national. Toute l’année, les agents s''engagent à vous faire découvrir les richesses naturelles, culturelles et paysagères de ce territoire d’exception sur le terrain ou dans les Maisons du Parc national.&nbsp;</p>  <p style=\"text-align: justify;\"><strong>Synopsis \"Hors Pistes\" :&nbsp;</strong><br>  Sensation de liberté, d''évasion. Quand les skis flottent sur la neige, quand le piolet se plante dans la cascade de glace ou quand la voile du parapente nous soulève... Nous pensons être seul pour profiter de ces instants ! Mais saviez-vous qu''ici, dans ces rochers où tout semble désert, des animaux se cachent en tentent de survivre ? Bien loin des interdictions, l''idée du film est :&nbsp;\"Comment avoir une meilleure pratique de nos activités de plein air pour réduire notre impact ?\"&nbsp;Ouvrir les yeux et découvrir ces espèces invisibles, les comprendre et prendre les informations utiles pour les appliquer dans sa pratique de la montagne . Laissez-vous emporter dans cette grande aventure de cinéma !</p>  <p style=\"text-align: justify;\"></p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><b>TARIF</b><br>  Offert&nbsp;</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5b8388fa-9312-44e0-8c36-64d788ad92f0');
