INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Petits points de vie" Cie Les Jolies Choses', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Spectacle \"Petit point de vie\" de la compagnie les jolies choses</strong></p>  <p>Eloïs et Léon narrent la rencontre magique et musicale entre un enfant trop bavard et un fils adoptif, qui n’ouvre jamais la bouche. Le Sourire d’Anaé est l’histoire d’une petite fille partie à la recherche de son sourire, qu’elle a perdu entre la maison de son père et celle de sa mère. Une étoile au fond du puits raconte jusqu’à quel point deux frères sont prêts à tout pour décrocher une étoile à leur mamie, pour ne pas que sa mémoire s’efface.&nbsp;</p>  <p>Au sein d''un dispositif scénique épuré, quatre comédiennes donnent vie à trois histoires courtes autour de questions qui se posent parfois, quand on est enfant.&nbsp;Petits Points De Vie est un spectacle tout public à partir de cinq ans dans lequel la compagnie Les Jolies Choses aborde les questions que soulève la transmission du théâtre contemporain aux plus jeunes.&nbsp;Le spectacle se veut, de fait, un objet scénique poétique conçu pour donner des pistes d''explorations artistiques et susciter la curiosité autour de principes de création qui s''éloignent des conventions traditionnelles. Il trouve sa singularité et son originalité dans ses partis pris de jeux et esthétiques à savoir: un principe de création collaborative et horizontale qui permet à chacun­e­s de s''exprimer et de trouver sa place; un texte \"support\" pour une création qui dépasse le texte; une esthétique en adéquation avec les principes du théâtre \"pauvre\".</p>  <p>\"C''est lorsque l''on élimine tout ce qui est superflu que l''on peut enfin reconnaître la puissance de l''art théâtral: un acteur se transforme sous nos yeux en utilisant uniquement son corps, ses impulsions intérieures.\"&nbsp;Jerzy Grotowski</p>  <p></p>  <p><strong>Distribution </strong>Costumes &nbsp;Caroline Laroche, musique &nbsp;Laurent Rochelle, régie technique Bastien Sallaberry, regards extérieurs Amélie Gasparotto, Nathalie Lhoste-Clos, jeu et mise en scène Maryline Petioch, Laurie Montamat, Sophie Barros, Mélia Bannerman.<br>  <strong>Crédit photo</strong>&nbsp;@Pixbynot<br>  <strong>La Compagnie Les Jolies Choses</strong>&nbsp;http://www.compagnielesjolieschoses.fr/</p>  <p></p>  <p><strong>Tarif&nbsp; Unique </strong>&nbsp;4€ &nbsp;dans la limite des places disponibles&nbsp;après l’arrivée des écoles<br>  <strong>Public</strong> Tout public à partir de 5 ans<br>  <strong>Lieu</strong> Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b85c68fa-a3dd-40e5-9d05-ebee06fc988f');
