INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('« Orage », Naïs Van Laer et Pali Meursault', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Orage propose une plongée sonore dans le territoire et les perceptions de plusieurs animaux cohabitant avec des humains dans un petit village de montagne des Pyrénées. A la tombée de la nuit, alors qu’un orage approche, toute une faune s''active dans les herbes folles d''un grand jardin au milieu du village de Luz-Saint-Sauveur. Orage nous invite à entendre depuis le monde et les modalités de perception de ces espèces compagnes, avec qui nous partageons nos lieux de vie, souvent sans les voir.</p>  <p>A la croisée de l’éthologie, de la recherche artistique, cinématographique, et des technologies de l’image et du son, nous voulons créer un moment d’expérience partagée. Un prolongement de soi dans des « mondes propres » animaux, altérités fascinantes qui - par le commun de l’orage - nous amènent à repenser notre positionnement face aux enjeux de la cohabitation avec le vivant.</p>  <p><strong>LIEU</strong><br>  Salle de cinéma</p>  <p><strong>DURÉE</strong><br>  Durée : 25 min&nbsp;</p>  <p><b>TARIF</b><br>  <b>​​​​​​​</b>Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a25ffc45-432a-4ac5-9696-6c9f0fd2b55b');
