('5abe9109-c037-436e-a308-68dcddc667af', 'exposition', true, false, NULL, '2024-03-02T23:00:00.000Z', '2024-03-29T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2024-03-02T23:00:00.000Z', '2024-03-02T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Empreintes" Anaïs Nony', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION<br>  Empreintes</strong><br>  De terre &amp; d''encre, première exposition de l''artiste Anaïs Nony, s''appropriant la matière brute à travers de près d''une trentaine d’œuvres inédites. Véritable voyage introspectif et méditatif, Anaïs invite les visiteurs à se questionner sur le pouvoir créatif de la matière brute - la terre - rencontrant l''art graphique - l''encre - dans cette exposition.</p>  <p style=\"text-align: justify;\">Convaincue que la peinture est une matière énergétique pouvant atteindre les sens et transformer les fréquences d’un lieu, Anaïs Nony puise dans le vivant la matière de ses images. Ainsi, elle utilise l’humus de la terre pour donner relief à ses tableaux. Les couleurs de l’encre et la matière vivante de l’humus deviennent les outils pour exprimer des sensations et des émotions. Tel un écho de test de Rorschach, un langage visuel fait de milliers de points prend création dans un ensemble créateur d''impressions et d''émotions visuelles par l’utilisation de la composition.</p>  <p style=\"text-align: justify;\">Le vivant et la nature sont les sources premières de ses inspirations. L’énergie de ses tableaux fonctionne comme des présences qui transforment les fréquences de l’espace et du temps afin d’offrir une ascension contemplative aux spectateurs.</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Des couleurs comme énergies, des formes comme émotions</strong><br>  Les couleurs sont habilement utilisées comme des fréquences vibratoires, les faisant résonner dans l’âme du spectateur. Ce sont des couleurs chaudes et froides : un contraste entre l’action, l’ancrage, l’énergie vitale, soulignée par des couleurs comme le rouge. Les tableaux, formés par des tâches encrées sur la toile sans avoir d’ordre apparent. Ce sont leurs couleurs qui donnent la tonalité émotionnelle à l’œuvre. Leur rythme, associé à la matière, donne forme à des compositions visuelles éclatantes, que s''approprie chaque visiteur</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Une technique inédite</strong><br>  La technique de l’encre est utilisée de manière non traditionnelle, à partir d’un pigment que l’artiste mélange à de la terre récoltée dans les bois de montagne du Pays Toy. La terre est sélectionnée dans la couche supérieure du sol, créée par la décomposition de la matière organique. L’humus désigne la partie biologiquement la plus active de la biosphère, sa capacité d’échange naturelle ainsi que sa décomposition lente délivrent aux racines des plantes de l’azote, du phosphore et tous les éléments nutritifs indispensables à la croissance des végétaux.</p>  <p style=\"text-align: justify;\">L’artiste utilise l’humus comme matière organique vivante pour la fabrication de ses peintures. En créant une pate colorée, l’artiste peint ensuite avec le dos de petites cuillères délicatement utilisée afin d’appliquer des milliers de pointillés donnant ainsi forme et structure au peinture. Les couleurs juxtaposées, superposées ou fusionnées, par tampons dirigés.</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Inspirations et résonances</strong><br>  Anaïs Nony commence à étudier les œuvres de l’expressionnisme abstrait de Jackson Pollock et Willem de Kooning mais aussi le travail de Beauford Delaney, Alice Rahon,Norman Lewis, Hedda Sterne, Tōkō Shinoda et Lee Krasner. Ce passage de la peinture abstraite est né en 2021, lorsqu''elle mélange pour la première fois de l’encre pigmentée et de la terre. Naît alors une recherche sur la relation entre l’art et le vivant afin de créer une composition dépourvue de contenu naturaliste où la matière organique devient support de la forme.</p>  <p></p>  <p style=\"text-align: justify;\"><strong>L''artiste Anaïs Nony</strong><br>  Anaïs Nony est une écrivaine et artiste peintre française. Docteure en philosophie de l’art et de la technologie, elle écrit des ouvrages concernant la culture technique et l’impact du digital sur la société. En 2009, elle part à New York étudier la performance et s’installe à Minneapolis en 2011 pour sa thèse de doctorat. Elle travaille ensuite en Floride, en Afrique du Sud et en Irlande jusqu’à ce qu’elle transforme sa carrière universitaire et s’installe dans les Hautes-Pyrénées en 2021. Empreintes est sa première exposition.</p>  <p style=\"text-align: justify;\"></p>  <p><strong>DATE</strong><br>  Du dimanche 03 mars au samedi 30 mars<br>  Sur les horaires d''ouvertures de la Maison<br>  Vernissage lundi 04 mars à 18h</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p><strong>ARTISTE</strong><br>  Anaïs Nony</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5abe9109-c037-436e-a308-68dcddc667af');
