INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('c79bc489-cae6-4024-8ac9-1a74cf5b7fd2', 'evenement', true, false, false, NULL, '2024-03-07T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-03-07T23:00:00.000Z', '2024-03-07T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"A More" HBBB Cie ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong></p>  <p style=\"text-align: justify;\">A MORE&nbsp;se situe dans le paradoxe de son titre. Lisez-le comme vous le souhaitez. C’est d’une solitude dont nous serons témoin. Dans ce solo à la lisière entre danse et performance, l’expérience&nbsp;progresse, se déplie au fur et à mesure que l’espace se transforme.&nbsp;On y observe un être inadapté sur un terrain qui se meut, se déchire et&nbsp;se dérobe.&nbsp;Une quête de sens, dont le corps s’empare, taisant les mots.<br>  Sur scène, la danseuse native du territoire évolue dans une scénographie tout à la fois, lisse, chargée et naïve en perpétuel déploiement dans l’espace.&nbsp;Un duo avec la matière en laquelle le corps vit contradictions, empêchements, provoquant des pulsions de liberté. Comment tenir debout quand tout se dérobe ? Comment exister dans plus grand que soi ?&nbsp;«&nbsp;Le corps sait et moi je cherche encore.&nbsp;»</p>  <p style=\"text-align: justify;\">Durée&nbsp;50 min&nbsp;/ à partir de&nbsp;7 ans</p>  <p style=\"text-align: justify;\"><strong>DISTRIBUTION</strong><br>  De et par Claire Lamothe<br>  Ana Samoilovich : Lumière<br>  Paul Boulier : Regie son<br>  Charlotte Thomas &amp; Claire : Scénographie<br>  Béatrice Debrabant : Assistance chorégraphique<br>  Elsa Guiet et Pierre Teregeol : Musique<br>  Claire Lamothe : Montage son</p>  <p style=\"text-align: justify;\"><strong>LA COMPAGNIE</strong><br>  La compagnie HBBB se développe en 2018 à l’occasion d’un projet de transmission auprès d’un large public.&nbsp;En découle la création IN SITU&nbsp; du duo NO ID&nbsp; qui se trouve entre danse, suspension et performance et insuffle un travail surfant sur un axe hybride mêlant la danse, les arts dramatiques et l’espace scénique dans un rapport au vivant et au spontanée.&nbsp;Cette création aborde des questions de l’identité dans l’espace public.&nbsp;<br>  Site internet :&nbsp;https://www.clairelamothelabex.com/</p>  <p style=\"text-align: justify;\"><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIFS</strong><br>  Normal &nbsp;8€<br>  Réduit (de 3 à 13 ans inclus + étudiants) 5€<br>  Offert (moins de 3 ans)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c79bc489-cae6-4024-8ac9-1a74cf5b7fd2');
