INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de Résidence "Diptyque de Cas" Tide Company', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>RÉSIDENCE ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Diptyque de Cas propose, à la manière d''un double album, une double pièce de théâtre aux variations sur le thème de l''autorité. Le Cas de Nozomi la Grenouille, nous plonge dans le voyage initiatique d''une petite fille qui n''arrive pas à ouvrir sa main. Aux allures de conte japonais et de studio Ghibli, il s''adresse au jeune public ainsi qu''au tout public. Le Cas de Winston Smith, pour public averti, propose un thriller terrifiant qui a pour cadre un appartement londonien. Ces deux Cas sont portés par trois comédiennes qui livrent une grande palette d''interprétation. Mapping, magie et ventriloquie se mettent au service de ces histoires merveilleuses ou inquiétantes.</p>  <p style=\"text-align: justify;\">La Maison de la Vallée sera notre deuxième résidence de plateau. La compagnie travaille de la façon suivante : l''écriture du texte est faite en amont par Benjamin, puis, lors des résidences nous \"ouvrons\" des scènes en improvisation, que nous écrivons au fur et à mesure des propositions retenues. Les scènes travaillées lors de cette résidence seront les deux premières scènes du Cas de Winston Smith ainsi que quatre scènes du Cas de Nozomi la Grenouille. L''objectif étant d''avoir la construction et l''écriture&nbsp;globale de ces scènes afin de les peaufiner par la suite. Le travail de la semaine sera présenté lors de la présentation publique.</p>  <p><strong>Tide Company</strong><br>  Facebook :&nbsp;https://www.facebook.com/tidecompany/<br>  &nbsp;</p>  <p><strong>DATE</strong><br>  Résidence du lundi 21 avril au vendredi 26&nbsp;avril<br>  Sortie de résidence le vendredi 26&nbsp;avril&nbsp;à 18h30</p>  <p><strong>LIEU</strong><br>  Forum de Luz-Saint-Sauveur</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9f84784f-d446-48ca-8667-c5f96d75ff9d');
