>  <p><strong>LIEU</strong><br>  Forum de Luz-Saint-Sauveur</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '9f84784f-d446-48ca-8667-c5f96d75ff9d');
