INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Vernissage Représentation "Vertical"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION<br>  Pour le vernissage de l''exposition \"Vertical\", l''artiste Flo Théas Bays&nbsp;vous propose&nbsp;une performance en lien avec ses oeuvres. Vous pourrez ensuite échanger avec elle sur sa représentation et son travail.</strong><br>  Vertical est une exploration à la fois intime et universelle, un récit de résilience, de redécouverte de soi, et de renaissance.&nbsp;À travers 12 photographies et 16 textes poétiques mis en relation lors d’une performance inédite, Flo raconte son périple émotionnel et physique, du tumulte des rues parisiennes à la sérénité majestueuse des Pyrénées.&nbsp;La pratique multidisciplinaire de Flo Théas Bays confronte la noirceur de nos montagnes personnelles, à la beauté difficile de l’ascension vers la lumière.</p>  <p><strong>ARTISTE</strong><br>  Flo Théas Bays<br>  Site internet :&nbsp;https://flotheasbays.fr/<br>  Instagram :&nbsp;mystic__moontain</p>  <p style=\"text-align: justify;\"><strong>DATE</strong><br>  Du mardi 02 avril&nbsp;au lundi 29 avril 2024<br>  Sur les horaires d''ouvertures de la Maison<br>  Vernissage vendredi 05 avril à 19h : Venez découvrir une performance&nbsp;de l''artiste Flo Théas Bays au coeur de son exposition. À la suite de cette représentation, échangez avec Flo sur ses réalisations et son travail.</p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '387fe05c-028b-42dc-a195-c407b3e64b7f');
