INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Échos du ciel" Jean-François Graffand', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Le ciel nocturne disparaît. En silence. Malgré les timides décrets semblant protéger la nuit, jamais elle n’a été tant menacée. L’expansion des villes, de leurs lumières, et la prolifération des leds, promesse d’un éclairage à moindre coût, diffusent un voile lumineux de plus en plus intense entre les étoiles et nous.</p>  <p style=\"text-align: justify;\">Cette fascination pour les lumières artificielles, dont on connaît pourtant les effets néfastes sur l’environnement et la santé, participe à notre amnésie environnementale : le ciel s’efface aujourd’hui de notre vision… et de notre mémoire. Baignant dans la pollution lumineuse et absorbés par nos écrans, notre droit à la nuit se trouve menacé. Nous vivons désormais coupés du ciel, et le délire technologique de milliers de satellites en cours de déploiement, dessinant bientôt des constellations artificielles, n’en est qu’un symptôme supplémentaire.</p>  <p style=\"text-align: justify;\">Dans ce contexte, « Echos du Ciel » invite par l’image à redécouvrir et réinstaller le ciel nocturne dans le paysage… à s’arrêter, lever les yeux, pour rappeler l’émerveillement que nous avons tous ressenti une nuit face à la voûte étoilée. Sensibilisé, le regard réunit à nouveau la Terre et le Ciel, pour rappeler la beauté de la nuit et inciter à la préserver.</p>  <p style=\"text-align: justify;\">Grâce à la pose longue à haute sensibilité, captant jusqu’aux infimes lumières que nos yeux perçoivent à peine, la photographie nous révèle un monde presque inconnu : étoiles, planètes, nébuleuses, Voie lactée… Tous ces astres dont nous ignorons parfois l’existence brillent pourtant chaque nuit au-dessus de nous. Un monde qui a toujours accompagné l’humanité. Même si celle-ci semble l’oublier.</p>  <p style=\"text-align: justify;\">« Echos du Ciel » c’est aussi le désir de capter l’écho silencieux, profond, émanant de ces espaces infinis. Et de ressentir notre place face à l’infiniment grand. Sonder le ciel, observer, et prendre conscience de cette immensité d’où nous sommes issus ; ressentir l’écho ; au-dehors, au-dedans… comme pour rappeler l’immensité de l’Univers, en nous.</p>  <p><strong>ARTISTE</strong><br>  Jean-François Graffand<br>  Site internet :&nbsp;http://www.echosduciel.fr/<br>  Facebook :&nbsp;https://www.facebook.com/EchoesPhotographie/<br>  Instagram :&nbsp;https://www.instagram.com/jeffgraffand/</p>  <p style=\"text-align: justify;\"><strong>DATE</strong><br>  Du mercredi 01 mai&nbsp;au jeudi 30 mai 2024.<br>  Sur les horaires d''ouvertures de la Maison<br>  Conférence rencontre mardi 07 mai à 18h en salle de spectacle</p>  <p><strong>LIEU</strong><br>  Salle des voûtes / Salle de spectacle<br>  Libre accès</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8ef5183e-b637-4312-a95a-c1a9848de46e');
