INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence rencontre "Échos du ciel" Jean-François Graffand', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Venez rencontrer le photographe Jean-François Graffand avec sa conférence tout public sur son exposition \"Échos du ciel\". Étoiles, planètes, voie lactée, galaxies… Quels sont ces objets célestes que nos yeux distinguent à peine et que la photographie révèle ? Fort de vingt ans d’expérience dans le partage de l’astronomie auprès du grand public, je propose de vous emmener pour un voyage dans l’espace à la découverte du ciel. D’image en image, l’Univers se révèle, nous rappelant la beauté de la nuit et notre lien au ciel, bien plus intime qu’il n’y paraît…</p>  <p><strong>ARTISTE</strong><br>  Jean-François Graffand<br>  Site internet :&nbsp;http://www.echosduciel.fr/<br>  Facebook :&nbsp;https://www.facebook.com/EchoesPhotographie/<br>  Instagram :&nbsp;https://www.instagram.com/jeffgraffand/</p>  <p style=\"text-align: justify;\"><strong>DATE</strong><br>  Du mercredi 01 mai&nbsp;au jeudi 30 mai 2024.<br>  Sur les horaires d''ouvertures de la Maison<br>  Conférence rencontre mardi 07 mai à 18h en salle de spectacle</p>  <p><strong>LIEU</strong><br>  Salle des voûtes / Salle de spectacle<br>  Libre accès</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '692bab55-c027-4230-8e7f-c794833f9393');
