INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Projection Conférence Parc national des Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Venez participer&nbsp;à la projection du film \"Le bel opportuniste\", d''une durée de 30 min, tout public, ayant eu le prix \"Prix Connaître et protéger\" du&nbsp;Festival International du Film Ornithologique de Ménigoute (FR) puis assister à une conférence et un échange avec un garde moniteur du Parc national des&nbsp;Pyrénées.</p>  <p style=\"text-align: justify;\"><br>  Synopsis : \"Le bel opportuniste\"<br>  Il est un animal aux sens hyper aiguisés, qui chasse aussi bien de jour que de nuit, capable de vivre dans les habitats les plus variés. Il se déjoue aussi bien des hommes que de l''altitude, du froid et de la pente. Son opportunisme et sa grande faculté d''adaptation lui ont permis de prospérer au point de devenir le carnivore le plus répandu de la planète. Il vit aussi dans nos montagnes. Quittons le sentier des hommes et de leurs préjugés pour suivre cette coulée discrète sur la trace du renard. Elle nous conduit à une tanière d’altitude au cœur des Alpes. Quatre renardeaux sont nés. Survivront-ils tous aux pièges de la vie en altitude ?&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p><strong>LIEU</strong><br>  Salle de spectacle</p>  <p><strong>TARIF</strong><br>  Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1683218a-5394-4387-a882-22735c3a9cfd');
