INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('8bb60721-afb5-4683-a369-957f4b0d98be', 'evenement', true, false, false, NULL, '2024-07-09T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-07-09T22:00:00.000Z', '2024-07-09T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi Artistique "Enfin" Cie En Transition', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>MERCREDI ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Nous sommes en 2044. Aujourd''hui il y a une célébration. Ou une cérémonie. Une commémoration ? Non, disons une fête.&nbsp;Il y a 20 ans, Ana avait 15 ans. La biodiversité s’effondrait. Le prix du pétrole grimpait en flèche. On découvrait un premier hiver sans pluie. Tout s''amplifiait à l''autre bout de la planète. A l''autre bout de la rue aussi. En bref, 2024 c’était pas ouf.&nbsp;C''est tout un mode de vie qui devait être réinventé. Ces changements, hors de question de les subir. Une révolution géniale du monde s’engageait, Ana comptait bien en faire partie !&nbsp;Aujourd''hui c''est la fête donc. Avant que ça commence Ana a des choses à vous raconter. Et avant de vous les raconter elle a quelques consignes à vous faire passer. Parce que si vous êtes là mais que vous ne faites rien, pas de fête.&nbsp;Nous sommes le 7 juin 2044 et Ana est heureuse de pouvoir dire : je suis fière de ce qu''on a accompli.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong><br>  Ecriture &amp; mise en scène&nbsp;Alexandre Cafarelli<br>  Jeu&nbsp;Virginie Nieddu<br>  Création &amp; interprétation musicale&nbsp;Félix-Dupin-Meynard<br>  Construction&nbsp;Louis Guidon<br>  Collaboration scientifique&nbsp;Sarah Cubaynes<br>  Production &amp; Diffusion&nbsp;Léonie Berberich<br>  Régie&nbsp;Benjamin Cambronne</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>La compagnie \"En Transition\"</strong><br>  Au rythme du monde et ancré dans les enjeux actuels, notre objectif est de défendre et participer à faire surgir dans le spectacle vivant une thématique : la fabrique des nouveaux imaginaires. Dans un contexte de mutation de nos sociétés, de bouleversements environnementaux et climatiques, il nous semble indispensable de participer à donner une vision désirable du futur. Par la création, la recherche, et la pratique artistiques nous souhaitons faire découvrir, sensibiliser, défendre, imaginer un tournant radical exaltant. Et puis on aime bien rire aussi.<br>  Pour en savoir plus :&nbsp;https://www.entransitioncie.fr/cie</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Lieu&nbsp;</strong>Balade Bastan - À côté du Carrous''ailes<br>  <strong>Tarif&nbsp;&nbsp;</strong>Offert dans le cadre des \"Mercredi Artistique\"<br>  <strong>Repli </strong>Salle de spectacle de la Maison du Parc national et de la vallée</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8bb60721-afb5-4683-a369-957f4b0d98be');
