INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('RESIDENCE "IMPORTANT DE DISPARAITRE" - ZOE CAVARO', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Projet photographique par Zoé Cavaro</strong></p>  <p style=\"text-align: justify;\">Le projet Important de disparaître est un travail d’autoportraits photographiques dans lequel deux espaces se répondent, avec au coeur la quête d’équilibre dans le rapport au corps et au monde. La série s’intéresse à l’impact traumatique sur le corps d’événements personnels comme universels. La complexité du rapport au corps, notamment en tant que femme, est centrale. Comment des questionnements s’inscrivent-ils dans notre chair, notre quotidien et notre rapport au paysage ? Et comment trouver l’équilibre dans un monde où l’avenir semble incertain ?</p>  <p style=\"text-align: justify;\">Le projet de Zoé Cavaro questionne le paysage et son évolution. Il invite à mesurer l’importance du sauvage, des saisons, de l’environnement. Les images se veulent à la fois brutes, surréalistes et documentaires. Elles illustrent une quête de recherche d’identité profonde, questionnant les notions d’existence, de présence et de passage, en lien direct avec les questionnements écologiques auxquels nous sommes confrontés.</p>  <p style=\"text-align: justify;\">« Important de disparaître » est un projet d’autoportraits photographiques dans lequel deux espaces se répondent, avec au coeur la quête d’équilibre dans le rapport au corps et au monde. D’une part, des images prises dans ma chambre tout au long de l’année ; de l’autre , des autoportraits en montagne aux différentes saisons. La série s’intéresse à l’impact traumatique sur le corps d’événements personnels comme universels. La complexité du rapport au corps, notamment en tant que femme, est centrale. Comment des questionnements existentiels s’inscrivent-ils dans notre chair, notre quotidien et notre rapport au paysage ? Et comment trouver l''équilibre dans un monde où l''avenir semble incertain ? Le projet questionne en parallèle le paysage et son évolution. Il invite à mesurer l’importance du sauvage, des saisons, de la préservation de l’environnement. Les images se veulent à la fois brutes, surréalistes, et documentaires. Dans cette double série photo, on joue avec le caché et le visible, notamment à partir du corps que l’on fragmente par l’espace, par sa posture, sa distance, la lumière… Autant de procédés qui renvoient à l’idée du corps comme une matière et de l’individu comme une entité. Ces images illustrent une quête de recherche d’identité profonde, questionnant les notions d''existence, de présence et de passage, en lien direct avec les questionnements écologiques auxquels nous sommes confronté-es. Le ton se veut contemplatif et non violent, car le message final du projet est celui d’un désir de renaissance.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Sortie de résidence </strong>Vendredi 18 octobre à 18h30<br>  <strong>Tarif&nbsp;</strong>Offert<br>  <strong>Public</strong>&nbsp;Tout public<br>  <strong>Lieu </strong>Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c7dd3289-85b6-4115-8180-1955707f383e');
