INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('RÉSIDENCE ELECTRO MAGMA', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Sortie de résidence \"Electro Magma\"</strong><br>  Electro Magma, c’est la rencontre entre Chloé Firefly et Electromic. Chloé est à la voix et au thérémine. Electromic est le chanteur et compositeur aux contrôleurs, à la batterie électronique et à la voix. Leur duo vous propose une musique captivante qui fusionne rap, trip-hop et musique électronique. L’univers complémentaire des deux artistes et le mélange de différentes langues comme l’anglais, le français, l’italien et l’espagnol, vous transportent vers une expérience sonore unique. Leurs influences variées donnent à la musique un côté hypnotique, dans une ambiance parfois sombre, parfois combative. Des lignes de basses qui prennent à l’estomac, des nappes mélodiques et des textes percutants et engagés .... Tous les ingrédients pour une performance live éclectique dans un style totalement personnel.</p>  <p></p>  <p></p>  <p><strong>Distribution</strong> Chanteuse, performeuse, thérémine Chloé Firefly et le chanteur, compositeur, contrôleurs, batterie électronique Electromic<br>  <strong>Electro Magma</strong>&nbsp;https://www.cirkulez.fr/electro-magma/</p>  <p></p>  <p><strong>Sortie de résidence</strong> Vendredi 10 janvier à&nbsp;18h30<br>  <strong>Tarif</strong> Offert<br>  <strong>Public </strong>Tout public<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '21d271b8-73b9-4630-8bbc-e01b64a4af12');
