INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Guides et Chasseurs" Céline Bonnal', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description</strong><br>  Après plusieurs conférences, dont celle durant la remise du label « terre d’Alpinisme » à la ville de Cauterets, Céline Bonnal vient proposer une nouvelle réflexion autour des guides chasseurs pêcheurs. Elle présentera, dans son diaporama, des guides cauterésiens mais aussi de la vallée de Gavarnie qui dans leurs vallées pyrénéennes ont participé à de grandes chasses commandées par des clients fortunés. Ces guides notamment François Boyrie ont déjà à leur époque une réflexion cynégétique.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Lieu&nbsp;</strong>Salle de spectacle<br>  <strong>Tarifs&nbsp;</strong>Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '8d6c4565-ab8a-419e-8b37-0366ba277632');
