INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Projection Conférence Parc national des Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description</strong><br>  Le Parc national des Pyrénées vous propose la projection de \"Rascos et nous\". Ce film&nbsp;va à la rencontre d’éleveurs et de bergers de plusieurs zones géographiques de France. Certains, encore novices, se font aider pour la mise en place de leur premier chien de protection, et d’autres plus expérimentés, partagent avec nous leurs expériences d’utilisateurs de chiens de protection. La projection sera animée par un médiateur du Parc national des Pyrénées.</p>  <p style=\"text-align: justify;\">Synopsis : \"Rasco et nous\"<br>  Lui, c’est Rasco ! Il est né en Savoie mais c’est dans la Drôme qu’il va accomplir sa mission : protéger les animaux d’élevage lors des attaques de prédateurs. Des chiens de protection de troupeaux comme lui, il y en a aujourd’hui plus de 5 000 en France et leur nombre augmente chaque année notamment pour faire face à l’expansion des grands carnivores sauvages. On les retrouve évidemment en alpages, mais aussi désormais au sein des troupeaux à proximité des villages ou en zones périurbaines. Mettre en place et maintenir des chiens de protection efficaces et adaptés à leur environnement de travail demande des savoirs et savoir-faire bien spécifiques. Accompagnés par des membres du réseau “chiens de protection” de l’Institut de l’Elevage, nous partons sur les routes de France à la rencontre d’éleveurs et de bergers pour comprendre et échanger sur la manière dont ils élèvent, mettent en place et gèrent au quotidien leurs chiens de protection, dans un contexte où ils cohabitent avec d’autres usagers du territoire.</p>  <p></p>  <p><strong>Lieu&nbsp;</strong>Salle de spectacle<br>  <strong>Tarif</strong> Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4ba09533-965d-4015-872d-fbb3ded9c493');
