INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fête de Saint-Sauveur', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description</strong><br>  La traditionnelle fête de Saint-Sauveur a lieu&nbsp;le mercredi 24 juillet dans le quartier thermal de Saint-Sauveur. Elle est organisée par la Maison du Parc national et de la vallée en partenariat avec&nbsp;la mairie de Luz-Saint-Sauveur, l''association des Amis de Saint-Sauveur et l''association La Pourtère. Trois performances rythmeront&nbsp;votre soirée à partir de&nbsp;18h30 jusqu''au tir du feu d''artifice. Une buvette et de la petite restauration rapide, seront proposées sur place&nbsp;par l''association La Pourtère. Les restaurants l''Ardiden et le Parnoramic vous proposerons également un menu. On vous dévoile ci-dessous la programmation de cet événement incontournable du mois de juillet :&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>18h30 - \"Beethoven Métalo Vivace\" de la&nbsp;Compagnie Monsieur Le Directeur</strong><br>  Du métal dans les airs : Un solo de guitare symphonique sur corde lisse.<br>  Beethoven Métalo Vivace, c''est de l''acrobatie aérienne, de l''humour&nbsp;et de la guitare électrique de haut vol. Un programme décoiffant que propose la compagnie Monsieur Le Directeur. On y écoute de la musique métal exécutée piano solo et aussi&nbsp;la 9ème Symphonie tronçonnée par un curieux et volubile chef d’orchestre qui joue de la guitare électrique en grimpant à la corde. Suspendu par la taille ou par les pieds, la tête à l’envers ou à l’horizontale, c''est un concert de haute voltige qui transforme Beethoven en une&nbsp;véritable star du rock.<br>  Pour en savoir plus sur :&nbsp;http://mledirecteur.unblog.fr/cirque/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>En seconde partie - \"Les Accords''Léons - La boîte à Léon\"</strong><strong>&nbsp;de Culture Son</strong><br>  Un grand banquet gastromusical proposé par les chefs cuisiniers de la fanfare Les Accords''Léons.<br>  Mesdames, Messieurs : alignez les tables, drapez les de vos plus belles nappes et sortez votre argenterie pour venir découvrir tout l’univers musical.&nbsp;À l''heure de la malbouffe auditive, ces<strong>&nbsp;</strong>épiciers comédiens de la chanson française vous&nbsp;proposent leur menu.&nbsp;À la carte, c''est du 100% terroir, des entrées, des plats et autres mets musicaux&nbsp;vous seront servis en tambour et fanfare ! Mais saurez-vous découvrir tous leurs ingrédients mélodiques au&nbsp;son de l'' accordéon? Venez et&nbsp;laissez-vous servir les petits plats dans les grands et en avant la musique !<br>  Pour en savoir plus :&nbsp;https://www.cultureson.fr/les-spectacles/les-accords-l%C3%A9on-la-bo%C3%AEte-%C3%A0-l%C3%A9on/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>En troisième partie - Un concert du groupe \"CSYMPADETCOOL\",&nbsp;programmé par l''association La Pourtère</strong><br>  Concert festif de l’incontournable groupe ossalois dont le répertoire s’organise autour de musiques et de textes originaux, 100 % compos. Il y a du style pop, rock, afrobeat, avec un zest de reggae, c’est festif et entrainant !&nbsp;</p>  <p style=\"text-align: justify;\"><strong>Clôture - Le feu d''artifice&nbsp;</strong><br>  Le clap de fin de cette grande soirée, c''est le feu d''artifice. Il saura éclairer de milles feux la chapelle impériale de Saint-Sauveur et éblouir le regard des petits et des grands !&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Lieu&nbsp;</strong>Quartier des thermes de Saint-Sauveur.&nbsp;En cas d''intempéries, la fête n''est pas annulée&nbsp;! Nous vous retrouverons au forum de Luz-Saint-Sauveur, au chaud et au sec. Pour les résidents&nbsp;du quartier des thermes,&nbsp;un courrier&nbsp;sera distribué&nbsp;précisant les dates et horaires auxquels les&nbsp;parking et les accès seront fermés.<br>  <strong>Tarif&nbsp;</strong>Comme chaque année, la fête de Saint-Sauveur et ses événements vous sont offerts&nbsp;!<br>  <strong>Repli</strong> Au forum de Luz-Saint-Sauveur</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '051e794d-095e-4e34-89e0-0f68cf1a19cb');
