INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('ade8da88-1ad1-4975-aff7-3602bd2f88a6', 'residence', true, false, false, NULL, '2024-12-08T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-12-08T23:00:00.000Z', '2024-12-08T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Inspire Puissance - Kollectif Kollisions', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Sortie de résidence \"Inspire puissance\" du&nbsp;Kollectif Kollisions</strong></p>  <p style=\"text-align: justify;\">Le Kollectif Kollisions est un collectif de danse composé de 4 interprètes. Ses activités sont caractérisées par la volonté de faire « collision » : faire se rencontrer les styles, mélanger les arts, et permettre le croisement des publics, des artistes, et des idées. Sa première pièce « Traces », en cours de diffusion, est un trio entre deux danseuses contemporaines et une peintre. Sur un rythme crescendo, avec des corps en ébullition, la prochaine création du Kollectif Kollisions \"Inspire puissance\"(titre provisoire), exalte la force individuelle vouée à nourrir le collectif. Elle offrira un moment partagé de vitalité et de cohésion où le public sera invité à ne pas rester simple spectateur. Les incarnations de cette puissance créatrice sont hétéroclites, inspirées et inspirantes. “Inspire puissance”(titre provisoire) sera un spectacle explosif qui raconte et réveille la puissance créatrice qui vit en chacun.e de nous.</p>  <p style=\"text-align: justify;\"><strong>Distribution</strong> Interprètes et co-chorégraphes Aglaé Curtil, Emmy Doucoure, Lory Baron, Alice Tincrès, regard extérieur Gilles Bareilles<br>  <strong>Le Kollectif Kollisions</strong>https://kollectifkollisions.fr/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Sortie de résidence </strong>Vendredi 13 décembre à 18h30<br>  <strong>Tarif </strong>Offert<br>  <strong>Public </strong>Tout public<br>  <strong>Lieu </strong>Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ade8da88-1ad1-4975-aff7-3602bd2f88a6');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Inspire Puissance - Kollectif Kollisions', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Sortie de résidence \"Inspire puissance\" du&nbsp;Kollectif Kollisions</strong></p>  <p style=\"text-align: justify;\">Le Kollectif Kollisions est un collectif de danse composé de 4 interprètes. Ses activités sont caractérisées par la volonté de faire « collision » : faire se rencontrer les styles, mélanger les arts, et permettre le croisement des publics, des artistes, et des idées. Sa première pièce « Traces », en cours de diffusion, est un trio entre deux danseuses contemporaines et une peintre. Sur un rythme crescendo, avec des corps en ébullition, la prochaine création du Kollectif Kollisions \"Inspire puissance\"(titre provisoire), exalte la force individuelle vouée à nourrir le collectif. Elle offrira un moment partagé de vitalité et de cohésion où le public sera invité à ne pas rester simple spectateur. Les incarnations de cette puissance créatrice sont hétéroclites, inspirées et inspirantes. “Inspire puissance”(titre provisoire) sera un spectacle explosif qui raconte et réveille la puissance créatrice qui vit en chacun.e de nous.</p>  <p style=\"text-align: justify;\"><strong>Distribution</strong> Interprètes et co-chorégraphes Aglaé Curtil, Emmy Doucoure, Lory Baron, Alice Tincrès, regard extérieur Gilles Bareilles<br>  <strong>Le Kollectif Kollisions</strong>https://kollectifkollisions.fr/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Sortie de résidence </strong>Vendredi 13 décembre à 18h30<br>  <strong>Tarif </strong>Offert<br>  <strong>Public </strong>Tout public<br>  <strong>Lieu </strong>Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'ade8da88-1ad1-4975-aff7-3602bd2f88a6');
