INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('D''un conflit à un autre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION</strong><br>  Pour honorer le 80ème anniversaire du débarquement et la bataille de Normandie, la Maison du Parc national et de la vallée accueille l''exposition \"D''un conflit à un autre\" proposée par M. Dupire et M. Haurine. Cette présentation rend&nbsp;hommage&nbsp;à la mémoire des hommes de la vallée du Pays Toy ayant combattu durant les deux guerres mondiales. Une multitude de supports raconte&nbsp;l''Histoire à travers&nbsp;le quotidien de ces combattants : des correspondances, des récits de vie, des aquarelles, des esquisses et des cartes militaires reprenant les dernières batailles des soldats.&nbsp;</p>  <p style=\"text-align: justify;\">L''exposition comprend deux volets relatifs aux deux conflits de 1914-1918 et 1939-1945. Dans&nbsp;un premier temps sont présentés les 16 soldats du village de Sazos morts pour la France, les circonstances de leur décès et le&nbsp;lieu&nbsp;de leur dernière&nbsp;bataille. Le deuxième évoque la vie quotidienne des 1 850 000 prisonniers partis en captivité en juin 1940 et détenus durant cinq années pour 1 500 000 d''entre-eux. Les témoignages du soldat Paul Petit, prisonnier en 1940 à l''âge de 20 ans sont aussi présentés.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>DATE</strong><br>  Du vendredi 31 mai&nbsp;au dimanche 30 juin&nbsp;2024.<br>  Sur les horaires d''ouvertures de la Maison.</p>  <p style=\"text-align: justify;\"></p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b265ec3f-0b5c-4b0b-965a-6ac84ddf9178');
