INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi Artistique "File, Ô Roméo !" Cie L''Âne Culotté', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>MERCREDI ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  Rose Idylle rêve d’interpréter le rôle de Juliette mais ne trouve pas de comédien à la hauteur de ses espérances pour incarner celui de Roméo. Rien n’est plus naturel pour elle que de se tourner vers Filomène, son alter égo. Néanmoins l''ânesse&nbsp;quadrupède à longues oreilles ne répond pas tout à fait aux exigences de Rose Idylle qui a tendance à oublier la vraie nature de sa partenaire …</p>  <p style=\"text-align: justify;\">File, Ô Roméo ! est un spectacle né de l’envie d’une rencontre entre un âne et un clown. Que pourrait-il bien se vivre entre les deux ? Quel serait leur langage commun ? Comment la nature de l’un influerait sur celle de l’autre ? Quelles formes poétiques émaneraient de ces corps distincts ? L’envie de cette rencontre est issue d’un long cheminement, d’une expérience de cinq ans d’itinérance en compagnie de l’ânesse Prune, la mère de Filomène. Filomène n’est donc pas une ânesse choisie au hasard pour répondre aux besoins d’un spectacle. Le jour de sa naissance annonçait une coopération basée sur une amitié de longue durée, une complicité et une confiance réciproque entre deux êtres de différentes espèces.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong><br>  Écriture et interprétation&nbsp;: Héloïse Derely et Filomène<br>  Regard complice : Julie Delille<br>  Mise en clown&nbsp;: Sylvain Duvignau<br>  Coaching dressage&nbsp;: Julien Hardorock et Mathilde Bonneville<br>  Conception décor&nbsp;: Menuiserie Girard et Ray Partant<br>  Conception costume : Noémie Borel&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>La compagnie \"L''Âne Culotté\"</strong><br>  À l''issue de cinq ans d''itinérance à pied avec des ânes bâtés, Héloïse Derely crée en 2017 la Compagnie l''Âne Culotté, dédiée au spectacle vivant, à l''art clownesque et à la relation entre l''être humain et les autres espèces animales. A travers des propositions artistiques diverses et en collaboration avec des artistes issues d''horizons différents, elle interroge la porosité qui existe entre des êtres de différentes espèces&nbsp;et tente par ce biais de mettre en lumière l''animalité inhérente à l''Homme. Soucieuse de placer le clown au cœur de ses propositions artistiques, la Cie aborde par le rire la notion d''identité et la difficulté à appréhender la différence au risque éventuel de perdre son appartenance à un groupe social.<br>  Site internet :&nbsp;https://www.compagnie-laneculotte.fr/<br>  Facebook :&nbsp;Cie L''Âne Culotté&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Crédit photo&nbsp;</strong>Robert Mueth Instagram : robert.mueth.photographies<br>  <strong>Lieu&nbsp;</strong>Place du 19 mars, Luz-Saint-Sauveur 65120<br>  <strong>Tarifs&nbsp;</strong>Offert dans le cadre des \"Mercredi Artistique\"</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e91fb7d7-4983-4211-abc8-90021dc87624');
