INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi Artistique "Kidnapping" Cie In Girum', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>MERCREDI ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  <strong>À partir de 10 ans.</strong><br>  Lamelle, une clown&nbsp;a kidnappé une marionnette pour pouvoir jouer dans les festivals mais elle ne connait ni le déroulé du spectacle qu''elle veut jouer, ni les règles qui régissent la manipulation marionnettique. Avec la marionnette et le public comme témoin s''entame une relation qui va nouer un duo que tout éloignait de prime abord. La langue bien pendue de Lamelle et son sens de la répartie ponctuent le spectacle qui croque avec beaucoup de légèreté et d''humour les figures banales de l''oppression dont Lamelle a fait son cheval de bataille. Un seul en scène jubilatoire à la croisée du clown et de la marionnette au rapport public déboussolant et aux niveaux de lecture pluriels.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>La compagnie \"In Girum\"</strong><br>  In&nbsp; Girum... est une compagnie d''Occitanie à l''origine composée d’une comédienne/marionnettiste et d’un sculpteur. Travaillant à partir de textes non théâtraux, d’albums jeunesse, de textes personnels, d’improvisations ou d''objets, la compagnie investit les questions du : comment écrire la parole ? Comment maintenir la rencontre spectaculaire au présent ? Comment rendre compte du réel dans la représentation ?<br>  Pour en savoir plus site internet :&nbsp;https://cieingirum.jimdofree.com/<br>  Facebook :&nbsp;Cie In Girum.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Crédit photo&nbsp;</strong>Jean-Pierre Patoux<br>  <b>Lieu&nbsp;</b>Place de l''Église, 65120 Luz-Saint-Sauveur<br>  <strong>Repli</strong> Salle de spectacle de la Maison du Parc national et de la vallée</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>TARIF</strong><br>  Offert dans le cadre des \"Mercredi Artistique\"</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'dba98ff4-7c36-44bf-901b-8107240dc8f3');
