INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence PESCALUNA', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Sortie de résidence Pescaluna - Musique médiévale</strong></p>  <p style=\"text-align: justify;\">La troupe PESCALUNA parcourt les routes pour partager musiques et danses sur un répertoire médiéval et renaissance. Ses artistes, basés dans le sud-ouest de la France et imprégnés de culture traditionnelle locale, sont passionnés de musique ancienne. Ils pratiquent divers instruments tels les hautbois, chalémie, bombarde, cornemuses, flûtes, tambourin à cordes, mandole, oud, orgue médiéval et percussions. Vos pieds commencent à bouger, c’est plus fort que vous ? ... Approchez, approchez, entrez dans la ronde et laissez-vous guider par le maître de danse !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong>&nbsp;Flûtes, orgue, cornemuse Sandrine Cur; flûtes, hautbois,&nbsp; bombarde, percussions Christian Tescher; danses et percussions Camille Bobelin; mandole Théo Gilbin; percussions Timothée Tchang Tien Ling<br>  <strong>Pescaluna&nbsp;</strong>http://pescaluna.fr/</p>  <p style=\"text-align: justify;\"><strong>Sortie de résidence </strong>Vendredi 29 novembre à 18h30<br>  <strong>Tarif </strong>Offert<br>  <strong>Public </strong>Tout public<br>  <strong>Lieu</strong> Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd433f944-b2af-4a09-bfb4-b4483df832e7');
