INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence PESCALUNA', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Sortie de résidence Pescaluna - Musique médiévale</strong></p>  <p style=\"text-align: justify;\">La troupe PESCALUNA parcourt les routes pour partager musiques et danses sur un répertoire médiéval et renaissance. Ses artistes, basés dans le sud-ouest de la France et imprégnés de culture traditionnelle locale, sont passionnés de musique ancienne. Ils pratiquent divers instruments tels les hautbois, chalémie, bombarde, cornemuses, flûtes, tambourin à cordes, mandole, oud, orgue médiéval et percussions. Vos pieds commencent à bouger, c’est plus fort que vous ? ... Approchez, approchez, entrez dans la ronde et laissez-vous guider par le maître de danse !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong>&nbsp;Flûtes, orgue, cornemuse Sandrine Cur; flûtes, hautbois,&nbsp; bombarde, percussions Christian Tescher; danses et percussions Camille Bobelin; mandole Théo Gilbin; percussions Timothée Tchang Tien Ling<br>  <strong>Pescaluna&nbsp;</strong>http://pescaluna.fr/</p>  <p style=\"text-align: justify;\"><strong>Sortie de résidence </strong>Vendredi 29 novembre à 18h30<br>  <strong>Tarif </strong>Offert<br>  <strong>Public </strong>Tout public<br>  <strong>Lieu</strong> Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'd433f944-b2af-4a09-bfb4-b4483df832e7');
INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('9adffdf7-f5b1-45df-86c8-368738505940', 'evenement', true, false, false, NULL, '2024-08-20T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-08-20T22:00:00.000Z', '2024-08-20T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi Artistique "Peels de Hut" Cie Anonima Teatro', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>MERCREDI ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description<br>  Tout public à partir de 5 ans.</strong>&nbsp;À une époque où religion et magie se côtoient : dragon, princesse, crise de foie et quête de soi… Les aventures déjantées d’un chevalier dans l’erreur. Dans une ambiance proche des Monty Python associée à la folie de la marionnette à gaine.&nbsp;</p>  <p style=\"text-align: justify;\">Note d''intention de&nbsp;Loïc Thomas<br>  J’ai découvert l’univers et la folie de la marionnette à gaine avec Brice Coupey, qui nous a montré les immenses possibilités qu’offre ce type de manipulation. Cette technique est entrée en résonance avec ma formation de l’école Jacques Lecoq ainsi que ma propre folie. Depuis, je suis fasciné par ce registre d’une grande richesse et d’une certaine simplicité à la fois, son rythme endiablé et son humour sans limite ni censure. Très rapidement je me suis mis à la construction de mes propres marionnettes afin d’assouvir mon désir de confronter cette forme à mes délires. Explorant l’univers de la chevalerie, ceci est une nouvelle collaboration avec un compagnon de longue date, Jacopo Faravelli. Liés par un humour commun, une rigueur et une exigence dans le travail, nous nous retrouvons dans une nouvelle déclinaison de notre efficace duo. Suite logique (ou pas) de nos collaborations actuelles et passées</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong><br>  Avec : Loïc Thomas<br>  De : Jacopo Faravelli&nbsp;et Loïc Thomas<br>  Décors et costumes : Solange Nourigat<em> </em></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>La compagnie\"Anonima Teatro\"</strong><br>  Lieu de nos envies, compagnie théâtrale et association loi 1901, Anonima Teatro habite à Tressan, petit village de la vallée de l’Hérault. Depuis 2002 elle s’occupe de marionnette, de théâtre de rue et d’objets, de musique (parfois) et d’autres bricolages artistiques.<br>  Site internet :&nbsp;https://www.anonimateatro.com/category/nous/<br>  Facebook :&nbsp;Cie AnonimaTeatro&nbsp;<br>  Instagram :&nbsp;cieanonimateatro</p>  <p style=\"text-align: justify;\"></p>  <ul></ul>  <p style=\"text-align: justify;\"><strong>Durée&nbsp;</strong>45 minutes<br>  <strong>Lieu&nbsp;</strong>Parc de la mairie, Luz-Saint-Sauveur 65120<br>  <strong>Tarifs&nbsp;</strong>Offert dans le cadre des \"Mercredi Artistique\"<br>  <strong>Repli </strong>Salle de spectacle de la Maison du Parc national et de la vallée</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9adffdf7-f5b1-45df-86c8-368738505940');
