INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Point rencontre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description</strong><br>  Profitez de la présence d''un garde-moniteur du Parc national des Pyrénées pour poser toutes vos questions sur la faune, la flore présentes dans les vallées, al réglementation de la zone cœur, les actions de préservation en place, etc … Un moment privilégié pour en savoir plus sur l''environnement qui vous entoure. Les rencontres ont lieu de 18h00 à 19h00.&nbsp;</p>  <p style=\"text-align: justify;\"><strong>Lieu&nbsp;</strong>Maison du Parc national et de la vallée<br>  <strong>Tarif&nbsp;</strong>Offert</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9243aad0-c972-45c3-9677-2a30a62592e1');
