INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Partageons la montagne', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description \"Partageons la montagne\"</strong><br>  Venez découvrir&nbsp;une exposition artistique et pédagogique.&nbsp;Le Parc national des Pyrénées vous propose des ressources sur la cohabitation des usages en estive. Ces outils seront accompagnés&nbsp;du travail artistique de&nbsp;Jobomart, graphiste de formation.&nbsp;Retrouvez les sites emblématiques des Hautes-Pyrénées à travers les affiches de José tout en apprenant de manière&nbsp;ludiques&nbsp;comment s''organisent les différentes activités en montagne.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Les ressources du Parc national des Pyrénées</strong><br>  La hausse de la fréquentation de la montagne pour des usages récréatifs, notamment depuis 2020 est un phénomène propice à l’économie du territoire et à la valorisation du patrimoine naturel des Pyrénées. Cependant, cela engendre des contacts plus étroits de nouveaux publics avec les acteurs du pastoralisme et de leurs troupeaux. Le manque de connaissance des bonnes pratiques de ces nouveaux usagers peut engendrer des situations conflictuelles, voire dangereuses pour l’ensemble des personnes, des animaux domestiques et sauvages.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Les affiches de Jobomart</strong><br>  Jobomart est un illustrateur et concepteur multimédia espagnol. Il a étudié les Beaux-Arts à l''Université de Valence, en Espagne, puis il a travaillé quelques années dans l''industrie graphique entre la France et l''Espagne, autour des Alpes et des Pyrénées. Il&nbsp;travaille désormais en freelance, ce qui lui permet de créer tout en privilégiant son cadre de&nbsp;vie entre montagne et océan, ses principales sources d''inspiration.<br>  Site internet :&nbsp;https://www.jobomart.net/<br>  Instagram :&nbsp;https://www.instagram.com/jobomart/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Date</strong><br>  Du vendredi 02&nbsp;août au jeudi 29 août 2024.<br>  Sur les horaires d''ouvertures de la Maison.</p>  <p style=\"text-align: justify;\"><strong>Lieu&nbsp;</strong>Salle des voûtes Libre accès</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '3fe6ceed-91a6-468c-9ee3-4e6640bec275');
