INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi Artistique "La Tchatche" ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>MERCREDI ARTISTIQUE</strong></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  La Tchatche est un quartet de passionnés de jazz et de swing. Ils allient volontiers le vieux jazz avec des chansons des années 30 à 50. Du moment que ça swingue ! Sur scène, ces quatre fans de Django Reinhardt, ne manquent pas de vous embarquer dans leur voyage. Leur énergie vous porte et ne vous lâche plus. On ne peut pas s''empêcher de taper du pied ou de danse.&nbsp;</p>  <p style=\"text-align: justify;\"><strong>Les artistes</strong><br>  Pour visionner un teaser&nbsp;:&nbsp;https://www.youtube.com/watch?v=3xUzitcYNC4<br>  Téléphone : 06.06.47.89.07<br>  Mail : otter.patrick67@gmail.com</p>  <p style=\"text-align: justify;\"><strong>Lieu&nbsp;</strong>Petit Jardin de la Poste, Luz-Saint-Sauveur 65120<br>  <strong>Tarifs&nbsp;</strong>Offert dans le cadre des \"Mercredi Artistique\"<br>  <strong>Repli</strong> Salle de spectacle de la Maison du Parc national et de la vallée</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'cea61f82-2ab5-4075-b11c-028eb57bb8d8');
