INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Ciné-Débat "Ibex, dans les pas du bouquetin"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description</strong><br>  IBEX dans les pas du bouquetin de Guillaume Collombet (52min).</p>  <p style=\"text-align: justify;\">À travers un carnet de terrain découvert par des enfants, découvrez l''histoire incroyable de son retour, et plongez au coeur de la vie de cet animal. En chemin vous apercevrez d''autres espèces qui parcourent parfois son territoire : marmotte, gypaète barbu, tétras-lyre, lièvre variable, aigle royal …&nbsp;La projection sera suivie par l''intervention d''Alexandre Garnier, responsable du suivi de la population de bouquetin au Parc national. Comment le bouquetin des Pyrénées est apparu ? Quelle différence avec le bouquetin des Alpes ? Comment réintroduit-on une espèce ? Autant de questions qui seront abordées pour tout comprendre de cette aventure humaine unique.&nbsp;</p>  <p></p>  <p></p>  <p><strong>Type&nbsp;</strong>Ciné-Débat<br>  <strong>Public&nbsp;</strong>Tout Public<br>  <strong>Horaire&nbsp;</strong>De 18h à 20h<br>  <strong>Lieu&nbsp;</strong>Maison du Parc national et de la vallée<br>  <strong>Tarifs&nbsp;</strong>Offert par le Parc national des Pyrénées</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '32fc29c6-b05c-485b-8bc6-87fadbe675e0');
