INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Ciné-Débat "Les Pyrénées Secrètes"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Description</strong><br>  Le Parc national des Pyrénées vous propose de découvrir quelques-unes des espèces emblématiques des Pyrénées au travers de l''un des documentaires issus de la trilogie \"Les Pyrénées Secrètes\" réalisée par la société de production Bellota films pour la chaîne ARTE. Cette série vous invite pour un voyage unique à la recherche de l''Ours ou du Gypaète ou de la Genette du massif des Pyrénées, l''un des plus sauvages de France. Cette projection sera suivie d''un échange avec un garde moniteur du Parc national des Pyrénées.</p>  <p><strong>Type</strong>Ciné-Débat<br>  <strong>Public&nbsp;</strong>Tout Public<br>  <strong>Durée&nbsp;</strong>43 minutes<br>  <strong>Horaire&nbsp;</strong>De 18h à 20h<br>  <strong>Lieu&nbsp;</strong>Maison du Parc national et de la vallée<br>  <strong>Tarifs&nbsp;</strong>Offert par le Parc national des Pyrénées</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a4bdea2f-83be-43f7-96c8-cc1c20301fc5');
