INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Où est Lucky ?" Une journée sur le bouquetin', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Animations du Parc national des Pyrénées \"Où est Lucky ?\"&nbsp;</strong><br>  Disparu depuis plus d’un siècle, le bouquetin foule à nouveau le sol du Parc national depuis un lâcher réalisé en juillet 2004, suivi de nombreux autres. Pour fêter les 10 ans de cette réintroduction mythique, des temps forts sont proposés tout au long de l’année. &nbsp;Le samedi 19 octobre à partir de 14h et jusqu’à 17h profitez d’animations gratuites et accessibles aux enfants comme aux adultes. Empreintes, forme des cornes, différences avec les autres ongulés ... Découvrez toutes les facettes du bouquetin. Grâce aux connaissances des gardes moniteurs du Parc national des Pyrénées, vous deviendrez incollables sur cette espèce emblématique des Pyrénées.&nbsp;</p>  <p><strong>Tarif</strong> Offert<br>  <strong>Public</strong> Tout public&nbsp;<br>  <strong>Lieu</strong> Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e11ed017-d84d-4be5-ba5a-9bc0bc41aea2');
