INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mercredi Artistique "Concerto pour camionneuse" Marion Hergas', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>ANNULATION Le spectacle est malheureusement annulé en raison d''un problème technique.&nbsp;</b></p>  <p style=\"text-align: justify;\"><strong>Description</strong><br>  <strong>Tout public.</strong><br>  Concerto pour camionneuse, ou le voyage clownesque d''une fil-de-feriste farfelue et son obsession pour les chaussures .... Armée de son brin de folie, de sa structure colossale et de ses innombrables chaussures rouges, une jeune femme un brin loufoque nous invite à entrer dans un monde où les régles marchent sur la tête. Mais elle ? En&nbsp; (des-)équilibre sur un fil, des chaussures dans les mains, d''auters sur les pieds, des qui volent, d''autres qui marchent, qui tombent, qui n''en font qu''à leur tête ... Pour le meilleur ... Et pour lire pire ! Et si tout ne tenait qu''à ça ? Cette fragilité, cette importance de marcher droit ...</p>  <p style=\"text-align: justify;\">Avec tout son humour, tour à tour grinçante, tendre ou espiègle, Marion propose une intimité partagée autour de nos petites folies quotidiennes, le tout baignant dans une atmosphère déjantée, à grands coups d''autodérision. Le périple acrobatique d''une femme qui joue avec les codes, et se fiche du monde entier.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Artiste Marion Hergas</strong><br>  Dès son plus jeune âge, Marion décide de passer le plus clair de son temps la tête en bas, à la recherche de la meilleure façon de provoquer le déséquilibre. De 16 à 22 ans, elle intègre différentes écoles de cirque pour se former au métier de d''artiste (Arc en Cirque, ENACR puis CNAC). Sa spécialité, c''est le fil de fer. Mais ce qu''elle aime particulièrement,&nbsp;c''est ne pas se donner de limites, jongler avec les styles et s''adapter encore et encore. Pendant plusieurs années, Marion saisira l''opportunité de continuer à se former auprès de cies ainées, en étant interprète (NoFit State Circus, Cie HDVZ, Cirque Baroque, etc.). Forte de ces expériences et influences qui l''ont forgée, elle écrit en 2016 un solo de cirque pour la rue, \"Concerto&nbsp;pour camionneuse\", encore en tournée à l''heure actuelle. Puis fin 2015 ses envies la poussent à rencontrer des femmes acrobates, et elles montent ensemble le Projet.PDF - Portés de femmes. De ce collectif de portés acrobatiques entièrement féminin et au fonctionnement horizontal et engagé sortira un spectacle en salle en 2018, \"Projet.PDF, Portés de femmes\" qui tournera en France et à l''international jusqu''en 2022. Puis à l''été 2023&nbsp;un second opus&nbsp;voit le jour, \"Légendes Urbaines\", une déambulation urbaine sur les thèmes de la question du genre dans l''espace public, de la culture du viol et de l''inceste. Toujours à la recherche de projets singuliers aux engagements forts et proches de ses valeurs, Marion reste profondément intéressée par la diversité et la découverte de nouveaux horizons</p>  <p style=\"text-align: justify;\">Pour en savoir plus site internet :&nbsp;https://marionhergas.weebly.com/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Crédit photo&nbsp;</strong>Solveig de la Hougue<br>  <strong>Durée&nbsp;</strong>45 minutes<br>  <strong>Lieu&nbsp;</strong>Boulodrome, 65120 Luz-Saint-Sauveur<br>  <strong>Tarif&nbsp;</strong>Offert dans le cadre des \"Mercredi Artistique\"</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e4412634-6262-427c-8f81-edecd72deb41');
