INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('f006c8cc-7606-4f69-ad48-68d4d44c4897', 'exposition', true, false, NULL, '2024-07-01T22:00:00.000Z', '2024-07-30T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2024-07-01T22:00:00.000Z', '2024-07-01T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mémoire d''eau', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION \"MÉMOIRE&nbsp;D''EAU\"</strong><br>  La genèse de cette exposition prend source dans la sélection d''un thème : L''eau.<br>  Ce&nbsp;sujet peut faire l''objet d''une multitude d''approches et intentions artistiques&nbsp;: le cycle de l''eau, les différents états de l''eau, la préservation de cette ressource, l''exploitation par l''humain, la puissance et la force de l''eau ... Cet élément, au coeur des enjeux écologiques,&nbsp;est aussi un élément incontournable du territoire des Hautes-Pyrénées. Comme en témoigne, avec ses 422 mètres de hauteur,&nbsp;la cascade de Gavarnie, la plus haute chute d''eau de&nbsp;France&nbsp;métropolitaine, et l''une des plus importantes d''Europe.&nbsp;</p>  <p>Le nom de l''exposition provient de l''oeuvre plastique de l''artiste Lorène Roustin, faite de cire. À&nbsp;ses côtés cohabite le travail du photographe palois Bernard Pradier.&nbsp;Tous deux, captivés par cet élément, vous présentent leurs propositions artistiques autour de l''eau, élément aussi commun qu''essentiel.</p>  <p></p>  <p style=\"text-align: justify;\">Retour sur l''oeuvre \"Mémoire d''eau\" de Lorène Roustin par Blandine Langlois: \"Mémoire d''eau présente une multitude d''éléments de cire suspendus telles des stalactites. Malgré la force visuelle et poétique qui en émane, l''installation est d''une grande fragilité. Suspendue à un fil, chaque cire semble pouvoir chuter à tout instant. Soucieuse des pénuries d''eau qui s''accroissent chaque année, Lorène Roustin s''empare de ce fluide précieux pour mieux faire passer son message. Chaque cire a été sculptée par le torrent du ruisseau de Hourquets. Versée dans l''eau glacée des Pyrénées, la cire blanche se fige instantanément. Lorène Roustin se place par ce geste en tant que gardienne de la mémoire de l''eau, sculptrice invisible de l''oeuvre. Mémoire d''eau à été réalisée lors d''Estives en résidence à Guran dans la vallée du Luchonais.\"</p>  <p></p>  <p><strong>Bernard Pradier - Photographe</strong><br>  La nature est ma source d’inspiration favorite. A toutes les échelles.</p>  <p>Je capture ce qui attire mon regard lors d’une randonnée ou d’un simple moment d’observation de ce qui m’entoure. Je ne suis pas chasseur d’image, je saisis ce qui est offert, sans rien toucher. Le hasard est un bon guide. La plupart du temps je préfère l’abstraction qui se niche dans un détail ou sous un angle de vue particulier. Ma photographie est essentiellement brute, telle que saisie sur place. J’essaie de retrouver sur le papier, sans artifice, la petite émotion&nbsp;ressentie au moment de ma découverte. Les images que je présente parlent de l’eau des torrents et des sous-bois, au gré des saisons, entre Estaubé et Bué, en passant par Campbieil et Gavarnie …</p>  <p style=\"text-align: justify;\"><strong>Lorène Roustin - Artiste plasticienne</strong><br>  Artiste plasticienne à la pratique itinérante vit à Toulouse et travaille à Tarbes dans les Hautes-Pyrénées où elle a son atelier. En 2020 elle a obtenu son D.N.S.E.P. option Arts mention céramique à l’École Supérieure d’Arts et Design site de Tarbes. Elle s’investit au sein de divers collectifs artistiques comme Artlinker, La Chaise et Patch-work arts émergents. En 2024 elle à été selectionnée pour faire partie de Documents D’Artistes d’Occitanie émergence.</p>  <p style=\"text-align: justify;\">Sa démarche artistique :&nbsp;Dans son travail et ses recherches actuelles, Lorène Roustin se concentre sur certains environnements extérieurs (forêts, parcs, rivières, terrains publics et privés) et tout ce qui se rapporte aux non humains. Dans ces environnements, elle cherche à vivre une expérience par la marche, les rencontres avec les habitants, des historiens, des pécheurs, des naturalistes etc. Les informations qu’elle récupère lors de ces échanges lui permettent de former une base de données rhizomatique dans laquelle elle peut venir s’appuyer et piocher pour créer. À partir de cela, l’artiste constitue une cartographie des spécificités du territoire exploré pour mieux comprendre ses enjeux: espèces endémiques, espèces envahissantes, phénomènes naturels, milieux aquatiques, milieux géologiques etc. Depuis longtemps intriguée par le processus qui régit le code du vivant, elle essaie de s’en approcher par la restitution d’éléments collectés et de ré-contextualiser ses expériences. La carte et les coordonnées géographiques étant une forme de codification pour comprendre le réel qui nous entoure, il s’agit pour Lorène Roustin de s’approprier ce territoire en dérangeant le moins possible l’éco système présent. Comme lorsqu’elle interviens avec des onguent d’argile et cartographie les arbres malades de la forêt communale de Lagos (64) comme sur les photographies ci-présente. Sa démarche est de retranscrire les éléments et sensations qu’elle à cumulé «au dehors» dans l’espace d’exposition, par le biais de l’installation , la photographie, la vidéo ou la performance. Une autre part de son travail est in situ, son regard se porte sur les rapports et les pratiques des humains sur la gestion du vivant: arbres morts, plantes domestiques, sélections d’espèces etc. Elle transpose alors des gestes de soins normalement destinés aux humains sur des éléments aquatiques ou végétaux par le biais de rituels d’embaumement, de manucure ou encore de chant.</p>  <p>Site internet :&nbsp;https://www.lorene-roustin.fr/<br>  Instagram :&nbsp;https://www.instagram.com/roustin.lorene/</p>  <p></p>  <p><br>  <strong>DATE</strong><br>  Du mardi 02&nbsp;juillet au mercredi 31 juillet 2024.<br>  Sur les horaires d''ouvertures de la Maison.</p>  <p></p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f006c8cc-7606-4f69-ad48-68d4d44c4897');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Mémoire d''eau', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>DESCRIPTION \"MÉMOIRE&nbsp;D''EAU\"</strong><br>  La genèse de cette exposition prend source dans la sélection d''un thème : L''eau.<br>  Ce&nbsp;sujet peut faire l''objet d''une multitude d''approches et intentions artistiques&nbsp;: le cycle de l''eau, les différents états de l''eau, la préservation de cette ressource, l''exploitation par l''humain, la puissance et la force de l''eau ... Cet élément, au coeur des enjeux écologiques,&nbsp;est aussi un élément incontournable du territoire des Hautes-Pyrénées. Comme en témoigne, avec ses 422 mètres de hauteur,&nbsp;la cascade de Gavarnie, la plus haute chute d''eau de&nbsp;France&nbsp;métropolitaine, et l''une des plus importantes d''Europe.&nbsp;</p>  <p>Le nom de l''exposition provient de l''oeuvre plastique de l''artiste Lorène Roustin, faite de cire. À&nbsp;ses côtés cohabite le travail du photographe palois Bernard Pradier.&nbsp;Tous deux, captivés par cet élément, vous présentent leurs propositions artistiques autour de l''eau, élément aussi commun qu''essentiel.</p>  <p></p>  <p style=\"text-align: justify;\">Retour sur l''oeuvre \"Mémoire d''eau\" de Lorène Roustin par Blandine Langlois: \"Mémoire d''eau présente une multitude d''éléments de cire suspendus telles des stalactites. Malgré la force visuelle et poétique qui en émane, l''installation est d''une grande fragilité. Suspendue à un fil, chaque cire semble pouvoir chuter à tout instant. Soucieuse des pénuries d''eau qui s''accroissent chaque année, Lorène Roustin s''empare de ce fluide précieux pour mieux faire passer son message. Chaque cire a été sculptée par le torrent du ruisseau de Hourquets. Versée dans l''eau glacée des Pyrénées, la cire blanche se fige instantanément. Lorène Roustin se place par ce geste en tant que gardienne de la mémoire de l''eau, sculptrice invisible de l''oeuvre. Mémoire d''eau à été réalisée lors d''Estives en résidence à Guran dans la vallée du Luchonais.\"</p>  <p></p>  <p><strong>Bernard Pradier - Photographe</strong><br>  La nature est ma source d’inspiration favorite. A toutes les échelles.</p>  <p>Je capture ce qui attire mon regard lors d’une randonnée ou d’un simple moment d’observation de ce qui m’entoure. Je ne suis pas chasseur d’image, je saisis ce qui est offert, sans rien toucher. Le hasard est un bon guide. La plupart du temps je préfère l’abstraction qui se niche dans un détail ou sous un angle de vue particulier. Ma photographie est essentiellement brute, telle que saisie sur place. J’essaie de retrouver sur le papier, sans artifice, la petite émotion&nbsp;ressentie au moment de ma découverte. Les images que je présente parlent de l’eau des torrents et des sous-bois, au gré des saisons, entre Estaubé et Bué, en passant par Campbieil et Gavarnie …</p>  <p style=\"text-align: justify;\"><strong>Lorène Roustin - Artiste plasticienne</strong><br>  Artiste plasticienne à la pratique itinérante vit à Toulouse et travaille à Tarbes dans les Hautes-Pyrénées où elle a son atelier. En 2020 elle a obtenu son D.N.S.E.P. option Arts mention céramique à l’École Supérieure d’Arts et Design site de Tarbes. Elle s’investit au sein de divers collectifs artistiques comme Artlinker, La Chaise et Patch-work arts émergents. En 2024 elle à été selectionnée pour faire partie de Documents D’Artistes d’Occitanie émergence.</p>  <p style=\"text-align: justify;\">Sa démarche artistique :&nbsp;Dans son travail et ses recherches actuelles, Lorène Roustin se concentre sur certains environnements extérieurs (forêts, parcs, rivières, terrains publics et privés) et tout ce qui se rapporte aux non humains. Dans ces environnements, elle cherche à vivre une expérience par la marche, les rencontres avec les habitants, des historiens, des pécheurs, des naturalistes etc. Les informations qu’elle récupère lors de ces échanges lui permettent de former une base de données rhizomatique dans laquelle elle peut venir s’appuyer et piocher pour créer. À partir de cela, l’artiste constitue une cartographie des spécificités du territoire exploré pour mieux comprendre ses enjeux: espèces endémiques, espèces envahissantes, phénomènes naturels, milieux aquatiques, milieux géologiques etc. Depuis longtemps intriguée par le processus qui régit le code du vivant, elle essaie de s’en approcher par la restitution d’éléments collectés et de ré-contextualiser ses expériences. La carte et les coordonnées géographiques étant une forme de codification pour comprendre le réel qui nous entoure, il s’agit pour Lorène Roustin de s’approprier ce territoire en dérangeant le moins possible l’éco système présent. Comme lorsqu’elle interviens avec des onguent d’argile et cartographie les arbres malades de la forêt communale de Lagos (64) comme sur les photographies ci-présente. Sa démarche est de retranscrire les éléments et sensations qu’elle à cumulé «au dehors» dans l’espace d’exposition, par le biais de l’installation , la photographie, la vidéo ou la performance. Une autre part de son travail est in situ, son regard se porte sur les rapports et les pratiques des humains sur la gestion du vivant: arbres morts, plantes domestiques, sélections d’espèces etc. Elle transpose alors des gestes de soins normalement destinés aux humains sur des éléments aquatiques ou végétaux par le biais de rituels d’embaumement, de manucure ou encore de chant.</p>  <p>Site internet :&nbsp;https://www.lorene-roustin.fr/<br>  Instagram :&nbsp;https://www.instagram.com/roustin.lorene/</p>  <p></p>  <p><br>  <strong>DATE</strong><br>  Du mardi 02&nbsp;juillet au mercredi 31 juillet 2024.<br>  Sur les horaires d''ouvertures de la Maison.</p>  <p></p>  <p><strong>LIEU</strong><br>  Salle des voûtes<br>  Libre accès</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'f006c8cc-7606-4f69-ad48-68d4d44c4897');
