INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('8cfe7c2a-2dec-4d0a-aad1-bb452cdf8769', 'evenement', true, false, false, NULL, '2024-09-21T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-09-21T22:00:00.000Z', '2024-09-21T22:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les surgissements chorégraphiques - Compagnie Yann Lheureux', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Spectacle programmé&nbsp;dans le cadre des Journées du Patrimoine&nbsp;</strong></p>  <p style=\"text-align: justify;\">Tout au long de la journée, les spectateurs-habitants reçoivent la proposition d’assister à une performance dansée en solo dans le village de Luz-Saint-Sauveur. Ils décident du lieu et de l’horaire de présentation pour cette rencontre en tête-à-tête. Il suffit d’appeler pour programmer son spectacle. Informations et inscriptions obligatoires auprès de l’accueil de la Maison du Parc national et de la vallée ou au 05 62 92 38 38. Au cours d’une journée, une myriade de rencontres, de surgissements chorégraphiques, émergent sur le territoire. Avec ces solis dansés, des liens visibles et invisibles offrent une cartographie imprévisible, insoupçonnée du territoire. Un dialogue poétique dans un espace public avec ses habitants.</p>  <p></p>  <p style=\"text-align: justify;\">Le protocole actuel propose la trame suivante : chaque danseur découvre le lieu où il a été invité dix minutes avant le moment du rendez-vous, il anticipe l’arrivée de l’invitant, il ne se signale pas immédiatement afin de laisser opérer l’imminence de la danse. Cela incite à ouvrir pendant cette attente le regard de l’invitant, sa curiosité de spectateur, à venir, préparer sa « disponibilité esthétique ». Puis le danseur s’intègre au lieu, cette présence pure du démarrage du solo demande à l’interprète de se fondre dans l’espace, de disparaître en se déposant dans la quotidienneté. S’en suivent des décalages opérés à partir des tactilités et textures rencontrées, puis des décollages qui permettent d’extraire des physicalités à partir de l’architecture, et des spécificités du lieu en présence. Ce travail sur les affordances est l’un des ancrages des soli. S’en suit une phase d’une durée de 7 minutes environ, pendant laquelle chaque Insoliste interprète une partition pré établie propre à chacun. Ce moment chorégraphique investi par les notions d’excès et de silence fera pré-echo au quintet à venir. L’écriture de ces partitions chorégraphiques s’adaptera à chaque situation, reliant le prévisible à l’aléatoire. Il s’agit de confronter deux modes d’écriture, la composition et l’improvisation.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Démarche artistique :&nbsp; l’éclosion d’instantanés chorégraphiques.<br>  L’unité de temps, de lieu et partiellement d’action est confiée aux spectateurs-habitants. Chacun participe à l’élaboration d’un fragment, de pièces solo inédites et tout à la fois, à l’élaboration d’une mosaïque. Une multitude de soli éclosent sur le territoire, réarticulant une dramaturgie en constellation. Les spectateurs adoptent en temps réel les postures qui leur conviennent : spectateur distant, spectre-acteur, partenaire, duelliste, témoin… Durant chaque solo, chaque lieu est traversé autant qu’interrogé, parfois détourné de ses multiples fonctions, usages et circulations. Il devient l’écrin de cette rencontre et signe l’accolade éphémère.&nbsp;Tout le talent des interprètes et de l’écriture sont de dévoiler sans avoir prémédité.&nbsp;Raconter le lieu, la relation, autant que l’interprète se raconte.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution </strong>Conception et chorégraphie Yann Lheureux, interprètes Camille Lericolais, Benjamin Tricha, Yann Lheureux.<br>  <strong>La compagnie Yann Lheureux</strong>&nbsp;https://cie-yannlheureux.fr/</p>  <p style=\"text-align: justify;\"><br>  <strong>Tarif</strong>&nbsp;Offert sur réservation<br>  <strong>Public</strong>&nbsp;Tout public<br>  <strong>Lieu</strong> Dans les rues de Luz-Saint-Sauveur</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '8cfe7c2a-2dec-4d0a-aad1-bb452cdf8769');
