('14ac6e94-b9a1-4994-90bb-7434c19833a4', 'evenement', true, false, NULL, '2024-06-30T22:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-06-30T22:00:00.000Z', '2024-06-30T22:00:00.000Z');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''eau, thématique de l''été', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>L''eau, thématique de l''été</strong><br>  La Maison du Parc national et de la vallée vous propose différents événéments culturels sur la thématique de l''eau. L''eau est un élément primordial de la vie. Elle est non seulement vitale en matière de santé, mais aussi d''emplois en permettant de subvenir au développement économique, social et humain. L’objectif est de sensibiliser sur l’importance de l’eau et la préservation durable de cette ressource. Le changement climatique, la croissance démographique et le développement économique nécessitent de trouver des solutions pour garantir une ressource en eau durable.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Exposition&nbsp;\"Mémoire d''eau\"</strong><br>  Durant le mois de juillet venez découvrir l''exposition \"Mémoire d''eau\" de la plasticienne Lorène Roustin et du photographe Bernard Pradier<br>  Pour en savoir plus :&nbsp;https://www.maisondelavallee.org/memoire-deau</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Cinéma sous les étoiles \"Ponyo sur la falaise\" Film animation</strong><br>  Mardi 13 août à 21h45 au Verges de Luz-Saint-Sauveur<br>  Pour échapper à la police, un fils et son père en cavale sont contraints de trouver refuge dans une colonie de vacances pour jeunes adultes en situation de handicap, se faisant passer pour un pensionnaire et son éducateur spécialisé. Le début des emmerdes et d’une formidable expérience humaine qui va les changer à jamais.<br>  Pour en savoir plus : https://www.maisondelavallee.org/cinema-sous-etoiles-ponyo-sur-falaise-0</p>  <p style=\"text-align: justify;\"><br>  <strong>Cinéma sous les étoiles \"La rivière\" Film documentaire</strong><br>  Mardi 20 août à 21h45 au Verger de Luz-Saint-Sauveur<br>  Entre Pyrénées et Atlantique coulent des rivières puissantes qu’on appelle les gaves. Les champs de maïs les assoiffent, les barrages bloquent la circulation du saumon. L’activité humaine bouleverse le cycle de l’eau et la biodiversité de la rivière. Des hommes et des femmes tendent leur regard curieux et amoureux vers ce monde fascinant fait de beauté et de désastre.<br>  Pour en savoir plus :&nbsp;https://www.maisondelavallee.org/cinema-sous-etoiles-riviere-0</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Table de lecture&nbsp;</strong><br>  La thématique&nbsp;de notre table de lecture de l''été s''intitule : \"Au fil de l''eau\". Retrouvez une sélection d''ouvrages pour mieux comprendre les enjeux futurs liés à l''eau potable. Petits et grands, renforcez vos connaissances scientifiques sur le cycle de l''eau, les nappes phréatiques, les rivières et torrents où les différents états de l''eau. Vous pourrez aussi découvrir des romans d''anticipation, des fictions ou encore des ouvrages de photographies sur ce sujet, pilier de la vallée des Gaves !&nbsp;<br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '14ac6e94-b9a1-4994-90bb-7434c19833a4');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''eau, thématique de l''été', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>L''eau, thématique de l''été</strong><br>  La Maison du Parc national et de la vallée vous propose différents événéments culturels sur la thématique de l''eau. L''eau est un élément primordial de la vie. Elle est non seulement vitale en matière de santé, mais aussi d''emplois en permettant de subvenir au développement économique, social et humain. L’objectif est de sensibiliser sur l’importance de l’eau et la préservation durable de cette ressource. Le changement climatique, la croissance démographique et le développement économique nécessitent de trouver des solutions pour garantir une ressource en eau durable.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Exposition&nbsp;\"Mémoire d''eau\"</strong><br>  Durant le mois de juillet venez découvrir l''exposition \"Mémoire d''eau\" de la plasticienne Lorène Roustin et du photographe Bernard Pradier<br>  Pour en savoir plus :&nbsp;https://www.maisondelavallee.org/memoire-deau</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Cinéma sous les étoiles \"Ponyo sur la falaise\" Film animation</strong><br>  Mardi 13 août à 21h45 au Verges de Luz-Saint-Sauveur<br>  Pour échapper à la police, un fils et son père en cavale sont contraints de trouver refuge dans une colonie de vacances pour jeunes adultes en situation de handicap, se faisant passer pour un pensionnaire et son éducateur spécialisé. Le début des emmerdes et d’une formidable expérience humaine qui va les changer à jamais.<br>  Pour en savoir plus : https://www.maisondelavallee.org/cinema-sous-etoiles-ponyo-sur-falaise-0</p>  <p style=\"text-align: justify;\"><br>  <strong>Cinéma sous les étoiles \"La rivière\" Film documentaire</strong><br>  Mardi 20 août à 21h45 au Verger de Luz-Saint-Sauveur<br>  Entre Pyrénées et Atlantique coulent des rivières puissantes qu’on appelle les gaves. Les champs de maïs les assoiffent, les barrages bloquent la circulation du saumon. L’activité humaine bouleverse le cycle de l’eau et la biodiversité de la rivière. Des hommes et des femmes tendent leur regard curieux et amoureux vers ce monde fascinant fait de beauté et de désastre.<br>  Pour en savoir plus :&nbsp;https://www.maisondelavallee.org/cinema-sous-etoiles-riviere-0</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Table de lecture&nbsp;</strong><br>  La thématique&nbsp;de notre table de lecture de l''été s''intitule : \"Au fil de l''eau\". Retrouvez une sélection d''ouvrages pour mieux comprendre les enjeux futurs liés à l''eau potable. Petits et grands, renforcez vos connaissances scientifiques sur le cycle de l''eau, les nappes phréatiques, les rivières et torrents où les différents états de l''eau. Vous pourrez aussi découvrir des romans d''anticipation, des fictions ou encore des ouvrages de photographies sur ce sujet, pilier de la vallée des Gaves !&nbsp;<br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '14ac6e94-b9a1-4994-90bb-7434c19833a4');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''eau, thématique de l''été', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>L''eau, thématique de l''été</strong><br>  La Maison du Parc national et de la vallée vous propose différents événéments culturels sur la thématique de l''eau. L''eau est un élément primordial de la vie. Elle est non seulement vitale en matière de santé, mais aussi d''emplois en permettant de subvenir au développement économique, social et humain. L’objectif est de sensibiliser sur l’importance de l’eau et la préservation durable de cette ressource. Le changement climatique, la croissance démographique et le développement économique nécessitent de trouver des solutions pour garantir une ressource en eau durable.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Exposition&nbsp;\"Mémoire d''eau\"</strong><br>  Durant le mois de juillet venez découvrir l''exposition \"Mémoire d''eau\" de la plasticienne Lorène Roustin et du photographe Bernard Pradier<br>  Pour en savoir plus :&nbsp;https://www.maisondelavallee.org/memoire-deau</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Cinéma sous les étoiles \"Ponyo sur la falaise\" Film animation</strong><br>  Mardi 13 août à 21h45 au Verges de Luz-Saint-Sauveur<br>  Pour échapper à la police, un fils et son père en cavale sont contraints de trouver refuge dans une colonie de vacances pour jeunes adultes en situation de handicap, se faisant passer pour un pensionnaire et son éducateur spécialisé. Le début des emmerdes et d’une formidable expérience humaine qui va les changer à jamais.<br>  Pour en savoir plus : https://www.maisondelavallee.org/cinema-sous-etoiles-ponyo-sur-falaise-0</p>  <p style=\"text-align: justify;\"><br>  <strong>Cinéma sous les étoiles \"La rivière\" Film docum