INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Paroles de bergères', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Paroles de bergères\"</strong></p>  <p style=\"text-align: justify;\">Dans le milieu pastoral des Pyrénées, les femmes ont longtemps tenu une place discrète dans les foyers loin du rêve de vivre en estive. Néanmoins leur rôle était essentiel au quotidien.&nbsp;</p>  <p style=\"text-align: justify;\">Durant les dernières décennies, le métier de berger est en pleine mutation et s’écrit au féminin. On ne cesse de voir des femmes arriver dans les estives et devenir chefs d’exploitation. Les témoignages de bergères des vallées d’Aspe, de Barétous, d’Ossau et du Piémont Oloronais vous feront découvrir ces femmes à travers les générations. L’exposition « Paroles de bergères » est proposée par le Pays d’art et d’histoire des Pyrénées Béarnaises et illustrée par les photographies de l’artiste Amanda Meunier. Cette programmation s’inscrit dans le cadre des Journées du matrimoine.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif</strong>&nbsp;Libre accès<br>  <strong>Public</strong> Tout public<br>  <strong>Lieu</strong>&nbsp;Salle des voûtes</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><br>  &nbsp;</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '26f68bef-2318-4232-8811-b100040be855');
