INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Chet Nuneta" Concert', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>Concert \"Chet Nuneta\"&nbsp;<br>  Partenariat avec le département des Hautes-Pyrénées dans le cadre des Escales d’Automne.</b></p>  <p style=\"text-align: justify;\">Aujourd’hui composé de trois chanteuses venues d’Espagne, de France et d’Italie, d’un chanteur percussionniste Franco-marocain et d’un percussionniste français aux influences multiples, Chet Nuneta présente sur scène son nouveau spectacle MAITA CHÉN (2021) et a réalisé son 4ème album (2022).</p>  <p style=\"text-align: justify;\">Fidèle à un esprit plus qu’à une forme, Chet Nuneta invite le spectateur dans un univers musical aux frontières des expressions théâtrales et dansées : au-delà de la voix, ce sont les corps qui résonnent, car depuis toujours, le groupe a une approche physique du chant et du rythme. Grâce à une très forte complicité entre ses membres, il s’en dégage une spontanéité et une sincérité en interaction permanente avec le public.</p>  <p style=\"text-align: justify;\">Chet Nuneta rend hommage à la femme et la nature : un écho aux luttes et aux voix qui montent pour défendre tout ce qui donne la vie. Aujourd’hui, face aux problématiques actuelles, le retour à l’essentiel féminin correspond aussi à l’indispensable réconciliation avec la nature. C’est à la suite d’une réflexion sensible et engagée que la nouvelle création de Chet Nuneta fait bruire ces chants jusqu’au coeur de la terre. Les origines de ses membres, leurs rencontres humaines, musicales et littéraires, leurs réactions au monde et à l’actualité ont nourri la création de chants en espagnol, bulgare, russe, portugais, italien, kanak, arabe, créole réunionnais.</p>  <p style=\"text-align: justify;\">Maita Chén est une production Mélodinote avec le soutien de l’OARA (Office Artistique Régional de Nouvelle-Aquitaine), le Centre culturel Yves Furet (La Souterraine), Le Rocher de Palmer (Cenon), La Sirène (La Rochelle), Les Ecuries de Baroja (Anglet), l’association Spirale (Riscle) et le CNM (Centre National de la Musique).</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong> Emma Spiesser, Emanuela Perrupato, Beatriz Salmerón Martín, Fouad Achkir, Frédéric Faure.<br>  <strong>Le groupe Chet Nuneta</strong>&nbsp;http://chetnuneta.net/concerts/dates-a-venir/#</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif </strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e87751d8-0a85-4622-b79a-208ce2bb4cf3');
