INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le funiculaire de l''Ayré', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Le funiculaire de l''Ayré\"</strong></p>  <p style=\"text-align: justify;\">L’association FuniToy vous propose de découvrir le funiculaire de l’Ayré au travers d’une exposition de photographies. Historiquement la station de Barèges fut l’une des premières stations de ski des Hautes-Pyrénées. Dans les années 1920, de nombreux skieurs montaient à pied ou en peaux de phoque pour pratiquer le ski. Avec l’ère de la mécanisation et de l’industrialisation, l’idée de relier le village de Barèges au plateau du Lienz par des moyens mécaniques émergea ! Le Funiculaire fût construit pour permettre aux locaux et aux touristes de profiter d’un merveilleux domaine skiable dans une forêt magnifique. L’installation fonctionnera de 1937 à 2000.&nbsp;</p>  <p style=\"text-align: justify;\">L’association Funitoy a été créée par six passionnés du village de Barèges et des forêts avoisinantes. L’association souhaite mettre en valeur le patrimoine naturel de la forêt du Lienz, de l’Ayré et de la Glère ainsi que la réhabilitation du funiculaire.</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '049dc515-bd59-4535-a9b4-bd5e7179619b');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le funiculaire de l''Ayré', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Le funiculaire de l''Ayré\"</strong></p>  <p style=\"text-align: justify;\">L’association FuniToy vous propose de découvrir le funiculaire de l’Ayré au travers d’une exposition de photographies. Historiquement la station de Barèges fut l’une des premières stations de ski des Hautes-Pyrénées. Dans les années 1920, de nombreux skieurs montaient à pied ou en peaux de phoque pour pratiquer le ski. Avec l’ère de la mécanisation et de l’industrialisation, l’idée de relier le village de Barèges au plateau du Lienz par des moyens mécaniques émergea ! Le Funiculaire fût construit pour permettre aux locaux et aux touristes de profiter d’un merveilleux domaine skiable dans une forêt magnifique. L’installation fonctionnera de 1937 à 2000.&nbsp;</p>  <p style=\"text-align: justify;\">L’association Funitoy a été créée par six passionnés du village de Barèges et des forêts avoisinantes. L’association souhaite mettre en valeur le patrimoine naturel de la forêt du Lienz, de l’Ayré et de la Glère ainsi que la réhabilitation du funiculaire.</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '049dc515-bd59-4535-a9b4-bd5e7179619b');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le funiculaire de l''Ayré', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Le funiculaire de l''Ayré\"</strong></p>  <p style=\"text-align: justify;\">L’association FuniToy vous propose de découvrir le funiculaire de l’Ayré au travers d’une exposition de photographies. Historiquement la station de Barèges fut l’une des premières stations de ski des Hautes-Pyrénées. Dans les années 1920, de nombreux skieurs montaient à pied ou en peaux de phoque pour pratiquer le ski. Avec l’ère de la mécanisation et de l’industrialisation, l’idée de relier le village de Barèges au plateau du Lienz par des moyens mécaniques émergea ! Le Funiculaire fût construit pour permettre aux locaux et aux touristes de profiter d’un merveilleux domaine skiable dans une forêt magnifique. L’installation fonctionnera de 1937 à 2000.&nbsp;</p>  <p style=\"text-align: justify;\">L’association Funitoy a été créée par six passionnés du village de Barèges et des forêts avoisinantes. L’association souhaite mettre en valeur le patrimoine naturel de la forêt du Lienz, de l’Ayré et de la Glère ainsi que la réhabilitation du funiculaire.</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '049dc515-bd59-4535-a9b4-bd5e7179619b');
