INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Insolite Lights - Atelier et parade', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Insolite Lights\" -&nbsp;Isabelle Barthélemy Atelier et parade nocturne</strong><br>  <a data-saferedirecturl=\"https://www.google.com/url?q=https://insolitelights.wordpress.com/presentation/&amp;source=gmail&amp;ust=1734875256099000&amp;usg=AOvVaw1QdErJCT2SKiKJ3g3QrpEr\" href=\"https://insolitelights.wordpress.com/presentation/\" target=\"_blank\">https://i</a><a data-saferedirecturl=\"https://www.google.com/url?q=http://sabelleb.net&amp;source=gmail&amp;ust=1734875256099000&amp;usg=AOvVaw337UA3M31zjm9jmnGTwLcZ\" href=\"http://sabelleb.net/\" target=\"_blank\">sabelleb.net</a></p>  <p style=\"text-align: justify;\">Créatrice de sculptures lumineuses pour le spectacle de rue ou le théâtre, Isabelle Barthélemy partage le plaisir de la fabrication lors d’ateliers ouverts à tous publics. En une journée, vous fabriquerez d’étonnantes lanternes/fleurs géantes de papier et d’osier. Toutes vos créations vont enchanter la parade de lanternes qui aura lieu le 27 décembre.</p>  <p style=\"text-align: justify;\">Jeudi 26 décembre, les ateliers auront lieu de 10h30 à 17h avec une pause de 1h30 pour le repas. Lors de cette journée, 10 lanternes seront créées. Inscription obligatoire à l’accueil de la Maison ou au 05.62.92.38.38. L’activité est offerte et s''adresse à tous publics, adultes ou enfants dès 8 ans et impérativement accompagnés d’un parent.</p>  <p style=\"text-align: justify;\">Vendredi 27 décembre à 18h, la parade débutera dans l’amphithéâtre extérieur de la Maison pour une promenade dans les rues du village. Les créateurs de lanternes pourront dévoiler leurs créations tandis que des volontaires pourront se relayer pour porter les lanternes supplémentaires. Le défilé sera accompagné par trois violonistes du territoire, promesse d’un moment féerique et empli de poésie pour cette fin d’année.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Jeudi 26 décembre et Vendredi 27 décembre<br>  Inscription obligatoire à l’accueil de la Maison ou au 05.62.92.38.38.&nbsp;</strong><br>  <strong>Tarif</strong> Offert sur inscription pour l''atelier<br>  <strong>Public </strong>Tout public</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '3d0ff2d5-919b-45c5-bed4-2f20cbb7f3cc');
