INSERT INTO autres_actualites (id, type, archive, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('299e5578-654d-4b82-9c2f-866b08a59b9b', 'evenement', true, false, NULL, '2024-12-29T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-12-29T23:00:00.000Z', '2024-12-29T23:00:00.000Z');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Ateliers Landart - Sylvain Trabut', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Atelier Landart - Sylvain Trabut</strong><br>  https://sylvain-trabut.fr/<br>  À partir d’éléments naturels, Sylvain Trabut&nbsp; confectionne des personnages ainsi que des décors. Il glane des petits trésors autour de chez lui et au cours de ses voyages. Ses créations sont fixes ou bien articulées. Il exposera les petits êtres durant le mois de janvier et vous propose un atelier.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Les ateliers</strong><br>  L’atelier débutera par la collecte des matières naturelles. S’en suivra l’explication des techniques d’assemblage pour confectionner les petits personnages et la mise en pratique ! La dernière étape sera la mise en situation de toutes les créations des participants dans une même scènette. L’atelier dure entre 1h et 1h30. Nous recommandons chaleureusement de faire cette activité entre générations, les enfants de moins de 8 ans doivent être accompagnés d’un parent. Quinze inscriptions maximum et chaque participant repartira avec sa création !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Lundi 30 décembre 14h30&nbsp;</strong><br>  <strong>Inscription obligatoire à l’accueil de la Maison ou au 05.62.92.38.38.&nbsp;</strong><br>  <strong>Tarif </strong>Offert sur inscription<br>  <strong>Public </strong>Tout public dès 6 ans<br>  <strong>Lieu </strong>Salle de réunion</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '299e5578-654d-4b82-9c2f-866b08a59b9b');
