INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Le secret des arbres" Compagnie Ici Théâtre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Spectacle \"Le secret des arbres\" Compagnie Ici Théâtre</strong><br>  Monsieur Gaspard, marchand de bois avare et égoïste, tient à raser la dernière forêt de la région, afin de s’enrichir davantage. Mais cette forêt appartient à une grand-mère démunie qui y puise gratuitement sa nourriture. Toudjik, son petit-fils, viendra lui prêter main forte pour lutter contre l’affreux marchand, et nous révèlera le secret des arbres ... Nous savons aujourd’hui que les arbres, par le biais de leurs racines, communiquent, s’entraident, et construisent un environnement bénéfique à chacun. Et si nous appliquions le principe à l’Humanité ? Le texte aborde notre capacité à vivre avec notre environnement, mais également les conditions de vie des plus démunis, l’entraide, la différence, tout autant que la solidarité intergénérationnelle.</p>  <p style=\"text-align: justify;\">Auteur&nbsp;:&nbsp;David Lesné<br>  Mise en scène et interprétation&nbsp;:&nbsp;Véronique Antolotti et David Lesné<br>  Musique&nbsp;:&nbsp;Julien Gonzalès</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Compagnie Ici Théâtre</strong><br>  Boulègue Production a pour mission, depuis 2002, de produire, diffuser, promouvoir et faire rayonner des spectacles de théâtres et des compagnies dans le département des Bouches du Rhône, la région SUD et sur le plan national. Elle a développé ses activités grâce à plusieurs spectacles qui ont connu un grand succès, tels que :&nbsp;Les Bonimenteurs, Ali au Pays des Merveilles, Peau d’Ane… Pour en savoir plus :&nbsp;https://www.boulegueproduction.com/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Lieu</strong> Salle de spectacle<br>  <strong>Public </strong>Tout public dès 6 ans<br>  <strong>Date </strong>Jeudi 02 janvier à 18h<br>  <strong>Tarif spectacle</strong> Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '33a86963-20d4-412c-be25-2f8aff902935');
