INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"DU SILENCE AU CONCERT" Cie Musique Acoustique Machine ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Du silence au concert\" de la&nbsp;Compagnie Musique Acoustique Machine - Intergénérationnel<br>  Partenariat avec le Parvis Scène Nationale de Tarbes Pyrénées</strong></p>  <p style=\"text-align: justify;\">Une exploration musicale et poétique mêlant sensations visuelles et auditives pour les tout-petits ! Redéfinissant l’univers du concert, Viviane Arnoux et François Michaud jouent avec le silence, des cubes et des boules lumineuses, et bien sûr leurs instruments respectifs : l’accordéon, le violon et l’alto. Du silence à la musique, de la pénombre à l’éclairage, dans un cheminement progressif les deux musiciens font découvrir aux enfants leurs compositions aux horizons contrastés et parsemées d’improvisations. Enfin, les petits seront invités à toucher, à jouer puis à danser à l’occasion d’un bal et goûter intergénérationnel ...</p>  <p style=\"text-align: justify;\"><strong>Distribution </strong>Accordéon et chant Viviane Arnoux, violon et alto François Michaud, création lumière et scénographie Sébastien Coppin, Frédéric Bourreau et Lucile Garric, regard extérieur et mise en espace Bérengère Altieri et Leca et Pauline Borras<br>  <strong>La&nbsp;Compagnie Musique Acoustique Machine </strong>https://musique-acoustique-machine.com/</p>  <p></p>  <p></p>  <p><strong>Tarif</strong> Abonnés Parvis&nbsp;et habitants de la vallée de Luz 8€, réduit 6€. Selon les places disponibles.<br>  <strong>Public </strong>Tout public dès 6 mois<br>  <strong>Lieu </strong>Forum de Luz-Saint-Sauveur</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '99670870-31f0-4615-a762-93fca2695ae5');
