INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('4eb90a0d-4a2a-44b0-806b-e184fda9c624', 'exposition', true, false, NULL, '2024-12-29T23:00:00.000Z', '2025-01-29T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2024-12-29T23:00:00.000Z', '2024-12-29T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Êtres de nature" - Sylvain Trabut', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Êtres de nature\" -&nbsp;Sylvain Trabut</strong><br>  https://sylvain-trabut.fr/</p>  <p style=\"text-align: justify;\">À partir d’éléments naturels, Sylvain Trabut&nbsp; confectionne des personnages ainsi que des décors. Il glane des petits trésors autour de chez lui et au cours de ses voyages. Ses créations sont fixes ou bien articulées. Il exposera les petits êtres durant le mois de janvier et vous propose un atelier.</p>  <p style=\"text-align: justify;\">J’ai grandi à la campagne, invité par la nature à venir l’observer de près. À ma naissance, mes parents ont planté un pin sylvestre. Mon frère végétal et moi avons le même âge, mais aujourd’hui sa cime dépasse de loin mes cheveux blancs.&nbsp;Enfant, pour observer la nature en « très petit », je louchais les yeux rivés sur de minuscules insectes. Les arbres étaient mon terrain de jeu principal. En grandissant j’ai continué à grimper dans les arbres, pour me recueillir quand j’avais besoin de prendre du recul.</p>  <p style=\"text-align: justify;\">Après un parcours artistique et créatif qui m’a emmené à travailler dans le jeu vidéo et l’illustration, je suis revenu auprès des arbres pour vivre de mon activité actuelle. Habité par ce petit univers que je développe. Aujourd’hui j’ai toujours la chance et l’occasion de monter aux arbres, agrippé aux branches enlacé à des écorces, pour récolter de précieuses ressources. Autant d’éléments que j’utilise, par la suite, pour créer des personnages. Je préfère autant que possible me perdre en forêt, parmi les branches et les mousses, plutôt que sur internet au milieu des intelligences artificielles et des algorithmes. Ce site et ma présence sur les réseaux sociaux c’est avant tout pour établir un contact, car pour cela c’est un outil formidable. J’aspire, à être le moins présent possible derrière un écran</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4eb90a0d-4a2a-44b0-806b-e184fda9c624');
