INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Le secret des arbres" - Compagnie Ici Théâtre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Le secret des arbres\" de la Compagnie Ici Théâtre - Théâtre jeunesse</strong></p>  <p style=\"text-align: justify;\">Monsieur Gaspard, marchand de bois avare et égoïste, tient à raser la dernière forêt de la région, afin de s’enrichir davantage. Mais cette forêt appartient à une grand-mère démunie qui y puise gratuitement sa nourriture. Toudjik, son petit-fils, viendra lui prêter main forte pour lutter contre l’affreux marchand et nous révèlera le secret des arbres ...&nbsp;</p>  <p style=\"text-align: justify;\">Nous savons aujourd’hui que les arbres, par le biais de leurs racines, communiquent, s’entraident et construisent un environnement bénéfique à chacun. Et si nous appliquions le principe à l’Humanité ? Le texte aborde notre capacité à vivre avec notre environnement, mais également les conditions de vie des plus démunis, l’entraide, la différence, tout autant que la solidarité intergénérationnelle.</p>  <p></p>  <p><strong>Distribution</strong> Auteur David Lesné, mise en scène et interprétation Véronique Antolotti et David Lesné, musique Julien Gonzalès<br>  <strong>La&nbsp;Compagnie Ici Théâtre&nbsp;</strong>http://ici.theatre.free.fr/lesecretdesarbres.html</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Normal&nbsp;10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;<br>  <strong>Public&nbsp;</strong>Tout public dès 5 ans<br>  <strong>Lieu&nbsp;</strong>Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '71ef8af0-5f5e-483d-ba21-e3be2407acfb');
