INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('cde6d095-73d1-4fcb-ae95-a78752136e3e', 'residence', true, false, false, NULL, '2025-01-26T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2025-01-26T23:00:00.000Z', '2025-01-26T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('En dessous - Compagnie De La Tong', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Sortie de résidence \"En dessous\" - Compagnie De La Tong&nbsp;- Théâtre jeunesse</strong></p>  <p style=\"text-align: justify;\">Les plantes communiquent entre elles, se parlent, se réconfortent et se protègent. Elles envoient des messages par un réseau de connexions vivantes complexes et surprenantes. Si on regardait en dessous,&nbsp; si on essayait de parler «arbre » et d‘imaginer ce qui se passe sous terre. Au travers de ce spectacle, l’équipe artistique invite les jeunes enfant, à visiter le monde méconnu d’En dessous, dans un décor de matières variées, tissu et vannerie sauvage, à travers le mouvement, la danse, la musique et le son et des projections vidéos. Selon un point de vue tour à tour végétal, animal ou humain, les jeunes spectateurs pourront s’identifier à ces personnages et à leurs modes de communication : comment se défendre, comment s’entraider... Comment ça marche ?</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Distribution</strong> &nbsp;Maya Paquereau, Sophie Barros<br>  <strong>Compagnie De La Tong&nbsp;</strong>https://www.compagniedelatong.com/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Sortie de résidence </strong>Vendredi 31 janvier à 18h30<br>  <strong>Tarif&nbsp;&nbsp;</strong>Offert<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'cde6d095-73d1-4fcb-ae95-a78752136e3e');
