INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Les bergères" Journées du Matrimoine', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Thématique \"Les bergères\"</strong><br>  La Maison du Parc national et de la vallée vous propose une programmation sur la thématique \"Les bergères\" dans le cadre des&nbsp;Journées du Matrimoine.</p>  <p style=\"text-align: justify;\"><strong>Les journées du Matrimoine</strong><br>  https://www.lematrimoine.fr/les-journees-du-matrimoine/<br>  Créées en 2015 à l’initiative de l’association HF Île-de-France, les Journées du Matrimoine font écho aux Journées du Patrimoine pour faire émerger « l’héritage des mères » et rendre visibles leurs œuvres. Elles se déroulent chaque année au cours du week-end de la 3ème semaine de septembre. Les journées du Matrimoine ambitionnent de faire connaître et de rendre visibles les femmes du passé, par le biais d’une programmation culturelle variée. Parcours, visites, expositions, installations, spectacles, performances, concerts, conférences, lectures, projections…. de nombreux événements sont proposés gratuitement au public tout au long du week-end. Les journées du Matrimoine s’adressent à un public large, de tous âges.</p>  <p style=\"text-align: justify;\"><strong>La programmation</strong></p>  <p style=\"text-align: justify;\"><strong>Exposition \"Paroles de bergères\" -&nbsp;Du&nbsp;02&nbsp;au&nbsp;29 septembre</strong><br>  Durant les dernières décennies, le métier de berger est en pleine mutation et s’écrit au féminin. On ne cesse de voir des femmes arriver dans les estives et devenir chefs d’exploitation.&nbsp;&nbsp;Les témoignages de bergères&nbsp;vous feront découvrir ces femmes à travers les générations. L’exposition « Paroles de bergères » est proposée par le Pays d’art et d’histoire des Pyrénées Béarnaises et illustrée par les photographies de l’artiste Amanda Meunier. Cette programmation s’inscrit dans le cadre des Journées du matrimoine.</p>  <p style=\"text-align: justify;\"><strong>Table de lecture \"Les bergères\" -&nbsp;Du 01 au 30 septembre</strong><br>  La table de lecture de septembre s''accorde avec la thématique de la Maison pour les Journées du Matrimoine : \"Les Bergères\". Notre sélection met en lumière les femmes qui écrivent ou vivent la montagne. Retrouvez des récits de bergères ou encore des ouvrages de passionnées à l''étage de la médiathèque. Durant le mois de septembre découvrez une exposition ainsi qu''une programmation cinéma sur ce même thème.</p>  <p style=\"text-align: justify;\"><strong>Projection-Rencontre \"Des brebis et des femmes\" Laurence Fleury - J</strong><time datetime=\"2024-09-19\"><strong>eudi 19 septembre&nbsp;à 20h30</strong></time><br>  Le métier de berger s’est beaucoup féminisé, au point qu’aujourd’hui en Béarn, un tiers des cabanes pastorales est occupé par des femmes. Le film de Laurence Fleury suit pendant plusieurs mois la vie et le parcours de six de ces bergères durant toute la période d’estive jusqu’à l’automne. La journaliste s’efface volontairement et laisse s’exprimer ses interlocutrices qui expliquent leur choix de vie, les difficultés à se faire accepter dans ce milieu jusque-là très masculin et les problèmes liés à l’installation et la transmission. Lors de cette projection, venez rencontrer la réalisatrice Laurence Fleury pour échanger sur son travail. Cet événement fait partie de la programmation de septembre intitulée «Les bergères» dans le cadre des Journées du Matrimoine. Retrouvez une exposition, une table de lecture ainsi que d’autres projections sur ce thème.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9ec38672-ba0a-47ae-a70b-acc1c384f02d');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Les bergères" Journées du Matrimoine', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Thématique \"Les bergères\"</strong><br>  La Maison du Parc national et de la vallée vous propose une programmation sur la thématique \"Les bergères\" dans le cadre des&nbsp;Journées du Matrimoine.</p>  <p style=\"text-align: justify;\"><strong>Les journées du Matrimoine</strong><br>  https://www.lematrimoine.fr/les-journees-du-matrimoine/<br>  Créées en 2015 à l’initiative de l’association HF Île-de-France, les Journées du Matrimoine font écho aux Journées du Patrimoine pour faire émerger « l’héritage des mères » et rendre visibles leurs œuvres. Elles se déroulent chaque année au cours du week-end de la 3ème semaine de septembre. Les journées du Matrimoine ambitionnent de faire connaître et de rendre visibles les femmes du passé, par le biais d’une programmation culturelle variée. Parcours, visites, expositions, installations, spectacles, performances, concerts, conférences, lectures, projections…. de nombreux événements sont proposés gratuitement au public tout au long du week-end. Les journées du Matrimoine s’adressent à un public large, de tous âges.</p>  <p style=\"text-align: justify;\"><strong>La programmation</strong></p>  <p style=\"text-align: justify;\"><strong>Exposition \"Paroles de bergères\" -&nbsp;Du&nbsp;02&nbsp;au&nbsp;29 septembre</strong><br>  Durant les dernières décennies, le métier de berger est en pleine mutation et s’écrit au féminin. On ne cesse de voir des femmes arriver dans les estives et devenir chefs d’exploitation.&nbsp;&nbsp;Les témoignages de bergères&nbsp;vous feront découvrir ces femmes à travers les générations. L’exposition « Paroles de bergères » est proposée par le Pays d’art et d’histoire des Pyrénées Béarnaises et illustrée par les photographies de l’artiste Amanda Meunier. Cette programmation s’inscrit dans le cadre des Journées du matrimoine.</p>  <p style=\"text-align: justify;\"><strong>Table de lecture \"Les bergères\" -&nbsp;Du 01 au 30 septembre</strong><br>  La table de lecture de septembre s''accorde avec la thématique de la Maison pour les Journées du Matrimoine : \"Les Bergères\". Notre sélection met en lumière les femmes qui écrivent ou vivent la montagne. Retrouvez des récits de bergères ou encore des ouvrages de passionnées à l''étage de la médiathèque. Durant le mois de septembre découvrez une exposition ainsi qu''une programmation cinéma sur ce même thème.</p>  <p style=\"text-align: justify;\"><strong>Projection-Rencontre \"Des brebis et des femmes\" Laurence Fleury - J</strong><time datetime=\"2024-09-19\"><strong>eudi 19 septembre&nbsp;à 20h30</strong></time><br>  Le métier de berger s’est beaucoup féminisé, au point qu’aujourd’hui en Béarn, un tiers des cabanes pastorales est occupé par des femmes. Le film de Laurence Fleury suit pendant plusieurs mois la vie et le parcours de six de ces bergères durant toute la période d’estive jusqu’à l’automne. La journaliste s’efface volontairement et laisse s’exprimer ses interlocutrices qui expliquent leur choix de vie, les difficultés à se faire accepter dans ce milieu jusque-là très masculin et les problèmes liés à l’installation et la transmission. Lors de cette projection, venez rencontrer la réalisatrice Laurence Fleury pour échanger sur son travail. Cet événement fait partie de la programmation de septembre intitulée «Les bergères» dans le cadre des Journées du Matrimoine. Retrouvez une exposition, une table de lecture ainsi que d’autres projections sur ce thème.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><br>  &nbsp;</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '9ec38672-ba0a-47ae-a70b-acc1c384f02d');
