INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('85b2f376-b076-40fa-9ac5-24f0ccd68f41', 'evenement', true, false, true, NULL, '2024-02-02T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2024-02-02T23:00:00.000Z', '2024-02-02T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Soon" Cie Le Club Dramatique', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Soon\" de la&nbsp;Compagnie Le Club dramatique<br>  Partenariat avec le Parvis Scène Nationale de Tarbes Pyrénées</strong></p>  <p style=\"text-align: justify;\">Comment le numérique s’est installé dans nos vies de façon extrêmement intime? Quels bouleversements cette révolution technologique induit dans nos relations aux autres ? Simon Le Floc’h et Mélanie Vayssettes mettent en lumière une solitude contemporaine face au numérique.&nbsp;Soon, ce sont des moments de la vie de Simon, un personnage qui vit seul dans un petit appartement et qui réalise des vidéos artistiques. Il aime chanter, être en lien avec les autres et inventer des dispositifs poétiques pour son public. Il ne sort jamais, il n’en a peut-être plus besoin. Un soir qu’il est en train de performer sur internet, sa connexion est coupée. Ce spectacle – inspiré du phénomène japonais des&nbsp;Hikikomori&nbsp;– rend sensible une forme de solitude contemporaine, un nouveau rapport aux autres et à soi, dans un monde où la technologie nous protège, nous parle, nous rassure mais finit par nous asservir.</p>  <p style=\"text-align: justify;\"><strong>Distribution</strong> acteur&nbsp;Simon Le Floc’h,&nbsp;mise en scène&nbsp;Mélanie Vayssettes,&nbsp;texte&nbsp;Julien Barthe, Simon Le Floc’h et Mélanie Vayssettes,&nbsp;regard extérieur&nbsp;Morgane Nagir,&nbsp;scénographie/costumes&nbsp;Elsa Séguier-Faucher,&nbsp;lumière&nbsp;Artur Canillas / Marylou Bateau,&nbsp;son&nbsp;Thomas Juvé / François Rivère<br>  <strong>La&nbsp;Compagnie Le Club Dramatique&nbsp;</strong>https://leclubdramatique.fr</p>  <p></p>  <p><strong>Tarif</strong> Abonnés Parvis&nbsp;et habitants de la vallée de Luz 8€, réduit 6€. Selon les places disponibles.<br>  <strong>Public </strong>Tout public dès 12&nbsp;ans<br>  <strong>Lieu </strong>Salle de spectacle&nbsp;de Luz-Saint-Sauveur</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '85b2f376-b076-40fa-9ac5-24f0ccd68f41');
