INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Soon" Compagnie Le Club Dramatique', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Soon\" de la&nbsp;Compagnie Le Club dramatique<br>  Partenariat avec le Parvis Scène Nationale de Tarbes Pyrénées</strong></p>  <p style=\"text-align: justify;\">Comment le numérique s’est installé dans nos vies de façon extrêmement intime? Quels bouleversements cette révolution technologique induit dans nos relations aux autres ? Simon Le Floc’h et Mélanie Vayssettes mettent en lumière une solitude contemporaine face au numérique.&nbsp;Soon, ce sont des moments de la vie de Simon, un personnage qui vit seul dans un petit appartement et qui réalise des vidéos artistiques. Il aime chanter, être en lien avec les autres et inventer des dispositifs poétiques pour son public. Il ne sort jamais, il n’en a peut-être plus besoin. Un soir qu’il est en train de performer sur internet, sa connexion est coupée. Ce spectacle – inspiré du phénomène japonais des&nbsp;Hikikomori&nbsp;– rend sensible une forme de solitude contemporaine, un nouveau rapport aux autres et à soi, dans un monde où la technologie nous protège, nous parle, nous rassure mais finit par nous asservir.</p>  <p style=\"text-align: justify;\"><strong>Distribution</strong> acteur&nbsp;Simon Le Floc’h,&nbsp;mise en scène&nbsp;Mélanie Vayssettes,&nbsp;texte&nbsp;Julien Barthe, Simon Le Floc’h et Mélanie Vayssettes,&nbsp;regard extérieur&nbsp;Morgane Nagir,&nbsp;scénographie/costumes&nbsp;Elsa Séguier-Faucher,&nbsp;lumière&nbsp;Artur Canillas / Marylou Bateau,&nbsp;son&nbsp;Thomas Juvé / François Rivère</p>  <p><strong>La&nbsp;Compagnie Le Club Dramatique&nbsp;</strong>https://leclubdramatique.fr</p>  <p></p>  <p><strong>Tarif</strong> Abonnés Parvis&nbsp;et habitants de la vallée de Luz 8€, réduit 6€. Selon les places disponibles.<br>  <strong>Public </strong>Tout public dès 12&nbsp;ans<br>  <strong>Lieu </strong>Salle de spectacle&nbsp;de Luz-Saint-Sauveur</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'a2d56c8f-5113-4404-92db-de38b43380fd');
INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('ff8b3f0e-6f3f-4ace-9639-6502c92dfbca', 'evenement', true, false, false, NULL, '2025-02-11T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2025-02-11T23:00:00.000Z', '2025-02-11T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"FAILLES" Compagnie La Féroce', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>Spectacle \"Failles\" - Théâtre circassien,&nbsp;</b><strong>Création circassienne pour deux fil-de-féristes</strong></p>  <p style=\"text-align: justify;\">“Ils sont deux. une cordée. À plus de 3000 m d’altitude, les lignes de failles découpent les montagnes devant eux. Elles sont inscrites dans le rocher. Elles sont aussi inscrites dans leur vie, dans leur passé comme dans leur présent. Là haut, on découvrira ce qui s’est joué entre eux, face au vide, face à l’euphorie de l’altitude, face à l’ivresse des sommets et au plaisir de la grimpe. Motivés par leur passion commune, jusqu''où iront-ils dans l''absurde, la solitude, l''amitié ?” Ce second opus fait suite au travail débuté avec \"Faces Nord\" en juillet 2022. Il explore à travers l’univers unique de l’alpinisme, le rapport des hommes et des femmes face aux sommets, quand l’humain est confronté au monde hostile de la montagne. La discipline circassienne, le clown et le théâtre sont ici mêlés à une scénographie, où les décors comme les agrès sont fabriqués à partir d’équipements de montagne ou de matières minérales.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong> Écriture, dramaturgie&nbsp;Laurette Gougeon, cirque, jeu, peinture&nbsp;Laurette Gougeon, Loic Leviel, scénographie&nbsp;Anaïs Blanchard et Laurette Gougeon, création musicale&nbsp;Alice Huc, regard complice en jeu d''acteur Maelle Mays, regard extérieur&nbsp;Manon Delage, intervenant technique Yannick Lataste, Loïc Lavault, production Gitanjali Picovschi<br>  <strong>Compagnie La Féroca&nbsp;</strong>https://www.laferoce.net/--propos</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif </strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public dès 8 ans<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ff8b3f0e-6f3f-4ace-9639-6502c92dfbca');
