INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('e65a6895-ab1e-4aa1-b028-c7a219feda39', 'exposition', true, false, NULL, '2025-02-03T23:00:00.000Z', '2025-02-26T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2025-02-03T23:00:00.000Z', '2025-02-03T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Origami Sauvage" - Jonathan Rebouillat', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Origami Sauvage\" -&nbsp;Jonathan Rebouillat</strong><br>  https://jonathanrebouillat.com/</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">\"Quelques plis, beaucoup de courbes. Suggérer plutôt que dévoiler. Je joue avec le papier et l’eau pour rendre un hommage infini à la beauté du monde.\" Jonathan</p>  <p style=\"text-align: justify;\">Jonathan Rebouillat a d’abord suivi des études d’ingénieur malgré son aspiration initiale à devenir poète. Cependant, une prise de conscience face aux problématiques écologiques et un séjour marquant en Amazonie l’ont poussé vers un mode de vie plus simple, militant et respectueux de la nature. En voyageant à vélo et en vivant dans des écolieux, il découvre l’origami, une forme d’art lui permettant de rendre hommage à la nature et aux oiseaux. Jonathan&nbsp;intègre ses œuvres dans l''habitat naturel de ses sujets, créant des photographies&nbsp;qui célèbrent la beauté du monde sauvage. En utilisant l’origami comme expression artistique, il sensibilise le public aux enjeux écologiques et à l’importance de rétablir des liens harmonieux avec le vivant.</p>  <p style=\"text-align: justify;\">Jonathan Rebouillat réside non loin d’ici, dans la vallée de Lesponne, proche de Bagnères de Bigorre. Il expose ses œuvres dans la Maison&nbsp;en février ! Si son univers résonne avec votre sensibilité et vos valeurs, vous aurez l’occasion de prolonger cette immersion artistique lors d’un atelier et d’une conférence, pour explorer davantage sa vision et son approche du monde sauvage par l''origami.</p>  <p></p>  <p></p>  <p style=\"text-align: justify;\"><strong>Jeudi 27 février</strong><br>  14h30 - Atelier, offert, pour plus d''informations :&nbsp;<br>  https://www.maisondelavallee.org/atelier-origami-sauvage-jonathan-rebouillat<br>  18h - Conférence, offerte, pour plus d''informations :&nbsp;<br>  https://www.maisondelavallee.org/conference-origami-sauvage-jonathan-rebouillat</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'e65a6895-ab1e-4aa1-b028-c7a219feda39');
