INSERT INTO parc_national (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('f0941f1e-f1d4-4bdf-96c8-61a02e98962c', 'evenement', true, false, false, NULL, '2025-02-26T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2025-02-26T23:00:00.000Z', '2025-02-26T23:00:00.000Z');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Origami Sauvage" - Jonathan Rebouillat', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Conférence \"Origami Sauvage\" :&nbsp;</strong><b>Venez découvrir la magie de l''origami !</b></p>  <p></p>  <p style=\"text-align: justify;\">L''artiste Jonathan Rebouillat propose une conférence pour découvrir les coulisses de la création de ses origamis.<br>  Tout commence dans la forêt, jumelles autour du cou, avec l’émotion d’une rencontre sauvage. Mais ensuite, comment traduire cette émotion en plis ? Quelles sont les règles de cet art si particulier de l’origami ? Cet art traditionnel est d’origine japonaise et consiste à transformer une feuille carrée en figures diverses sans découpage ni collage. À travers une série de plis minutieux, on peut créer des formes allant des animaux aux motifs abstraits. Ouvrons la porte sur l’atelier de Jonathan. Par quelles étapes passe t-il ? Combien de tentatives infructueuses ?Comment cherche t-il dans un morceau de papier, en quelques plis, l’essence de chaque animal ? Venez avec votre curiosité et vos questions à la conférence que donnera Jonathan Rebouillat à la Maison du Parc.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Pour en savoir plus sur l''artiste :&nbsp;</strong>https://jonathanrebouillat.com/</p>  <p style=\"text-align: justify;\">Jonathan Rebouillat a d’abord suivi des études d’ingénieur malgré son aspiration initiale à devenir poète. Cependant, une prise de conscience face aux problématiques écologiques et un séjour marquant en Amazonie l’ont poussé vers un mode de vie plus simple, militant et respectueux de la nature. En voyageant à vélo et en vivant dans des écolieux, il découvre l’origami, une forme d’art lui permettant de rendre hommage à la nature et aux oiseaux. Jonathan&nbsp;intègre ses œuvres dans l''habitat naturel de ses sujets, créant des photographies&nbsp;qui célèbrent la beauté du monde sauvage. En utilisant l’origami comme expression artistique, il sensibilise le public aux enjeux écologiques et à l’importance de rétablir des liens harmonieux avec le vivant.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Jeudi 27 février à 18h</strong><br>  Tarif : Offert<br>  Durée : 1h<br>  Public :&nbsp;&nbsp;Tout public<br>  Lieu : Salle de spectacle<br>  &nbsp;</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f0941f1e-f1d4-4bdf-96c8-61a02e98962c');
