INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('be9e6b91-6c5c-4270-baf4-5e31f53469bc', 'evenement', true, false, true, NULL, '2025-02-12T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2025-02-12T23:00:00.000Z', '2025-02-12T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"1,2,3 Savane" Ladji Diallo', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>Spectacle \"1,2,3 Savane\" - Théâtre jeunesse</b></p>  <p>Les bruits courent dans la savane. Des voix d’hommes et d’animaux résonnent.<br>  Les arbres, les grandes herbes, le vent, la rivière, tout parle.<br>  Ça siffle, ça chante, ça marche, ça s’agite. Le cœur des pierres brille, Dieu se fait entendre.<br>  1, 2, 3 Savane, le singe fait des pirouettes et se vante&nbsp;: «&nbsp;je serai le maître d’ici-bas&nbsp;!&nbsp;».<br>  1, 2, 3 Savane, le lion&nbsp;a les crocs, gare à celui qui croisera sa route.<br>  1, 2, 3 Savane, qui portera le plus beau pagne&nbsp;à la fête de Moussa ?<br>  1, 2, 3 Savane, tous les chemins mènent à la savane&nbsp;!</p>  <p></p>  <p style=\"text-align: justify;\">Puisant dans les traditions africaines, avec des lions majestueux, des esprits mystérieux, la vaste savane et Moussa mis à l’honneur, Ladji Diallo sait captiver l’imaginaire des enfants du monde entier. Il leur&nbsp;livre&nbsp;des récits hauts en couleurs, où les animaux dialoguent, où les petits défient les puissants avec succès, et où, malgré des épreuves qui paraissent insurmontables, tout se termine toujours de manière heureuse !</p>  <p style=\"text-align: justify;\"><br>  <strong>Distribution : </strong>Comédien, conteur, chanteur Ladji Diallo.&nbsp;Crédit photo : Léo Duquette<br>  <strong>Compagnie :</strong>&nbsp;La Divine Fabrique&nbsp;https://www.ladjidiallo.com/accueil/&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif </strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public dès 7&nbsp;ans<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'be9e6b91-6c5c-4270-baf4-5e31f53469bc');
