INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"L''Odyssée d''Ayouk" Vis-à-vis Théâtre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>Spectacle et atelier \"L''Odysée d''Ayouk\" - Théâtre&nbsp;</b><strong>des Matières et de Récup''</strong><br>  La veille du spectacle, participez à l''atelier \"Récup'' ton spectacle\", le mardi 18 février&nbsp;à 18h. Pour plus d''informations :&nbsp;https://www.maisondelavallee.org/atelier-recup-ton-spectacle-vis-vis-theatre</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><em>L’Odyssée d’Ayouk</em> raconte l’histoire d’un village côtier confronté à la colère de la Reine des océans après la capture d’Aziz, son fils, par des pêcheurs. Ayouk, une enfant rejetée pour son pouvoir de parler aux créatures marines, se lance dans une quête pour sauver le village et réconcilier son peuple avec la nature.</p>  <p style=\"text-align: justify;\">La matière plastique sert de point de départ créatif pour donner vie au texte de Natalie Quintart, en offrant une relecture imaginative de cette matière, symbole de la société de consommation. Cette fable aborde les thèmes de la surconsommation, de la différence et de la cohabitation avec le vivant, invitant à imaginer un monde plus respectueux et inclusif, porté par l’espoir et la détermination de l’enfance. Le spectacle, une adaptation théâtrale et marionnettique du conte contemporain <em>Ayouk et Aziz</em>, joue avec la matière plastique pour créer des univers visuels, drôles et poétiques. Avec un désir de faire beaucoup avec peu, il détourne cette matière du quotidien pour inviter à la rêver et à la réinventer.</p>  <p style=\"text-align: justify;\"><br>  <strong>Distribution : </strong>Acteurs&nbsp;Luna de Lamotte, Clémentine Michel, regard extérieur&nbsp;Guillaume Carrignon et Aurélie Lepoutre, aide à l''écriture&nbsp;Natalie Quintar, regard marionnette François&nbsp;Salon, musique&nbsp;Luna de Lamotte, création lumière Julien Lécutier, création marionettes&nbsp;Luna de Lamotte,&nbsp; Clémentine Michel, diffusion Natalie Quintart</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie :</strong>&nbsp;Vis-à-vis Théâtre&nbsp;https://www.visavistheatre.com/<br>  La compagnie Vis-A-Vis théâtre est basée à&nbsp;lille. la recherche autour des matières brutes et le désir de proposer au jeune public des espaces de liberté, d''expérimentation et de contemplation, forgent l''identité artistique de la compagnie&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif spectacle&nbsp;</strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public dès 5&nbsp;ans<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9ca28a82-96e8-404a-aec4-f28b9f412b7e');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"L''Odyssée d''Ayouk" Vis-à-vis Théâtre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>Spectacle et atelier \"L''Odysée d''Ayouk\" - Théâtre&nbsp;</b><strong>des Matières et de Récup''</strong><br>  La veille du spectacle, participez à l''atelier \"Récup'' ton spectacle\", le mardi 18 février&nbsp;à 18h. Pour plus d''informations :&nbsp;https://www.maisondelavallee.org/atelier-recup-ton-spectacle-vis-vis-theatre</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><em>L’Odyssée d’Ayouk</em> raconte l’histoire d’un village côtier confronté à la colère de la Reine des océans après la capture d’Aziz, son fils, par des pêcheurs. Ayouk, une enfant rejetée pour son pouvoir de parler aux créatures marines, se lance dans une quête pour sauver le village et réconcilier son peuple avec la nature.</p>  <p style=\"text-align: justify;\">La matière plastique sert de point de départ créatif pour donner vie au texte de Natalie Quintart, en offrant une relecture imaginative de cette matière, symbole de la société de consommation. Cette fable aborde les thèmes de la surconsommation, de la différence et de la cohabitation avec le vivant, invitant à imaginer un monde plus respectueux et inclusif, porté par l’espoir et la détermination de l’enfance. Le spectacle, une adaptation théâtrale et marionnettique du conte contemporain <em>Ayouk et Aziz</em>, joue avec la matière plastique pour créer des univers visuels, drôles et poétiques. Avec un désir de faire beaucoup avec peu, il détourne cette matière du quotidien pour inviter à la rêver et à la réinventer.</p>  <p style=\"text-align: justify;\"><br>  <strong>Distribution : </strong>Acteurs&nbsp;Luna de Lamotte, Clémentine Michel, regard extérieur&nbsp;Guillaume Carrignon et Aurélie Lepoutre, aide à l''écriture&nbsp;Natalie Quintar, regard marionnette François&nbsp;Salon, musique&nbsp;Luna de Lamotte, création lumière Julien Lécutier, création marionettes&nbsp;Luna de Lamotte,&nbsp; Clémentine Michel, diffusion Natalie Quintart</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie :</strong>&nbsp;Vis-à-vis Théâtre&nbsp;https://www.visavistheatre.com/<br>  La compagnie Vis-A-Vis théâtre est basée à&nbsp;lille. la recherche autour des matières brutes et le désir de proposer au jeune public des espaces de liberté, d''expérimentation et de contemplation, forgent l''identité artistique de la compagnie&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif spectacle&nbsp;</strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public dès 5&nbsp;ans<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '9ca28a82-96e8-404a-aec4-f28b9f412b7e');
