INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Atelier "Récup'' ton spectacle" Vis-à-vis Théâtre', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>Atelier \"L''Odysée d''Ayouk\" - Théâtre&nbsp;</b><strong>des Matières et de Récup''</strong></p>  <p style=\"text-align: justify;\">Inscription obligatoire à l’accueil de la Maison ou au 05.62.92.38.38. Chaque participant doit apporter un contenant en plastique avec un pull ou un gilet. Cet atelier est en lien avec la programmation du spectacle L’Odysée d’Ayouk qui aura lieu&nbsp;le mercredi 19&nbsp;février&nbsp;à 18h30. Pour plus d''informations :&nbsp;https://www.maisondelavallee.org/lodyssee-dayouk-vis-vis-theatre</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Tout objet peut devenir marionnettique. L''atelier est destiné à faire le pont entre les objets et matières du quotidien et leur utilisation marionnettique. L’atelier commence par une initiation aux techniques propres à la marionnette. Ensuite, nous amenons les participant⋅e⋅s à appliquer ces techniques à des objets du quotidien. Un sac poubelle, un arrosoir, un tuyau peut devenir une marionnette dès lors que l’on sait comment le manipuler. Une fois que l’objet est devenu marionnette, on peut jouer entre la symbolique propre à l’objet d’origine et sa nouvelle fonction marionnettique. Les participant⋅e⋅s feront l’expérience de ces paradoxes et pourront ensuite faire vivre leurs marionnettes, provoquer des rencontres entre les différents objets marionnettique. Des univers décalés et poétiques apparaîtront.&nbsp;</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie :</strong>&nbsp;Vis-à-vis Théâtre&nbsp;https://www.visavistheatre.com/<br>  La compagnie Vis-A-Vis théâtre est basée à&nbsp;lille. la recherche autour des matières brutes et le désir de proposer au jeune public des espaces de liberté, d''expérimentation et de contemplation, forgent l''identité artistique de la compagnie&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p>  <p style=\"text-align: justify;\"><br>  <strong>Tarif atelier </strong>Offert<br>  <strong>Public</strong> Tout public dès 5&nbsp;ans<br>  <strong>Lieu</strong>&nbsp;Salle de réunion</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd06da8ec-66e2-41ea-9068-6e754dc283fc');
