INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Apéro-Concert "Cocanha" Compagnie Dardalh', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>L''apéro-concert \"Cocanha\" Compagnie Dardalh - Polyphonie&nbsp;occitane</b><br>  Dans un Etat français centraliste au passé colonial prégnant, taisant les langues qui l’habitent et formatant les accents, Cocanha choisit de chanter en occitan.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les deux voix singulières de Caroline Dufau et Lila Fraysse se mêlent dans une polyphonie hypnotique portée par la pulsation des tambourins à cordes, des pieds et des mains. Dans ce face-à-face percutant, les deux musiciennes livrent leurs personnalités vocales complémentaires, tressées par 12 ans de complicité artistique. Cocanha cultive le minimalisme et s’inscrit dans l’esthétique des musiques amplifiées, engageant les corps dans la danse. Les deux musiciennes puisent dans le répertoire traditionnel occitan, remettent en mouvement des archives et les replacent dans le fil de l’oralité. Certaines paroles sont réécrites, d’autres inventées, émanant d’un imaginaire commun à ciel ouvert. Les personnages féminins des chansons se réapproprient leur puissance désirante et l’affirment.</p>  <p style=\"text-align: justify;\"><br>  <strong>Distribution : </strong>Caroline Dufau et Lila Fraysse. Crédit photo :&nbsp;Amic Bedel</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie :</strong>&nbsp;Dardalh https://cocanha.net/qual-sem/&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif spectacle&nbsp;</strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public<br>  <strong>Lieu</strong>&nbsp;Salle des voûtes, buvette sur place</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '26e432e4-e03c-44b6-a899-866967c7e1e7');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Apéro-Concert "Cocanha" Compagnie Dardalh', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>L''apéro-concert \"Cocanha\" Compagnie Dardalh - Polyphonie&nbsp;occitane</b><br>  Dans un Etat français centraliste au passé colonial prégnant, taisant les langues qui l’habitent et formatant les accents, Cocanha choisit de chanter en occitan.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les deux voix singulières de Caroline Dufau et Lila Fraysse se mêlent dans une polyphonie hypnotique portée par la pulsation des tambourins à cordes, des pieds et des mains. Dans ce face-à-face percutant, les deux musiciennes livrent leurs personnalités vocales complémentaires, tressées par 12 ans de complicité artistique. Cocanha cultive le minimalisme et s’inscrit dans l’esthétique des musiques amplifiées, engageant les corps dans la danse. Les deux musiciennes puisent dans le répertoire traditionnel occitan, remettent en mouvement des archives et les replacent dans le fil de l’oralité. Certaines paroles sont réécrites, d’autres inventées, émanant d’un imaginaire commun à ciel ouvert. Les personnages féminins des chansons se réapproprient leur puissance désirante et l’affirment.</p>  <p style=\"text-align: justify;\"><br>  <strong>Distribution : </strong>Caroline Dufau et Lila Fraysse. Crédit photo :&nbsp;Amic Bedel</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie :</strong>&nbsp;Dardalh https://cocanha.net/qual-sem/&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif spectacle&nbsp;</strong>Normal (à partir de 14 ans) 10€ Réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€&nbsp;Offert (pour les moins de 3 ans)<br>  <strong>Public</strong> Tout public<br>  <strong>Lieu</strong>&nbsp;Salle des voûtes, buvette sur place</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '26e432e4-e03c-44b6-a899-866967c7e1e7');
