lic<br>  <strong>Lieu</strong>&nbsp;Salle des voûtes, buvette sur place</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '26e432e4-e03c-44b6-a899-866967c7e1e7');
