INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Carnaval', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Venez célébrer le Carnaval à Luz-Saint-Sauveur avec Filibusters, la fanfare pirate !&nbsp;</strong><br>  Les rues du village s''empliront de joie et de musique ce mardi 04 mars&nbsp;à l''occasion du grand Carnaval ! Préparez-vous à vibrer au rythme entraînant de la fanfare en déambulation Filibusters, qui promet de mettre une ambiance festive et inoubliable !&nbsp;Rendez-vous&nbsp;en costumes pour partager un moment convivial et haut en couleurs au départ de l''Office de tourisme de Luz-Saint-Sauveur. Un concert des Filibusters aura aussi lieu sur le front de neige de la station de ski de Luz-Ardiden dans l''après-midi.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Pour en savoir plus sur la fanfare Filibuster :&nbsp;</strong>https://www.filibusters.fr/<br>  Avec leur esprit de pirates, les Filibusters bousculent les codes des fanfares traditionnelles. Tantôt enracinée dans l''énergie festive de la New-Orleans, tantôt imprégnée des vagues audacieuses de la Surf Music, cette fanfare à géométrie variable propose des prestations aussi bien en statique qu’en déambulation.&nbsp;Avec une énergie débordante, ils sabordent les conventions des cuivres classiques pour nous entraîner dans une traversée en eaux troubles, mêlant funk puissant et rock déchaîné. Préparez-vous à affronter une tempête sonore et à danser au rythme d’un funk’n’roll endiablé qui ne laisse personne indifférent !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Mardi 04 mars&nbsp;<br>  Départ de la déambulation de l''Office de tourisme de Luz-Saint-Sauveur&nbsp;à 18h</strong><br>  Tarif : Offert<br>  Public :&nbsp;Tout public<br>  Lieu : Rues de Luz-Saint-Sauveur</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'dbe57fe3-c209-4b4d-b5b5-aca6482be810');
