INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les voyages de Peer Gynt - Les cadets', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Le voyage de Peer Gynt\"&nbsp;Philippe Estèphe -&nbsp;Les Cadets compagnie lyrique - Conte musical</strong><br>  À partir du monument de la culture norvégienne, Les Cadets proposent une adaptation de&nbsp;Peer Gynt&nbsp;sous la forme d’un concert conté, interactif et familial dans une version originale pour récitant, baryton, soprano et accordéon.&nbsp;Tout le monde connaît la musique de&nbsp;Peer Gynt&nbsp;sans le savoir, tant ses thèmes musicaux sont passés dans la culture populaire. Ce conte initiatique suit les mensonges et voyages d’un anti-héros, Peer Gynt, jeune norvégien qui ne peut s’empêcher de raconter des histoires et de s’inventer des vies, fuyant toujours plus loin les conséquences de ses actes.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Pour en savoir plus sur la compagnie Les Cadets :&nbsp;</strong>https://www.nma32.com/la-compagnie-des-cadets/spectacles-en-diffusion/voyages-peer-gynt<br>  La compagnie des Cadets a pour vocation de créer de nouvelles formes lyriques et de mettre cet art au service de tous les publics. Constitués d''artistes évoluant sur les scènes nationales et ayant grandi au sein des Nuits Musicales en Armagnac, les Cadets mettent en place un écosystème culturel de la formation à la programmation, de la création locale à la diffusion sur les territoires, des plus jeunes publics jusqu’à nos aînés</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Mercredi 05&nbsp;mars à 18h30</strong><br>  Réservation via le Parvis :&nbsp;https://parvis.notre-billetterie.net/formulaire?dial=sommaire2425<br>  Tarifs : Tarif normal 12€ / Abonnés et habitants Luz St Sauveur 8€ / Réduit 6€, selon les places disponibles<br>  Public :&nbsp;Tout public dès 6 ans<br>  Lieu : Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '26333ba0-893a-4ac9-b46d-c6d663d9b536');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les voyages de Peer Gynt - Les cadets', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Le voyage de Peer Gynt\"&nbsp;Philippe Estèphe -&nbsp;Les Cadets compagnie lyrique - Conte musical</strong><br>  À partir du monument de la culture norvégienne, Les Cadets proposent une adaptation de&nbsp;Peer Gynt&nbsp;sous la forme d’un concert conté, interactif et familial dans une version originale pour récitant, baryton, soprano et accordéon.&nbsp;Tout le monde connaît la musique de&nbsp;Peer Gynt&nbsp;sans le savoir, tant ses thèmes musicaux sont passés dans la culture populaire. Ce conte initiatique suit les mensonges et voyages d’un anti-héros, Peer Gynt, jeune norvégien qui ne peut s’empêcher de raconter des histoires et de s’inventer des vies, fuyant toujours plus loin les conséquences de ses actes.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Pour en savoir plus sur la compagnie Les Cadets :&nbsp;</strong>https://www.nma32.com/la-compagnie-des-cadets/spectacles-en-diffusion/voyages-peer-gynt<br>  La compagnie des Cadets a pour vocation de créer de nouvelles formes lyriques et de mettre cet art au service de tous les publics. Constitués d''artistes évoluant sur les scènes nationales et ayant grandi au sein des Nuits Musicales en Armagnac, les Cadets mettent en place un écosystème culturel de la formation à la programmation, de la création locale à la diffusion sur les territoires, des plus jeunes publics jusqu’à nos aînés</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Mercredi 05&nbsp;mars à 18h30</strong><br>  Réservation via le Parvis :&nbsp;https://parvis.notre-billetterie.net/formulaire?dial=sommaire2425<br>  Tarifs : Tarif normal 12€ / Abonnés et habitants Luz St Sauveur 8€ / Réduit 6€, selon les places disponibles<br>  Public :&nbsp;Tout public dès 6 ans<br>  Lieu : Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '26333ba0-893a-4ac9-b46d-c6d663d9b536');
