INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Décidément bleu - Collectif décomposé', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Décidément bleu\" -&nbsp; Collectif décomposé - Sortie de résidence (Théâtre, musique, danse)</strong></p>  <p style=\"text-align: justify;\">La vie a un début. Et si elle n''avait pas de fin ? L''unique personnage de la pièce, un adolescent, en rêve. Il décide d''écrire un roman sur ses Grands-parents : \"Vers le ciel, bleu\". À&nbsp;l''écriture du dernier chapitre, le petit monde de ce jeune homme bascule en un délire mal maîtrisé ... À&nbsp;travers cette écriture scénique, nous souhaitons parvenir à draper de justesse et de poésie le regard que l''on peut porter sur la grande faucheuse ... Un spectacle enlevé où les mots, la musique et le corps s''entrechoquent.</p>  <p style=\"text-align: justify;\">Distribution :&nbsp;Texte édité aux éditions Vox Scriba, écriture, mise en scène et interprète Eric Durand, musique piano&nbsp;Vianney oudart</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Pour en savoir plus sur le Collectif Décomposé&nbsp;:&nbsp;</strong>https://www.letheatredecompose.com/<br>  Le Collectif Décomposé est soutenu par la Région Occitanie, le Conseil Départemental des Hautes-Pyrénées et la Communauté de Communes Pyrénées Vallées des Gaves.&nbsp;Ce spectacle est soutenu par la Spédidam.&nbsp;Après 12 ans de travail de recherche et de créations en région Nord Pas De Calais, la compagnie souhaite se donner un nouveau souffle en s’implantant en milieu rural et ainsi rapprocher les œuvres et les artistes des habitants les plus éloignés de l’offre culturelle. Sortir des grandes agglomérations, se confronter à un public moins «&nbsp;aguerri&nbsp;» à la chose culturelle, sensibiliser les publics de demain… tels sont les enjeux et les objectifs que la compagnie souhaite se donner.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Du lundi 10 mars au vendredi 14 mars<br>  Sortie de résidence vendredi 14 mars à 18h30</strong><br>  Tarif : Offert<br>  Public :&nbsp;Tout public dès 14&nbsp;ans<br>  Lieu : Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '388f2210-ed98-4d8f-a30b-09aafcec0413');
