INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Comedy Club 50 ans Luz Ardiden', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Présentation des 50 ans de Luz Ardiden</strong><br>  Les 17, 18 et 19 janvier 2025, la station de ski Luz Ardiden célèbre ses 50 ans dans une ambiance festive et inoubliable. Pendant trois jours, un programme riche et varié mêlera concerts, animations sportives et moments conviviaux. Vendredi 17 Janvier, pour l’ouverture du week-end anniversaire un Comedy Club exceptionnel est programmé à la Maison du Parc national et de la vallée. Avec Antony GIULIANI, Yassir BOUCHNAFA et Eliott Doyle. Pour plus d''informations et pour accéder à la billetterie :&nbsp;<a data-saferedirecturl=\"https://www.google.com/url?q=https://luz-ardiden.com/50-ans/&amp;source=gmail&amp;ust=1734964825077000&amp;usg=AOvVaw24Rnph1UtNLCXDlVAR0cj4\" href=\"https://luz-ardiden.com/50-ans/\" target=\"_blank\">https://luz-ardiden.com/50-<wbr>ans/</a></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Yassir BOUCHNAFA</strong><br>  Découvert dans le programme Amazon Comedy Class, Yassir, originaire de Toulouse, écume les scènes et plateaux parisiens depuis 4 ans : Paname Art Café, Sacré, Jamel Comedy Club… Il fait les premières parties de Roman Frayssinet, Paul Mirabel, Morgane Cadignan, Louis Chappey, Ahmed Sparrow, ou encore Nordine Ganso. S’interrogant sur le monde dans sa globalité et dans sa profondeur, il aborde des sujets et thèmes qui divisent avec poésie et bienveillance. Il remet en perspective notre normalité de façon singulière, drôle et attachante.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Eliott DOYLE</strong><br>  Eliott Doyle est désormais un membre incontournable de la communauté humour. Cet OVNI, que les Suisses comparent à <a href=\"https://www.lespotdurire.fr/2023/07/10/pain-surprise-blaise-bersinger/\">Blaise Bersinger</a> (voir podcast plus bas), a un style unique. Portrait de cette sensation plus atypique que l’atypisme !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Antony GIULIANI</strong><br>  Il intègre la prestigieuse Ecole Nationale de l''Humour à Montréal, il en sortira diplômé en 2020. Lors de cette expérience à l''étranger, il passe sur scène dans des festivals, tels que ; \"juste pour rire\", le \"Zoofest\". De retour à Paris, il a rapidement fait sa place dans tous les comedy clubs parisiens.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9e6bf1bf-d635-4d04-8dda-ca77b6c48e02');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Comedy Club 50 ans Luz Ardiden', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Présentation des 50 ans de Luz Ardiden</strong><br>  Les 17, 18 et 19 janvier 2025, la station de ski Luz Ardiden célèbre ses 50 ans dans une ambiance festive et inoubliable. Pendant trois jours, un programme riche et varié mêlera concerts, animations sportives et moments conviviaux. Vendredi 17 Janvier, pour l’ouverture du week-end anniversaire un Comedy Club exceptionnel est programmé à la Maison du Parc national et de la vallée. Avec Antony GIULIANI, Yassir BOUCHNAFA et Eliott Doyle. Pour plus d''informations et pour accéder à la billetterie :&nbsp;<a data-saferedirecturl=\"https://www.google.com/url?q=https://luz-ardiden.com/50-ans/&amp;source=gmail&amp;ust=1734964825077000&amp;usg=AOvVaw24Rnph1UtNLCXDlVAR0cj4\" href=\"https://luz-ardiden.com/50-ans/\" target=\"_blank\">https://luz-ardiden.com/50-<wbr>ans/</a></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Yassir BOUCHNAFA</strong><br>  Découvert dans le programme Amazon Comedy Class, Yassir, originaire de Toulouse, écume les scènes et plateaux parisiens depuis 4 ans : Paname Art Café, Sacré, Jamel Comedy Club… Il fait les premières parties de Roman Frayssinet, Paul Mirabel, Morgane Cadignan, Louis Chappey, Ahmed Sparrow, ou encore Nordine Ganso. S’interrogant sur le monde dans sa globalité et dans sa profondeur, il aborde des sujets et thèmes qui divisent avec poésie et bienveillance. Il remet en perspective notre normalité de façon singulière, drôle et attachante.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Eliott DOYLE</strong><br>  Eliott Doyle est désormais un membre incontournable de la communauté humour. Cet OVNI, que les Suisses comparent à <a href=\"https://www.lespotdurire.fr/2023/07/10/pain-surprise-blaise-bersinger/\">Blaise Bersinger</a> (voir podcast plus bas), a un style unique. Portrait de cette sensation plus atypique que l’atypisme !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Antony GIULIANI</strong><br>  Il intègre la prestigieuse Ecole Nationale de l''Humour à Montréal, il en sortira diplômé en 2020. Lors de cette expérience à l''étranger, il passe sur scène dans des festivals, tels que ; \"juste pour rire\", le \"Zoofest\". De retour à Paris, il a rapidement fait sa place dans tous les comedy clubs parisiens.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '9e6bf1bf-d635-4d04-8dda-ca77b6c48e02');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Comedy Club 50 ans Luz Ardiden', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Présentation des 50 ans de Luz Ardiden</strong><br>  Les 17, 18 et 19 janvier 2025, la station de ski Luz Ardiden célèbre ses 50 ans dans une ambiance festive et inoubliable. Pendant trois jours, un programme riche et varié mêlera concerts, animations sportives et moments conviviaux. Vendredi 17 Janvier, pour l’ouverture du week-end anniversaire un Comedy Club exceptionnel est programmé à la Maison du Parc national et de la vallée. Avec Antony GIULIANI, Yassir BOUCHNAFA et Eliott Doyle. Pour plus d''informations et pour accéder à la billetterie :&nbsp;<a data-saferedirecturl=\"https://www.google.com/url?q=https://luz-ardiden.com/50-ans/&amp;source=gmail&amp;ust=1734964825077000&amp;usg=AOvVaw24Rnph1UtNLCXDlVAR0cj4\" href=\"https://luz-ardiden.com/50-ans/\" target=\"_blank\">https://luz-ardiden.com/50-<wbr>ans/</a></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Yassir BOUCHNAFA</strong><br>  Découvert dans le programme Amazon Comedy Class, Yassir, originaire de Toulouse, écume les scènes et plateaux parisiens depuis 4 ans : Paname Art Café, Sacré, Jamel Comedy Club… Il fait les premières parties de Roman Frayssinet, Paul Mirabel, Morgane Cadignan, Louis Chappey, Ahmed Sparrow, ou encore Nordine Ganso. S’interrogant sur le monde dans sa globalité et dans sa profondeur, il aborde des sujets et thèmes qui divisent avec poésie et bienveillance. Il remet en perspective notre normalité de façon singulière, drôle et attachante.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Eliott DOYLE</strong><br>  Eliott Doyle est désormais un membre incontournable de la communauté humour. Cet OVNI, que les Suisses comparent à <a href=\"https://www.lespotdurire.fr/2023/07/10/pain-surprise-blaise-bersinger/\">Blaise Bersinger</a> (voir podcast plus bas), a un style unique. Portrait de cette sensation plus atypique que l’atypisme !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Antony GIULIANI</strong><br>  Il intègre la prestigieuse Ecole Nationale de l''Humour à Montréal, il en sortira diplômé en 2020. Lors de cette expérience à l''étranger, il passe sur scène dans des festivals, tels que ; \"juste pour rire\", le \"Zoofest\". De retour à Paris, il a rapidement fait sa place dans tous les comedy clubs parisiens.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '9e6bf1bf-d635-4d04-8dda-ca77b6c48e02');
INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('04734152-e65f-436a-8d50-8635adb59665', 'exposition', true, false, NULL, '2025-03-01T23:00:00.000Z', '2025-03-29T23:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2025-03-01T23:00:00.000Z', '2025-03-01T23:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Pyrénight" - Christophe Cieslar', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Pyrénight\" -&nbsp;Christophe Cieslar</strong><br>  Le mot de l''artiste : Comme il est bien connu, les sens comme la vue, l’ouïe sont plus sensibles la nuit et nous arrivons alors à percevoir et ressentir des émotions uniques. Au-delà du rendu des clichés, elle nous apporte réflexion, nous aide à prendre conscience de la beauté de ce qui nous entoure. Les moments d’attente et de pose (photographique) génèrent un mélange d’excitation entre l’impatience de constater le résultat du cliché et le désir de vouloir s’imprégner à l’œil nu de ce que peut nous offrir le monde de la nuit. Dénuée de toute pollution sonore, nous arrivons alors à voir tout ce qui nous entoure d’un œil différent, beaucoup plus humain. Elle nous fait nous sentir vivant, notamment dans nos chères Pyrénées, où elle nous permet également de reprendre notre modeste place d’humain face à ses majestueuses montagnes. En opposition, le sens du détail prend toute son importance et peut transformer un cliché. C’est ce mélange de sensations, d’émotions qui fait le charme et la richesse de la photo de nuit.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Christophe Cieslar</strong><br>  Il débute la photographie en 2014 et se passionne très vite pour la photo nocturne. Autodidacte, il participe aux deux premières éditions du \"NIGHTSCAPADES\" (festival international axé sur le monde de la nuit avec les meilleures pointures mondiales de la photo nocturne Ses clichés font partie d''une exposition commune \"Vous connaissez les Pyrénées le jour : découvrez les la nuit\" avec sept autres photographes nocturnes de renom, en partenariat avec la Réserve Internationale de Ciel Étoilé.<br>  Site internet :&nbsp;https://www.christophe-cieslar-photographie.fr/<br>  Facebook :&nbsp;https://www.christophe-cieslar-photographie.fr/</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '04734152-e65f-436a-8d50-8635adb59665');
