INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Projet de création', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\">Un spectacle inédit créé par les lycéens de Tarbes aux côtés de la Compagnie Le Cirque Jafarson.</p>  <p style=\"text-align: justify;\">Réunir des élèves passionnés de théâtre et de musique autour d’un seul projet : c’est l’aventure initiée par Rachel Cazenave et Fanny Padovani, de la compagnie Le Cirque Jafarson. À travers ce projet, elles offrent une voix aux élèves internes du lycée Marie-Curie de Tarbes. Création d’un spectacle, découverte des métiers du spectacle vivant, et lancement d’une tournée dans le département : les élèves deviennent, le temps de ce projet ambitieux, de véritables professionnels du monde artistique. Le thème abordé cette année portera sur les relations familiales, en particulier celles entre frères et sœurs.</p>  <p style=\"text-align: justify;\"><br>  Offert<br>  Tout public<br>  Salle de spectacle</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '50191fd6-786b-4e1c-afba-0395cf3be478');
