INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('0d92372a-c37d-4ef6-8f2d-f9808838256e', 'exposition', true, false, NULL, '2025-05-01T22:00:00.000Z', '2025-05-28T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2025-05-01T22:00:00.000Z', '2025-05-01T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Terres perdues" - Maxime Daviron', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Terres Perdues\" -&nbsp;Maxime Daviron</strong></p>  <p style=\"text-align: justify;\">Il émane une certaine puissance des hautes altitudes sauvages. De vaporeux sentiments s''y entremêlent : fascination, angoisse, humilité. Une étrangeté omniprésente réveille en nous des instincts enfouis, ramenant l''esprit au stade d''une contemplation craintive face aux forces brutes qui semblent habiter ces immensités.&nbsp;</p>  <p style=\"text-align: justify;\"><meta charset=\"utf-8\"></p>  <p style=\"text-align: justify;\">C''est de cet état de conscience introspectif que \"Terres Perdues\" puise ses racines. La démarche de la série est avant tout artistique : sous des influences picturales et cinématographiques, elle cherche à retranscrire des atmosphères, à insuffler dans chaque image une histoire et une expérience. En cela, les éléments climatiques les plus tourmentés agissent comme un révélateur, ouvrant des fenêtres éphémères sur un monde insoupçonné et exacerbant le \"sauvage\" qui règne dans cet univers vertical. Dans la prolongation de cette démarche, le parti pris s''est imposé naturellement de fuir toute trace humaine pour évoquer une époque antérieure à l''anthropocène, un ailleurs primitif et intact. Si ces visions évoquent un passé vierge de la main de l''Homme, c''est aussi pour éveiller implicitement les consciences à la préservation cruciale de ces derniers bastions du sauvage qui subsistent encore autour de nous. En s''articulant essentiellement autour des montagnes pyrénéennes, la série tente aussi de montrer ce qu''il est possible de voir et de vivre à deux pas de chez soi, inspirée par le mouvement pyrénéiste.&nbsp;&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Maxime Daviron</strong><br>  La photographie a commencé à m’attirer assez tôt. Assez vite elle est devenue primordiale, passant de simple outil de témoignage à véritable moyen d’expression artistique. Mes images se sont rapidement axées autour de la nature, toujours avec un fort attrait pour les ambiances surréalistes et oniriques, avec une influence visuelle de la peinture et du cinéma. Fasciné par les territoires sauvages, je pars régulièrement à la recherche d’atmosphères hors du temps, animé par la volonté de ne pas se contenter de montrer ce que je vois, mais de tenter de faire ressentir ce que je vis.</p>  <p style=\"text-align: justify;\"><meta charset=\"utf-8\"></p>  <p dir=\"ltr\">Site web : www.maximedaviron.com&nbsp;<br>  Facebook : www.facebook.com/terres.perdues&nbsp;<br>  Instagram : www.instagram.com/maximedaviron&nbsp;</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '0d92372a-c37d-4ef6-8f2d-f9808838256e');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Terres perdues" - Maxime Daviron', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Terres Perdues\" -&nbsp;Maxime Daviron</strong></p>  <p style=\"text-align: justify;\">Il émane une certaine puissance des hautes altitudes sauvages. De vaporeux sentiments s''y entremêlent : fascination, angoisse, humilité. Une étrangeté omniprésente réveille en nous des instincts enfouis, ramenant l''esprit au stade d''une contemplation craintive face aux forces brutes qui semblent habiter ces immensités.&nbsp;</p>  <p style=\"text-align: justify;\"><meta charset=\"utf-8\"></p>  <p style=\"text-align: justify;\">C''est de cet état de conscience introspectif que \"Terres Perdues\" puise ses racines. La démarche de la série est avant tout artistique : sous des influences picturales et cinématographiques, elle cherche à retranscrire des atmosphères, à insuffler dans chaque image une histoire et une expérience. En cela, les éléments climatiques les plus tourmentés agissent comme un révélateur, ouvrant des fenêtres éphémères sur un monde insoupçonné et exacerbant le \"sauvage\" qui règne dans cet univers vertical. Dans la prolongation de cette démarche, le parti pris s''est imposé naturellement de fuir toute trace humaine pour évoquer une époque antérieure à l''anthropocène, un ailleurs primitif et intact. Si ces visions évoquent un passé vierge de la main de l''Homme, c''est aussi pour éveiller implicitement les consciences à la préservation cruciale de ces derniers bastions du sauvage qui subsistent encore autour de nous. En s''articulant essentiellement autour des montagnes pyrénéennes, la série tente aussi de montrer ce qu''il est possible de voir et de vivre à deux pas de chez soi, inspirée par le mouvement pyrénéiste.&nbsp;&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Maxime Daviron</strong><br>  La photographie a commencé à m’attirer assez tôt. Assez vite elle est devenue primordiale, passant de simple outil de témoignage à véritable moyen d’expression artistique. Mes images se sont rapidement axées autour de la nature, toujours avec un fort attrait pour les ambiances surréalistes et oniriques, avec une influence visuelle de la peinture et du cinéma. Fasciné par les territoires sauvages, je pars régulièrement à la recherche d’atmosphères hors du temps, animé par la volonté de ne pas se contenter de montrer ce que je vois, mais de tenter de faire ressentir ce que je vis.</p>  <p style=\"text-align: justify;\"><meta charset=\"utf-8\"></p>  <p dir=\"ltr\">Site web : www.maximedaviron.com&nbsp;<br>  Facebook : www.facebook.com/terres.perdues&nbsp;<br>  Instagram : www.instagram.com/maximedaviron&nbsp;</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '0d92372a-c37d-4ef6-8f2d-f9808838256e');
