INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Les failles du réel" - Compagnie Le Cirque Jafarson ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Les failles du réel\" -&nbsp;Compagnie Le Cirque Jafarson</strong></p>  <p style=\"text-align: justify;\">L’A.R.F.E.D. (Amicale Révélatrice de Failles et d’Expertise en Décryptologie) vous invite à explorer les mystères des Pyrénées à travers une exposition unique de leurs travaux. Leur récente enquête sur la mystérieuse « Carte de Mont » a révélé des failles entre notre monde et un monde « autre » . Preuves sonores, photographiques et dessins inédits sont présentés pour retracer cette enquête hors du commun. « Les Failles du Réel » est un projet artistique ancré au coeur des sommets pyrénéens, porté par l’association Le Cirque Jafarson. Il présente l’imaginaire comme un outil pour réinterpréter le territoire. Une soirée de lancement sera organisée le mercredi 2 juillet de 18h à 22h en salle des voûtes. Crédit photo : Virginie Terroitin. Graphisme : Jack Tezam.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '92d0de89-fa84-4a70-a7c9-970bb6233d40');
