INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Jubilä - Leïla Martial ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Jubilä\"&nbsp;Leïla Martial&nbsp; - Solo pour vocaliste multi-timbrée<br>  Partenariats avec le Parvis Scène Nationale de Tarbes Pyrénées et l’association Jazz Pyr’</strong></p>  <p style=\"text-align: justify;\">Dans Jubilä, Leïla Martial&nbsp; réalise un solo clownesque qui explore les sons tous azimuts. Voici l’appétissante proposition de cette vocaliste de jazz aussi poignante qu’extravagante. En scène, vêtue d’une robe de nymphe et d’une couronne sauvage, Leïla Martial incarne une créature à la fois antique et espiègle. Passant d’une invocation de Bach à des souvenirs enfouis, elle alterne entre français, anglais, espagnol et des langages inventés. Sa voix, véritable archipel d’émotions, dévoile des timbres inédits et des confessions touchantes.&nbsp;</p>  <p style=\"text-align: justify;\">Distribution : voix Leïla Martial, ingénieur du son Alexandre Verbiese, régie générale Patrick Cunha, complicité sonore Léo Grislin, scénographe Ben Farey, création lumières Alice Huc, regard extérieur Marine Mane. Crédit photo : Jean-Christophe Hanché.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Leïla Martial</strong><br>  Site internet :&nbsp;<a href=\"https://leilamartial.com/solos/\">https://leilamartial.com/solos/</a></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Vendredi 4 avril&nbsp;à 20h30</strong><br>  Normal 12€, abonnés Parvis et adhérents Jazz Pyr'' 8€, réduit 6€.&nbsp;</p>  <p style=\"text-align: justify;\">Réservations&nbsp;sur&nbsp;<a href=\"https://parvis.notre-billetterie.net/formulaire?dial=sommaire2425\">Billetterie Parvis</a></p>  <p style=\"text-align: justify;\">Tout public dès 7 ans</p>  <p style=\"text-align: justify;\">Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b16b54d3-9771-4d0b-b53f-d9d706b4d9ea');
