INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Sortie de résidence - KALEIDOSCOPE Cie De La Mandragore', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Sortie de résidence \"Kaleidoscope\" - Compagnie De La Mandragore</strong></p>  <p style=\"text-align: justify;\">Kaleïdoscope est une pièce d’auto-fiction, pensée pour une danseuse, un DJ et un vidéaste. La pièce s’appuie sur les souvenirs et les rencontres de la metteuse en scène et chorégraphe Corinne Mathou, qui revisite son parcours à partir d’archives éclectiques : photographies, lettres, carnets de routes … Entre une Inde rêvée où elle vécut plusieurs années et un monde occidental qui semble s’effondrer, l’artiste aborde le thème de la quête existentielle. De ces traces et de ces fragments de vie l’artiste s’interroge: Que reste-il d’une vie ? Comment une trajectoire personnelle peut-elle s’inscrire dans une réflexion plus large sur la société, les femmes et le monde ?</p>  <p>Distribution : concept, écriture et chorégraphie Corinne Mathou, musique Félix Reynau, vidéo et lumière Ilan Mercher.</p>  <p><br>  <b>Compagnie De La Mandragore&nbsp;</b>:&nbsp;https://www.cielamandragore.com/</p>  <p></p>  <p><strong>Sortie de résidence</strong> Vendredi 11&nbsp;janvier à&nbsp;18h30<br>  <strong>Tarif</strong> Offert<br>  <strong>Public </strong>Tout public<br>  <strong>Lieu</strong>&nbsp;Salle de spectacle</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '69b1bd09-3606-437f-a8ac-5b97d7cf1bb6');
