INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les audacieuses du Vignemale - Compagnie Théâtre Fébus ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Les audacieuses du Vignemale\" - Compagnie Le Théâtre Fébus<br>  Programmation en collaboration avec l’école primaire de Luz-Saint-Sauveur</strong></p>  <p style=\"text-align: justify;\">Qui a fait la gloire du Vignemale et de son massif ? Il y a eu Henri Russel, Henri Brulle, les guides Célestin Passet et François Bernart-Salles. On les appelle les glorieux du Vignemale. Mais il y a eu des femmes issues d’une certaine aristocratie, elles ont marché, approché, effleuré, grimpé, dévalé le massif. Il y a la curieuse, la courageuse, l’impétueuse et la guerrière. Il y a la sœur, la fille, la femme, l’amie ...&nbsp;</p>  <p style=\"text-align: justify;\">Elles ont pour nom Rosalie Ramond, Hortense de Beauharnais, Laure d’ Abrantès, Ann Lister. Elles ont marqué à jamais l’histoire de ce massif mythique. Chacune a son histoire, son lien avec cette montagne et sa nature environnante. Elles semblent à la recherche d’un absolu ou d’un supplément d’âme mais surtout d’une quête d’amour… Un couple étrange, sorti de nulle part, va vous raconter leur incroyable aventure !</p>  <p style=\"text-align: justify;\">Distribution : interprété, illustré, chanté et mis en musique par Bruno Spiesser et Carole Gantheil.</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Mardi 29 avril&nbsp;à 14h30</strong></p>  <p style=\"text-align: justify;\"><strong>Programmation en collaboration avec l’école primaire de Luz-Saint-Sauveur.</strong><br>  Tarif unique 4€ (selon les places disponibles)<br>  Tout public<br>  Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1176c7e4-7d00-486a-bf52-bf612a274804');
