INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Bien ... Reprenons" Cie du Détachement International du Muerto Coco', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Mercredi Artistique \"Bien ... Reprenons\"<br>  Compagnie&nbsp;Détachement International du Muerto Coco&nbsp;</strong></p>  <p style=\"text-align: justify;\">C''est un road trip musical où l''on parle, entre autres, de pédagogie poussiéreuse de conservatoire, de repas de famille, de flûte à bec et de conseillers Pôle emploi, de \"Est-ce que vous êtes chauds, Carcassonne ?!\" et d''une possible réincarnation en homard bleu de l''Atlantique. C’est de la fiction semi-autobiographique qui révèle et s''amuse avec la dimension poétique, humoristique, absurde et sensible dissimulée dans le réel. C’est un hublot de machine à voyager dans l’intimité d’une vie de musicien, celle qu’on ne peut pas voir quand il revêt sa carapace de scène. C’est un spectacle qui se situe quelque part entre le théâtre, la musique live et la création radiophonique.</p>  <p></p>  <p><strong>Distribution</strong><br>  Informations :&nbsp;https://muertococo.jimdofree.com/cr%C3%A9ations-en-tourn%C3%A9e/bien-reprenons/<br>  Roman Gigoi-Gary : Jeu, écriture, composition.&nbsp;Arnaud Clément : Sonorisation. Regards extérieurs et accompagnement artistique : Raphaëlle Bouvier, Maxime Potard, Marc Prépus, Léonardo Montecchia. Regards complices : Roland Gigoi, Michèle Gary. Création Lumière : Marco Simon.&nbsp;Régie Lumière : Édith Richard.</p>  <p></p>  <p><strong>Informations&nbsp;</strong><br>  Offert<br>  Tout public dès 8 ans<br>  Près du manège sur la promenade du Bastan de Luz-Saint-Sauveur</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd8354baa-32dd-4a93-ba54-c2c32e158e3c');
