INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Instants" Cie Non Sin Tri', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Mercredi Artistique \"Instants\"<br>  Compagnie&nbsp;Non Sin&nbsp;Tri&nbsp;- Circassien</strong><br>  https://nonsintri.com/la-comania/</p>  <p style=\"text-align: justify;\">Trois personnages grandissent ensemble, se découvrent et tissent des liens à travers un langage de mouvements abstraits et de disciplines circassiennes, donnant vie à une poésie visuelle qui explore les métamorphoses humaines et les moments partagés par l’humanité. Voir la mer pour la première fois, la sensation de se brûler la langue, l''absence jamais ressentie auparavant, le toucher d''une étreinte qui a changé ma vie... Des instants gravés dans la mémoire. Le passage du temps et ces moments précieux qui façonnent nos existences. Un regard intime et empreint de tendresse sur la vieillesse.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Offert, tout public<br>  Place du 19 mars, Luz-Saint-Sauveur<br>  Crédit photo :&nbsp;Andrés Itro</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '609ecc6e-f868-4aa2-903f-39e6040204e0');
