INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Fête de Saint-Sauveur', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<h3><span style=\"color:#e74c3c;\"><strong>En raison de la météo pluvieuse annoncée pour le mercredi 23 juillet, la fête de St Sauveur aura lieu à l''intérieur !</strong></span></h3>  <h3></h3>  <h3><span style=\"color:#e74c3c;\"><strong>18h30 spectacle \"Qui m''aime me suive\" au gymnase de Luz</strong></span></h3>  <h3><span style=\"color:#e74c3c;\"><strong>Pour la suite nous irons au forum de Luz Avec le concert de groupe \"A La Bonheur\" et pour finir le concert des \"Désorientés !\"</strong></span></h3>  <h3><span style=\"color:#e74c3c;\"><strong>Buvette et restauration sur place par l''association La Pourtère.</strong></span></h3>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Fête de Saint-Sauveur&nbsp;</strong></p>  <p style=\"text-align: justify;\"><strong>Manifestation en partenariat avec les associations La Pourtère, Les Amis de Saint-Sauveur, l’Économie Montagnarde et la Mairie de Luz-Saint-Sauveur.</strong><br>  La traditionnelle fête de Saint-Sauveur a lieu&nbsp;le mercredi 23&nbsp;juillet dans le quartier thermal de Saint-Sauveur. Elle est organisée par la Maison du Parc national et de la vallée en partenariat avec&nbsp;la mairie de Luz-Saint-Sauveur, l''association des Amis de Saint-Sauveur et l''association La Pourtère. Des&nbsp;performances rythmeront&nbsp;votre soirée à partir de&nbsp;18h30 jusqu''au tir du feu d''artifice à 23h. Une buvette et de la petite restauration rapide, seront proposées sur place par l''association La Pourtère. Les restaurants l''Ardiden et le Parnoramic vous proposerons également un menu. On vous dévoile ci-dessous la programmation de cet événement incontournable du mois de juillet :&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>PROGRAMME DE LA SOIREE </strong></p>  <p style=\"text-align: justify;\"><strong>A partir de 18h30 : </strong></p>  <p style=\"text-align: justify;\"><strong>Spectacle danse - cirque \"Qui m''aime me suive\" de la Compagnie Storyteller</strong><br>  Tout public dès 6 ans.<strong> </strong></p>  <p style=\"text-align: justify;\">Pour plus d''informations :<strong>&nbsp;</strong>https://www.compagniestoryteller.com/</p>  <p style=\"text-align: justify;\"><strong>Concert&nbsp; \"À la bonheur\"&nbsp;</strong><br>  https://www.facebook.com/zalabonheur/?locale=fr_FR</p>  <p style=\"text-align: justify;\"><strong>Pause repas</strong></p>  <p style=\"text-align: justify;\"><strong>Concert \"Les&nbsp;Désorientés\"</strong><br>  https://www.instagram.com/desorientes_lille/</p>  <p style=\"text-align: justify;\"><strong>23h - Feu d''artifice pour cloturer la soirée</strong></p>  <p style=\"text-align: justify;\">L’association Les Amis de Saint-Sauveur ouvre leur local, 34 avenue de l’Impératrice Eugénie de 16 h à 20 h30, pour présenter des oeuvres de leurs amis artistes et échanger avec toutes celles et ceux qui le souhaiteront. L''économie montagnarde sera également présente.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Offert<br>  Tout public</p>  <p style=\"text-align: justify;\">Buvette et restauration sur place<br>  Au quartier thermal de Saint-Sauveur<br>  <em>Crédit photo :&nbsp;Amélie Jousseaume</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c4ad9845-71c9-4282-8bfc-143662f069e2');
