INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"WaZoWaZo" Ernest Barbery', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Concert \"WaZoWaZo\" Ernest Barbery</strong><br>  Avec WaZoWaZo, Ernest Barbery livre un concert solo tout en délicatesse, mêlant folk ouatée et mélancolie joyeuse, dans une ode à la nature et à l’amour où résonne la&nbsp;sobriété acoustique des instruments en bois</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Pour en savoir plus sur l''artiste :&nbsp;</strong><br>  <a data-saferedirecturl=\"https://www.google.com/url?q=https://youtu.be/MLSob1GxymM?si%3DdV2nld6MoJvZKV1y&amp;source=gmail&amp;ust=1741858776008000&amp;usg=AOvVaw1qTlOv7pfWVVA6WgJJA7Cv\" href=\"https://youtu.be/MLSob1GxymM?si=dV2nld6MoJvZKV1y\" target=\"_blank\">https://youtu.be/<wbr>MLSob1GxymM?si=<wbr>dV2nld6MoJvZKV1y</a></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Offert, tout public<br>  Crédit photo&nbsp;:&nbsp;Pauline Herbillon<br>  Au jardin de la poste de Luz-Saint-Sauveur</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '7e3c2317-359a-4ea5-9aee-11dae506bf66');
