INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Le cerf au sabot d''argent" Compagnie L''Aurore', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Le cerf au sabot d''argent\" Compagnie L''Aurore<br>  Théâtre jeunesse :&nbsp;Marionnettes et clown en liberté</strong><br>  C’est l’histoire d’un vieil&nbsp;homme qui s’ennuie, d’une petite fille en quête de merveilleux, et de leur rencontre autour d’un livre de contes. C’est l’histoire d’un marionnettiste qui a perdu sa voix et d’une clown qui cherche son chat. Deux histoires parallèles, réunies autour de cette question : le cerf au sabot d’argent existe-t-i l ? Et si oui , peut-on le voir ici et maintenant ? Dans l’espoir d’apercevoir cet animal fantastique, le marionnettiste et la clown vont faire vivre la petite fille et le vieux avec les objets qui les entourent.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Inspiré d''un conte russe, \"Le Cerf au Sabot d’Argent\" a été créé en 2017. Ce spectacle tout public évoque le passage de l’enfance à l''âge adulte, le retour de l’adulte à sa propre enfance, et la rencontre des âges à travers l’imaginaire.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><b>Compagnie L''Aurore :&nbsp;</b>https://compagnie-l-aurore.com/<br>  Distribution :&nbsp;Caroline Lemignard, Frédéric Vern et Jean-Christophe Robert (en alternance avec François Dubois).&nbsp;Mise en scène et Marionnettes :&nbsp;François Dubois.&nbsp;Costumes :&nbsp;Marion Bourdil.&nbsp;Création lumière pour la salle :&nbsp;Jean-Christophe Robert.&nbsp;Illustration pour l’affiche :&nbsp;Lauranne Quentric.&nbsp;Photos :&nbsp;Frédéric Dhenin</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Offert<br>  Tout public dès 6 ans<br>  Parc de la mairie&nbsp;à Luz-Saint-Sauveur (Changement de lieu en raison des fortes chaleurs annoncées)</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b5eccc99-a8b5-4f0a-8499-513c4c9856c4');
