INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Prise de terre" Compagnie Le Poisson Soluble', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Prise de terre\" Compagnie Le Poisson Soluble<br>  Théâtre jeunesse :&nbsp;Marionnette d’argile éphémère et fait main</strong><br>  L''un est grand et maladroit, l''autre est précis et droit, on les surnomme bambou et frêne. Inspiré des mouvements des potiers passés au crible du théâtre gestuel, ce duo burlesque modèle des marionnettes d''argile. De cet artisanat naissent les figures d''un bestiaire fantastique où l''homme et la Terre se mêlent et se démêlent, se forment et se déforment jusqu''à la rupture.Ce théâtre de matière interroge avec poésie la résilience de la Terre et le rapport qu''entretient l''homme avec celle-ci.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><b>Compagnie Le Poisson Soluble :&nbsp;</b>https://lepoissonsoluble.org/<br>  Mise en scène :&nbsp;Fabio Ezechiele Sforzini.&nbsp;Comédiens manipulateurs : Sébastien Dehaye et François Salon. Régisseur :&nbsp;Paul Fontaine ou Franck Levin. Scénographe :&nbsp;Delphine Lancelle. Créateur sonore :&nbsp;Jacques Rossello. Créateurs lumière :&nbsp;David Auvergne et François Salon. Crédit photo : Jean-Jacques Abadie.&nbsp;Coproduction: Association Entracte, Mugron (40) / Théâtre Le Colombier, Les Cabannes (81) / Petit Théâtre Spirale, Riscles (32) / Théâtre des Franciscains, Ville de Béziers (34) / Bouillon Cube, Causse de la Selle (34) Soutiens: Association Arlesie, Daumazan sur Arize (09) / Ax-Animation, Ax-les-Therme (09) / MIMA, Mirepoix (09) / Ville de Limbrassac (09) / Département de l''Ariège (09) / Région Occitanie</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Offert<br>  Tout public dès 6 ans<br>  Parc de la mairie de Luz-Saint-Sauveur</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'c9e6a130-bc8e-4da7-90ae-943d142f1ec0');
