INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Duo Daïs" Susan Edward Nicolas Thevenin ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>ATTENTION : En raison de la météo, le concert est maintenu mais replié en salle de spectacle de la Maison du Parc national et de la vallée 24 Place Saint-Clément 65120 Luz-Saint-Sauveur</strong></p>  <p style=\"text-align: justify;\"><strong>\"Duo Daïs\" Constellations mélodiques - Concert</strong><br>  Le duo Daïs est né de la rencontre inopinée de deux musiciens aux goûts complémentaires. Issus de milieux musicaux très différents, Susan Edward au violoncelle et Nicolas Thevenin à la basse acoustique cherchent aujourd’hui ensemble un nouvel espace sonore, liant la liberté du jazz à la rigueur baroque, la surprenante sensibilité française à la diversité des musiques du monde. Les fruits de cette alchimie sont des compositions mélodiques, vivantes et sensibles.</p>  <p style=\"text-align: justify;\">Le duo Daïs est né de la rencontre comme évidente du violoncelle, précis, joyeux, soyeuxde Susan Edward et de la basse acoustique, rythmique et sensitive de Nicolas Thévenin.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p><strong>DUO DAÏS </strong>Découvrez la chaine youtube de&nbsp;Susan Edward et Nicolas Thévenin<br>  https://www.youtube.com/@DuoDa%C3%AFs</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Offert<br>  Tout public<br>  Crédit photo : Matthew Weinreb</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'fa8a85bf-2854-4ac9-8249-3d2464ede278');
