INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Dédicace "Pyrénight" - Christophe Cieslar', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Dédicace livre \"Pyrénight\"&nbsp;-&nbsp;Christophe Cieslar</strong><br>  Christophe Cieslar vous invite dans son livre \"Pyrénight\" à découvrir les Pyrénées à travers la magie de la nuit. Chaque photo est une invitation à explorer des paysages secrets, invisibles de jour. Venez rencontrer et échanger avec Christophe lors de la dédicace de son livre ! Les Pyrénées sont une chaîne de montagnes séparant la péninsule Ibérique du reste de l''Europe.&nbsp;Habitant à ses pieds et ayant la chance de pouvoir les parcourir, il m’est venu l’idée de les mettre en valeur à travers mon objectif en donnant une vision nocturne de celles-ci.&nbsp;Seul ou accompagné, il est très intéressant de pouvoir observer, contempler et profiter du spectacle que Dame Nature nous réserve la nuit tout en écoutant le bruit du silence.&nbsp;Ce livre est le fruit de huit années de travail faites d’études, de calculs, de repérages et de sorties photographiques en toutes périodes et par tous temps pour vous les faire découvrir autrement.&nbsp;Il se composera de&nbsp;96 pages illustrées&nbsp;de mes plus belles photos nocturnes prises dans les Pyrénées.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Christophe Cieslar</strong><br>  Il débute la photographie en 2014 et se passionne très vite pour la photo nocturne. Autodidacte, il participe aux deux premières éditions du \"NIGHTSCAPADES\" (festival international axé sur le monde de la nuit avec les meilleures pointures mondiales de la photo nocturne Ses clichés font partie d''une exposition commune \"Vous connaissez les Pyrénées le jour : découvrez les la nuit\" avec sept autres photographes nocturnes de renom, en partenariat avec la Réserve Internationale de Ciel Étoilé.<br>  Site internet :&nbsp;https://www.christophe-cieslar-photographie.fr/<br>  Facebook :&nbsp;https://www.christophe-cieslar-photographie.fr/</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Dimanche 02 mars de 17h à19h et lundi 03 mars de 17h à 19h. </strong><br>  Libre accès<br>  Tout public<br>  Salle des voûtes</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'd64c3b92-ae73-4987-9267-b98ae2eba666');
