INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Conférence "Vallée de Barèges"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Conférence \"Vallée de Barèges.&nbsp;Mœurs, habitudes, coutumes\", de Jean-Pierre Rondou</strong><br>  Souvent citée, l’étude consacrée à la Vallée de Barèges (souvent nommée aujourd''hui pays toy) par Jean-Pierre Rondou est demeurée en très grande partie inédite. Instituteur apprécié et naturaliste reconnu en tant que spécialiste des papillons pyrénéens, il a voulu dresser ce monument en hommage à sa vallée et à ses habitants. Nous en publions ici la partie que son auteur a rassemblée sous le titre, Mœurs, habitudes, coutumes. Au fil des chapitres, le lecteur pourra découvrir ainsi de nombreuses facettes de la vie des hommes et des femmes d’une vallée des Pyrénées centrales au XIXe siècle et au début du XXe siècle. Le texte de Rondou est une mine d’informations sur la vie pastorale et la gestion de l’espace valléen, les marques du bétail, les sonnailles, les cultures et l’alimentation, les relations avec les Aragonais, l’artisanat, les vêtements, les coutumes successorales, les contes et légendes, les chansons, les jeux d’enfants… L''ouvrage comprend de nombreux textes et notes de vocabulaire en gascon pyrénéen. Une étude de Jean-François Le Nail – ancien archiviste des Hautes-Pyrénées – consacrée à la biographie de Jean-Pierre Rondou et à ses œuvres introduit l’ouvrage.</p>  <p style=\"text-align: justify;\">La vie et l''œuvre de Rondou seront présentées par Jean-François Le Nail et par l''éditeur, Jean Eygun.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Mardi 18&nbsp;mars à 18h</strong><br>  Tarif : Offert<br>  Public :&nbsp;Tout public<br>  Lieu : Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '673c594b-ca6b-47bd-b1ae-6fdc520b3a8c');
