INSERT INTO exposition (id, type, archive, immanquable, thumbnail_id, date_start, date_end, location, tags, authors, portfolio_authors, credits_photos, updated_at, created_at) VALUES
('890a5966-1998-4899-9442-025e62175042', 'exposition', true, false, NULL, '2025-04-03T22:00:00.000Z', '2025-04-28T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2025-04-03T22:00:00.000Z', '2025-04-03T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Rythmes Sauvages" Frédéric Poulain', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Exposition \"Rythmes Sauvages : Une Allégorie Animalière\" - Frédéric Poulain</strong></p>  <p style=\"text-align: justify;\">Rythmes Sauvages des Hautes-Pyrénées, une exposition photographique capturant la vie simple et sauvage dans nos montagnes. À travers ces clichés authentiques, j''ai cherché à figer l''instant paisible de la vie sauvage.Chaque rencontre furtive, chaque image révèle une histoire secrète mais précieuse. Cette exposition se veut être un témoignage de la richesse de la nature dans notre région. J''espère que ces instantanés vous inspireront à apprécier la beauté simple qui nous entoure et à redécouvrir la magie des Pyrénées à travers les yeux des animaux qui y vivent. \"Je vous invite à consacrer un instant à cet hommage rendu à notre environnement naturel et à la vie sauvage qui l''anime.\" Frédéric Poulain</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Frédéric Poulain</strong><br>  Né en Normandie en 1970, j''ai emménagé dans les Pyrénées en 1980. C''est dans cette région que j''ai découvert la montagne, la randonnée et le ski, des activités qui m''ont profondément marqué . La découverte des sentiers d''altitude et ma passion pour le bivouac m''ont conduit progressivement vers la contemplation et l''observation de ces nouveaux décors. Ces instants précieux m''ont accompagné pendant de nombreuses années, renforçant mon respect pour les espaces sauvages. Il y a neuf ans, l''achat d''un petit Reflex a eu un impact majeur sur ma vie. L''animalier est rapidement devenu évident pour moi, et j''ai entamé mes premiers affûts. Les papillons, les mammifères, les oiseaux et les insectes sont mes sources d''inspiration photographique, me transportant dans des instants éphémères qui accaparent une grande partie de mon temps. La photographie me permet de figer la beauté tragique de la nature et de consacrer ma passion pour ces moments uniques. Site web :https://fredericpoulainphoto.myportfolio.com/<br>  &nbsp;</p>  <p><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '890a5966-1998-4899-9442-025e62175042');
