INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Atelier Recyclerie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Venez créer votre objet insolite avec des matériaux de récupération !</strong><br>  L’association La Mines des Gaves&nbsp;propose un atelier original et ludique où l’imagination n’a pas de limites ! Dans cet espace dédié à la création, les participants sont invités à transformer des matériaux de récupération en objets insolites et uniques. Accompagnés par les membres de l’association,&nbsp;chacun pourra laisser libre cours à sa créativité et concevoir des pièces originales, tout en apprenant les techniques de récupération et de revalorisation des matériaux. L’atelier est une occasion idéale de découvrir l''art du bricolage durable tout en sensibilisant les participants à l’importance du recyclage. Accessible à tous, cet atelier est un moment convivial où chacun peut s’exprimer, apprendre et repartir avec ses créations insolites. Rejoignez-nous pour un moment de partage, de créativité et de réemploi !</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>L''association La Mine&nbsp;des Gaves</strong><br>  La Mine des Gaves, située à Soulom, se consacre à donner une seconde vie aux objets dans un esprit de solidarité et de préservation de l''environnement. Elle récupère des articles divers, les répare, les rénove et les met ensuite en vente, permettant ainsi de réduire le gaspillage tout en favorisant une économie circulaire locale.&nbsp;Que ce soit pour acheter des objets de seconde main, réparer un article ou simplement faire un geste en faveur de la planète, La Mine des Gaves&nbsp;offre une solution accessible et responsable, tout en contribuant à un avenir plus durable.</p>  <p style=\"text-align: justify;\">Retrouvez la page facebook de l''association :&nbsp;https://www.facebook.com/p/Recyclerie-La-Mine-Des-Gaves-100093457450745/</p>  <p style=\"text-align: justify;\"><br>  Offert, sur réservation à l''accueil de la Maison ou par téléphone au&nbsp;05 62 92 38 38<br>  Tout public, salle de réunion&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Prolongez la journée avec la projection-rencontre des membres de l''association, le jeudi 17 avril à partir de 20h avec un début de séance à 20h30 avec le film \"Low Tech\". (Tarif unique d 5€)</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'dd4414bc-d72f-4fb7-abf7-16fa473d3cee');
