INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rencontre Frédéric Poulain', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Exposition \"Rythmes Sauvages : Une Allégorie Animalière\" - Frédéric Poulain</strong><br>  \"Rythmes Sauvages\" est la nouvelle exposition en salle des voûtes proposé par le photographe Frédéric Poulain. Si vous souhaitez le rencontrer et échanger avec lui sur son travail, il sera présent dans la Maison le samedi 05 avril, le samedi 12 avril et le samedi 26 avril de 16h à 19h.</p>  <p></p>  <p style=\"text-align: justify;\"><strong>Frédéric Poulain</strong><br>  Pour plus d''informations : <a attributionsrc=\"/privacy_sandbox/comet/register/source/?xt=AZVhf0L7EBTeS7ru6XHBk2ItCLl7czoGJryFe7vyHiCVr67ap8X9ebqjJ0bca_q4wXo0Vhku7Dvpen-M7tIhMRe_FrzerhBYmcMkrJBIw2pF5N12Ujb8UNbiQCXq7dBLomwmXYO258Y0FtBi9WNSwSAbIMSVRbqau1dHCeiKCcCCX666u3i8CdNjs_P1mSMy2zIR-sYMkd5-Xo-iBKMoF3do461tQHxfmAr_iw6X3m0Nz5gSbaXGpzP5rIL_0urmsvgSMvj1B8MIhiiKjhjo9sb52ulLBIjzrdjwSvnZqq6vmlzdqiRA-OWoV1f_TXneeDWa96XXQqplXmUU9F4QCtXqR2gXrXlpXZsme6jCcfK8O_tD1fiekAeeTVEDI2JjqLsI81sTJAfpOFkfWIeS62nZPYnVrElhbChLkkXAeYeHA3TR5Or_QjhChHfjSAlr9724nK8fjSP861HW989XhWEA8z1cebbVei-2CBfXc4Fdhy2q3U6557pvrEqsYDMP0QS0_uKgaqQonrwHjIgYCdTmLTjCFE3pqwpfPSE7QtrL3Zd6qgJEjmhiUFHQB76xrDrzVl9JSBtYJXyCJYoD-NiWKOHgN8dw8_mu81lehmD7BOcSghNVRa4iBzOPyZdHcuYG36EZrIlzFaVystM2uOjCPzW4T-Oo1aCSBXy7OgiHIUzMF2vGuiw12ugVrQOQ4-E2ih7SlyOda9VlF499eUvKHZaPufEdR-92KtMG1GMsGGBSntkqjZ5W0NGpeTNtAbkFingdP76gWpG3ak96cbmEQNiJVoT1_0DqVQJINKh5wYpoxE52p1B8ctGm-qcjnztgC6pL0yFkITgUZ3jkS-hyXdU8ay2BgeQQ_CwOrgWub4UPNaLC7hQVXHVVlAt6OjGbxZB_cs4r2DJOE9p9_XJz3HIao4XPqbNbNTR8uu1qulh0-Ov-dh6O2AB3PuP47a6IgJ6HHBmE47dw89czEQj-zKK21Q-AS0bj-26-9qXrdXdwNMmibggEybSfvOvOA-5N45yg9ihvQ1ugqImMMDh-4Hg-8YDHcOmQVNEaNaiimO3ren90TRnRPho4f0H4rsY\" href=\"https://www.maisondelavallee.org/rythmes-sauvages-frederic-poulain?fbclid=IwZXh0bgNhZW0CMTAAAR20B4fT-DjhzL