INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Chorale du Lac', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><b>La Maison du Parc national et de la vallée met à disposition sa salle de spectacle pour accueillir la Chorale du Lac avec son concert \"Le temps du bonheur\".&nbsp;</b><br>  Ci-dessous le programme des chansons :<br>  1 - Aimer<br>  2 - Quand on n''a que l''amour<br>  3 - Dis quand reviendras-tu<br>  4 - Ma môme<br>  5 - Confidentiel<br>  6 - La valse de Chostakovitch<br>  7 - Je suis venu pour elle&nbsp;<br>  8 - Comme toi<br>  9 - Il suffisait de presque rien<br>  10 - Le temps&nbsp;<br>  11 - Dans l''eau de la claire fontaine&nbsp;<br>  12 - La belle et la bête<br>  13 - La tendresse&nbsp;<br>  14 - Mon frère&nbsp;<br>  15 - Les vacances au bord de la mer&nbsp;<br>  16 - Dès que le vent souffleras<br>  17 - La complainte du phoque&nbsp;<br>  18 - L''envie d''aimer&nbsp;<br>  19 - L''amour brilel sous les étoiles&nbsp;<br>  20 - Les deux guitares<br>  21 - Quand les hommes vivront d''amour&nbsp;<br>  22 - Les gens qu''on aime&nbsp;<br>  &nbsp;<br>  &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Tout public, offert<br>  Salle de spectacle</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '347f819a-3fa8-4cce-906d-490526266dfe');
