('1cf46f49-64e1-44db-8a0d-4eb104305e6a', 'exposition', true, false, NULL, '2025-06-01T22:00:00.000Z', '2025-06-26T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2025-06-01T22:00:00.000Z', '2025-06-01T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"L’épopée pyrénéiste à travers le fonds Patrimoine Ecrit" ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Exposition \"L’épopée pyrénéiste à travers le fonds Patrimoine Ecrit\"&nbsp;<br>  Centre culturel et patrimonial du Haut-Béarn</strong></p>  <p></p>  <p><strong>Cette exposition s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p></p>  <p style=\"text-align: justify;\">De l’Atlantique à la Méditerranée, la chaîne des Pyrénées, véritable muraille naturelle frontalière, berceau de légendes, de rêves, de découvertes et d’exploits, impressionne par son coté sauvage et mystérieux.<br>  Lieu de passages et d’échanges, fréquentée pour le bienfait de ses eaux depuis l’Antiquité, elle fascine et inspire de nombreux voyageurs, explorateurs, scientifiques, sportifs, artistes… qui, à travers leurs productions littéraires, iconographiques, artistiques… nous font partager leurs observations, leurs émotions, leurs visions, leurs expériences de la montagne.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes<br>  <strong>Photo :&nbsp;</strong>G.E.CADIER-costerillou</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1cf46f49-64e1-44db-8a0d-4eb104305e6a');
