INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Les glaciers des Pyrénées" Pierre René ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Exposition \"Les glaciers des Pyrénées\" - De Pierre René, glaciologue<br>  Parc national des Pyrénées</strong></p>  <p></p>  <p style=\"text-align: justify;\"><strong>Cette exposition s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p style=\"text-align: justify;\">Les glaciers reculent à une vitesse accélérée. Mais qu’en est-il des plantes qui prennent leur place et transforment, peu à peu, nos paysages de montagne ? Les premiers résultats des relevés de terrain révèlent une impressionnante diversité végétale qui s’installe rapidement après la fonte des glaces. De nouveaux écosystèmes pourraient émerger dans ces zones nouvellement découvertes, à condition que les plantes soient capables de les coloniser. Venez découvrir les premiers résultats des études menées sur ces milieux lors de cette conférence.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes<br>  <b>Conférence </b>Pierre René tiendra une conférence en lien avec l''exposition \"L''évolution des glaciers\", le lundi 04 août à 18h en salle de cinéma<br>  <strong>Crédit photo </strong>Crédit photo&nbsp;: O. Pasquet – Parc national des Pyrénées</p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '63ea52ad-dc28-4ca5-8204-b21f72438c1a');
