INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('L''évolution des glaciers pyrénéens', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Conférence \"L’évolution des glaciers pyrénéens\"- De Pierre René, glaciologue<br>  Parc national des Pyrénées</strong></p>  <p></p>  <p><strong>Cette conférence s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p></p>  <p style=\"text-align: justify;\">Qu’appelle-t-on réellement un glacier&nbsp;? Combien de glaciers restent-ils dans les Pyrénées&nbsp;? Pourquoi disparaissent-ils&nbsp;? Et quels impacts cela aura sur nos environnements d’altitude&nbsp;?&nbsp; À&nbsp;l’occasion de l’année internationale de la préservation des glaciers, Pierre René, unique glaciologue des Pyrénées françaises et président de l’association MORAINE, répondra à toutes ces questions et vous propose un échange autour de l’évolution des glaciers des Pyrénées.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle de spectacle<br>  <strong>Crédit photo&nbsp;</strong>C. Sallaberry – Parc national des Pyrénées.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '6e62a170-10c8-472f-a7ce-ede70bd722be');
