INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La grande marche pour l''accueil', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Événement Paroles d''Exil - La grande marche pour l''accueil<br>  Une programmation en partenariat avec l''association Accueil d''Azun, Jazz Pyr'', La Pourtère et la Toy Musique.</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les acteurs culturels de Luz-Saint-Sauveur et du Pays Toy se réunissent et s’unissent autour du projet de La grande marche pour l’accueil initiée par l’association Accueil Azun et leur festival Paroles d’Exils.&nbsp;Lors d’une soirée placée sous le signe de la fraternité et de l’égalité, les associations La Pourtère, Jazz Pyr’, Toy Musique et la Maison du Parc national et de la Vallée de Luz-Saint-Sauveur présenteront main dans la main avec la commune, le programme suivant&nbsp;:</p>  <p style=\"text-align: justify;\"><strong>18h Chorale de la Toy Musique - Mairie</strong><br>  La chorale de la Toy Musique est issue de l''école de musique associative de la vallée de Luz-Saint-Sauveur et du Pays Toy. Conduite par Nathalie Lascombe, accompagnée par Guy Guarric à la guitare, ce grand ensemble chante avec engagement et passion au travers d’un répertoire de reprises arrangées avec conviction et humanité.</p>  <p style=\"text-align: justify;\"><strong>18h30 - Déclaration communce : Parrainages et prises de paroles</strong></p>  <p style=\"text-align: justify;\"><strong>19h-23h Restauration et buvette sur place proposées par l''association La Pourtère</strong></p>  <p style=\"text-align: justify;\"><strong>20h Une jungle, sur le fil de l''exil. Compagnie Chao.S - Parc Massoure</strong><br>  Deux êtres tour à tour, bousculés, enlisés, percutés, écrasés, propulsés par une destinée qui s’impose à eux : l’exil.Leur jeu est dans l’action, celle qui nous fait avancer coûte que coûte.&nbsp;Une Jungle, c’est cette émotion brute générée par l’errance de corps nomades livrés à eux-même. La pièce est écrite de bout en bout, comme un fil inéluctable, un destin qui se trace sans pouvoir le détourner de sa trajectoire. Une Jungle est une tentative, une prise de parole poétique, un besoin urgent de se saisir de la danse pour qu’elle soutienne ce premier pas vers l’autre. Chorégraphe :&nbsp;Sandrine Chaoulli.&nbsp;Interprètes :&nbsp;Tésia Peirat, Tanguy Allaire.&nbsp;Texte :&nbsp;Patrick Chamoiseau&nbsp;dit par&nbsp;Garniouze&nbsp;et&nbsp;Sandrine Chaoulli.&nbsp;Régie générale :&nbsp;Thierry Allaire.</p>  <p style=\"text-align: justify;\"><strong>21h Toy''Zik - Parc Massoure</strong><br>  Cet ensemble musical, issu de l''école de musique associative de la vallée, est composé d''une vingtaine de musiciens amateurs, avec instruments à vent (saxophones, trompettes, trombone, clarinette), batterie, percussions, guitares, claviers et chanteurs. Il est présent sur toutes sortes d''évènements avec un répertoire varié et enjoué (latino, rock, chansons populaires françaises et internationales) et sème la bonne humeur partout où il passe. Cette bande de joyeux lurons saura à coup sûr mettre l''ambiance et nous faire danser pour clôturer cette belle soirée de partage.</p>  <p><strong>Public&nbsp;</strong>Tout public<br>  <strong>Tarif&nbsp;</strong>Entrée libre<br>  <strong>Lieu </strong>Mairie et Parc Massoure</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '5649a31e-ef78-4839-97c4-3b1a5d2ce5cd');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('La grande marche pour l''accueil', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Événement Paroles d''Exil - La grande marche pour l''accueil<br>  Une programmation en partenariat avec l''association Accueil d''Azun, Jazz Pyr'', La Pourtère et la Toy Musique.</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les acteurs culturels de Luz-Saint-Sauveur et du Pays Toy se réunissent et s’unissent autour du projet de La grande marche pour l’accueil initiée par l’association Accueil Azun et leur festival Paroles d’Exils.&nbsp;Lors d’une soirée placée sous le signe de la fraternité et de l’égalité, les associations La Pourtère, Jazz Pyr’, Toy Musique et la Maison du Parc national et de la Vallée de Luz-Saint-Sauveur présenteront main dans la main avec la commune, le programme suivant&nbsp;:</p>  <p style=\"text-align: justify;\"><strong>18h Chorale de la Toy Musique - Mairie</strong><br>  La chorale de la Toy Musique est issue de l''école de musique associative de la vallée de Luz-Saint-Sauveur et du Pays Toy. Conduite par Nathalie Lascombe, accompagnée par Guy Guarric à la guitare, ce grand ensemble chante avec engagement et passion au travers d’un répertoire de reprises arrangées avec conviction et humanité.</p>  <p style=\"text-align: justify;\"><strong>18h30 - Déclaration communce : Parrainages et prises de paroles</strong></p>  <p style=\"text-align: justify;\"><strong>19h-23h Restauration et buvette sur place proposées par l''association La Pourtère</strong></p>  <p style=\"text-align: justify;\"><strong>20h Une jungle, sur le fil de l''exil. Compagnie Chao.S - Parc Massoure</strong><br>  Deux êtres tour à tour, bousculés, enlisés, percutés, écrasés, propulsés par une destinée qui s’impose à eux : l’exil.Leur jeu est dans l’action, celle qui nous fait avancer coûte que coûte.&nbsp;Une Jungle, c’est cette émotion brute générée par l’errance de corps nomades livrés à eux-même. La pièce est écrite de bout en bout, comme un fil inéluctable, un destin qui se trace sans pouvoir le détourner de sa trajectoire. Une Jungle est une tentative, une prise de parole poétique, un besoin urgent de se saisir de la danse pour qu’elle soutienne ce premier pas vers l’autre. Chorégraphe :&nbsp;Sandrine Chaoulli.&nbsp;Interprètes :&nbsp;Tésia Peirat, Tanguy Allaire.&nbsp;Texte :&nbsp;Patrick Chamoiseau&nbsp;dit par&nbsp;Garniouze&nbsp;et&nbsp;Sandrine Chaoulli.&nbsp;Régie générale :&nbsp;Thierry Allaire.</p>  <p style=\"text-align: justify;\"><strong>21h Toy''Zik - Parc Massoure</strong><br>  Cet ensemble musical, issu de l''école de musique associative de la vallée, est composé d''une vingtaine de musiciens amateurs, avec instruments à vent (saxophones, trompettes, trombone, clarinette), batterie, percussions, guitares, claviers et chanteurs. Il est présent sur toutes sortes d''évènements avec un répertoire varié et enjoué (latino, rock, chansons populaires françaises et internationales) et sème la bonne humeur partout où il passe. Cette bande de joyeux lurons saura à coup sûr mettre l''ambiance et nous faire danser pour clôturer cette belle soirée de partage.</p>  <p><strong>Public&nbsp;</strong>Tout public<br>  <strong>Tarif&nbsp;</strong>Entrée libre<br>  <strong>Lieu </strong>Mairie et Parc Massoure</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '5649a31e-ef78-4839-97c4-3b1a5d2ce5cd');
