INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le petit âge glaciaire dans les Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Conférence \"Le petit âge glaciaire dans les Pyrénées : 4 siècles d''une géohistoire climatique et environnementale des hautes altitudes\" -&nbsp;De Jean-Christophe Sanchez</strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\"><strong>Cette conférence s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les Nations Unies ont proclamé cette année 2025 comme Année internationale des glaciers et la disparition des dix-sept deniers glaciers pyrénéens se profile d’ici une décennie. Les hivers plus chauds et moins neigeux ont déjà eu raison des premières stations de ski désormais fantôme. Le réchauffement et le dérèglement climatiques de cette nouvelle ère qu’est l’anthropocène a succédé au Petit Âge Glaciaire qui correspond à une période de refroidissement climatique qui a duré environ du XIVe au XIXe siècle. Hivers rigoureux et plus longs, abondantes chutes de neiges et persistances des névés, avalanches dévastatrices, calendrier agricole raccourci, essor des appareils glaciaires… ont profondément marqué les populations pyrénéennes ainsi que les espaces et paysages des hautes altitudes.</p>  <p style=\"text-align: justify;\"></p>  <p>Jean-Christophe Sanchez est inspecteur académique et inspecteur pédagogique régionale, professeur agrégé, docteur en histoire moderne, chercheur-associé à l’université Jean-Jaurès et président de la Société Ramond.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes<br>  <strong>Photo&nbsp;</strong>Carte postale de la maison d’édition MITL Maurice Tesson Imprimeur Limoges. C. 1910</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f89f3b02-9bd5-4f1d-9b21-30d34a4bf5b6');
INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Le petit âge glaciaire dans les Pyrénées', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Conférence \"Le petit âge glaciaire dans les Pyrénées : 4 siècles d''une géohistoire climatique et environnementale des hautes altitudes\" -&nbsp;De Jean-Christophe Sanchez</strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\"><strong>Cette conférence s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les Nations Unies ont proclamé cette année 2025 comme Année internationale des glaciers et la disparition des dix-sept deniers glaciers pyrénéens se profile d’ici une décennie. Les hivers plus chauds et moins neigeux ont déjà eu raison des premières stations de ski désormais fantôme. Le réchauffement et le dérèglement climatiques de cette nouvelle ère qu’est l’anthropocène a succédé au Petit Âge Glaciaire qui correspond à une période de refroidissement climatique qui a duré environ du XIVe au XIXe siècle. Hivers rigoureux et plus longs, abondantes chutes de neiges et persistances des névés, avalanches dévastatrices, calendrier agricole raccourci, essor des appareils glaciaires… ont profondément marqué les populations pyrénéennes ainsi que les espaces et paysages des hautes altitudes.</p>  <p style=\"text-align: justify;\"></p>  <p>Jean-Christophe Sanchez est inspecteur académique et inspecteur pédagogique régionale, professeur agrégé, docteur en histoire moderne, chercheur-associé à l’université Jean-Jaurès et président de la Société Ramond.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle des voûtes<br>  <strong>Photo&nbsp;</strong>Carte postale de la maison d’édition MITL Maurice Tesson Imprimeur Limoges. C. 1910</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'f89f3b02-9bd5-4f1d-9b21-30d34a4bf5b6');
