INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Compagnie l''Arlequin', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>Représentations des différents groupes&nbsp;de la Compagnie de l’Arlequin.&nbsp;</p>  <p><strong>Vendredi 6 juin à 20h30&nbsp;</strong><br>  <em>Une clinique en folie</em></p>  <p><strong>Samedi 7 juin à 14h30</strong><br>  <em>Cendrillon dépoussiérée </em>suivi de <em>Un vrai p’tit bijou </em>et <em>Chacun son histoire</em> à 20h30</p>  <p><strong>Dimanche 8 juin à 14h</strong><br>  <em>Dormir cent ans</em> suivi de <em>Revanche</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'be9805aa-519a-4629-b312-91e821520873');
