INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Et après les glaciers ?', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Conférence \"Et après les glaciers\" - Présentée par&nbsp;Ludovic OLICARD&nbsp;accompagné de Nadine&nbsp;SAUTER&nbsp;du Conservatoire Botanique de Midi-Pyrénées</strong></p>  <p></p>  <p><strong>Cette conférence s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Les glaciers reculent à vitesse accélérée. Mais qu’en est-il des plantes qui font suite à la glace, et qui transforment petit à petit nos paysages de montagne ? Les premiers résultats des relevés de terrain révèlent une diversité végétale impressionnante qui s’installe rapidement suite à la fonte des glaces. De nouveaux écosystèmes pourraient se former dans ces marges si les plantes ont la capacité de coloniser ces terrains découverts. Découvrez les premiers résultats des études menées sur ces milieux lors de cette conférence.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle de spectacle<br>  <strong>Crédit photo </strong>O. Pasquet – Parc national des Pyrénées</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'b0cea2ee-9b22-4900-9085-422060601494');
