INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Évolution des glaciers des vallées des Gaves', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Conférence \"Évolution des glaciers des vallées des Gaves\"&nbsp;</strong></p>  <p><strong>Cette conférence s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p style=\"text-align: justify;\">Venez échanger avec un garde-moniteur du Parc national des Pyrénées pour en savoir plus sur les glaciers des vallées des Gaves. À l’aide d’un support vidéo, il expliquera comment l’évolution des glaciers est suivie et quelles en sont les conséquences pour l’écosystème montagnard.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle de spectacle<br>  <strong>Crédit photo</strong>&nbsp;: C. Sallaberry –&nbsp;Parc national&nbsp;des Pyrénées.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '91c801ab-2b04-47bd-b7d7-accc4c05e573');
