INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Rendez-vous des cimes"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>Spectacle \"Rendez-vous des cimes\"- proposé par le Parc national des Pyrénées</strong></p>  <p></p>  <p><strong>Ce spectacle s’inscrit dans le cadre du programme de sensibilisation du Parc national des Pyrénées, à l’occasion de l’Année internationale de la préservation des glaciers.</strong></p>  <p></p>  <p style=\"text-align: justify;\">Le Parc national des Pyrénées s’associe au réseau Éducation Pyrénées Vivantes pour vous donner un «&nbsp;Rendez-vous des cimes&nbsp;». Des estives aux glaciers, de la nuit aux lacs, plongez dans 7 univers pyrénéens. Un voyage sensible et poétique au cœur des Pyrénées pour poser un autre regard sur la cohabitation entre le monde humain et non humain. Venez découvrir au travers d’une promenade visuelle et sonore la richesse et les fragilités du massif et partager votre désir de montagne.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Tarif&nbsp;</strong>Libre accès<br>  <strong>Public&nbsp;</strong>Tout public<br>  <strong>Lieu&nbsp;</strong>Salle de spectacle</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '97acb4c5-f7e8-44ee-8255-e693d4663bc4');
