INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Les livreurs de mots', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p><strong>\"Les livreurs de mots\"<br>  Compagnie&nbsp;Cie de l''Illustre Corsaire</strong></p>  <p style=\"text-align: justify;\">Le Marché poétique à Luz St Sauveur… C''est dans leur camion-salon et sous les parapluies-cabines que Les Livreurs de Mots offriront aux oreilles gourmandes (des grands et des plus petits), une jardinière de textes rafraîchissants et feront germer l''imaginaire et l''émotion...<br>  <br>  Avec Rimbaud, Prévert, Rilke, Tardieu, Guillevic, Chédid, Luca, Aragon et bien d’autres…. Ils évoqueront l’Amour, le temps qui passe, les mystères de la nature, les Pyrénées …</p>  <p style=\"text-align: justify;\"><br>  Avec Rosemonde Cathala, Marc Lallement, Corinne Marsollier et, Anna Mazzoti</p>  <p></p>  <p><strong>Informations&nbsp;</strong><br>  Offert, de 17h à 21h<br>  Tout public<br>  Place du marché de Luz-Saint-Sauveur</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2175554b-dc74-4432-8a9e-b3ab04e8ed11');
