INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Ateliers  "Les failles du réel"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align:justify;\"><span style=\"font-size:13px;\"><strong>Ateliers -&nbsp; Les failles du réel - Compagnie le cirque Jafarson</strong></span></p>  <p style=\"font-style:normal;font-weight:400;text-decoration-style:initial;text-decoration-thickness:initial;\"><span style=\"font-size:13px;\">vendredi 11 juillet de 10h à 12h</span></p>  <p style=\"font-style:normal;font-weight:400;text-decoration-style:initial;text-decoration-thickness:initial;\"><span style=\"font-size:13px;\">mardi 22 juillet de 10h à 12h</span></p>  <p style=\"font-style:normal;font-weight:400;text-decoration-style:initial;text-decoration-thickness:initial;\"></p>  <p><span style=\"font-size:13px;\"><strong>Excursion avec l’A.R.F.E.D. – À la recherche des failles du réel</strong></span></p>  <p></p>  <p><span style=\"font-size:13px;\">Et si notre monde n’était pas aussi solide qu’il en a l’air ?</span><br>  <span style=\"font-size:13px;\">Rejoignez l’A.R.F.E.D., l’Amicale Révélatrice de Faille et d’Expertise en Décryptologie, le temps d’une excursion !</span></p>  <p><span style=\"font-size:13px;\">Nous partirons en balade à la recherche des&nbsp;failles du réel&nbsp;: ces fêlures discrètes dans notre quotidien, ces brèches presque invisibles qui laissent filtrer des éclats d’autres mondes.</span></p>  <p><span style=\"font-size:13px;\">Qu’est-ce qu’une faille du réel ?</span><br>  <span style=\"font-size:13px;\">C’est ce moment où un détail cloche, où le paysage semble vaciller, où un objet ou une situation révèle une étrangeté, une ouverture, un autre récit.</span></p>  <p></p>  <p><span style=\"font-size:13px;\"><strong>Au programme :</strong></span></p>  <p><br>  <span style=\"font-size:13px;\">Exploration sensible du terrain</span><br>  <span style=\"font-size:13px;\">Création de&nbsp;<i>carnets d’expédition</i>&nbsp;pour documenter nos trouvailles : dessins, textes, sons, objets récoltés ou inventés</span><br>  <span style=\"font-size:13px;\">Décryptage et discussion autour des indices relevés</span></p>  <p><span style=\"font-size:13px;\">Une aventure entre balade et pratique artistique.</span></p>  <p></p>  <p><span style=\"font-size:13px;\"><i>20 personnes maximum - tout enfant devra être accompagné d''un adulte responsable&nbsp;</i></span></p>  <p></p>  <p>CREDIT PHOTO JACK TEZAM</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '85ce2a05-6d27-4af4-8404-971478501620');
