INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Résidence "La légende de Colapesce" Cie Momatique', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Résidence \"La légende de Colapesce\"&nbsp;Compagnie Momatique</strong><br>  Réadaptation du conte écrit par Bruno Giannotta (2019)</p>  <p style=\"text-align: justify;\">Quelque part au sud de l''Italie, un homme initie son fils à la pêche en apnée. Au même moment, de l''autre côté de la Méditerranée, un migrant apprend à sa fille à faire la planche pour ne pas couler. Colapesce est un enfant de dix ans, il porte le nom d''un demi-dieu, un homme-poisson, personnage emblématique d''une ancienne légende de son pays. De l''autre côté de la mer du Milieu, en Afrique, Azuka attend avec son père le bateau qui les sauvera de la guerre qui est en train de ravager leur pays. Un matin, Colapesce apprend aux infos locales qu''un bateau s''est échoué près de son village. Il se rend sur les lieux et il découvre Azuka sur le point de se noyer.</p>  <p></p>  <p><strong>La Compagnie Momatique</strong></p>  <p style=\"text-align: justify;\">Nous sommes la compagnie pluridisciplinaire Momatique, créée en 2016 d’un goût partagé pour la création artistique par les membres fondateurs, les musiciens Jeff Manuel et Béatriz Salmeron Martin. Nos pratiques sont multiples, nous explorons aussi bien la musique que le conte et la danse. Nos créations sont riches de ces diverses influences qui se croisent au service d’un objectif bien précis : partager une expérience artistique avec un large public, enfants et familles, un temps suspendu de rêverie et de réflexion par la poésie et les émotions. La compagnie s’adresse à son public avec une approche méticuleuse afin d’éveiller l’attention et l’intérêt du spectateur dans une démarche d’échanges qui permettent l’appréhension de grands sujets, « comme des graines qu’on sème… ». Les sujets dont la compagnie s’empare justifient un travail de sensibilisation et d’éducation : protection de l’environnement, diversité culturelle, lutte contre les stéréotypes… La compagnie est basée en milieu rural dans le Gers et leurs créations sont en général accompagnées d’actions culturelles.</p>  <p>Pour en savoir plus : https://momatique.com/</p>  <p></p>  <p><strong>Informations&nbsp;</strong></p>  <p><strong>Résidence du lundi 29 septembre au vendredi 3 octobre<br>  Sortie de résidence, étape de création le vendredi 3 octobre à 18h</strong><br>  Offert, tout public dès 6 ans<br>  <em>Crédit dessin :&nbsp;Amélie Saavedra</em></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '46d7d988-b3a8-4812-a9c5-6abcdc401fc7');
