INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Qui, Que, Quoi ?" Carré Blanc Cie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Qui, Que, Quoi ?\" -&nbsp;Carré Blanc&nbsp;Cie<br>  Grandes questions pour petite enfance</strong><br>  Qui, que, quoi&nbsp;?&nbsp;célèbre la différence, danse la rencontre et chante le plaisir de vivre cela ensemble. Les trois danseuses et la musicienne parlent d’elles, de nous, de notre société, mais surtout laissent place à l’expression de leurs dissemblances pour en faire une force, un atout et imaginer un renouveau d’acceptation et d’inclusion.&nbsp;<br>  Parce que les petits ne jugent pas, que leur insatiable curiosité ne freine pas leur ardeur à aller vers l’autre,&nbsp;Qui&nbsp;? Que&nbsp;? Quoi&nbsp;?&nbsp;ne prend pas le parti d’être un manifeste, mais plutôt une vivifiante chorégraphie liant les pas de l’une dans ceux de l’autre pour construire et refléter la beauté des différences.</p>  <p style=\"text-align: center;\">Voix mêlées, souffles d’énergie, délice d’être ensemble…<br>  Qui du racisme, que du handicap, quoi du genre&nbsp;?&nbsp;<br>  Alors dansons, dansons et encore dansons, de concert, de front, de pair, du même pas, à l’unisson, en accord, en bloc, en chœur, en harmonie, en masse, en même temps, en entier en sororité&nbsp;!&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Carré Blanc Cie - Distribution</strong><br>  Pour en savoir plus sur la compagnie : https://carreblanccie.com/spectacles/qui-que-quoi-creation-2023-2024/<br>  Distribution : Chorégraphie : Yane Corfa, Michèle Dhallu et Bryan Montarou. Musique :&nbsp;Sophie Le Morzadec. Scénographie&nbsp;: Odile Stemmelin. Couture : Marie-Pierre Ufferte. Lumière&nbsp;: Yves-Marie Corfa. Régie&nbsp;: Franck Catoire. Interprétation : Juliette Fisson, Angeline Guiraudies, Capucine Bartholi, danseuses ; et Sophie Le Morzadec, musicienne. Crédit photo :&nbsp;Ian Grandjean&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Informations&nbsp;</strong><br>  Programmation scolaire, ouvert au public dans la limite des places disponibles, au tarif unique de 4€.<br>  Durée : 30 min<br>  Public : À partir de 1 an<br>  &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f5f3bea7-e123-461c-bb32-be23cc9167ff');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Qui, Que, Quoi ?" Carré Blanc Cie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Qui, Que, Quoi ?\" -&nbsp;Carré Blanc&nbsp;Cie<br>  Grandes questions pour petite enfance</strong><br>  Qui, que, quoi&nbsp;?&nbsp;célèbre la différence, danse la rencontre et chante le plaisir de vivre cela ensemble. Les trois danseuses et la musicienne parlent d’elles, de nous, de notre société, mais surtout laissent place à l’expression de leurs dissemblances pour en faire une force, un atout et imaginer un renouveau d’acceptation et d’inclusion.&nbsp;<br>  Parce que les petits ne jugent pas, que leur insatiable curiosité ne freine pas leur ardeur à aller vers l’autre,&nbsp;Qui&nbsp;? Que&nbsp;? Quoi&nbsp;?&nbsp;ne prend pas le parti d’être un manifeste, mais plutôt une vivifiante chorégraphie liant les pas de l’une dans ceux de l’autre pour construire et refléter la beauté des différences.</p>  <p style=\"text-align: center;\">Voix mêlées, souffles d’énergie, délice d’être ensemble…<br>  Qui du racisme, que du handicap, quoi du genre&nbsp;?&nbsp;<br>  Alors dansons, dansons et encore dansons, de concert, de front, de pair, du même pas, à l’unisson, en accord, en bloc, en chœur, en harmonie, en masse, en même temps, en entier en sororité&nbsp;!&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Carré Blanc Cie - Distribution</strong><br>  Pour en savoir plus sur la compagnie : https://carreblanccie.com/spectacles/qui-que-quoi-creation-2023-2024/<br>  Distribution : Chorégraphie : Yane Corfa, Michèle Dhallu et Bryan Montarou. Musique :&nbsp;Sophie Le Morzadec. Scénographie&nbsp;: Odile Stemmelin. Couture : Marie-Pierre Ufferte. Lumière&nbsp;: Yves-Marie Corfa. Régie&nbsp;: Franck Catoire. Interprétation : Juliette Fisson, Angeline Guiraudies, Capucine Bartholi, danseuses ; et Sophie Le Morzadec, musicienne. Crédit photo :&nbsp;Ian Grandjean&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Informations&nbsp;</strong><br>  Programmation scolaire, ouvert au public dans la limite des places disponibles, au tarif unique de 4€.<br>  Durée : 30 min<br>  Public : À partir de 1 an<br>  &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', 'f5f3bea7-e123-461c-bb32-be23cc9167ff');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Qui, Que, Quoi ?" Carré Blanc Cie', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>\"Qui, Que, Quoi ?\" -&nbsp;Carré Blanc&nbsp;Cie<br>  Grandes questions pour petite enfance</strong><br>  Qui, que, quoi&nbsp;?&nbsp;célèbre la différence, danse la rencontre et chante le plaisir de vivre cela ensemble. Les trois danseuses et la musicienne parlent d’elles, de nous, de notre société, mais surtout laissent place à l’expression de leurs dissemblances pour en faire une force, un atout et imaginer un renouveau d’acceptation et d’inclusion.&nbsp;<br>  Parce que les petits ne jugent pas, que leur insatiable curiosité ne freine pas leur ardeur à aller vers l’autre,&nbsp;Qui&nbsp;? Que&nbsp;? Quoi&nbsp;?&nbsp;ne prend pas le parti d’être un manifeste, mais plutôt une vivifiante chorégraphie liant les pas de l’une dans ceux de l’autre pour construire et refléter la beauté des différences.</p>  <p style=\"text-align: center;\">Voix mêlées, souffles d’énergie, délice d’être ensemble…<br>  Qui du racisme, que du handicap, quoi du genre&nbsp;?&nbsp;<br>  Alors dansons, dansons et encore dansons, de concert, de front, de pair, du même pas, à l’unisson, en accord, en bloc, en chœur, en harmonie, en masse, en même temps, en entier en sororité&nbsp;!&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Carré Blanc Cie - Distribution</strong><br>  Pour en savoir plus sur la compagnie : https://carreblanccie.com/spectacles/qui-que-quoi-creation-2023-2024/<br>  Distribution : Chorégraphie : Yane Corfa, Michèle Dhallu et Bryan Montarou. Musique :&nbsp;Sophie Le Morzadec. Scénographie&nbsp;: Odile Stemmelin. Couture : Marie-Pierre Ufferte. Lumière&nbsp;: Yves-Marie Corfa. Régie&nbsp;: Franck Catoire. Interprétation : Juliette Fisson, Angeline Guiraudies, Capucine Bartholi, danseuses ; et Sophie Le Morzadec, musicienne. Crédit photo :&nbsp;Ian Grandjean&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p><strong>Informations&nbsp;</strong><br>  Programmation scolaire, ouvert au public dans la limite des places disponibles, au tarif unique de 4€.<br>  Durée : 30 min<br>  Public : À partir de 1 an<br>  &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', 'f5f3bea7-e123-461c-bb32-be23cc9167ff');
