INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Le silence de nuit" Magari', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Le silence de nuit -&nbsp;Magari<br>  Spectacle en présence des autrices Mylène Souyeux&nbsp;et sa fille Yuna&nbsp;Buron</strong></p>  <p style=\"text-align: justify;\">Qu’est-ce que faire l’expérience de la différence ? Qu’est-ce que vivre de l’autre coté du fossé qui nous sépare de la “ norme “ ? Le système peut rapidement paraître inadapté face au questionnement d’un parent, à la solitude qu’il peut éprouver face à un fonctionnement trop souvent froid et distant. Ce texte est une invitation à chasser les tabous. Les gens ne savent pas toujours comment faire avec la différence, avec le handicap : l’incompréhension, la peur de la maladresse, la peur d’avoir des réactions non appropriées crée des barrières qui freinent la rencontre et limite la communication et la reconnaissance des personnes singulières dans leur pleine dimension.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Écrit par Mylène Souyeux&nbsp;et sa fille Yuna&nbsp;Buron, en situation de handicap,<em> Le silence de nuit</em>&nbsp;est leur parcours de résilience, c’est le jaillissement d’un vécu, d’une expérience fondatrice.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Un trio au seuil du Silence. Il nous entraînera dans la vie de Nuit, dans celle de sa Mère, et dans leur Monde. Le texte impose sa partition et la dramaturgie du spectacle, et par là-même, la construction de la musique. Et celle-ci nous nappe, portée pour les mots et par les mots, elle rend possible l''accès à l''invisible. Les pages des scènes de la vie de NUIT et de sa MÈRE se suivent et ne se ressemblent pas, parfois portées par la voix seule, parfois par la musique seule, et toutes les combinatoires possibles sont habilement convoquées sur une palette fine et extrêmement variée :</p>  <p style=\"text-align: center;\">Instants mélancoliques ou méditatifs…</p>  <p style=\"text-align: center;\">Explosions de colère ou de triomphe…</p>  <p style=\"text-align: center;\">Retenue allant jusqu''au murmure, au silence…</p>  <p style=\"text-align: center;\">Espaces plus bruitistes ou abstraits…</p>  <p style=\"text-align: center;\">Moment d''humour désillusionné…</p>  <p style=\"text-align: center;\">Jaillissements de lyrisme sans limite…</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Le trio Magari - Distribution</strong><br>  Pour en savoir plus&nbsp;: https://www.magari-trio.fr/<br>  Distribution : voix Merilù Solito, saxophone ténor Marc Maffiolo, batterie et effets voix Nicolas Poirier, textes Mylène Souyeux et Yuna Buron.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations</strong><br>  Ce spectacle est programmé en partenariat avec l''association Le Toy Social Club. La soirée débute avec une présentation de l''association suivie de la représentation.<br>  Tarifs spectacle : normal (à partir de 14 ans)&nbsp;10€, réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€,(pour les moins de 3 ans&nbsp;offert</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '414e0076-2395-40b3-9f5f-c65acc29af44');
