INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Rolls-Royce" Le collectif Suzette et Nora', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Rolls-Royce ou la tentative de sauvetage de nos imaginaires&nbsp;- Le Collectif Suzette et Nora</strong></p>  <p style=\"text-align: center;\">« L’histoire se répète toujours deux fois, la première comme une tragédie, la seconde comme une farce »&nbsp;<br>  K. Marx</p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Quatre entités venues d’un nulle-part aux confins des songes s’incarnent parce que le monde humain, paraît-il, court à sa perte. Elles s’inquiètent d’imaginaires dysfonctionnels qui ne parviennent plus à rêver ni à croire. Elles plongent dans les fictions auxquelles les humain·es s’accrochent, celles qui les ont façonné·es, et portent un regard attendri, amusé, et franchement critique sur cette manière incongrue de se raconter. Elles ont leur manière à elles et, sans prétention, très peu de doutes quant à leur capacité à sauver le monde. Après tout, il a bien fallu l’imaginer pour le créer. Elles installeront dans l’espace public quatre micros et un grand cercle de gradins où chacune et chacun sera invité à prendre place pour participer à une conférence qui utilise le théâtre comme rituel. Collectivement, nous enterrerons définitivement les figures de héros, nous briserons notre fascination pour les images plates et nous remettrons notre langage dans son vrai sens.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Le Collectif Suzette et Nora - Distribution</strong><br>  Le Collectif de théâtre de rue Suzette et Nora a été créé à Toulouse en 2021 sous l’impulsion des artistes Fanny Honoré et Nadège Rossato. Il défend une écriture de plateau originale pensée pour le hors-les-murs et portée par des femmes actrices-créatrices. La question centrale qui anime ses recherches dramaturgiques et esthétiques est comment retrouver une pulsion d’intensité, de désir et de rêve dans un contexte de crise ? Autrement dit : comment pouvons nous échapper collectivement (et avec humour) à notre condition ?&nbsp;Pour en savoir plus&nbsp;:&nbsp;https://collectifsuzetteetnora.fr/rolls-royce/</p>  <p style=\"text-align: justify;\"><br>  Distribution :&nbsp;Création et jeu&nbsp;Laurène Brun, Fanny Honoré, Nadège Rossato, Louise Tardif. Écriture collective&nbsp;coordonnée par Fanny Honoré. Sons, musiques et arrangements&nbsp;Aurélien Calvo. Production, diffusion, administration&nbsp;La Petite Prod 31</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Résidence du lundi 20 octobre au vendredi 24 octobre&nbsp;<br>  Sortie de résidence, étape de création, vendredi 24 octobre, 18h, au forum de Luz-Saint-Sauveur&nbsp;tout public, offert</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '1d424ad3-eaf9-4cf1-8f37-031cba1cd788');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Rolls-Royce" Le collectif Suzette et Nora', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Rolls-Royce ou la tentative de sauvetage de nos imaginaires&nbsp;- Le Collectif Suzette et Nora</strong></p>  <p style=\"text-align: center;\">« L’histoire se répète toujours deux fois, la première comme une tragédie, la seconde comme une farce »&nbsp;<br>  K. Marx</p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Quatre entités venues d’un nulle-part aux confins des songes s’incarnent parce que le monde humain, paraît-il, court à sa perte. Elles s’inquiètent d’imaginaires dysfonctionnels qui ne parviennent plus à rêver ni à croire. Elles plongent dans les fictions auxquelles les humain·es s’accrochent, celles qui les ont façonné·es, et portent un regard attendri, amusé, et franchement critique sur cette manière incongrue de se raconter. Elles ont leur manière à elles et, sans prétention, très peu de doutes quant à leur capacité à sauver le monde. Après tout, il a bien fallu l’imaginer pour le créer. Elles installeront dans l’espace public quatre micros et un grand cercle de gradins où chacune et chacun sera invité à prendre place pour participer à une conférence qui utilise le théâtre comme rituel. Collectivement, nous enterrerons définitivement les figures de héros, nous briserons notre fascination pour les images plates et nous remettrons notre langage dans son vrai sens.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Le Collectif Suzette et Nora - Distribution</strong><br>  Le Collectif de théâtre de rue Suzette et Nora a été créé à Toulouse en 2021 sous l’impulsion des artistes Fanny Honoré et Nadège Rossato. Il défend une écriture de plateau originale pensée pour le hors-les-murs et portée par des femmes actrices-créatrices. La question centrale qui anime ses recherches dramaturgiques et esthétiques est comment retrouver une pulsion d’intensité, de désir et de rêve dans un contexte de crise ? Autrement dit : comment pouvons nous échapper collectivement (et avec humour) à notre condition ?&nbsp;Pour en savoir plus&nbsp;:&nbsp;https://collectifsuzetteetnora.fr/rolls-royce/</p>  <p style=\"text-align: justify;\"><br>  Distribution :&nbsp;Création et jeu&nbsp;Laurène Brun, Fanny Honoré, Nadège Rossato, Louise Tardif. Écriture collective&nbsp;coordonnée par Fanny Honoré. Sons, musiques et arrangements&nbsp;Aurélien Calvo. Production, diffusion, administration&nbsp;La Petite Prod 31</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations&nbsp;</strong><br>  Résidence du lundi 20 octobre au vendredi 24 octobre&nbsp;<br>  Sortie de résidence, étape de création, vendredi 24 octobre, 18h, au forum de Luz-Saint-Sauveur&nbsp;tout public, offert</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '1d424ad3-eaf9-4cf1-8f37-031cba1cd788');
