INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"La nuit d''Elif" Compagnie A Noise', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>La nuit d''Elif - Compagnie A Noise</strong></p>  <p style=\"text-align: center;\">titre provisoire</p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">\"La Nuit d''Élif \" est un spectacle visuel et musical immersif qui plonge le jeune public dans un voyage sensoriel à travers la nuit. Dans sa course pour rattraper les Perséides, la petite étoile&nbsp; Élif découvre la beauté&nbsp; du monde terrestre. Elle survole des forêts mystérieuses, traverse des aurores boréales éblouissantes et contemple de vastes plaines au clair de lune. Du crépuscule au lever du jour, elle assiste à la grande symphonie de la nuit et découvre la poésie du monde nocturne. La musique interprétée en direct par la chanteuse Annoïe - Anne Roy accompagnera ce périple au gré d''improvisations libres et joueuses, de bruitismes&nbsp; électroniques, de chants du monde et de compositions originales.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Compagnie A Noise - Distribution</strong><br>  Distribution :&nbsp;Conception - composition musicale - interprétation : Annoïe - Anne Roy. Dramaturgie : Annoïe, Cannelle Perré, Célina Guiné. Scénographie et création lumière : Cannelle Perré -&nbsp;LucieCaillis. Illustration : Célina Guiné. Régie : Lucie Caillis</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Résidence artistique en collaboration avec l''association Jazz Pyr''<br>  Sans sortie de résidence</strong></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '3acfb9c2-c6ea-4b48-a553-7fef2546483a');
