INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Mère" Amanda Righetti', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Mère - Amanda Righetti<br>  Résidence artistique</strong></p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Amanda Righetti est comedienne et acrobate. Elle travaille à la création d''un solo qui aborde les premières années de la maternité avec toutes les transformations que ce moment implique. Une mise en mots et en corps de ses questionnements et de son regard sur ce que signifie de devenir Mère.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong><br>  Écriture et interprétation Amanda Righetti. Mise en scène Pauline Dau. Composition Musicale Aurélien Calvo. Technique, scénographie Charles Rousseau. Production Diffusion Pollen Production.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '09f89762-b0f8-4e5d-8fac-0ed612a989b2');
