INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Grandes Surfaces" Cie L''annexe', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Grandes Surfaces - Compagnie L''Annexe<br>  Baptiste Amann</strong></p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Quand Baptiste Amann a découvert l’album&nbsp;L’école du micro d’argent&nbsp;du groupe IAM, c’était au casque audio sur l’une de ces bornes d’écoute que l’on trouvait alors dans les centres commerciaux. C’était à Avignon, en avril 1997. Il avait 11 ans et se souvient du choc sensible, considérable, qui l’a traversé. De cette expérience fondatrice, il tire un monologue personnel qui dit l’importance fondamentale de cet album dans sa construction. Comme un aveu de faiblesse, il parle aussi des motifs de la superficialité de sa jeunesse, du sentiment d’illégitimité, et il se rappelle qu’on n’est pas tous « nés sous la même étoile ». Un spectacle poétique, politique, sensible, qui parle de musique, ce qui revient immanquablement à parler d’intimité.</p>  <p></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Distribution</strong><br>  Ce texte a été créé suite à une commande de la compagnie Ouvre le Chien (Renaud Cojo) pour le festival Discotake à Bordeaux. Renaud Cojo est également invité cette saison avec&nbsp;While my guitar gently weeps. Texte et interprétation&nbsp;Baptiste Amann&nbsp;/ production&nbsp;Morgan Helou. Crédit photo&nbsp;Xavier Cantat.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations</strong><br>  Dès 12 ans, 45 min, programmation en partenariat avec le Parvis Scène nationale Tarbes Pyrénées<br>  Découvrez la carte blanche cinéma de Baptiste Amann à Luz-Saint-Sauveur durant cette soirée<br>  Tarifs et inscriptions via la billeterie du Parvis :&nbsp;normal 12€, réduit 6€, -26 ans 6€, abonné 8€</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '284c3522-5a5d-4c4b-b21d-d8e48be2fb60');
