INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Manger un phoque" Cie Les Jolies Choses', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Manger un phoque - Compagnie Les Jolies Choses</strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\">Dans cette histoire deux univers se font échos. D’un coté, Picot, élevé par sa sœur et son frère, qui s’endort dans le bus de Monsieur Gustave tous les jours et qui, au lieu d’aller à l’école, descend au terminus pour errer dans un zoo désaffecté. Dans ce zoo il retrouve Madame Sue sur un banc, au milieu des cages ouvertes. De l’autre coté une bande d’animaux s’échappe d’un zoo en quête d’un avenir meilleur. Les deux histoires se répondent en questionnant les notions de voyage, de migration, de quête de soi et de vivre ensemble.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Compagnie Les Jolies Choses&nbsp;- Distribution</strong><br>  Pour en savoir plus sur la compagnie :&nbsp;http://www.compagnielesjolieschoses.fr/<br>  Distribution : de Sophie Merceron, au plateau Mélia Bannerman, Sophie Barros, Laurie Montamat,&nbsp;création lumière Bastien Sallaberry, regards extérieurs Amélie Gasparrotto et Maryline Petioch, production Compagnie Les Jolies Choses, crédit photo Mupcedrick<br>  Dans son processus de création la compagnie accorde un temps conséquent à la recherche et défend une méthode de création basée sur : une mise en scène collective , un travail choral, spatial, corporel et rythmique, une approche sensible de la narration, qui traite de problématiques liées à l’enfance.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations</strong><br>  Dès 6 ans, 50&nbsp;min.<br>  Tarifs spectacle : normal (à partir de 14 ans)&nbsp;10€, réduit&nbsp;(de 3 à 13 ans inclus + étudiant) 7€,(pour les moins de 3 ans&nbsp;offert</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2dd7c261-4cee-4aeb-bd0f-07ca40e75fa6');
