INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Ami.e" Cie La Muse', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Ami.e - Compagnie La Muse<br>  résidence artistique - étape de création</strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\">Suite à de longues années d’amitié qui nous ont nourries, portées, construites, le prochain spectacle souhaite être une éloge de l’amitié. Le travail philosophique de Geoffroy de Lagasnerie avec « L’éloge de l’amitié »*, d’Alice Raybaud avec « Nos puissantes amitiés »*, ont appuyé le caractère essentiel de ces relations dans nos vies au point d’être un enjeu sociétal. « L’amitié est un espace où l’on apprend chacun à se grandir » dit Alice Raybaud. Dès ses premiers pas, l’enfant rencontre l’Autre et commence des liens d’amitié qui vont l’accompagner dans son épanouissement personnel de la même manière que ses relations intra familiales. Dans notre société contemporaine où l’amitié est peu valorisée, il nous semble important de la remettre sur le<br>  devant de la scène et de lui redonner sa part belle. L’amitié c’est du jeu, c’est du lien, du don, du contre-don, de la construction d’imaginaires communs, autant d’espaces également constitutifs de l’art. Un terrain de jeu qui nous met en joie parce qu’il est propice à la poésie et à la création. La parole des enfants tiendra aussi une place essentielle. Elle est à la fois brute et légère. Et nous aimons l’idée que ce soit des enfants qui s’adressent à d’autres enfants. Enfin la musique au coeur de notre création, essentielle et vaste, nous continuerons à asp’ puyer sur elle, comme un rebond ou un écho à nos propos.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Compagnie La Muse - Distribution</strong><br>  Pour en savoir plus sur la compagnie :&nbsp;https://www.cielamuse.com/<br>  Distribution : artistes (compositrices, musiciennes) Charlène Moura et Sophie Boudieux, regard extérieur Sabrina Chézeau, création lumières&nbsp;Mathieu Maisonneuve, constructeur&nbsp;Antoine Bersoux, graphiste, illustratrice&nbsp;Evelyne Mary.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations</strong><br>  Dès 2&nbsp;ans, 35&nbsp;min.<br>  &nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'ed60841b-0c99-47e3-8ef9-1d53a90726d3');
