INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Atlas de l''anthropocène" Cie Vertical Détour', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>\"Atlas de l''anthropocène\" -&nbsp; De la morue, cartographie 6<br>  Compagnie Vertical Détour,&nbsp;&nbsp;Frédéric Ferrer<br>  &nbsp;Théâtre humour</strong></p>  <p></p>  <p style=\"text-align: justify;\">On connaît l’histoire. La morue a façonné pendant plus de 5 siècles les paysages et la vie des êtres humains, alimenté un commerce triangulaire puissant, lancé l’économie-monde, fondé le libéralisme, permis l’indépendance et la montée en puissance des Etats-Unis et nourri les esprits et les ventres de millions d’êtres humains sur tous les continents. Mais la morue était trop belle... et fut victime de son succès. Ce poisson, emblématique de la folie destructrice de l’espèce humaine, est parti. La morue n’est plus là. Et maintenant les humains l’attendent... et désespèrent de son retour...<br>  Mais une morue peut-elle revenir&nbsp;? La question est évidemment essentielle.</p>  <p></p>  <p><strong>Compagnie&nbsp;Vertical Détour&nbsp;- Distribution</strong><br>  Pour en savoir plus sur la compagnie :&nbsp;https://www.verticaldetour.fr/</p>  <p></p>  <p><strong>Informations</strong><br>  Dès 14 ans, 1h20min.<br>  Tarifs Parvis : normal 12€, réduit 6€, -26 ans 6€, abonné 8€. Réservation via la billetterie du Parvis scène nationale : https://www.parvis.net/spectacle-vivant/atlas-de-lanthropocene</p>  <p></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '98001d52-d9a8-419e-8762-14a6e95c2904');
