INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES (' "Le poisson Belge" Cie du Baluchon', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Le poisson Belge - Compagnie du Baluchon<br>  résidence artistique - étape de création</strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\">Grande Monsieur, un vieux garçon solitaire, voit sa vie bien ordonnée bouleverssée par l’intrusion de Petit Fille. Sommé de prendre en charge la jeune orpheline, il l’aide à faire le deuil de ses parents, selon un rituel venu du Japon, tandis qu’elle le pousse à révéler et à accepter sa vraie nature en dépassant les traumatismes du passé, en achevant un deuil en suspens et en reprenant ce qui lui a été retiré.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Note d’intention</strong><br>  Ce texte est un jeu de piste, incitant à rassembler les pièces qui révèlent progressivement l’identité de ces personnages jusqu’au puzzle complet: à l’image du résultat de l’équation mathématique qu’ils peinent à résoudre ensemble au début de la pièce, ils sont une seule et même personne.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Petit mot sur l’équipe</strong><br>  Anaïs a commencé le théâtre dans les ateliers du Baluchon avec Patrick Lode, c’est professionnalisé au sein de cette même compagnie. Après de nombreuses créations et de collaborations, ils ont décidé de se lancer dans l’aventure au plateau dans un duo touchant, retraçant une histoire d’amitié improbable.</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie du Baluchon - distribution</strong><br>  La compagnie du Baluchon de Tarbes est une association dédiée aux arts du spectacle vivant. Créée en 1990, elle développe des créations théâtrales professionnelles, propose des actions culturelles et anime des ateliers de théâtre amateur, s''investissant tant en milieu rural qu''urbain. Pour en savoir plus sur la compagnie<b>&nbsp;:&nbsp;Fb</b> Compagnie du Baluchon&nbsp;<b>Instagram</b> compagnie_du_baluchon<br>  Distribution : Grand Monsieur Patrick Lode, Petit fille Anaïs Fauth,&nbsp;équipe&nbsp;Bastien Sallabery (technique),&nbsp;Patrick Lode (comédien + prod),&nbsp;Anaïs Fauth (comédienne + communication),&nbsp;Regard extérieur : <i>en cours,&nbsp;</i>auteur Leonore Confino</p>  <p style=\"text-align: justify;\"><br>  <strong>Informations&nbsp;</strong><br>  Résidence du lundi 26 janvier au vendredi 30 janvier<br>  Sortie de résidence vendredi 30 janvier à 18h<br>  À partir de 12 ans, durée 1h (création en cours)</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '90bd0264-1cbc-440a-9ae4-b46951db064f');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES (' "Le poisson Belge" Cie du Baluchon', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Le poisson Belge - Compagnie du Baluchon<br>  résidence artistique - étape de création</strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\">Grande Monsieur, un vieux garçon solitaire, voit sa vie bien ordonnée bouleverssée par l’intrusion de Petit Fille. Sommé de prendre en charge la jeune orpheline, il l’aide à faire le deuil de ses parents, selon un rituel venu du Japon, tandis qu’elle le pousse à révéler et à accepter sa vraie nature en dépassant les traumatismes du passé, en achevant un deuil en suspens et en reprenant ce qui lui a été retiré.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Note d’intention</strong><br>  Ce texte est un jeu de piste, incitant à rassembler les pièces qui révèlent progressivement l’identité de ces personnages jusqu’au puzzle complet: à l’image du résultat de l’équation mathématique qu’ils peinent à résoudre ensemble au début de la pièce, ils sont une seule et même personne.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Petit mot sur l’équipe</strong><br>  Anaïs a commencé le théâtre dans les ateliers du Baluchon avec Patrick Lode, c’est professionnalisé au sein de cette même compagnie. Après de nombreuses créations et de collaborations, ils ont décidé de se lancer dans l’aventure au plateau dans un duo touchant, retraçant une histoire d’amitié improbable.</p>  <p style=\"text-align: justify;\"><br>  <strong>Compagnie du Baluchon - distribution</strong><br>  La compagnie du Baluchon de Tarbes est une association dédiée aux arts du spectacle vivant. Créée en 1990, elle développe des créations théâtrales professionnelles, propose des actions culturelles et anime des ateliers de théâtre amateur, s''investissant tant en milieu rural qu''urbain. Pour en savoir plus sur la compagnie<b>&nbsp;:&nbsp;Fb</b> Compagnie du Baluchon&nbsp;<b>Instagram</b> compagnie_du_baluchon<br>  Distribution : Grand Monsieur Patrick Lode, Petit fille Anaïs Fauth,&nbsp;équipe&nbsp;Bastien Sallabery (technique),&nbsp;Patrick Lode (comédien + prod),&nbsp;Anaïs Fauth (comédienne + communication),&nbsp;Regard extérieur : <i>en cours,&nbsp;</i>auteur Leonore Confino</p>  <p style=\"text-align: justify;\"><br>  <strong>Informations&nbsp;</strong><br>  Résidence du lundi 26 janvier au vendredi 30 janvier<br>  Sortie de résidence vendredi 30 janvier à 18h<br>  À partir de 12 ans, durée 1h (création en cours)</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '90bd0264-1cbc-440a-9ae4-b46951db064f');
