('968451e4-221b-441a-8898-1fd8bfab446a', 'evenement', true, false, NULL, '2025-09-10T22:00:00.000Z', '2025-09-10T22:00:00.000Z', NULL, NULL, NULL, NULL, NULL, '2025-09-10T22:00:00.000Z', '2025-09-10T22:00:00.000Z');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Visite accompagnée "Pourquoi tant de laine ?" ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Visite accompagnée de l''exposition \"Pourquoi tant de laine ?\" de Natacha Sansoz</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Un moment de partage avec Natacha Sansoz pour découvrir les coulisses de sa démarche.</strong></p>  <p style=\"text-align: justify;\">À travers une visite guidée en sa compagnie, l’artiste Natacha Sansoz vous invite à découvrir son univers et les coulisses de sa recherche autour de la laine. Entre pratiques ancestrales et démarches contemporaines, son travail mêle art textile, performance et anthropologie. Cette rencontre sera l’occasion d’en apprendre davantage sur sa résidence itinérante dans les Pyrénées et sur La Colporteuse, personnage nomade qui l’accompagne dans sa collecte de gestes, d’histoires et de savoir-faire liés à la laine.</p>  <p style=\"text-align: justify;\">Pour prolonger la soirée, nous vous proposons à 20h30 la projection du film \"Enfant de la montagne en Pays Toy\" du réalisateur Philippe Armary, tarifs cinéma.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Exposition du 12 au 27 septembre</strong><br>  Libre accès sur les horaires d’ouverture, tout public, salle des voûtes.</p>  <p style=\"text-align: justify;\"><strong>Jeudi 11 septembre à 18h&nbsp;</strong><br>  Visite accompagnée de l’exposition, suivie à 20h30 de la projection du film Enfant de la montagne en Pays Toy du réalisateur Philippe Armary, tarifs cinéma.</p>  <p style=\"text-align: justify;\"><strong>Samedi 27 septembre 10h à 12h</strong><br>  Visite accompagnée de l’exposition.</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '968451e4-221b-441a-8898-1fd8bfab446a');
