INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Visite accompagnée "Pourquoi tant de laine ?" ', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Visite accompagnée de l''exposition \"Pourquoi tant de laine ?\" de Natacha Sansoz</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Partez à la découverte de l’exposition avec les membres de l''associaiton TRAM.E.</strong></p>  <p style=\"text-align: justify;\">Les membres de l’association TRAM.E vous proposent une visite commentée de l’exposition consacrée au travail de Natacha Sansoz. L’occasion de découvrir l’univers de l’artiste, son approche de la laine à travers les pratiques artisanales et les savoir-faire collectés dans les Pyrénées et à l’étranger. Cette rencontre permettra également de mieux comprendre le rôle de La Colporteuse, personnage central de sa résidence itinérante, et les enjeux culturels et sociaux qui traversent la filière laine.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Exposition du 12 au 27 septembre</strong><br>  Libre accès sur les horaires d’ouverture, tout public, salle des voûtes.</p>  <p style=\"text-align: justify;\"><strong>Samedi 27 septembre 10h à 12h</strong><br>  Visite accompagnée de l’exposition.</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '07f76de0-e833-4208-a2d7-c53d4ec91366');
