INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Voyage Sauvage" Agustin "Mole" Peláez', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Voyage Sauvage\" - De Agustin \"Mole\" Peláez</strong><br>  Plongez dans l’univers vibrant et onirique de l’artiste argentin Agustin “Mole” Peláez.</p>  <p style=\"text-align: justify;\">Avec ses toiles aux couleurs éclatantes, il nous invite à un voyage sauvage au cœur de mondes fantastiques, peuplés d’animaux mythiques, de paysages luxuriants et de symboles profondément enracinés dans les cultures d’Amérique du Sud.&nbsp;</p>  <p style=\"text-align: justify;\">Huiles, acryliques, crayons et marqueurs deviennent les outils de son imaginaire débordant. Chaque œuvre révèle un équilibre entre spontanéité et précision, entre rêve et réalité, où les traditions, les plantes, les vêtements et les esprits de la terre prennent vie dans un foisonnement chromatique.</p>  <p style=\"text-align: justify;\">Cette exposition est une ode à la vitalité et à la diversité sud-américaine, mais aussi une invitation à se perdre dans des univers parallèles, où l’énergie primitive et la poésie visuelle se rencontrent.</p>  <p style=\"text-align: justify;\">Laissez-vous emporter par ce voyage sauvage – une traversée sensorielle, où l’art devient un pont entre l’intime et l’universel.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Du 1er octobre&nbsp;au 30 octobre</strong><br>  Libre accès sur les horaires d’ouverture, tout public, salle des voûtes.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f2ad3c63-c42a-4b7e-9c1a-fc347bce5dfa');
