INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Ce que la roche nous raconte - Lila Ogier & Zoé B. Tapàl', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Ce que la roche nous raconte\" - De&nbsp;Lila Ogier &amp; Zoé B. Tapàl</strong><br>  Itinérance artistique et expérimentations plastiques du paysage.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Artistes pluridisciplinaires, Lila et Zoé mêlent leurs regards et pratiques pour la première fois lors de cette exposition. Toutes deux sensibles au monde qui les entoure, à l’empreinte du temps sur le paysage, elles aiment arpenter, recueillir fragments et textures de ce qu’elles peuvent observer autour d’elles et tentent de saisir l’imperceptible de ces lieux. En septembre 2025, Lila et Zoé partent en itinérance et en autonomie dans les montagnes alentour durant plusieurs jours. Au creux des cirques, en haut des crêtes, à flanc de collines, leurs rythmes de marche et leurs pratiques s’accorderont pour retracer l’expérience sensible de leurs corps déambulant dans l’immensité de la roche. Alors chaque détail, chaque ligne constituant le paysage et faisant chemin, peut devenir support, trace, espace de création.&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Du vendredi 28 novembre au dimanche 4&nbsp;janvier 2026<br>  Vernissage le vendredi 12 décembre à 18h</strong><br>  Libre accès sur les horaires d’ouverture, tout public, salle des voûtes.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'f4d1573c-d549-4ad2-9ee8-53cf905382c4');
