INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Glaciers des Pyrénées - Lilian Cazabet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Glaciers des Pyrénées\" - De&nbsp;Lilian Cazabet</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">L’exposition “Glaciers des Pyrénées” est constituée de 27 photos prises par Lilian Cazabet entre 2020 et 2024 dans les Pyrénées, autour du massif du Vignemale. L’objectif a été de documenter plusieurs missions scientifiques de l’association Moraine, experte des glaciers pyrénéens. Dans le cadre de la Journée Mondiale de l’Eau 2025 - sur le thème des glaciers - la Maison Garonne a choisi d’imprimer ces photos afin de sensibiliser le grand public aux caractéristiques des glaciers et d’alerter sur leur dangereux déclin.&nbsp;</p>  <p style=\"text-align: justify;\">Lilian Cazabet vit et travaille comme photojournaliste dans les Pyrénées centrales. Ses sujets de reportage s''orientent vers la campagne et les montagnes pyrénéennes - lieux dans lesquels il a grandi - et sur celles et ceux qui habitent ces territoires pour les mettre en lumière.</p>  <p style=\"text-align: justify;\">Sciences et art se conjuguent à Maison Garonne à travers des expositions temporaires, des animations et des conférences. Ce lieu multiculturel permet aussi de renouer avec le fleuve Garonne grâce son exposition permanente qui met en valeur le patrimoine naturel, culturel et historique du fleuve. Construite sur les vestiges d''une ancienne scierie / batellerie, la Maison Garonne voit le jour en 2019 grâce à un contrat environnement proposé par le réseau Natura 2000.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Du samedi 01 novembre au dimanche 23 novembre&nbsp;</strong><br>  Libre accès sur les horaires d’ouverture, tout public, salle des voûtes.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '9d30ad37-209f-4eab-a12e-3c2535f151a8');
INSERT INTO exposition_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Glaciers des Pyrénées - Lilian Cazabet', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\"><strong>Exposition \"Glaciers des Pyrénées\" - De&nbsp;Lilian Cazabet</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">L’exposition “Glaciers des Pyrénées” est constituée de 27 photos prises par Lilian Cazabet entre 2020 et 2024 dans les Pyrénées, autour du massif du Vignemale. L’objectif a été de documenter plusieurs missions scientifiques de l’association Moraine, experte des glaciers pyrénéens. Dans le cadre de la Journée Mondiale de l’Eau 2025 - sur le thème des glaciers - la Maison Garonne a choisi d’imprimer ces photos afin de sensibiliser le grand public aux caractéristiques des glaciers et d’alerter sur leur dangereux déclin.&nbsp;</p>  <p style=\"text-align: justify;\">Lilian Cazabet vit et travaille comme photojournaliste dans les Pyrénées centrales. Ses sujets de reportage s''orientent vers la campagne et les montagnes pyrénéennes - lieux dans lesquels il a grandi - et sur celles et ceux qui habitent ces territoires pour les mettre en lumière.</p>  <p style=\"text-align: justify;\">Sciences et art se conjuguent à Maison Garonne à travers des expositions temporaires, des animations et des conférences. Ce lieu multiculturel permet aussi de renouer avec le fleuve Garonne grâce son exposition permanente qui met en valeur le patrimoine naturel, culturel et historique du fleuve. Construite sur les vestiges d''une ancienne scierie / batellerie, la Maison Garonne voit le jour en 2019 grâce à un contrat environnement proposé par le réseau Natura 2000.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Du samedi 01 novembre au dimanche 23 novembre&nbsp;</strong><br>  Libre accès sur les horaires d’ouverture, tout public, salle des voûtes.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '9d30ad37-209f-4eab-a12e-3c2535f151a8');
