INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Miroir" Cie Filao', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>\"Miroir\" - Compagnie Filao<br>  Duo chorégraphique</strong></p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: center;\">Et si on jouait à être quelqu''un d''autre<br>  et si on s''explorait dans nos reflets<br>  et si on se regardait yeux dans les yeux<br>  &nbsp;</p>  <p style=\"text-align: center;\">Mille fois nous pouvons changer,<br>  mille choses nous pouvons danser,<br>  mille facettes nous pouvons regarder.<br>  &nbsp;</p>  <p style=\"text-align: center;\">\" MIROIЯ \" c''est l''histoire de deux êtres qui cherchent à se connaître.<br>  Magnifiques dans leur reflet, ils sont pourtant envahis par la crainte de l''autre et d''eux même, la peur de ne pas être comme il faut.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Propos</strong><br>  « MIROIЯ » est une réflexion sur le regard que l''on se porte en lien avec celui de l''autre. Le point de départ est issu du mythe de Narcisse évoquant la découverte de son propre reflet et les sensations qu''il suscite. Dans cette pièce chorégraphique il s''agit d''aborder l''image comme potentiel vecteur de lien ou au contraire comme révélateur d''un manque d''amour propre. Immensément présent dans notre société l''action de se mirer est-elle vraiment une preuve de narcissisme ou révèle-t-elle paradoxalement un manque d''estime de soi ? Cette pièce chorégraphique invite ainsi à se questionner sur les changements de perception de soi qui évoluent avec l''histoire intime de chacun. Les figures que l''on découvre plongent progressivement dans l''intimité de l''autre pressentant qu''ils ont peut-être les mêmes peurs, les mêmes blessures. Ils nous invitent ainsi à les comprendre et à questionner la manière dont on arrive à se détacher de l''image de soi pour enfin créer un espace de rencontre. Les figures que l''on découvre plongent progressivement dans l''intimité de l''autre, comprenant, pressentant qu''ils ont peut-être les mêmes peurs, les mêmes blessures. Ils vont nous laisser entrevoir ce qui se cache derrière leurs apparences pour offrir une danse passant de l''extimité à l''intimité.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Compagnie Filao - Distribution</strong><br>  Pour en savoir plus sur la compagnie :&nbsp;https://ciefilao.com/<br>  Mise en scène &amp; Chorégraphie&nbsp;Géraldine Borghi<br>  Interprétation&nbsp;Géraldine Borghi &amp;&nbsp;Privaël Burkhard<br>  Création musicale&nbsp;Laurent Avizou<br>  Costumes&nbsp;Elodie Sellier<br>  Création lumières&nbsp;Amandine Richaud<br>  Création graphique&nbsp;Milan Bismuth-Kimpé<br>  Chargée de production&nbsp;Marie Ousset<br>  Crédit photo :&nbsp;Marie Ousset<br>  Coproduction&nbsp;Ville de Colomiers et le Théâtre du Grand Rond à Toulouse<br>  Soutiens &amp; Résidences&nbsp;Ville de Colomiers, Conservatoire de Colomiers, Département de la Haute-Garonne, Centre culturel de la Brique de Toulouse et la Ville de Toulouse<br>  La création Miroir a été sélectionnée dans le cadre de l’Appel à projet Les Hivernales #2 de la Ville de Toulouse</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"><strong>Informations</strong><br>  Dès 3&nbsp;ans, 35min<br>  Cette séance est complète (programmation scolaire)</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Licences&nbsp;spectacle L1-R-25-3328 L3-R-25-3332</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '2d269421-bcb7-49d8-8f45-db3746d88287');
