INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Journée Battle', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Journée de battle - Dans6T</strong></p>  <p style=\"text-align: center;\"></p>  <p><strong>Déroulé du programme : </strong><br>  &nbsp;</p>  <p><strong>15h30 : \"Des danses &amp; des luttes\" - conférence-dansée- Durée : 1h30</strong></p>  <p><strong>17h-17h45 : Goûter</strong></p>  <p><strong>17h45-19h : \"Battle all style enfants\" (jusqu''à 13 ans)</strong></p>  <p><strong>20h30 : Film Yoroï de&nbsp;David Tomaszewski (interdit -12 ans)</strong></p>  <p></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Chorégraphe et directeur artistique de la Cie Dans6T, Bouziane Bouteldja découvre le breakdance lors d’un stage avec Tayeb Benamara. En 2001, il fonde Dans6T, un centre de danse à Tarbes puis crée sa compagnie en 2007 et y développe un travail d’auteur en tissant des liens entre Art et Société. À son répertoire, quinze spectacles qui auscultent le pouls de nos sociétés contemporaines : l’identité, les discriminations, la religion, l’ego, la mort, la malbouffe, les migrations, la jeunesse, le dialogue entre les peuples... Des thématiques qui résonnent avec le parcours de vie du chorégraphe qui place, au cœur de ses réflexions, la pratique de la danse comme vecteur d’émancipation et comme exutoire d’une histoire personnelle. Un axe incontournable de son projet artistique qu’il continue à transmettre aujourd’hui le plus largement possible avec toujours autant d’engagement et de cœur. Bouziane Bouteldja est Membre de la Zulu Nation et Chevalier des Arts et des Lettres.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Crédit photo :&nbsp;<strong>Pamela Perschke</strong></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '349d7825-ec89-426e-afdb-ea9599513625');
