INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Entre Plumes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: justify;\">Vous aimez la lecture et le partage?&nbsp;un petit groupe de l''association Entre Plumes vous propose de participer à des rencontres (fréquence et modalités à définir) pour partager nos coups de cœur après avoir arpenté les rayons de la médiathèque.&nbsp;Premier RDV le lundi 24 novembre à 17h30&nbsp;dans la salle des voûtes de la Maison de la Vallée.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'a8a2a2b8-431f-4b26-9f8e-0b9d30345af2');
