INSERT INTO parc_national_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Hors-Piste" Ciné-Débat', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Hors-Piste<br>  Projection - Rencontre&nbsp;avec un garde-moniteur</strong></p>  <p style=\"text-align: justify;\">Sensation de liberté, d’évasion. Quand les skis flottent sur la neige, quand le piolet se plante dans la cascade de glace ou quand la voile du parapente nous soulève... Nous pensons être seul pour profiter de ces instants ! Mais saviez-vous qu’ici, dans ces rochers où tout semble désert, des animaux se cachent et tentent de survivre? Bien loin des interdictions, l’idée du film est : « Comment avoir une meilleure pratique de nos activités de plein air pour réduire notre impact ? » Ouvrir les yeux et découvrir ces espèces invisibles, les comprendre et prendre les informations utiles pour les appliquer dans sa pratique de la montagne. Laissez-vous emporter dans cette grande aventure de cinéma !</p>  <p style=\"text-align: justify;\">Cette projection gratuite se prolongera par l’intervention d’un garde du Parc national pour échanger sur les gestes à adopter et ainsi limiter notre dérangement hivernal auprès des espèces.</p>  <p style=\"text-align: justify;\"><br>  &gt; Programmé en partenariat avec le Parc national des Pyrénées<br>  &gt;&nbsp;Tout public&nbsp;<br>  &gt; Salle de cinéma<br>  &gt; Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'bcb674b0-67c1-4765-bcd9-2f6b63976ab1');
