INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Carnaval', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Soirée Carnaval !</strong></p>  <p data-end=\"385\" data-start=\"103\" style=\"text-align: justify;\">Comme chaque année, nous vous donnons rendez-vous pour célébrer le carnaval dans la bonne humeur ! La soirée est offerte et commencera par une déambulation festive accompagnée d’une fanfare, puis un concert pour prolonger la fête avec une buvette et de la petite restauration sur place pour régaler petits et grands. Venez nombreux partager ce moment convivial et musical !</p>  <p data-end=\"385\" data-start=\"103\">Départ à 18h<br>  Déambulation au départ de l’office de tourisme jusqu’à la Maison du Parc national et de la vallée avec la fanfare Pash Pash Orkestar.<br>  Puis en salle des voûtes, buvette et petite restauration avec l’association La Pourtère.<br>  Suivi du concert avec le groupe Tout&nbsp;à l’Est.</p>  <p data-end=\"385\" data-start=\"103\"></p>  <p data-end=\"385\" data-start=\"103\">Pash Pash Orkestar -&nbsp;&nbsp;<a href=\"https://collectif-fanfarnaum.fr/pash-pash-orkestar/\">Pour en savoir plus</a></p>  <p style=\"text-align: justify;\">Le Pash Pash Orkestar, c’est&nbsp;sept musicien.nes&nbsp;toulousain.es réuni.es pour&nbsp;faire sonner les cuivres&nbsp;et les percussions dans la&nbsp;rue, dans ton&nbsp;bar favori, ou dans ton&nbsp;salon&nbsp;! De&nbsp;Goran Bregovic&nbsp;à&nbsp;Ferus Mustafov, en passant par&nbsp;Ekrem Mamutovic&nbsp;et bien d’autres, le Pash Pash Orkestar vous invite au voyage en&nbsp;terres balkaniques&nbsp;sur les rythmes profonds et endiablés des&nbsp;Coček et autres merveilles. Line-up&nbsp;Line up :&nbsp;&nbsp;Julien Alibert – sax alto,&nbsp;​&nbsp;Lisa Hervas – trompette,​&nbsp;Marius Mortier – trompette, ​​&nbsp;Laura Macré – trombone,​​&nbsp;Samuel Berger – trombone,​ Coline Lemarchand – hélicon,&nbsp;&nbsp;Arthur Lemarchand – batterie.</p>  <p style=\"text-align: justify;\">Tout à l''Est -&nbsp;<a href=\"https://www.toutalest.com/?fbclid=IwY2xjawOpFrdleHRuA2FlbQIxMABicmlkETBac0pyeERadlFtS0tUa1hOc3J0YwZhcHBfaWQQMjIyMDM5MTc4ODIwMDg5MgABHmtdwuoz6bNWt1bvDKxFjb016ffrtKPKY23oMkW7r-yjjKnVeHB3n-rmgwc8_aem_c3ESE2tMe0V0xAPCsEVgSw\">Pour en savoir plus</a><br>  Des âmes envoutées par les mélodies tziganes</p>  <p data-end=\"385\" data-start=\"103\" style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">&gt; Offert<br>  &gt; Tout public<br>  &gt; Buvette et restauration sur place<br>  &gt;&nbsp;Organisé par la Maison du Parcnational etde la vallée en partenariat avec l''association La Pourtère</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '4bdc6276-1ba5-4277-a1c5-2e78811613fd');
