INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Appelez-moi encore "Le Funi"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Appelez-moi encore \"Le Funi\"<br>  Association FuniToy</strong></p>  <p style=\"text-align: justify;\">Historiquement la station de Barèges fut l’une des premières stations de ski des Hautes-Pyrénées. Dans les années 1920, de nombreux skieurs montaient à pied ou en peaux de phoque pour pratiquer le ski. Avec l’ère de la mécanisation et de l’industrialisation, l’idée de relier le village de Barèges au plateau du Lienz par des moyens mécaniques émergea ! Le Funiculaire fût construit pour permettre aux locaux et aux touristes de profiter d’un merveilleux domaine skiable dans une forêt magnifique. L’installation fonctionnera de 1937 à 2000.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">L’association Funitoy a été créée par six passionnés du village de Barèges et des forêts avoisinantes. L’association souhaite mettre en valeur le patrimoine naturel de la forêt du Lienz, de l’Ayré et de la Glère ainsi que la réhabilitation du funiculaire.</p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">&gt; Offert<br>  &gt; Tout public<br>  &gt; Salle de cinéma</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '237ed6e6-3b85-4b27-b4b0-db00b3a0e7a3');
