INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Appelez-moi encore "Le Funi"', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Appelez-moi encore \"Le Funi\"<br>  Association FuniToy</strong></p>  <p style=\"text-align: justify;\">Historiquement la station de Barèges fut l’une des premières stations de ski des Hautes-Pyrénées. Dans les années 1920, de nombreux skieurs montaient à pied ou en peaux de phoque pour pratiquer le ski. Avec l’ère de la mécanisation et de l’industrialisation, l’idée de relier le village de Barèges au plateau du Lienz par des moyens mécaniques émergea ! Le Funiculaire fût construit pour permettre aux locaux et aux touristes de profiter d’un merveilleux domaine skiable dans une forêt magnifique. L’installation fonctionnera de 1937 à 2000.</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">L’association Funitoy a été créée par six passionnés du village de Barèges et des forêts avoisinantes. L’association souhaite mettre en valeur le patrimoine naturel de la forêt du Lienz, de l’Ayré et de la Glère ainsi que la réhabilitation du funiculaire.</p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">&gt; Offert<br>  &gt; Tout public<br>  &gt; Salle de cinéma</p>  <p style=\"text-align: justify;\"></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '237ed6e6-3b85-4b27-b4b0-db00b3a0e7a3');
INSERT INTO art_vivant (id, type, archive, immanquable, jeune_public, thumbnail_id, date_start, price, duration, authors, portfolio_authors, tags, location, updated_at, created_at) VALUES
('47bd3f28-bc0b-4e82-bb5c-7c1aa0afc598', 'evenement', true, false, false, NULL, '2026-02-24T23:00:00.000Z', '12€ Normal; 8 € Abonnée; 6 €; 6€ Réduit - 26 ans', '2h', NULL, NULL, NULL, NULL, '2026-02-24T23:00:00.000Z', '2026-02-24T23:00:00.000Z');
INSERT INTO art_vivant_locales (title, description, informations_more, _locale, _parent_id) VALUES ('"Momentum" Cie HBBB', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Momentum . (À&nbsp;nos consolations irrassasiables)</strong><br>  <strong>Compagnie HBB .&nbsp;(Human Body Bastards Brains) </strong><br>  &nbsp;</p>  <p style=\"text-align: justify;\">Dans cette situation sans narration, nous sommes invités à éprouver des décalages. Avec humour et dérapages, la forme propose à voir des archétypes contemporains pour mieux les mettre en crise. Les situations glissent, bifurquent, l’absurde s’invite, la poésie agit comme une stratégie de survie. Le papier, matière centrale, enferme autant qu’il transforme. Il représente le cadre, les règles. Fragile et contraignant, il oppose une résistance où chaque action devient négociation. L’élan naît de la contrainte. Ce qui se brise ouvre un passage. Un lien. Quand il devient impossible de faire demi-tour, ni de voir en avant, créer n’est plus un choix mais une nécessité. Le Momentum selon l’artiste, c’est ce petit décalage qui rend la réalité plus supportable et les liens possibles.</p>  <p style=\"text-align: justify;\"></p>  <p data-end=\"385\" data-start=\"103\"><strong>Distribution</strong><br>  Initié par Claire Lamothe avec Armande Sanseverino et Kostia Cerda<br>  Création lumière Carole China<br>  Création sonore Valérie Leroux<br>  Collaboration à la dramaturgie Marie Menechi<br>  Scénographie Lola Sergent et Claire Lamothe<br>  Compositeur :&nbsp;Martin Malatray-Ravit&nbsp;<br>  Regard chorégraphique Béatrice Debrabant<br>  Regard burlesque Edouard Penaud<br>  Regard extérieur&nbsp;Marine Izard&nbsp;<br>  Crédit photo : Jeanne Lepreux<br>  Remerciements artistes complices Marine Izard, Robinson Khoury, Marie-Elisabeth Wachter<br>  Production / Diffusion Laura Terrieux – bureau PLAYTIME à Toulouse</p>  <p data-end=\"385\" data-start=\"103\"></p>  <p data-end=\"385\" data-start=\"103\"></p>  <p style=\"text-align: justify;\">&gt; Tout public à partir de 8 ans<br>  &gt; Salle de spectacle<br>  &gt; Tarifs spectacle : normal à partir de 14 ans 10€, réduit&nbsp;de 3 à 13 ans inclus + étudiant&nbsp;7€, offert pour les moins de 3 ans&nbsp;</p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\"></p>  <p style=\"text-align: justify;\">Production&nbsp;: Compagnie HBBB<br>  Coproducteurs&nbsp;: L’Escale de Tournefeuille via le dispositif Pas à Pas 2025 DRAC Occitanie), Le Réseau Danse Occitanie, Réseau Pyrénart II, Association TRAVERSE, L’Essieu du Batut, Scène Nationale Albi-Tarn, Le Parvis SN Tarbes Pyrenées (en cours)<br>  Partenaires&nbsp;: Le Lieu NeufNeuf, Centre Culturel Bellegarde à Toulouse, Maison du Parc National et de la Vallée (65), La Tangente à Versailles (78), L’Onde Théâtre - centre d’art (78), La ménagerie de verre (75), Le Théâtre du Fil de l’eau Pantin (93), Réservoir Danse (35), Dantzas, Espagne, Ultima Vez (Belgique)<br>  Soutiens&nbsp;: La DRAC Occitanie - aide au projet danse 2026 - en cours, La région Occitanie - en cours, Le conseil départemental des Hautes-Pyrénées.&nbsp;Ce spectacle reçoit le soutien d''Occitanie en scène dans le cadre du projet Pyrenart II. Le projet Pyrenart Il a été cofinancé à 65 %par l''Union européenne à travers le programme Interreg VI-A Espagne- France-Andorre (POCTEFA 2021-2027). L''objectif du POCTEFA est de renforcer l''intégration économique et sociale de la zone frontalière Espagne-France-Andorre. Lauréate dispositif DRAC Occitanie pas à pas 2024 -2026 avec L’Escale de Tournefeuille en lieu d’accueil et Sylvain Huc comme parrain chorégraphique. Ce projet bénéficie d’un soutien financier du Réseau Danse Occitanie au titre de l’aide à la création 2024.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '47bd3f28-bc0b-4e82-bb5c-7c1aa0afc598');
