INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Atelier impression végétale', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Atelier Impression Végétale<br>  avec l''artiste Emmanuelle Williot</strong></p>  <p></p>  <p style=\"text-align: justify;\">Découvrez l’impression végétale lors d’un atelier créatif animé par Emmanuelle Williot, artiste peintre. À partir de plantes, feuilles et fleurs, vous explorerez une technique artistique poétique permettant de créer des empreintes naturelles uniques sur papier. Un moment de création et d’expérimentation, accessible à tous, pour se laisser surprendre par les formes et les couleurs du végétal.</p>  <p></p>  <p><strong>Informations</strong><br>  Dès 6 ans accompagné d''un adulte, de 15h à 17h soit 2h, offert<br>  Sur inscription à l''accueil de la Maison ou par téléphone au 05 62 92 38 38, 10 personnes maximum</p>  <p></p>  <p></p>  <p></p>  <p></p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'dc759f73-2e92-4faa-aae4-0e63eb8fc325');
