INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rendez-vous des cimes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Rendez-vous des cimes<br>  Animation Nature - Dessins&nbsp;projetés et lectures de textes<br>  Avec l''association Eco''DELS</strong></p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Dans le cadre des projets réalisés avec le Réseau d’Éducation Pyrénées vivantes, l’association Eco’DELS propose une projection immersive et poétique.</p>  <p style=\"text-align: justify;\">Un voyage sensible au coeur des Pyrénées où les dessins d’aquarelle d’Émilie Tarascou et les textes de grands auteurs se rencontrent pour unir les paysages montagnards et répondre au projet Poctefa : « Désir de montagne, désir de refuge ».</p>  <p style=\"text-align: justify;\">La projection sera suivie d’un échange afin de répondre à toutes les questions.</p>  <p style=\"text-align: justify;\">L’Association Eco’DELS, Ecologie, Déchets, Education Ludique et Sensibilisation, a pour principal but de faire prendre conscience de l’impact de l’activité humaine dans notre environnement et en particulier dans nos montagnes. Son mode d’action est de créer des moments d’échanges au travers de jeux éducatifs et collaboratifs sur différents thèmes pour devenir un « randonneur responsable » comme : la vie des animaux, reconnaître une fleur, la vie du déchet dans nos vallées, la vie d’une goutte d’eau et bien d’autres encore.</p>  <p style=\"text-align: justify;\"></p>  <p>&gt; Tout public&nbsp;<br>  &gt; Salle de spectacle<br>  &gt; Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', '88667824-e690-451f-9c96-bdacc1099fe2');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rendez-vous des cimes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Rendez-vous des cimes<br>  Animation Nature - Dessins&nbsp;projetés et lectures de textes<br>  Avec l''association Eco''DELS</strong></p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Dans le cadre des projets réalisés avec le Réseau d’Éducation Pyrénées vivantes, l’association Eco’DELS propose une projection immersive et poétique.</p>  <p style=\"text-align: justify;\">Un voyage sensible au coeur des Pyrénées où les dessins d’aquarelle d’Émilie Tarascou et les textes de grands auteurs se rencontrent pour unir les paysages montagnards et répondre au projet Poctefa : « Désir de montagne, désir de refuge ».</p>  <p style=\"text-align: justify;\">La projection sera suivie d’un échange afin de répondre à toutes les questions.</p>  <p style=\"text-align: justify;\">L’Association Eco’DELS, Ecologie, Déchets, Education Ludique et Sensibilisation, a pour principal but de faire prendre conscience de l’impact de l’activité humaine dans notre environnement et en particulier dans nos montagnes. Son mode d’action est de créer des moments d’échanges au travers de jeux éducatifs et collaboratifs sur différents thèmes pour devenir un « randonneur responsable » comme : la vie des animaux, reconnaître une fleur, la vie du déchet dans nos vallées, la vie d’une goutte d’eau et bien d’autres encore.</p>  <p style=\"text-align: justify;\"></p>  <p>&gt; Tout public&nbsp;<br>  &gt; Salle de spectacle<br>  &gt; Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'en', '88667824-e690-451f-9c96-bdacc1099fe2');
INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Rendez-vous des cimes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p style=\"text-align: center;\"><strong>Rendez-vous des cimes<br>  Animation Nature - Dessins&nbsp;projetés et lectures de textes<br>  Avec l''association Eco''DELS</strong></p>  <p style=\"text-align: center;\"></p>  <p style=\"text-align: justify;\">Dans le cadre des projets réalisés avec le Réseau d’Éducation Pyrénées vivantes, l’association Eco’DELS propose une projection immersive et poétique.</p>  <p style=\"text-align: justify;\">Un voyage sensible au coeur des Pyrénées où les dessins d’aquarelle d’Émilie Tarascou et les textes de grands auteurs se rencontrent pour unir les paysages montagnards et répondre au projet Poctefa : « Désir de montagne, désir de refuge ».</p>  <p style=\"text-align: justify;\">La projection sera suivie d’un échange afin de répondre à toutes les questions.</p>  <p style=\"text-align: justify;\">L’Association Eco’DELS, Ecologie, Déchets, Education Ludique et Sensibilisation, a pour principal but de faire prendre conscience de l’impact de l’activité humaine dans notre environnement et en particulier dans nos montagnes. Son mode d’action est de créer des moments d’échanges au travers de jeux éducatifs et collaboratifs sur différents thèmes pour devenir un « randonneur responsable » comme : la vie des animaux, reconnaître une fleur, la vie du déchet dans nos vallées, la vie d’une goutte d’eau et bien d’autres encore.</p>  <p style=\"text-align: justify;\"></p>  <p>&gt; Tout public&nbsp;<br>  &gt; Salle de spectacle<br>  &gt; Offert</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'es', '88667824-e690-451f-9c96-bdacc1099fe2');
