INSERT INTO autres_actualites_locales (title, description, informations_more, _locale, _parent_id) VALUES ('Entre Plumes', '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"<p>La prochaine rencontre du club se tiendra le&nbsp;lundi 16 février à 17h30&nbsp;salle des voûtes&nbsp;à la maison de la vallée: venez partager vos avis sur l''ouvrage que vous avez choisi: en plus de la présentation au groupe, vous pouvez rédiger votre commentaire sur une fiche qui sera apposée sur la couverture du livre à la médiathèque.&nbsp;Si vous ne pouvez pas être&nbsp;parmi nous, vous pouvez nous envoyer par mail vos avis et conseils que nous partagerons en séance.</p> ","type":"text","version":1}],"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1}],"direction":"ltr","format":"","indent":0,"type":"root","version":1}}', NULL, 'fr', 'dfb8f2e9-599e-4e11-8071-d74a8178ac84');
